const modern = {"1":[["Sensiz yola girersem, adım atmaya çârem yok;","bedenimdeki güç sensin, başımı taşıyıp yürümeye (mecâl sensin)."],["Gönlüm, canım, aklım, bilgim ancak seninle karar (huzur) bulur;","durmadan kanat çırparlar, uçup dosta gitmek için."],["Kendi benliğinden geçeni, sevgili bir doğana çevirir;","ördekle keklik üstüne salar, sürüp avlasın diye."],["Tanrı'nın cennetini seveni, âşık diye mi anayım?","Cennet bile bir tuzakmış, mümin canları (kendine) tutmaya."],["Ganî ve Cebbâr olan Allah, aşk erine bin Hamza gücü verir;","dağları yerinden oynatır, dosta gitmek için yol açar."],["Yüz bin Ferhad kazmayı eline almış, dağların temelini kazar;","kayaları kesip yol açar, Âb-ı Hayât'ı (ölümsüzlük suyunu) akıtmaya."],["Âb-ı Hayât'ın çeşmesi, âşıkların (sevgiliye) kavuşmasıdır;","dolu kadehini dolaştırır, susamışları (özlemle) yakmaya."],["Âşık olan kişi alçakgönüllü olur, yol boyunca teslim olur;","kim ne yaparsa yapsın boyun eğer; gönül yıkmaya (kırmaya) çaresi yoktur."],["Âşıkların âhı, yedi çukurlu cehennemi kül eder;","sekiz cenneti de nura çevirip nura katmaya niyetlenir."],["Bildik: gelenler geçti; gördük: konanlar göçtü;","ama aşk şarabını içen canlar, bu konup göçmeye uymaz (bunun üstündedir)."],["Yunus'un canı hiçbir yere takılmadı; cehennemi de cenneti de aştı;","yola düşüp dosta gider, yeniden aslına (kaynağına) kavuşmaya."]],"2":[["Aşk iddiasında bulunan kişi, hırsı ve nefsanî hevesi hiç anmamalı;","aşk evine girenlere artık ne (başka şeye) eğilim kalır, ne (dünyaya) bağlılık."],["Gerçek âşık olan kişi, ne dünyayı anar ne ahireti;","itibar (makam) peşinde koşan kişi, âşık değildir."],["Kim itibardan (makam sevgisinden) geçmediyse, ona âşıklık (demek) bir iftiradır;","aşk ile itibar, asla tek bir eve birlikte girmemiştir."],["Diliyle 'aşk' diyenler, aşkın ne olduğunu bilmediler;","sen söyle bana: aşkın bedeli itibar (makam) mıdır?"],["İtibar ve mevki, bunların hepsi dünya sevgisidir;","dünyanın itibarını seven, aşktan hiç söz etmesin."],["Dünya ve itibar, aşkla asla bağdaşmadı;","vallahi bu ince söz benim değil — aşkın kendisi (buradadır ve) bunu uygun görmez."],["Kimde aşk varsa, o yere (gönle) artık başka ne sığar?","Dostun döşeğine at da, katır da, deve de geçemez."],["Bütün bu âşık olanlar, aşkla birlikte (var olup) geldiler;","(İlahî) müşâhadeye dalıp gark olan, artık o eve (dünya evine) düşmez."],["Yunus'a âşık deyip de, sakın özenerek (hevesle) bu yola gelmeyin;","nice tüccar, uzak diyara gidince zarar eder."]],"3":[["Senin yüzünü bir kez gören, ömrü boyunca onu hiç unutmaz;","dilindeki zikir sensin, artık başka bir şey söylemez olur."],["İbadetine durmuş sofu, senin nazarına (lütfuna) bir erişirse,","zikrini unutur, artık senden başkasına secde etmez olur."],["Ağzına şeker almışken gözü sana ilişen kişi,","şekerini unutur; onu artık ne çiğner, ne yutar."],["Gelip senin yüzünün nurunun parıltısını bir görse,","dolunay bile parlaklığını senden ders alırdı."],["Seni sevdiğim için bir bedel isteseler,","iki dünyanın mülkünü versem yine de değerini ödeyemem."],["İki dünya baştan başa bağ bahçe olsa,","o bahçede senin kokundan güzel bir gül bitmez."],["Gülün ve fesleğenin kokusu, âşıkla sevgili gibidir;","âşık olanın sevgilisi, gözünün önünden asla gitmez."],["İsrafil sûru üfleyip bütün yaratıklar (dirilip) ayağa kalktığında,","kulağım senin sesinden başka hiçbir şey işitmez."],["Zühre (yıldızı) yere inip sazını çalsa bile,","âşığın zevki sensiz olmaz; gözü o yana bile bakmaz."],["Âşık ev barkını ne yapsın, sensiz dünyayı, hatta canı neylesin?","İki dünya sana feda olsun; kimse bundan şüphe etmesin."],["Sekiz cennetin hurileri süslenip gelseler bile,","gönlüm senin sevginden başkasını asla kabul etmez."],["Bu dünyada olup da ahirette bulunmayacak ne var ki?","Huriyle gılman gelse bile, âşık (onlara) elini uzatmaz."],["Yunus seni seveli, canına müjde erdi;","her an yeni bir hayattadır; ömrü asla eskimez."]],"4":[["İki dünya bir zindan olsa bile, (senin yüzünden) bana bir bahçe olur;","dosttan inâyet (lütuf) geldikten sonra, bana artık ne gam ne tasa?"],["Varıp o dosta kul olayım, her an açılıp gül olayım;","hem ötüp bülbül olayım, durağım gül bahçesi olsun."],["Gözüm o dostun yüzünü gördü; yüzüm erenlere toprak olsun;","sözden anlayana, bu sözüm bir şeker tarlası gibi (tatlı/değerli) gelir."],["Sensiz iki dünya, gözüme bir zindan görünür;","senin aşkınla (sana) âşinâ olan, seçkinlerin seçkini olsa gerek."],["Her iddiadan geçen, Hak'tan yana uçan kişi;","aşk şarabını içen kişi, kâh sarhoş kâh mest olur."],["Münâfığın (ikiyüzlünün) gözü kördür; yarın (mahşerde) yüzü kara çıkar;","halkın bana söylediği acı sözler, (benim için) şeker tarlası gibi (tatlı) olsun."],["Her an yüzümü yere koyup Allah'ıma şükredeyim;","benliğimi dosta vereyim — (artık) ne iddia kalır, ne (benlik) destanı?"],["Özüm aşka dayanamadı; sırrım kendiliğinden açılıverdi;","Yunus, bu sözün âlemlere destan olsun."]],"5":[["Aşkın eteğine yapışmak gerek ki sonunda yok oluş (zevâl) olmasın;","aşktan bir 'elif' bile okuyana, kimse soru sormaz (o sorgudan beridir)."],["Aşk dediğin şeyi bilirsen, aşka gönül verirsen,","aşk yolunda mal nedir ki? Can vermek bile gözüne imkânsız görünmesin."],["Soyluların (asilzâdelerin) alâmetini bilmek istersen:","her sözünün bir manası vardır; sözleri boş ve hafif değildir."],["Âriflerin (irfan ehlinin) alâmeti şudur: her gönülde hazır (her kalbe yakın) olur;","kendini (Hakk'a) teslim eder, sözünde boş çekişme (dedikodu) bulunmaz."],["Görmez misin arıyı — her çiçekten bal yapar;","oysa sineğin ve pervanenin yuvasında bal bulunmaz."],["Cevher (mücevher) istiyorsan, âriflere hizmet et;","câhil bin söz söylese, o sözlerde zerre kadar mana bulunmaz."],["Miskin Yunus — öldürücü zehir bile, aşkın elinde panzehir olur;","ilim ve amel, zühd ve ibadet — hiçbiri aşksız helal (makbul) olmaz."]],"6":[["Anmaz mısın o günü — gözün hiçbir şey görmez olur;","yüzün (bedenin) toprağa düşer, dilin konuşamaz olur."],["Azrail'i hiçbir şey alıkoyamaz; (dünya malı) ne anaya ne babaya fayda eder;","kimse o heybete dayanamaz, halktan (kimseden) sana yardım erişmez olur."],["Sana can alıcı (Azrail) gelir, hem de can alan kılıcıyla;","aklını başından alır, bir an bile aman vermez olur."],["Önce o yıkayıcı gelir, ardından su döken;","sonra (seni) götürüp kefen saran — bunlar artık senin hâlini bilmez olur."],["Oğul hocaya gider, dosta düşmana sala verilir (cenazen duyurulur);","sonra pişman olmak sana fayda etmez olur."],["Seni tahta ata (tabuta) bindirirler, mezara doğru gönderirler;","yer altına indirirler, artık kimse seni görmez olur."],["Üç güne kadar (yas için) otururlar, bütün işini bitirirler;","o sırada (seni) dile getirirler, sonra artık kimse anmaz olur."],["Miskin Yunus, bu öğüdü (önce) kendine versen daha iyiydi;","bu şimdiki insanlara öğüt fayda etmez olur."]],"7":[["Ey âşıklar, ey âşıklar! Aşk yolu (mezhebi) benim dinimdir;","gözüm dostun yüzünü gördü; artık bütün yaslar bana düğündür."],["Artık bizi hiçbir şey yasa boğmaz, gönlümüzü paslandırmaz (kederlendirmez);","Hak'tan gelen güzel ses, O'ndan gelen seda — işte bana her şey odur."],["Artık ne kendime 'ben' derim, ne kimseye 'sen';","ne 'kul' derim ne 'sultan'; varsın işitenler şaşıp kalsın."],["Yolum senden sana varır; dilim seni senden söyler;","Allah'ım, elim sana erişemez; bu hikmet karşısında şaşıp kaldım."],["Aşkından ayrılmayayım, dergâhından (kapından) sürülmeyeyim;","buradan göçsem bile, seninle yine sana varayım."],["O dost bizi gönderdi, 'git, dünyayı bir gör' dedi;","geldim gördüm — dünya bir süsmüş; seni seven ona takılıp kalmaz."],["Kullarına söz verdi, 'yarın (mahşerde) görüneceğim' dedi;","o dostların sevindiği o 'yarın', benim için bugündür."],["Dostun aşkına ulaşalı, dünya ile ahiret bir oldu;","ezeli ve ebedi sorarsan, onlar bana dün ile bugündür."],["Yunus seni din edindi; din nedir? — (seni) iman edindi;","aşka 'bugün', 'yarın' ne ki? Onun baştan sona derdi (nedir)?"]],"8":[["Ey padişah, ey padişah! İşte ben kendimi sana verdim;","bütün hazinem, definem sensin — baştan sona (her şeyim sensin)."],["Başlangıçta da bu akıl ve can seninleydi — (her şeyin) asıl kaynağıydı;","sonunda yine varılacak mekân sensin; oraya, sana doğru varacağım."],["Bu âh ile bu inleyişle, bu sırrı kim ne bilsin?","Bilse de dile gelmez; ben yüzümü sana döndüm."],["Dursam seninle dururum, baksam seninle bakarım;","nereye yürürsem yürüyeyim, gönlümün yönü sana doğrudur."],["Sen bana can ve cihansın, sen bana gizli hazinesin;","kâr da zarar da senindir; kendi başıma bana ne (iş) gelir ki?"],["Yunus yüzünü sana döndü, bütün benliğini unuttu;","bütün sözünü sana söyler; bana sözü söyleten sensin."]],"9":[["Anmaz mısın o günü — bütün âlem şaşkına döner;","kişi ne yapacağını bilemez, kendinden geçip sersemler."],["İsrafil sûrunu üfler, bütün yaratıklar ayağa kalkar;","dirilip mahşere varırlar; orada hâkim (kadı), Sübhân olan Allah'tır."],["Zebânîler çekip tutar, götürüp cehenneme atar;","derisi yanar, kemiği tüter; gece gündüz işi feryattır."],["Mâlik (cehennem bekçisi) seslenir: 'Çekin onu, meydana getirin';","Allah korkusundan, cehennemde (bile herkes) titreyip feryat eder."],["Mâlik 'hey hey, ey cehennem!' der; herkes korkudan titrer;","Tanrı'nın buyruğunu tutmayan, orada (çalı çırpı gibi) kebap olup yanar."],["Dağlar yerinden oynar, heybetinden gök yarılır;","yıldızların bağı kopar, uçuşarak yere düşer."],["Günahlarımız tartılır, nice perdeler yırtılır;","bilmediğin günahların orada sana ayan (açık) olur."],["Yunus bu sözü söyler: yüzünü O'nun dergâhına dön;","gözü Hakk'ı görmek isteyen, lütfun da O'ndan gelmesini dilesin."]],"10":[["Şaşılacak şey — bu dert ve ayrılık benim için ne (tuhaf) şeydir;","canımı sarhoş etti; aşkın zehiri, bana panzehir oldu."],["Kimin bir derdi varsa, derdine derman istesin;","benim bu derdimi (aşk) kesti (iyileştirdi); bu dert bana derman oldu."],["'Aşk ateşine yan' dersen, 'gönüllere gir' dersen,","karanlıklar aydınlanır; bana ne kandil gerek ne mum."],["Gökten inen dört kitabı günde bin kez okusan da,","erenleri inkâr edersen, (İlahî) cemâl (dîdâr) senden uzaktır."],["Miskin Yunus, erenlere karşı kibirlenme, toprak ol;","her şey topraktan biter; gül bahçesi bile topraktandır benim için."]],"11":[["O kişinin (sevgili) dostu yoksa, bu dünya ona bir zindandır;","'ben mutluyum' demesin — mutluluk ona nereden gelsin?"],["Şeddâd (kendi) cennetini yaptı; daha girmeden canını aldılar;","yedi iklimi (bütün dünyayı) elinde tutan Allah, ona bir an aman vermedi."],["'Müslümanım, Çalap'ın (Tanrı'nın) emrine boyun eğmişim' demesin;","Hakk'ın sözünü tutmazsa, dinden ona fayda yoktur."],["'Güneş doğunca etim tenim üşümez' demesin;","madem vücudu (içi) bir pencere gibi açık değil, güneşten ona ışık erişmez."],["Er (derviş) hırkasını giyip de doğru yola gelmezse,","o hırkayı çıkarsın; yoksa o hırkadan ona eksiklik (zarar) gelir."],["(Manen) sağır olan kişiye, Hakk'ın sözünü söyleme;","söylersen boşa gider; o sözden ona nasip yoktur."],["Yol eri olan kişi, garip (kimsesiz) gönüllerin dostudur;","bir söz söyleyeyim — tutarsa, ona şekerden baldan tatlı (üstün) gelir."],["Yunus senin kulundur; sen onu açıkça bilirsin;","bırak konuşanlar konuşsun — onların dilinden ona ne yapışır (zarar gelmez)?"]],"12":[["Ben o aşk denizinin dalgıcıyım; denizler bana hayran;","koca derya bana bir damladır, zerreler bana bir umman."],["Kaf Dağı bana bir zerre bile değil; ay ve güneş bana kul;","aslım Hak'tır, şüphesiz; Kur'an bana kılavuzdur (mürşittir)."],["Madem yolum dosta gider, ülkem ezel mülküdür;","bu dilim Hak'tan söyler; artık bana ne kul var ne sultan."],["Bu koca saray (âlem) yokken, yalnız o padişah (Allah) vardı;","âh bu aşkın elinden âh! — dermanım dert oldu."],["Âdem yaratılmadan, can bedene girmeden,","Şeytan lanetlenmeden — (Allah'ın) Arş'ı bana gölgelikti (sığınaktı)."],["(Allah) kendi yüzünü görmek, kendi sözünü işitmek diledi;","bir kez nazar kıldı (baktı), işte o an bana can verdi."],["Mustafâ (Hz. Peygamber) yaratıldı — yüzü nur, gönlü saflık;","o, Hakk'a vefâ gösterdi; bana gelen ihsan ondandır."],["O dinin değerli sermayesi doğdu; her şey ondan (Hz. Muhammed'den) oldu;","Âdem, Halil (İbrahim) ve Musa — bana hep delil ve burhandır."],["Âşığın dilini bilmeyen, ya delidir ya da dehrî (maddeci);","ben kuş dilini bilirim; Süleyman o dili bana söyler."],["Yunus Emre'm bu yolda kendi eksikliğini bildirir;","mest olup çağırır: 'dervişlik (bana yakıştırılırsa) bir iftiradır, ben ona lâyık değilim.'"]],"13":[["Kim bana yabancı (düşman) ise, Hak Tanrı ona dost olsun;","nereye giderse gitsin, ona bağ ve bahar olsun."],["Bana zehir sunan kişinin aşı (yemeği) bal ve şeker olsun;","bütün işi kolay gelsin; eli (her dilediğine) erişir olsun."],["Önümde bana kuyu kazanı, Hak yüce makama (tahta) yükseltsin;","ardımdan taş atana, güller saçılsın."],["Bana acı bir hayat dileyen, dünyada tatlı (mutlu) yaşasın;","kim ölümümü isterse, ona bin yıl ömür verilsin."],["Kim benim hor olmamı, düşman elinde inlememi dilerse,","onun dostları sevinçli olsun, düşmanı bile ona dost ve yâr olsun."],["Kim benim o dostumdan ayrılmamı dilerse,","gözlerinden perde kalksın; (İlahî) cemâl (dîdâr) ona ayan (açık) olsun."],["Miskin Yunus'un dünyada güldüğünü işitmeyin;","ağlamamı isteyene, gözüm (ona) bir pınar olsun."]],"14":[["Ey zevâlsiz (ebedî) padişah! Yönümü sana döndüm;","bu (günahkâr) kara yüzümle, sana kavuşmayı (vasl) dilerim."],["Bu gözümde gören sensin, dilimde söyleyen sensin;","beni var eden sensin; baştan sona yalnız sensin."],["Sen ki bana 'ben sana, senden (kendinden) daha yakınım' dedin;","madem benden bana daha yakınsın, güzel yüzünü bana göster."],["Sen bana ne kadar yakınsın — ama ben sana müştâk ve hasretim;","gece gündüz seni gözleyip göremiyorum; şaşıp kaldım."],["Her gelen O'dur, giden O; görünen O'dur, gören O;","yüce de alçak da, hepsi birden O'dur — bana öyle görünürse."],["Yunus, bu sır Hakk'ındır; bu dile (sözle) gelmez;","bunu bilmek (yaşanan) bir zevktir; akılla anlayış buna erişmez."]],"15":[["Acaba bu canım âzâd (kurtulmuş) olur mu yâ Rab?","Yoksa yedi cehennemde yanıp kalır mı yâ Rab?"],["Acaba benim hâlim, yer altındaki ahvâlim ne olur?","Varıp yatacağım yer akreple dolar mı yâ Rab?"],["Allah hâkim (kadı) olunca, bizden razı olur mu?","Habîb'i (Peygamber'i) görüp bize şefaatçi olur mu yâ Rab?"],["Can boğazıma geldiğinde, Azrail'i gördüğümde,","ya da canımı aldığında — kolay olur mu yâ Rab?"],["Yunus kabre vardığında, Münker ile Nekir geldiğinde,","bana soru sorduklarında — dilim döner mi yâ Rab?"]],"16":[["İri iri (büyük) günahlarım bana yüz bırakmadı, Çalap (Tanrı'm);","hiç kimse çare bulamadı; yine sana döndüm, Çalap."],["Âlimlere sordum: günahlı derdime derman nedir?","Onlar da dediler ki: ona derman yine Çalap'tır (Allah'tır)."],["Ecel gelip ölünce, o mezara varınca,","zebânîler gelince — sen inâyet eyle (lütfet), Çalap."],["Zebânîler gelip beni yalnız bulunca,","bilmediğim bir dille sorgulayınca — sen yardım eyle, Çalap."],["Kabirde bu soruyu sorunca, onlar bizi esirgemez;","biz de sana yüz tuttuk; sen bizi esirge (bize acı), Çalap."],["Sensin benim sultanım, bu canlar içinde canım;","günahlarım çoktur; sen meded eyle (yardım et), Çalap."],["Cennetteki huriler, nur elbiseler giymiş;","o ne bahtlı müminlerdir — onu bize de nasip eyle, Çalap."],["Durmadan sözümü söylerim; günahıma içim yanar;","günahlı Yunus'un sözünü, sen kabul eyle, Çalap."]],"17":[["Din ve mezhep soracaksan — âşıklara (resmî) dinin ne lüzumu var?","Âşık kişi (aşktan) harap olur; âşık artık din diyaneti (dış kuralları) bilmez (onun ötesindedir)."],["Âşıkların gönlü gözü, sevgiliyi (ma'şûku) isteyerek gider;","artık dış görünüşte ne kalır ki? Kim (kalıp da) zühd ve ibadet yapacak?"],["Kimi cennet için ibadet eder, kimi cehennem (korkusu) için din tutar;","âşık ise bu ikisinden de vazgeçmiştir — bu işaret neye benzer (bir düşün)?"],["Kim dostu severse, dosttan yana gitmesi gerek;","işi gücü dost olunca, bütün öteki işlerden âzât olur (kurtulur)."],["Böyle bir sevgilinin haberini kim getirebilir?","O (mahrem) münâcât olurken, oraya elçi Cebrâil bile sığmaz."],["Dünyayı da ahireti de bırakana, sorgu sual (hesap) olmayacak;","bütün istekler terk edilince, Münker ile Nekir ne sorar?"],["Varlığı yokluğu (benliği) bırakana, korku ve umut nasıl gelir?","Orada ilim de amel de sığmaz — ne (amel) terazisi, ne Sırat (köprüsü)."],["O kıyamet pazarında her kulun derdi (kaygısı) kendi başınadır;","Yunus, sen âşıklarla (beraber olup) kıyameti hiç görmeyesin."]],"18":[["Bu dünyanın mülkünü Kaf'tan Kaf'a (baştan başa) ele geçirdin, diyelim;","ya da bu âlemin malını kumarda oynayıp kazandın, diyelim."],["Süleyman'ın köşkünde taht kurup oturdun, bil;","dev ve perilere baştan başa hükümler yürüttün, diyelim."],["Ferîdûn'un hazinesini, Nûşirevân'ın definesiyle,","hatta Kârûn'un malını da malına kattın, diyelim."],["Bu dünya bir lokmadır, ağızda çiğnenmiş;","çiğnenmişi tutmanın ne anlamı var — haydi, onu yuttun, diyelim."],["Ömrün, yaya çekilmiş dopdolu bir oktur;","gergin okun durması olmaz — haydi, onu attın, diyelim."],["Bu dünya mülkünden seni ansızın çağırırlar;","o 'ansızın'ı şimdiden bil — hazırlanıp gittin, diyelim."],["Madem denizde boğuldun, su boğazına geldi;","deli gibi çırpınma — ey çaresiz, battın, diyelim."],["Her ne zaman bir nefes gelse, o keseden (ömür kesesinden) eksilir;","kese yarılandığına göre, onu tükettin, diyelim."],["Bu ecel şerbetini elbette tadacaksın;","tadacağına şüphe yok — onu şimdiden tattın, diyelim."],["Sonunda bir gün ölürsün; ölüm var, bilirsin;","herkesten ayrılıp varıp mezarda yattın, diyelim."],["Yüz yıl hoşlukla (mutlulukla) ömrün olsa bile, Yunus,","sonu bir nefestir; geç ondan da — onu da aşıp geçtin, diyelim."]],"19":[["Mahiyetimi (niteliğimi) soran, hikâyeyi dinle:","su ve toprak, ateş ve yel — bunlar sûret (beden) oldu."],["Birbirine zıt dört nesneden, (bedenin) dört duvarını","uyumlu kıldı; ona bir kerâmet (olağanüstü düzen) verdi."],["Yel ile toprağı (boşlukta) askıda tuttu;","suyun içinde ateşi (bozulmadan) sapasağlam tuttu."],["Ömrümün rızkını (daha ben yokken) tamamladı;","altı yön (mekân âlemi) oluşmadan, (ruhun) giyeceği kisve (beden) belliydi."],["Ruhumdan kimse haber veremez (onu kimse bilemez);","o (Rabbin) emrindendir; (Allah'ın) kudreti ona hareket verir."],["Geri kalan düzenimi (tertîbimi) açıklayayım:","(Allah'ın) hazır inâyeti, bana işitme ve görme (basiret) verir."],["Aklımın haberi (bilgisi) bugünden değildir;","ona erersen (kavrarsan), o ilk (ezelî) âyettir."],["Soru-cevap sözü ancak buraya kadardır;","bundan sonrası, benim âlemim sonsuzdur."],["Yunus'la (bu konuda) nasibim ancak bu kadar;","gönlüm dostun durağı, dilim de şehadettir (tanıklıktır)."]],"20":[["Aşk bize imamdır, gönül cemaat;","kıblemiz dostun yüzü, namazımız (salâtımız) ise süreklidir."],["Can, dostun mihrabına secdeye vardı;","yüzünü yere koyup münâcât eder (yakarır)."],["Beş vakit (namaz) düzenimiz, tek bir vakte geldi (sürekli oldu);","artık kim beşe bölünüp (ayrı ayrı) ibadet eder?"],["Şeriat bize 'şartı (kuralı) bırakma' der;","oysa o şart, (Hakk'a) hıyanet eden kişi içindir."],["Dostun yüzü görülünce, şirk (ikilik) yağmalanıp gitti;","bu yüzden (sırf dış kabuğuyla) şeriat kapıda kaldı."],["Bizim için münâcât gibi (ayrı) bir vakit yoktur;","çünkü dostla bu an (her an) halvettedir (baş başadır)."],["Kimsenin dinine aykırı bir şey demeyiz;","din tamam (kâmil) olunca, ondan muhabbet (sevgi) doğar."],["Devletimiz (saadetimiz), erenlerin nefesidir;","bu yüzden fitneden (karışıklıktan) selâmette (güvende) olduk."],["Ezelde (ilk demde) 'Kâlû belâ' dedik ('evet, Rabbimizsin' dedik);","o an ile bu saat, hâlâ aynı bugündür."],["Dostun kapısında doğruluğu (sadakati) gözeten,","şüphesiz ki İlahî devleti (saadeti) bulur."],["Yunus o kapıda öyle bir esirdir ki,","ebediyen (o aşktan kurtulup) rahata ermek bile istemez."]],"21":[["Yol boyunca giderken, alabildiğine boy atmış bir ağaç (gördüm);","böyle hoş, böyle tatlı... gönlüm der ki: 'haydi, birkaç sır açıver.'"],["Böyle uzamak ne demek, madem bu dünya fânidir?","Bu, (haddini aşan) bir taşkınlık nişanıdır; gel beri, alçakgönüllülüğe (miskînliğe) geç."],["Böyle hoş süslenip, böyle tatlı donanıp dururken,","gönül Hakk'a uzanmışken — daha ne dilersin, neye muhtaçsın?"],["Ağaç yaşlanır, felek döner; kuş dala bir kez konar;","üstelik sana daha hiç kuş konmamış — ne güvercin, ne de turaç."],["Bir gün sana da son (zevâl) erişir, o yüce boyun yere iner;","dallarınsa ateşe girer — kazan kaynar, saç ısınır (sen odun olursun)."],["Senin sırrın bir erin (ermişin) sırrıdır, yerin bir erin yeridir;","yerin nerededir? sana soruyorum, ey ağaç."],["Yunus Emre, senin eksiklerin pek çok — hem de yüz bin kat;","kuru ağaca yol soracağına, gönlünü ferah tut da yoluna geç."]],"22":[["Gafil olma, gözünü aç; hâline bak, öleni gör;","dünyada taşkınlık (azgınlık) etme; günahların yüzünden (yarın) el açıp dileneceğini gör."],["Nice kişi düşmüş yatar, üstüne yılan çıyan üşüşmüş;","kemikleri dağılıp çürümüş — (bir zamanlar ulu olanı) gör."],["Kimi âh edip inler; elindeki tek varlık günahtır;","göçüp kara toprakta yatar — bir zamanlar gülüp duran o zavallıları gör."],["Kiminin hâlini sorma, Rahmân'sız (imansız) olana varma;","kendi bedenine sarılıp yeni yola koyulanı (göçeni) gör."],["Hani o Muhammed Mustafâ — (nuruyla) Kaf'tan Kaf'a hükmetti (o bile göçtü);","dünya kime vefa göstermiş ki? Ona aldanıp kalanı gör."],["Mala davara aldanma; Hakk'a kulluk et, (O) yardımcına;","sevgiyle öbür dünyaya birlikte gidecek o kalıcı yoldaşı gör (onu edin)."],["Yunus bu sözleri dizer, halka irfan (marifet) satar;","kendisi bu öğütleri ne kadar tutuyor? — söylediği yalana bak!"]],"23":[["Gece gider, gündüz gelir — bak, ne güzel (yerli yerinde) gelir;","Hakk'ın emri, baştan başa bütün cihana dümdüz (her yana eşit) gelir."],["Karanlık sürülür, âlem nurlanır;","karanlığın yerine, ışıkla gündüz gelir."],["İbret almaz mısın, yoksa anlamaz mısın?","Dinle kuşların sesini — ne türlü ezgiler (sazlar) gelir."],["Kuş bir zamanlar yumurtaydı, yuva ise bir perdeydi;","o ses, aslında kudret sesidir; bilmeyene (sadece) bir kaz (sesi) gibi gelir."],["'Anlayayım' diyorsan, sözümün manasını dinle;","ârifin kulağına, kudret sesi hemen (tez) erişir."],["Sağına soluna bir bak; her yola dağılıp gitme;","kudret bağından sana ne sesler (âvâzlar) gelir, gör."],["Sözün sahibi sözünü geri alır, beden (sûret) toprakta kalır;","kim bu hâli bilirse, kendi benliğinden vazgeçer."],["Aklım bu yola gitti, beni benden alıp götürdü;","Yunus'un yükü (yerine) ulaştı; bilmeyene bu az gelir."]],"24":[["Aşkla (Hakk'a) âşinâ olan canlara, ezel-ebed (denen sınır) kalmaz;","(oysa) yolunu şaşırıp bu dünyada kimse kalıcı (bâkî) olmayacak."],["Bir elbiseye kan bulaşınca, yıkanmadıkça temiz (mismil) olmaz;","gönlün pası yıkanmadıkça da namaz (gereği gibi) eda olmaz."],["Gönlün pasını yıkadıysan, kibri kini bıraktıysan (bile),","(yola) ikrârın tam olmadıkça, erden (mürşitten) nazar (himmet) gelmez."],["Bu (iç) kirini biriktirenler, onu (sıradan) su ile yıkadık sanır;","erden himmet gelmedikçe, ömür geçer ama (gönül) yıkanmaz."],["Yunus, şimdi sen Hakk'a er; gece gündüz gönlünü Hakk'a ver;","gönül gözü görmedikçe, bu baş gözü (de) görmez."]],"25":[["Aşkın makamı yücedir; aşk kadîmdir, ezelîdir;","aşkın sözünü söyleyen — bunların hepsi kudretin dilidir (Allah söyletir)."],["Dinleyen O, işiten O; gören O, gösteren O;","her sözü söyleyen O'dur; bu sûret (beden), canın konağıdır."],["Sûret (cansız beden) sözü nereden buldu, söz nerede iş (eyleme) döndü?","(Söz) sûrete kendiliğinden geldi; dil, hikmetin (İlahî sırrın) yoludur."],["Sûretler kendi başına ses çıkaramaz; söz, O olmadan söylenmez;","işler de perdesiz (vasıtasız) olmaz — bu, risâletin (peygamberliğin) ürünüdür."],["Bu, bizim (gönül) meclisimizdir; bu, bizim lezzetimizdir;","içip sarhoş olduğumuz şey, aşk şerbetinin gülüdür."],["Onu O'na (Hakk'a) verirsin; söyleyen O'dur, söz O'nundur;","O bizimdir, biz O'nunuz; gerisi yalnızca tesbih (zikir) dilidir."],["Yunus'un sözüne kusur bulan inkârcı, (gerçeği) görememiştir;","ömrünü karanlığa salan kişi, marifet (irfan) yoksuludur."]],"26":[["Ey beni ayıplayan, gel de beni aşktan kurtar;","elinden gelmiyorsa, boş (yanlış) söz söyleme."],["Âşıkların işi (ahvâli), sevgilinin katında biter;","sözün varsa O'na söyle; benim elimde ne var ki?"],["Kim dostun yüzünden peçeyi (nikâbı) kaldırdıysa,","ona artık perde kalmadı — ne hayır ne şer (ikiliği)."],["Hiç kimse kendi gücüyle hâlden hâle geçmedi;","âşıkların canına gagasını (minkârını) vuran, sevgilidir."],["Kim aşk kadehinden bir zerre içtiyse,","onda ne akıl kalır ne us, ne (sıradan) sarhoşluk ne de humar (baş ağrısı)."],["O sevgilinin nazarında âşık tek ben değilim;","aşk yoluna can feda olmuş — benim gibi yüz binlercesi var."],["Âşıkların hâlini, ancak âşık olanlar bilir;","aşk gizli bir hazinedir; sırları da gizli kalmalıdır."],["Şeriat edebinden ötürü söylemeye korkarım;","yoksa sana daha (bambaşka) sırlar söylerdim."],["Bu (sıradan) dille o sevgiliden kim haber verebilir?","Ancak canının içinde (bir başka) canı olanlar verebilir."],["Yunus aşk içinde ölürse ne gam, kardeşler;","aşk yoluna uyan kişi, sevgilinin burcunda (yeniden) doğar."]],"27":[["Haberi, manadan (hakikatten) haberi olan bir kişiden sor;","gönlünü, canında aşk izi (eseri) olan bir kişiye ver."],["Dışı hoş görünenin, bil ki içi boştur;","gece gündüz baykuş öter orada; duvarları sağlam sanma."],["Bir çaylak yuva yapar, dolaşıp ilden yavru kapar;","doğanın yanından kaçar; pençesinde leş (murdar) taşır."],["Onun (çaylağın) ne doğanla birliği var, ne Hakk'a layık bir yaşayışı;","sen erliği (ermişliği), bakışı tertemiz (safâ-nazar) olan bir kişiden um."],["Sûretçe (görünüşte) insan çoktur, ama her birinde (gerçek) bir kadem (makam) yoktur;","başta da sonda da önder (pîş-kadem), o tek Muhammed serveridir."],["Aceleci kişinin yolu ormanlıktır; orman, hilekâra (kolmaşa) kolay gelir;","orman olan yerde, ey efendi, Anter gibi nice haydut vardır."],["Şeyh, âlim ve velî — erin yolu hepsi için birdir;","Yunus, dervişlerin kuludur; Tapduk gibi bir önderi (serveri) var."]],"28":[["Ey aşk eri, gözünü aç, yeryüzüne bir bak;","şu zarif çiçekleri gör — süslenip Hakk'a gider."],["Bunlar yazın süslenip, dosttan yana uzanıp dururken,","sen bir sor, ahî (kardeş), onlara: yolculuk nereye?"],["Her çiçek bin nazla, yakararak (niyazla) Hakk'ı över;","her kuş, hoş sesiyle o padişahı zikreder."],["(Çiçek) O'nun kudretini, her işe hazır oluşunu över;","ama ömrün kısalığını anınca, rengi solar (döner)."],["Rengi günden güne solar, yine toprağa dökülür;","bu, anlayana bir ibrettir; bu ibreti ârif sezer."],["Bu sırrı bir sezeydin, ya bu gamı (içine) çekeydin,","olduğun yerde eriyiverirdin; iş güç (dünya telaşı) senden giderdi."],["Ne gelişin (gerçek) bir geliştir, ne bilişin (gerçek) bir biliş;","son durağın ölümdür; oysa aşktan bir iz bile sezmedin."],["Bildik ki gelen geçermiş, konan yine göçermiş;","bu manayı sezen kim varsa, aşk şerbetini içermiş."],["Yunus, bu sözleri bırak; kendi benliğinden elini çek (vazgeç);","bir kez söyle: senden ne gelir ki — madem hayır da şer de Hak'tandır."]],"29":[["Susmanın sıradanı (en düşüğü bile), söylemenin özü (en iyisi) sayılır;","söylemenin sıradanı (boş lakırdı) ise, gönüllerin pasıdır."],["Bu gönüllerin pasını yıkayıp gidermek için,","sözün özü (hülâsası) olan o sözü söyle."],["Sözü doğru söyleyene Çalap (Allah) 'Kuli'l-Hak' (gerçeği söyle) dedi;","burada yalan söyleyen, yarın (mahşerde) utanacaktır."],["Yetmiş iki millete birlik (eşitlik) gözüyle bakmayan kişi,","şeriatçe veli sayılsa bile, hakikatte âsîdir (isyankârdır)."],["Şeriat ile hakikatin vasfını sana söyleyeyim:","şeriat bir gemidir, hakikat (onun yüzdüğü) deryadır."],["Geminin tahtaları ne kadar sağlam olsa da,","deniz bir dalga vurunca onu paramparça eder."],["Aşktan perişan (şûrîde) olanların dünyası, sonsuzdur;","akıl, gönül, anlayış, can, fikir — onun yanında ne ki?"],["Biz tâlibiz (isteğiz); her an aşkın dersini (sebak) okuruz;","dersi Tanrı verir; aşkın kendisi (bize) müderristir (hocadır)."],["Bundan daha derin bir haber işit, sana söyleyeyim, ey dost:","hakikatin kâfiri olan kişi, ancak şeriatın velisidir (dış kabukla velidir)."],["Geyiklü Baba bize bir kez nazar kılalı (bakalı),","Yunus'a nasibi ne ise, hepsi hâsıl oldu (gerçekleşti)."]],"30":[["Bu yokluk yoluna bugün bize yoldaş olan kimdir?","Aslımıza (ülkemize) yönelelim; sorun bakalım — kardeş olan kimdir?"],["Bu iklimde (dünyada) ağır yüklerin altında ne çok kaldık;","bu yükleri, bu (gereksiz) ağırlıkları döküp hâldaş (yoldaş) olan kimdir?"],["Seni buraya gönderdi, 'bir gez, bir seyret (teferrüc et)' dedi;","sen (kalıcıymışsın gibi) ev yaparsın, ey efendi — o evi yıkacak olan kimdir?"],["Bu yeryüzünü (Ferş'i) gördük, aldandık; henüz Arş'a (göğe) eremedik;","ey efendi, gör bakalım — bu Arş'ı ve Ferş'i döşeyen (ferrâş) kimdir?"],["Gelin gidelim, gelin — çünkü Yunus geçti, (yola) yöneldi;","Yunus herkesin ayağına kapanır; bu yola baş (önder) olan kimdir?"]],"31":[["Ben sâhib-kırânım (talihli cihan eriyim); devrân (dünya) benimdir;","ben yaman bir pehlivanım; meydan benimdir."],["Haydutten ne korkum var ne kaygım;","bu güç, bu kuvvet, Hak'tan (bana verilmiş) benimdir."],["Ebû Bekir ile Ömer — o din ulusu;","Aliyy-i Murtazâ ve Osman benimdir."],["Çevgânımızdan (sopamızdan) topu kim alabilir?","Bu çevgân, top ve meydan — hepsi benimdir."],["Yoksul olan bana gelsin, zengin (bay) olsun;","bu mal, bu sermaye, bu dükkân benimdir."],["Bedenimdeki iman nuru Hasan'dır;","irfan sahibi Hüseyin de benimdir."],["Yunus'um ben, Yunus — bu cihanda;","ben sultanın kuluyum; o sultan da benimdir."]],"32":[["Dostla kavuşmuş (visâle ermiş) o âşığın canına feda ol (her şeyini saç);","onun canı sevgiliyle birdir; başka ne hâli olsun ki?"],["Can ve gönül, akıl ve anlayış — hepsi sevgiliye feda olsun;","o hâlde âşığın O'ndan başka ne mülkü ne malı olur?"],["Bu yer ve gök, Arş ve Ferş, aşkın tadıyla ayakta durur;","temeli aşktır; âşığın her yerde bir eli (payı) vardır."],["Âşıkların nesi varsa — aslolan aradaki tecrîddir (her şeyden soyunmaktır);","o, her şeye hükmeder; her yolun içinde kendi yolu vardır."],["Kalıcı (bâkî) hayatı seven kişi, aşkın eteğine yapışmalı;","aşktan başka her şey değişir ve bir sonu (zevâli) vardır."],["Âşıklara bu sûret (beden), mesela bir gömlek gibidir;","yüz bin gömlek eskitseler bile, âşıkların (ölmesi) imkânsızdır (muhâldir)."],["Niceleri Yunus'a der: 'madem yaşlandın, aşkı bırak artık';","oysa zaman aşka uğramaz (etki etmez); aşkın ne ayı var ne yılı?"]],"33":[["Ölüm düşüncesini bırak; âşık ölmez, bâkîdir (kalıcıdır);","canın İlâhî (Allah'tan) olduğuna göre, ölüm senin neyin olabilir?"],["Ölümden niye korkarsın? Korkma — sen ebedîsin;","madem (Hakk'ın katında) işe yararsın, (yok olacağın) sözü asılsız bir iddiadır."],["Bu cevhere, ya da bu gizli nura bir bak;","Hakk'ın nazargâhı (baktığı yer) olduğuna göre, o nur hiç yiter mi?"],["'Kâlû belâ' denmeden, biz O'nu ezelden beri bilirdik;","iyice anla bunun ne olduğunu — asıl tanışıklığın nerededir?"],["Yaratıcıya (Hâlik'e) şükret; O, Hayyü'l-Bekâ'dır (ebediyen diridir);","O'na mutlaka varacaksın; bâri şükür ile hazır dur."],["Ezelden tanışıktık, birliğe ermiştik;","sen bu sûrete (bedene) bakma; vücut, canın kabıdır (zarfıdır)."],["Bu ezelî birliği, ya bu dünya yaşayışını (dirliğini),","ya da bu gönül birliğini — bil ki hepsi kudretin bir dalıdır."],["Bilen kişiye, gerçek dirliği tutup gelene yabancılık yoktur;","beraberliği (birliği) dile getirene, kavuşma (vuslat) yolu sağlamdır."],["Yürüyen hükmün (akan kaderin) mülkünü, o işi ancak kendisi bilir;","iş (yaratılış) husule geldiğine göre, bu mülk varlık evidir."],["Yunus, sana müjde; dosttan yana 'gel' derler;","'Her şey aslına döner' (Küllü şey'in yerciu ilâ aslihî) — işte sözün aslı budur."]],"34":[["Can, ulu bir kimsedir; beden ise onun aletidir;","yediğin her lokma, yalnız bedenin kuvvetidir."],["Ne kadar çok yersen, o kadar tok dolaşırsın;","cana hiç fayda (assı) yok — bunların hepsi bedenin (sûretin) işidir."],["Bu canın nimeti (azığı) hani? Gelin onu bulalım;","cana huzur (asayiş) veren şey, evliyâ sohbetidir."],["Sohbet, canı besler; hem âşığın asıl ömrüdür;","Hak Çalap'ın emriyle, erenin himmetidir."],["Erenin yüz suyu (itibarı), himmeti, Arş'tan yücedir;","bu güzel hâlde kimi görsen, o, erenin inâyetidir (sayesindedir)."],["İnâyet O'nun işidir; bunu her kişi anlamaz;","bil ki bu hümâ kuşu (devlet kuşu), âşıkların saadetidir."],["Yunus'un içi yanar, gönlü herkesten alçaktır (küçüktür);","soyla (asaletle) anılmaması (umursamaması), erenin himmeti sayesindedir."]],"35":[["O (dünya malı) seni Hak'tan alıkoyar; neyin varsa ver de geç;","bu teni niye beslersin? Mezarda kurt kuş yer de gider."],["Gözünü aç, öleni gör; sakalı saçı dökülür;","yılan çıyan aç gelir; yiyip içip doyarak (sir) gider."],["Bizden ulu olanlar, pek iyi huylular,","o iyi amelliler — bu haberi böyle söyler de gider."],["Elini haramdan kes, dilini gıybetten kes;","Azrail'in eli ermeden, (bir bakmışsın) bu dükkân (ömür) dürülüp gider."],["Ecel erer, baş kurur; o uzun ömür tez tükenir;","dağ taş dümdüz olur, gök dürülür, yer (yok olup) gider."],["Madem can (sonunda) Hazret'e (Hakk'a) yükselir, ahirete azık hazırla;","seher vakti ibadete kalkıp, Tanrı evine er de git."],["Ey Yunus, sen ölünce, mezarın nurla dolunca,","iman sana yoldaş olunca — ahirete arslan (şîr) gibi gidersin."]],"36":[["Canını aşk yoluna vermeyen, âşık mıdır?","Cehd edip (çabalayıp) o dosta erişmeyen, âşık mıdır?"],["Aşk kadehinden içip, nefsin dileğinden geçip,","Hak yolunda er gibi durmayan, âşık mıdır?"],["Dost sevgisini gönülde canıyla pekiştirmeyen,","uzun (bitmez) dünya hevesinin defterini dürmeyen — âşık mıdır?"],["Sürekli riyâzet çekip (nefsini terbiye edip), halvetlerde diz çöküp,","Hak cemâlinden (dîdâr) bir iz görmeyen — âşık mıdır?"],["Aşka hesap kitap (danışıklık) sığmaz; her can göğe yükselemez;","pervane gibi ateşe yanmayan, âşık mıdır?"],["Kişi dertli olunca, derman isteyen olur;","kendi derdinin dermanını sormayan, âşık mıdır?"],["Ey Yunus, sen dostunun cefasına katlan;","yüreğine aşk okunu vurmayan, âşık mıdır?"]],"37":[["Vuslata (kavuşmaya) erdiysen, bu dert ve ayrılık nedir?","Dostu yakın gördüysen, bu baktığın 'uzak' nedir?"],["Vuslat eri olan kişi, benliğinden (varlıktan) yok olmalı (mahvolmalı);","bu yola girmek için, bir görelim — azık (yarak) nedir?"],["Vuslat eri olduysan, gözün perdesini (hicâbını) bildiysen,","dostu apaçık (ıyân) gördüysen — bu benliği (varlığı) bırak, ne duruyorsun?"],["İlmin kendisi (zaten) gözün perdesidir; o, dünya-ahiret hesabıdır;","asıl kitap, aşk kitabıdır; bu okunan (öteki) yapraklar nedir?"],["Sakın, gözünü açıver; nefsin tuzağını seçip ayırt et;","dostun meclisine (mahfiline) geçiver — ondan daha iyi bir makam (durak) var mı?"],["'Gözüm görür' dersin; öyleyse iddiasını manaya (gerçeğe) erdir;","gündüz güneş ışık verirken, gece yanan o mum (çırak) ne işe yarar?"],["Yunus der: açıkça da, gizlice de, Hak iki cihanı doldurmuştur;","dosta giden beri gelsin — ona huri, köşk, Burak da nedir?"]],"38":[["Hakikatin manasını, kuru şerhle (açıklamayla) bilemediler;","erenler bu hayatı (dirliği), riyâ (ikiyüzlülük) ile yaşamadılar."],["Hakikat bir denizdir, şeriat onun gemisi;","çokları gemiden çıkıp denize dalmadılar."],["Bunlar huzura (tapuya) geldi, ama yalnızca şeriatı tutup durdu;","içeri girip orada ne olduğunu (hakikati) bilmediler."],["Şeriat çocukları (acemileri) tartışıp iddialaşır;","hakikat erenleri ise boş iddiaya kalmadılar (takılmadılar)."],["Dört kitabı (yalnızca) kuru kuruya şerh eden, hakikatte âsîdir (isyandadır);","zira tefsir okuyup gerçek manasını bilmediler."],["Yunus, bu yola geldiysen, adın sâdıktır (doğrudur);","adını (eski benliğini) değiştirmeyenler, bu yola gelmediler."]],"39":[["Süsü, (resim gibi) güzeli bırak gel; sakın o suret sana yol bulmasın;","nakışla (dış güzellikle) yola giren, sonunda dünyayı sever."],["Dünyayı elden bırak; bu yolda dünya bir perdedir (hicâb);","biz, veliden de nebîden de haberi böyle işittik."],["Ya dünyayı sev, dünyayı tut; ya gel, yolu yürü;","'iki iddia tek mana' (ikisi bir arada) bu yola sığmaz, derler."],["Yaratılmışlar için (gösterişe dayalı) ibadeti geç; gözünü dostun katından ayırma;","geçici (fânî) surete aldanma — geçici nakşı ne yapsınlar (neye yarar)?"],["Bu rengârenk (oyalayan) dünyaya, yüz bin yıllık o uzun mesafeye takılıp kalma;","erenler iki cihanı tek adımda, hiç şaşmadan geçiverirler."],["Bu devrandan (dünyadan) öteye geç; kervan gitti — sen de yetiş;","sağda solda tehlike (korku) var; erenler hiç sapmadan giderler."],["Dışarının (yabanın) yolunu gözetme; yol senin içindedir — dışarı çıkma;","canın yolu canın içindedir; canın sırrını ancak can sezer."],["Canın sırrını ancak can bilsin; can, sırrını dile vermez;","gerçek âşık, dostuyla (olan bağında) yalanı ne zaman söyler (asla)?"],["Ezelden beri vahdet (birlik) evine gelen kişi,","yücelerek içeri girer; oysa Yunus dışarıda, habersiz kalır."]],"40":[["Hak erleri (merdân) bu dünyada (geçici) muratlara takılıp kalmadılar;","bekâ (ölümsüzlük) mülkünü bulmuşken, fâniye meyletmediler."],["Bellidir, ahî (kardeş), yol erlerinin Mevlâ için neler ettiği;","her biri mihnet (sıkıntı) içinde alçakgönüllü (miskîn) olup gülmediler."],["Müştakların (özlem çekenlerin) işi şudur: gözyaşları durmadan (müdâm) akar;","Hakk'ı mutlak (gerçekten) seven kişiler, ne mala ne cana takıldılar."],["Mansûr, derdiyle birlikte meşhur olup yola geldi;","Mecnun gibi dillere düştüler; yine de sevgiliden ayrılmadılar."],["Bu işe (kadere) mahkûmsan, inkârcı gibi 'niçin?' deme;","baştan başa hiçbir zorluğu (müşkili) yok — mümin olanlar (gerçekte) ölmediler."],["Yaratılmışların bilgisinden geçen kişi, işte Mi'râc'a doğru uçan odur;","mana şarabını içenler, o sarhoşluktan bir daha ayılmadılar."],["Yunus'a asıl menzil (varış) bu aşktır; Hakk'a yüz bin şükür, minnet;","menzili bulan buldu; artık övgüyle (dünya) mülküne çekilip sapmadılar."]],"41":[["Ey bana 'iyi' diyen, ben hepsinin en aşağısıyım (kemterim);","öyle suçluyum ki, yoldaki suçlular bana göre önder (benden üstün) sayılır."],["Benim gibi suçlu bir kul ara da bir tane daha bul;","dilimde ilim ve usûl var, ama gönlüm dünyayı sever."],["Dışım iyi adla anılır, ama gönlüm ibadette bozuktur (fâsid);","Bağdat'ta bile benim gibi bir ayyâr (ikiyüzlü) bulunmaz."],["Dışım dost gibi, içim yabancı; dilim hoş, gönlüm dönek (mürted);","kötü işe güzel ad... böyle fitne (ikiyüzlülük) nerede var?"],["Dışım yanar, içim ham; hâlim hep böyle;","yolda bir adım bile gitmedim, ama Arş'tan haber veririm."],["Hırkam, suçuma bir perdedir; düşüncem kötü (fâsid) yerlerde;","gönlüm başka pazarda (dünyada), dilimdeyse sözüm sırlardan (esrâr)."],["Kime öğüt verdiysem, onun Hakk'a erdiğini gördüm;","ama kendi öğüdüm bana hiç etki etmedi."],["Şeyhlik adını takındım, sevgilinin ibadetini bıraktım;","nefsin isteğini verdim — hani Hak'la olan alışverişim (hesabım)?"],["Yunus'un adı dört yana yayıldı; oysa bütün ibadeti suçtur;","olsa olsa, Çalap'ımın (Allah'ımın) inâyeti (lütfu) suçunu bağışlar."]],"42":[["Ey sözlerin aslını bilen, gel söyle: bu söz nereden gelir?","Sözün aslını anlamayan, bu sözün benden geldiğini sanır."],["Söz vardır gönlü şâd (sevinçli) eder; söz vardır dostu yabancı (yad) kılar;","ister horluk olsun ister itibar, her kişiye sözünden gelir."],["Söz, karadan akdan (yazıdan) değil, yazıp okumaktan değil;","bu söz, gezen halktan değil — Yaratıcının (Hâlik'in) sesinden gelir."],["Ne elif okudum ne cim (harf bilmem); sözüm kendi varlığımdan değil;","yüz bin müneccim bilemez — tâlihim hangi yıldızdan gelir."],["Işığımız aydan değil; aşk eri bu soydan (sıradan nesilden) değil;","rızkımız bu evden değil — engin deryadan (deryâ-yı ummân) gelir."],["Başlangıçta Hak, gönül levhasına bir sayfa yazmıştı;","şimdi okunan bu ders (sebak), ezellerin ezelinden gelir."],["Önce Hak cana hitap eder; can, O'ndan tene gelir;","biz aletiz, bahaneyiz; elimizden başka ne gelir ki?"],["Aklımız o levhaya bakar; gizli dertlerimi (marazlarımı) açar;","söz gelir gönlüme akar; söz dile ansızın gelir."],["Biz aradaki bir bahaneyiz; söyle, başka elden ne gelir?","Madem Hak cana emreder, bu söz (keleci) O'ndan gelir."],["Yunus, bu dertle âh et; kahır evinde rahatın ne işi var?","Bu derde derman ve kefaret, bir âh ile yanmaktan (sûz) gelir."]],"43":[["İşitin, ey büyük küçük; size bir haberim var;","ne büyük saadet (zihî devlet) bugün benim — senin gibi bir yârim var."],["Yürürsem önümdesin, söylersem dilimdesin;","oturursam yanımdasın; başka yerde ne işim (pazarım) var?"],["Ne bir yere yürürüm ne dururum, ne de uzak bir sefere giderim;","madem dostu burada buldum, başka neye seferim var?"],["Tüccarlar kâr (assı) etmek için uzak yola giderler;","madem cevher zaten elimde, söyle — başka ne pazarım var?"],["Miskin Yunus'un bu canı, o dosta ulaşalı,","her an aşkını artırır; yüce bir yerden gelen bir tîmârım (bakımım) var."]],"44":[["İşin sahibini (Allah'ı) arayalım, nerede olduğunu bulalım;","can kulağıyla dinlersen, bu sözüm turfandadır (taptaze, kıymetli)."],["Turfandadan (bu taze nimetten) alın; onu ancak aşk eri tadar;","burada boyun eğen (alçakgönüllü) insan, Hak katında (el açan) bir muhtaçtır."],["Kişi O'nu bilmeli; hem canı uyanık (ârif) olmalı;","bilirsin, dünyayı seven, baykuş gibi viranededir (harabededir)."],["Baykuş viranede öter; kimse orada muradına ermez;","iyi amel işleyin — o Hak terazisi (mizan) oradadır (ahirettedir)."],["Teraziye varınca, Hak günaha (yazıya) bizzat bakar;","o dehşeti görünce dağlar erir; o zebânîler oradadır."],["Amel defteri (biti) eline verilir; ne işlediysen önüne gelir;","şahitler de bulunur; dostun da düşmanın da oradadır."],["Tahtı tacı (makamı mevkiyi) terk edersin; ettiğin göçü (ölümü) anlarsın;","Muhammed, Hakk'a yalvarandır; şefaatçimiz oradadır."],["Ey Yunus, sen âşıksan, iman kuşağını sıkıca kuşan;","benliğini (varlığını) yokluğa değiş; bütün eksiklik sendedir."]],"45":[["Âşıklara müjdeleyin; bu aşk, ulu bir saadet (devlet) olur;","aşk kime erdiyse, bil ki onun canında bir gönül şenliği (işret) olur."],["Sevdiği her şeyi terk etsin, her yana (her şeye) sapmasın;","her an onun seyran yeri, hem Allah'ın zâtı hem sıfatları olur."],["Seyrinde (yolculuğunda) çevik bir ustadır; düşüncesi daima naz ve niyazdır;","sırdaşı (hem-râz) saadeti olunca, binlerce münâcât (yakarış) olur."],["Müşâhade (İlahî temaşa) onu kapar; canı bir an duramaz olur;","her an, mana iddiasızdır; lütuf esirgemeden gelir, huzur olur."],["O, cihandan münezzeh, nişansızdır; dilimiz O'ndan ne söylesin?","O — her şeyi bilen (âlim) ve hesap gören (deyyân) zât — her özün içindeki özdür."],["Cimrilik ve aç gözlülük ona sığmaz; itibar kaygısı da bir yana kalkmıştır;","kimde bu saadet (devlet) varsa, ona hırs ve heves yol bulamaz."],["O işlere eli yeten, Hak aşkına gönül veren,","dostunu yüz yüze gören kişi — bütün benlikten mât olur (silinir)."],["O İlahî iniş (feyiz) kime indiyse, bütün asıllar ona gelir;","bir taziyeye varsa, o ölüye rahmet olur."],["Yunus, sonu olmayan bir erdir; aşk ise ondan da sınırsızdır;","ne sınır var ne son — hepsi bir Hazret (İlahî huzur) olur."]],"46":[["Bir an, bu bedenimin şehrine giresim gelir;","içindeki sultanın yüzünü göresim gelir."],["Sözünü işitirim, ama yüzünü göremem;","yüzünü görmek için canımı veresim gelir."],["Sevgilinin halvetinin (gizli odasının) yedi kapısı vardır;","o kapıdan içeri girip seyran (temaşa) kılasım gelir."],["Her kapıda bir kişi, onun da yüz bin askeri (çerisi) vardır;","aşk kılıcını kuşanıp hepsini kırasım gelir."],["Erenlerin sohbeti, marifeti (irfanı) artırır;","dertsizleri (aşktan habersizleri) sohbetten her an süresim gelir."],["Mecnun'un Leylâ'sı benim; Rahmân'ın divanesi (şeydâsı) benim;","Leylâ'nın yüzünü görmek için Mecnun olasım gelir."],["Dost bize bunca yıl, bunca zaman misafir oldu;","gerçek İsmail gibi kurban olasım gelir."],["Erenlerin nazarı (bakışı), toprağı cevher eder;","erenlerin ayağında (kademinde) toprak olasım gelir."],["Yârimden elçi gelir, canımdan bir haberci (ulak) ister;","merkepten (binekten) inip yayan (yürüyerek) varasım gelir."],["Miskin Yunus'un nefsi, dört tabiat (dört unsur) içindedir;","aşkla, canın sırrına gizlice (pinhân) varasım gelir."]],"47":[["Yüreğim yandı, bağrım tutuştu, ciğerim kebap oldu;","âşıkların şerbetleri (içtiği aşk), bu derdimin sebebidir."],["Aşk kimini düzeltir (yapar), kimini bozar;","kimi sarhoş (esrük) gezer; öylesi var ki büsbütün harap (kendinden geçmiş) olur."],["Kader kalemi aşkla çalındı (yazıldı); âlem aşka esirdir (yesir);","âşıklar arasında Cebrâil bile bir perdedir (hicâb)."],["Medreselerin müderrisleri (hocaları) bu dersi okumadılar;","öylece âciz kaldılar; bunun hangi bab (konu) olduğunu bilmediler."],["Azâzîl (İblis) bir iddia ileri sürdü; iddiası yalan çıktı;","yalan iddia edenlerin cezası, öyleyse azaptır."],["Bu aşk âşinâları (dostları) ölmez; bunlar manevî meclisin sarhoşlarıdır;","daima işleri çeng (harp), şeşte ve rebab (çalgılarla semâ)dır."],["Yunus, şimdi alçakgönüllü (miskîn) ol; hem miskînlere kul ol;","zira miskîn olanları arzulayan (seven), Çalap'tır (Allah'tır)."]],"48":[["Padişahlık senindir, kudretin var;","yeri göğü sen yarattın, heybetin (azametin) var."],["Nişansız (izsiz) olan nişanını kimse bilmez;","her ne kadar sonsuz (bî-nihâyet) âyetin (delilin) varsa da."],["Dil, senin mahiyetini (niteliğini) nasıl söyleyebilsin?","Dile getirilecek bin bir adın var."],["Ne ölçün (oranın) var ne kıyasın, ne nakşın ne nişanın;","ne ortan ne kenarın — ne de bir sonun (nihâyetin)."],["Ne rengin ne şeklin, ne cismin ne de bir biçimin;","ne boyun bosun (kadd ü kâmetin) ne sûretin var."],["Bütün bu insanlara ve cinlere, rahmetinden;","inâyet (lütuf) yoluyla, hoş bir himmetin var."],["Ne dünya ne ahiret, ne Kaf (dağı) ne öteki Kaf;","bunlar (senin yanında) bir damladır; senin koca bir deryan, melekûtun var."],["Ne bir sonun (intihâ) var, ne bir sınırın (had), ne de mekânın;","ne sınırlı bir benliğin (eniyet) ne de bir niceliğin (keyfiyet) var."],["Akıllar, senin mahiyetin karşısında mât olur (yenilir);","zira bir zerrede bile bin bin (sayısız) ibretin var."],["Baştan başa, yer ve gök üzre dopdolu;","bu kudretin her yerde yürür; senin hoş bir mülkün (milketin) var."],["Arş ve Kürsî, Levh ve Kalem senindir;","felek (çarh) döner, yer durur; senin hoş bir hikmetin var."],["Bu yüz yirmi dört bin peygamberle birlikte;","Mi'râc ve Tûr (Sînâ) — senin münâcâtın (yakarış yerlerin) var."],["Her şey emrin içinde boyun eğmiştir (musahhardır);","bütün kullarına mürüvvetin (cömertliğin) var."],["Dört yüz kırk dört mertebe (tabaka) evliyâya;","verilmiştir — onlara bağışladığın kerâmetin var."],["Altı bin altı yüz altmış altı (adet);","halk üzere okunan âyetin var."],["Rahmetin yalnız Yunus'a değil, ey Rabbim; rahmetin çoktur;","bütün günahlılara senin rahmetin var."]],"49":[["Hak bana bir gönül verdi; 'ha' demeye kalmadan hayran (şaşkın) olur;","bir an gelir sevinçli (şâdî) olur, bir an gelir ağlar (giryân)."],["Bir an, kış gibi sanırsın — sanki zemheri (karakış) olmuş gibi;","bir an müjdeyle doğar, hoş bir bağ bahçe olur."],["Bir an gelir konuşamaz, bir sözü bile açıklayamaz;","bir an dilinden inciler döker, dertlilere derman olur."],["Bir an Arş'ın üstüne çıkar, bir an yerin dibine (tahte's-serâ) iner;","bir an damla (katre) sanırsın, bir an taşar, umman olur."],["Bir an cehalette kalır, hiçbir şey bilmez olur;","bir an hikmetlere dalar, Câlinûs (Galen) ve Lokman (gibi hekim) olur."],["Bir an dev (dîv) ya peri olur, yeri viraneler olur;","bir an Belkıs'la (Saba melikesiyle) uçar, insanların ve cinlerin sultanı olur."],["Bir an bakarsın dilenci (gedâ) olmuş, çıplak tenine aba giymiş;","bir an zengin bir himmetle, Fagfûr (Çin imparatoru) ve Hakan olur."],["Bir an gelir âsî (isyankâr) olur, Hakk'ın zikrini yitirir;","bir an gelir ki, yoldaşı hem zühd hem iman olur."],["Bir an günahını düşünür, dosdoğru cehenneme gider;","bir an Hakk'ın rahmetini görür, cennetlerin Rıdvân'ı (bekçisi) olur."],["Bir an mescitlere varır, orada yüzünü yere sürer;","bir an kiliseye (deyre) girer, İncil okur, rahip (ruhbân) olur."],["Bir an gelir Musa olur, yüz bin münâcât (yakarış) eder;","bir an kibir evine girer, Firavun ve Hâmân olur."],["Bir an gelir İsa gibi ölmüşleri diriltir;","bir an gelir, yolunu şaşırmış gibi, yolunda sersem (ser-gerdân) olur."],["Bir an Cebrâil'e döner, her meclise (mahfile) rahmet saçar;","bir an gelir yolunu şaşırır — miskin Yunus hayran (şaşkın) kalır."]],"50":[["Gönlüm, gözüm aşkla doludur;","dilim senden yardım diler, yüzüm gözyaşıyla ıslaktır."],["Vücudum öd ağacı (ud) gibi yanar;","dumanım göklere yükselen seher yelidir."],["Zırh, cevşen (savaş zırhı) bu aşk ateşine dayanamaz;","oku cana batar; pek keskin (ve alevli)dir."],["Senin aşkın bir deniz, ben o denizde küçük bir balık;","balık sudan çıkınca hemen ölür."],["Şahımı kendi dilimce çağırırım;","Şahım bana der: 'her an gel (gelmeye devam et).'"],["Seni sevenlerin aklı olur mu hiç?","Bir an akıllıysa, her an delidir."],["Yunus, sen Tapduk'a dualar et;","âşıkların meydanı, Arş'tan bile yücedir."]],"51":[["Ey dost, seni severim; canımın içinde bir yerin var;","gece gündüz uyumaz oldum; tuhaf (acayip) bir hâlim var."],["Sen gülü görürken, dikene elini uzatma;","düşmandan niye korkarsın — madem doğru (gerçek) bir yârin var?"],["Düşmanlar der ki: 'sana böyle söz söylemek sana nereden düştü?';","bana laf etmek kimin haddine — benim bir üstadım (mürşidim) var."],["Ele geçirdiğini yoksullara (miskînlere) harca;","ne kadar çok yaşarsan yaşa, sonunda ölüm var."],["Burada kendi benliğini öne çıkaran kişi, işte yolda kalan odur;","vallahi benim bir karıncaya bile gönül borcum (saygım) var (ondan üstün durmam)."],["Seher vakti kalkınca, bülbül gibi ötüp söylerim;","gönülde mana yeşerir; dertli bir ciğerim var."],["Yunus Emre, benliğini bırak; yüzünü toprağa koy;","sevgiliye yaraşır bir alçakgönüllülüğüm (miskînliğim) var."]],"52":[["Sen benim canımın canısın; sensiz hiç huzurum (karârım) yok;","cennette sen olmayacaksan, vallahi oraya hiç bakmam (ilgim yok)."],["Baksam gözüm seni görür, söylersem sözüm sensin;","seni gözetmekten daha iyi bir avım (şikârım) yok."],["Söylersem dilimdesin, sussam gönlümdesin;","gönlüm gözüm seni sever; başka bir sevgilim (nigârım) yok."],["Madem kendimi unutmuşum, öyle ki sana gitmişim;","hangi sözde, hangi hâlde olursam olayım, bir an bile durulamam (karârım yok)."],["Beni Cercîs gibi yetmiş kez öldürsen bile,","yine döner sana gelirim; çünkü bunda hiç çekincem (utancım) yok."],["Seni güneş gibi gördüm; cennet bana zindan gibi geldi;","sofuyu (zâhidi) cennetiyle bırak — benim cennette hiç arzum yok."],["Yunus da sana âşıktır; ona yüzünü (dîdârunı) göster;","yârim de sensin; benim başka bir dîdârım (yüzüm) yok."]],"53":[["O gönle hoş gelen sevgili, benimle ne ettiğini söyleyivereyim;","her an yeni bir nazla (cilveyle), beni yeniden esir eder."],["Nereye bakarsam, gözüme görünen O'dur;","o ulu (server) zatın lütfu, bizi bu şekilde gönülden görür kıldı (basîr etti)."],["Ömrüm ne kadar olursa olsun, özgürlüğüm (âzâdlığım) imkânsızdır;","av tuzağa düşünce, avcının elinden onu kim alabilir?"],["Akıllıysan, gel ama O'nun mahiyetini (niteliğini) bana sorma;","nasıl bir nişan (iz) söyleyebilirim — O'nun benzeri yok, O eşsizdir (bî-nazîr)."],["Herkese, O'nu yarın (mahşerde) görecekleri vaat olundu;","oysa benim yârim burada; o Kadîr (Allah) burada göründü."],["Yunus, canıyla aşkın Kâbe'sine yöneleli,","ayağı altındaki deve dikeni (bile) ipek (harîr) oldu."]],"54":[["Ey gece gündüz Hakk'ı arayan, Hakk'ın nerede olduğunu bilmez misin?","Nerede olursam orada hazırdır; nereye baksam oradadır."],["Hakk'ı uzakta arama; Hakk'ın durağı gönüldedir;","sen benliğini elden bırak — O, tenin içindeki candadır."],["Gönüle gir, orada Tûr'u bulasın; 'sen-ben' demenin defterini dür (ikiliği bırak);","gerçek cevher (güher), erin (ermişin) gönlündedir; sanma ki o ummandadır."],["O ummanda yüz bin cevher, tam bir damlaya benzer (o kadar küçük kalır);","o gerçek cana zaman ve yok oluş yoktur; ölümlü (geçici) can ise hayvana aittir."],["Gözün nereye bakarsa, Çalap (Allah) mutlaka oradadır;","Hakk'a erişemeyen şu can, kârsızdır (assısı yok), ziyandadır."],["Sûretini (benliğini) viran et; Hakk'a eren, canın sırrıdır;","dostu gören, iç (bâtın) gözüdür; dış (zâhir) gözü ise yabandadır (uzaktadır)."],["Sûretin (benliğin) viran olunca, gönül bahçen cennetlere döner;","canının hazinesi o viranede olsun; çünkü (derler ki) hazine viranededir."],["Kim gaflet içinde geçerse, canı yok oluş (zevâl) suyunu içer;","dervişin sırrı Arş'tan uçar (gelir); gerçeği ise yeryüzündedir."],["Miskin Yunus, gözünü aç, bak — iki cihan baştan başa Hak doludur;","şüpheni sıdk (doğruluk) ateşinde yak; O, apaçığın içinde gizlidir."]],"55":[["Ayrılığın bağrımı dağlar (yakar); dert görmemiş sağlamlar bunun değerini (acısını) ne bilsin?","Seni görmeyeli, dostum, bu gözüm kanlı yaş ağlar."],["Akan yaşım sele benzer; ömür geçer, yele benzer;","güler yüzün güle benzer — bu zamanların böyle geçtiğini ne bilsin?"],["Gülün yâri bülbüldür; bülbül onun için inler (zârı kılar);","bülbülün yeri gül bahçesidir; ama bahçeler ona kalıcı bir makam olmaz."],["Bülbül balı yağı ne yapsın — ona deyin, karşısında gül gülsün (yeter);","âşığın yükünü şöyle bil: o yükü yüce dağlar bile çekemedi."],["Âşık, aşkın yükünü çeker; yücelerden yüce çıkar;","görür, dostun yüzüne bakar; gönlünü sevgiliye (ma'şûka) bağlar."],["Derviş Yunus'un sofrası (hônı) geldi; ama yönelişi sevgiliye dönük kaldı;","sevdiğini gönlünde buldu; gönlünü O'nunla bağlar."]],"56":[["Gerçek âşıksan, boynundaki o ferman (menşûr/iddia) nedir?","Hak yoluna sadıksan, bu yanlış zan ve sahtekârlık (tezvîr) nedir?"],["Gönlünün putunu (bût) kırman gerek; yoksa bütün ibadetin bozuktur (fâsid);","ibadetin makbul olup geçmedikçe, Hak katında senin için ne mazeret olabilir?"],["Madem adın 'falanca' oldu da bütün yaşayışın yalan oldu;","mana bilen bize söylesin: hakikatte örtülü (mestûr) olan nedir?"],["Bedenin (dış) düzenini bırak; benlik adını üzerinden at;","için bayındır (imar) olmadıkça, dışındaki bayındırlık (ma'mûr) neye yarar?"],["'Gözüm görür' dersin; öyleyse iddiasını manaya (gerçeğe) erdir;","gündüz güneş ışık verirken, gece yanan o ışık (nûr) nedir?"],["Her gün birileriniz gider durur; komşun durmadan sefere (ölüme) gider durur;","ecel birer birer yutar durur; bu dünyaya aldanmak (magrûr olmak) neden?"],["Dinini küfürle (karışık) tuttun; şüpheni (gümân) yağmaya ver (at gitsin);","getir, delilini (burhânunı) görelim; belki söyle, işin doğru açıklaması (takrîri) nedir?"],["Hiç yokken diri (canlı) oldun; gözünü aç, yolunca yürü;","şu sırrı anlayasın: apaçık haber, gözle görülen (manzûr) nedir?"],["Sana daha yakın bir haber söyleyeyim; apaçık (bellü beyân) anlayasın:","nefsinin dileğini terk eden o kişi, ezelden bağışlanmış (magfûr) değil de nedir?"],["Mümin isen beri gel; Cebbâr (olan Allah) sana burç ve sur (kale) olsun;","mürşidimizle övünelim; inkârcının (münkir) ne olduğu böylece belli olsun."],["Burada (ezelde) 'Belî (evet)' diyen kişinin işi, orada (ahirette) tamam olur;","bizden nişan (delil) isteyene, o Hallâc-ı Mansûr (örnek) değil de nedir?"],["Yunus, şimdi Hakk'ı söyle; Allah sana sâkî (kadeh sunan) oldu;","gönlündeki şüpheyi (şek) gider; madem O sâkîn, elindeki o boş boru (menkûr) nedir?"]],"57":[["Âriflerin önünde sofuluk satmasınlar (taslamasınlar);","ihlâs (samimiyet) görüntüsüyle bu aşka riyâ (ikiyüzlülük) katmasınlar."],["Ya bildiğini söyle, ya da bilen birinden işit;","teslimiyetin (bağlılığın) ucundan tut; sözü uzatmasınlar."],["Allah 'Kur'an benim sözümdür' dedi, 'gönül benim evimdir' dedi;","gönül evinin sahibini bilmeyeni, gerçek insandan saymasınlar."],["Gönül kırıldı, bulutlandı (kederlendi); ama yine de Hakk'a yakındı;","'yine dikerim' diye, sağlam (bütün) olanı yırtmasınlar."],["Şeriat (petekli) ballı mumdur, tarikat tortusuz (saf) yağdır;","dost için, balı yağa öyleyse niçin katmasınlar (ikisini birleştirsinler)?"],["Ârif, canını verir de farkına bile varmaz; yalancı ise malına bile kıyamaz;","yalanla gerçeği bir tutmasınlar."],["Değerini sezersen, bil ki şu an neye değer;","erenlerin manasını, kıymetini bilmeyip almayacak olana satmasınlar."],["Miskin Âdem yanıldı, cennette yasak buğdayı yedi;","her işi Hak'tan bilenler, suçu şeytandan bilmesinler (ona yıkmasınlar)."],["Tatlı huylar edin; tatlı sözler söyle;","sohbetlerde Yunus'u asla unutmasınlar."]],"58":[["Bu semâ'a girmeyen, sonunda pişman olur;","bizimle çatışır (irişir), baştan başa düşman olur."],["Bizi çağıran, üstümüze (kuş gibi) öten, aslında dosttur;","şimdiyse üç buçuk kitap okuyan, 'derin âlim' (dânişmend) kesilir."],["Âlimlerin câhili, dervişleri onaylamaz;","derviş ile âlim, birbiriyle pek çekişir (didişir)."],["Kimilerinin gönlüne şeytanlar dolmuştur;","bunlar, erenlerin semâ'ına (alayla) gülüşür."],["Âlim, bilgisini okuyup kitapta buldu;","dert ehli dervişlere ise canı karışır (onlarla karışmak ister)."],["Ey çaresiz âlim, sen de 'derviş, dervişler' de (onlara saygı göster);","dervişlere sataşan, ettiğine pişman olur."],["Yunus der ki: Mevlânâ, sen yerinde suskun (epsem) otur;","bu sohbete dayanamayan, sonunda kavgacı (savaşgan) olur."]],"59":[["Aşk erinin gönlü doludur; o gönül, padişahın hazinesidir;","aşksız insan ne anlasın — aşk, şeriatın (iç) manasıdır."],["Aşk, âşıkların dermanıdır; muratları aşktan hâsıl olur (elde edilir);","âşık kişinin sohbeti, aşksız kişiye bir beladır."],["Kimi eşini çocuğunu sever, kimi mülkünü, ev barkını sever;","kimi sermayeyi, dükkânı sever; bu dünya hâlden hâle (geçici)dir."],["Âşık bu dünyayı ne yapsın? Sonunda bir gün terk eder;","aşkın eteğine yapışıp gider; bu yola kim gelmek isterse, çağrı açıktır (saladır)."],["Ezel meclisinde (bezm-i ezel) padişah, elime bir kadeh sundu;","içtiğimden beri âh ederim; bu ne türlü bir beladır, bilmem."],["Madem ezelden beri, ey Yunus, canın aşkla sarhoş oldu;","O'nun dergâhında (kapısında) her an şaşkın ve hayran kalakal."]],"60":[["İşitin, ey ulular: ahir zaman gelecek;","sağlam Müslüman az (seyrek)tir; o da şüpheli olacak."],["Âlim okur ama tutmaz; derviş yolunu gözetmez;","bu halk öğüt işitmez; ne çetin (sarp) bir zaman olacak."],["Beylerin mürveti (cömertliği) gitti; birer ata binmişler;","yedikleri yoksul eti, içtikleri kan olacak (yoksulu sömürecekler)."],["Yani gerçek er, insanların içinden çıkıp şerden (kötülükten) elini çekmiştir;","Deccal yerden kopacak (çıkacak); ahir zaman olacak."],["Tuhaf yaratıklar türedi; gözünü yumup (körü körüne) didinir;","helal haram birbirine karıştı; kâr zarar (belirsiz) olacak."],["Birbirine kötülük (yavuz) düşünür; yaptığı gizli kalır sanır;","yarın mahşer gününde işi (yaptıkları) apaçık (beyân) olacak."],["Ey Yunus, şimdi senin günün aşkla geçsin;","sevdiğin kişi (Hak), senin canına can olacak."]],"61":[["Ey dost, bunca dedikodu (kıyl u kâl) — maksat ne? Aslı bir tek haberdir;","yahut bunca arayış (cüst ü cû) nedir? Görene (anlayana) bir tek bakıştır."],["Dağlar aşıp çölleri geçip uzak diyara emek dökerek —","aradığın işte buradayken, bu ne tuhaf bir yolculuk (sefer)?"],["O'nu hiç uzakta arama; O, canından içeri (daha derininde) bir candır;","O seninle beraberdir; O'nu görmemek, körlüktür (bî-basar)."],["Hiç uzak sefere çıkma; ömrün geçer, ecel erişir;","Dost buradadır, halveti (yalnızlığı) sever; bu kalabalık gürültü neye yarar?"],["O, canından bile yakındır; edebini iyi gözet, çok sakın;","dostluğun hakkını bilirsen, O daima senin yârindir."],["Dilin 'Çalap (Allah) hazırdır' der; öyleyse kulağın neden sağır?","Kendi sözünü kendin inkâr ediyorsun (münkir); vallahi bu iş tehlikelidir (hatar)."],["Sen uyursun, O uyanıktır; eksiğini açıkça (bayık) bil;","daha ne kadar tanık arayayım — O hem yoldaşın hem sırdaşındır (râz-dâr)."],["Mescit de medrese de sende; oysa sen dağınık (perâkende) dolaşırsın;","bu esaslarda (erkânda) uzak kaldın; bu iş çok güçtür (düşvâr)."],["Bu tevhid hırkasını (tonını) giyen, varlığını (benliğini) hiçe sayan,","işte bu yolda sebatla duran kişi — kesin bilin ki gerçek erdir."],["O işler tamamlanınca, o (iç) düzen kurulunca,","gözünün perdesi (hicâbı) silinince, yer gök baştan başa dîdâr (Hakk'ın cemâli) doludur."],["Yunus, derde girip aşkın yolunda her an (dem-be-dem),","varlığını (benliğini) hiçe sayarak, sevgiliyi (ma'şûku) bekler (intizâr)."]],"62":[["Bu aşkı gafiller, ahmaklar (uyalar) ne bilsin?","Bu yola azıksız (ibadetsiz) yayalar nasıl dayansın (döysün)?"],["Gelin biz varalım, Yûsuf'u (güzelliğin sembolünü) görelim;","onun cemâlinin (güzelliğinin) sofrasından bin aç (gönül) doysun."],["O birlik (vahdet) ilinde, gülünde diken yoktur;","dilinde çok şeker (tatlılık), yüzünde haya (edep) vardır."],["Âşıklar dağında, ma'şûklar (sevgililer) bahçesinde,","dal budak salmışlar, serbestçe (duduksuz) yayılmışlar."],["Madem aşk, harâbât ehlinden (melâmet erenlerinden) göründü;","bu (sahte) utancı ne yapsınlar — bu (riya) rengini yıkayıp atsınlar."],["Ne olurdu, ben O'nu bu (baş) gözüyle göreydim;","ama bu gözler nasıl dayansın — bu (kaba, bedensel) gözler ona dayanamaz."],["Bizi (benliğimizi) bir yana koyalım; onlar (erenler/Hak) biz olalım;","birliği (vahdeti) sezenler, ikiliği (ayrılığı) bırakır."],["Yunus, sen bir ol; gönülde bir sır ol;","ki derviş olanlar bu sırdan (bir şeyler) sezsin."]],"63":[["Bu dünyaya gönül veren, sonunda pişman olacak;","'dünya benim' diyenlere, dünya hep düşman olacak."],["Ey dostunu düşman tutan, gıybet etme, yalan söyleme;","burada fitnecilik (gammâzlık) edenin, orada (ahirette) yeri dar olacak."],["Madem yeri dar olacak — herkesinki kazandığı (ameli) kadar;","müminlere haber geldi: âşıklar dîdârı (Hakk'ın cemâlini) görecek."],["Maksadımız dîdârdı (O'nu görmekti); şeyhimiz gerçek bir erdi;","O (Hak), evvelde (başlangıçta) de vardı, âhirde (sonda) de var olacak."],["O âhirdir (sondur), O ebeddir (sonsuzdur); dillerde 'küfüven ehad' (O'nun dengi yoktur) vardır;","evliya dünyadan göçtü — kime bir saat (kalıcılık) kalacak?"],["Evliyanın elini tutun; Hakk'ın yolunu dosdoğru gidin;","mana budur, açıkça bilin; 'bildim' diyen, aslında bilemez."],["Yunus, şimdi 'bildim' deme; alçakgönüllülüğü (miskînliği/benlik terkini) elden bırakma;","kimde miskînlik (benliksizlik) varsa, Hakk'ın dîdârını o görecek."]],"64":[["Evliyayı inkâr edenler (münkirler), Hak yoluna isyan etmiş (âsî) olur;","o yola isyan eden, gönüllerin pasıdır."],["Bu aşkın cefasını, sevgiliye (ma'şûka) erişene dek çektik;","çünkü o dost, benim derdimin devasıdır."],["Daha bu yer yokken, gökler yaratılmadan,","evliyanın vatanı, padişahın (Hakk'ın) kalesiydi."],["Mevlânâ Hudâvendgâr bize nazar kılalı (lütufla bakalı),","onun mübarek (görklü) bakışı, gönlümüzün aynasıdır."],["O yâre karşı alçakgönüllü (miskîn) ol, alçakgönüllü; kibir ve kin senden gitsin;","zaman (rûzigâr) gelir geçer; öyleyse kime kalacak?"],["Geyiklü'nün o Hasan'ı (bir veli) kendinden söz söylemiş gibi görünse de,","aslında konuşan kudret (Hakk'ın) dilidir — onun kendine ait sözü ne ki?"],["Okuyup yazmadan, yanılıp sapmadan —","Yunus, bu aşk sözünü gerçekten kim bildiyse, içten bilir."]],"65":[["Bilir misiniz, ey dostlar (yârenler), gerçek erenler nerededir?","Nereye baksam orada hazırdır; nerede istesem oradadır."],["Kim dostu sevdiyse, evini barkını (hânumânı) terk etsin;","herkes (rastgele kişi) dostu sevemez; dostun sevgisi candadır."],["Aşksızlara benim sözüm, kaya yankısına benzer (boşa gider);","zerre kadar aşkı olmayan — açıkça bilin — yabandadır (Hak'tan uzaktadır)."],["Yalancılık etme; aşka 'yalandır' deme;","burada yalan söyleyenin, orada (ahirette) yeri zindandadır."],["Ey kendini bilmeyen, sözün manasını anlamayan;","Hakk'ın varlığını istiyorsan, işte o, ilim ile Kur'an'dadır."],["Allah, 'benim' dediği (kuluna) aşkın varlığını vermiştir;","kime bir zerre aşk verirse, Çalap'ın (Allah'ın) varlığı ondadır."],["Niceleri Yunus'a der ki: 'yaşlandın, aşkı bırak';","oysa aşk bize yeni değdi; daha turfanda (ilk baharında)dır."]],"66":[["İşitin, ey dostlar: aşk bir güneşe benzer;","aşkı olmayan gönül, taşa benzer."],["Taş gönülde ne biter? Dilinde zehir (agu) damlar;","ne kadar yumuşak konuşsa da, sözü kavgaya benzer."],["Aşkı olan gönül yanar, yumuşar, muma döner;","taş gönüller kararmış — sert, katı bir kışa benzer."],["O sultanın kapısında, o Hazret'in huzurunda (tapusında),","âşıkların yıldızı her an bir çavuşa (öncü/nöbetçiye) benzer (hep hizmettedir)."],["O, hırsın ta kendisi olmuş; nefsine takılıp kalmış;","kendine düşman olmuş; kötü bir yoldaşa (yavuz yoldaşa) benzer."],["Aşk, kudretin körüğüdür; âşıkları kaynatır;","nice kaptan (potadan) geçirir; sonunda âşık saf gümüşe benzer."],["Âşığın gönlü, sevgilisini (ma'şûkunu) bulmadıkça yatışmaz;","dünyada karârı (durulması) yok; kanat çırpışı (pervâzı) kuşa benzer."],["İnkârcı (münkir), aşkın sözünü bilmez; sözü de ileri gitmez (ağırlık taşımaz);","neye benzetirsin — anlamı çıkmayan bir rüyaya (düşe) benzer."],["Yunus, kaygıyı (endîşeyi) geç (bırak); bu uğraşa (pîşeye) ne gerek?","Ere önce aşk gerek; ondan sonra kişi dervişe benzer."]],"67":[["Ansızın sevgilinin (cânân) ilinden bu cana bir haber erişti:","bu harâbât (fânî) iklimde eğlenip kalma, yürü, sefere çık."],["Bu harâbât ikliminin giysisi melâmettir (kınanmayı göze almaktır);","kanlar dökülür saçılır, yüz binlerce baş yok olur (nice benlikler ölür)."],["Bu yerin (cehennem gibi) külhanları (ocakları), âşığın gül bahçeleridir;","orada bülbüller, aşk ateşine kanat tüy (bâl u per) yakarlar."],["Orada yedi deniz gördüm; biri ateştendi;","derler ki, bu harâbât ehlinin yolu o ateşten geçer."],["Orada dostun iki saç lülesinin (zülfeyn) can boynuna takıldığını gördüm;","O, bir tek kılla yüz binlerce Mansûr'u darağacına asar (ber-dâr eder)."],["Orada sordum: âşıklara bu bağdan (bendden) kurtuluş (halâs) var mı?","Dediler ki: yok; ipin (urganın) ucunu sevgili (dilber) tutar."],["Şah ve sultanın (Hakk'ın) sohbetinde, nûrdan kadehler sunulur;","sâkîler çağrışıp der: dost elinden kim içer?"],["Varlığını (benliğini) yağmaya verdi, Resûl'ün (bâtınî) manasına erişti;","sen de o kapıdan içeri gir; yürü, var — ama edeple (hazer ederek) git."],["Yunus'a, bu sözleri nereden aldığını sorarsan —","meğer o, aşkın divanının (dîvân-ı ışk) defterinden onları hatırlarmış."]],"68":[["Türlü türlü cefanın adını 'aşk' koymuşlar;","bu cefaya katlanan, dostla halvete (baş başa olmaya) erişmiş."],["Her kim aşka erişirse, aşk onunla barışır;","kim aşka müşteriyse (talipse), onun canına ateş vermişler."],["Her kim aşka rastladıysa, o an kaynayıp taştı;","kimi 'deli' der, kimi 'akıllı' (uslu) — dört bir yanında durmuşlar (öyle bakışırlar)."],["Aşk bir afet, bir beladır; insanı hâlden hâle döndürür;","dost elinden içtikleri kadehle, hoşça melâmet ehli (kınanmayı göze alanlar) olmuşlar."],["Aşk, Yunus'un canıdır; başındaki (yazgısındaki) son (ser-encâm) odur;","aşkı inkâr eden kişiyi, bu meydandan sürmüşler (kovmuşlar)."]],"69":[["Bu dünyanın misali, büyük bir şehre (şâr) benzer;","ama bizim ömrümüz, çabucak (tîz) dağılan bir pazara benzer."],["Her kim bu şehre geldiyse, bir an (lahza) durdu (kaldı);","geri dönüp gitmesi, bir daha dönülmeyen bir yolculuğa benzer."],["Bu şehrin ilk tadı, baldan şekerden tatlıdır (şîrîn);","ama sonundaki acıya bak: yılan zehrine (zehr-i mâr) benzer."],["Önce gönül alışı, güzellere (hûblara) benzer;","sonunda yüz çevirişi, hilekâr bir kocakarıya (acûz mekkâr) benzer."],["Bu şehrin hayalleri, türlü türlü hâlleri,","gafilleri aldatmış; hileci bir büyücüye (câzû ayyâr) benzer."],["Bu şehirde hayallerin sınırı, sayısı (şumârı) yok;","bu hayale aldanan, otlayan davara (hayvana) benzer."],["Bu şehirden üç yol çıkar: biri cennete, biri cehenneme (nâr);","birinin arzusu ise, özlenen dîdâra (Hakk'ı görmeye) benzer."],["Bu şehrin bir sultanı var; herkese ihsanı (lütfu) var;","sultanla tanışan (bilişen), yokken var olmuşa benzer (gerçek varlığa kavuşur)."],["Kendi ölçüsünü (haddini) bilen, kendi hâlini bildi;","üstelik aşkla, ilkbahara (evvel bahâr) benzer (tazelenir)."],["Çaresiz Yunus'a bak — dertle hayran (kendinden geçmiş) olmuş;","onun her bir nefesi, bala şekere benzer."]],"70":[["Dost, senin aşkının oku, en katı taştan bile geçer;","aşkına düşen âşık, canından da başından (hayatından) da geçer."],["Aşkına düşenlerin yüreği yanar olur;","kendini sana veren, bütün işlerden (dünya kaygılarından) geçer."],["Gece gündüz inler (zâr olur), aşkınla yâr olur;","tek düşüncesi (endîşesi) sen olan, bütün kargaşadan (teşvîşten) geçer."],["Âriflere bu dünya, hayal ve rüya (düş) gibidir;","kendini sana veren, hayalden de rüyadan da geçer."],["Dünyanın sevgisi (mahabbeti), zehirli aşa (yemeğe) benzer;","sonunu (âkıbetini) düşünen kişi, o zehirli aştan geçer (el çeker)."],["Başında aklı olan, ahiret (mükâfatı) için çıkar gözeterek amel etmez;","hurilere aldanmaz; cennet vaadinden (gözle kaştan) geçer (gönlü yalnız Hak'tadır)."],["Gerçek âşık o olur ki, can vermeye o (hemen) koşar;","dostla yapacağı alışveriş (bâzâr) için, nice bin baştan (candan) geçer."],["Yunus'un gönlü gözü, Hak sevgisiyle doludur;","O'nunla sohbeti seçen (ihtiyâr eden), yabancıdan da tanıdıktan da (yâd u bilişten) geçer."]],"71":[["Daima 'Allah' diyelim;","Allah görelüm n'eyler;","yolda sebatla (kâim) duralım;","Allah görelüm n'eyler."],["'Allah' diye inle (zârı kıl);","herkesin varı (her şeyi) O'dur;","yardımı O'ndan umalım;","Allah görelüm n'eyler."],["O'nu dilimizden düşürmeyelim;","yârden (sevgiliden) ayrılmayalım;","yoldan sapmayalım (ırılmayalım);","Allah görelüm n'eyler."],["Açlığın sonu tokluktur;","tokluğun sonu yokluktur;","bu yollar korkuludur;","Allah görelüm n'eyler."],["Sen ummadığın yerde,","ansızın (nâgâh) perde açılır;","derde derman erişir;","Allah görelüm n'eyler."],["Gündüz oruçlu (sâim) olalım;","gece (ibadette) ayakta (kâim) olalım;","daima 'Allah' diyelim;","Allah görelüm n'eyler."],["Adı sanı dillerde,","sevgisi gönüllerde;","şu korkulu yollarda,","Allah görelüm n'eyler."],["Adımı sanımı (ün davasını) ufaladım;","küfrümü (inkârımı) suya attım;","miskînliğe (benlik terkine) el attım;","Allah görelüm n'eyler."],["Her an (aşk) denizine dalalım;","dünyaya (dehre) aldanmayalım;","sıkıntıya (kahra) sabredelim;","Allah görelüm n'eyler."],["Ar-namus (kaygısını) bıraktım;","külümü suya attım (geçmiş benliğimi sildim);","dervişliğe el attım;","Allah görelüm n'eyler."],["Mecnun gibi avare (başıboş),","yâre âşık olarak,","de ki, ey çaresiz Yunus:","Allah görelüm n'eyler."],["Yunus, sen onu (kendinden) sanma;","bu aşk sana (görünüşte) sendendir;","gerçekteyse can, herkese O'ndandır;","Allah görelüm n'eyler."],["Bu Yunus ne yaptı, ne yaptı?","Bir doğru yola gitti;","pîrlerin (mürşitlerin) eteğini tuttu;","Allah görelüm n'eyler."]],"72":[["Ey padişah, ey padişah (Allah'ım); her an işini (kâinatı) düzene koyar durur;","dünya O'nun bahçesidir (bostânıdır); sevdiğini (meyve gibi) koparır durur."],["Sakın kötülük (yavuzlık) etme; ecel sana senden yakındır;","nicelerinin aslını kökünü, yurdunu yıkıp bozar durur."],["Sen oraya gideceksin; onun için burada çok azık (ibadet) hazırla;","canlar tende kalıcı (bâkî) değil; de ki, birkaç gün gezer durur."],["Sorgucu (kabir meleği) gelir, yeri yırtıp 'Tanrın kimdir?' diye sorar;","işte bu canım onu sezip, kemiklerim sızlar durur."],["Ey Tanrı'yı bir bilenler, canını Hakk'a kurban edenler;","bu canlar ölü değildir; aşk gölünde yüzer durur."],["Ben gördüm: erenler uçtu (göçtü), aşk kadehini dolu içti;","Hak katında nazı (yakarışı) geçerli oldu; öyleyken yüzü hâlâ tevazuyla yerdedir."],["Erenlerin kulu (bağlısı) isen, Yunus, ölümünü (ona hazır) bekle;","nice erenler geldi geçti; nöbet (sıra) şimdi bizdedir."]],"73":[["Şu gönül evim, aşkın elinden (zorundan) taşmaya başlar;","ne kadar yüksek (başım dik) yürürsem, aşk başımdan aşar (beni aşar)."],["Ne kadar 'sırrımı (râz) kimseye söylemeyeyim' desem de,","bu sabrım, durulumum gider; dost aklıma (önüme) düşüverir."],["Ben kendi hâllerimi bilirim; benim gibi (bir başka) er bunu ne bilsin?","Benim, her şeyi görene (Hakk'a) duyduğum sevgi — ne güzel bir sevmektir, gönle hoş gelir."],["Hey, dostun yüzünü gören kişi nasıl sabredebilir?","'Hakikati gördüm' diyen, kendinden geçer (şaşırır)."],["Sevgilinin (ma'şûkun) tecellîsi (görünüşü), türlü türlü renklerde olur;","bir tek nazıyla (şîvesiyle), işte yüz bin gönül durmadan coşar (cûşa gelir)."],["Öyle bir padişaha kimin gözü ilişirse (duş olursa),","vaktin sultanı (kutub) bile olsa, o, aklından şaşar (aklını yitirir)."],["O dostla benim hâlim, bulut ile güneş gibidir;","bir an perde (hicâb) açılır, bir an (yüze) peçe (nikâb) iner."],["Bana sorarsan, şu kişinin (gerçek) canı yoktur:","gönlüne, sevgiliyi (ma'şûku) sevmekten başka bir düşünce (endîşe) gelen kişinin."],["Şaşılır — miskin Yunus, meğer aşktan (öte) bir sevmeyle sevmiş;","çünkü insanın başına gelen bu aşktan daha iyisi (yigrek) hiç yoktur."]],"74":[["Sabahleyin mezarlara vardım; gördüm hepsi ölmüş yatıyor;","her biri çaresiz kalmış, ömrünü yitirmiş yatıyor."],["Bunların yanına vardım; ecelin heybetine baktım;","nice yiğit, muradına eremeden ölmüş yatıyor."],["Bunları kurt, kuş, keler yemiş; nicelerin bağrını deler (bu manzara);","şu küçücük yavrular (nâ-resteler), gül gibi solmuş yatıyor."],["Bedenleri toprağa düşmüş, canları Hakk'a ulaşmış;","sen bunları görmez misin — nöbet (sıra) bize gelmiş (bekliyor)."],["İnci dişleri sökülmüş, sarı saçları dökülmüş;","bütün dertleri (teşvişleri) bitmiş; Hak, varlıklarını (kendine) almış, yatıyorlar."],["Gözünün karası gitmiş; ayağa kalkacak hiçbir işi (hâli) yok;","kefen bezinin bir parçası, kemiğe sarılmış yatıyor."],["Yunus, akıllıysan, bu dünya (mülk) için bedenini (sûretini) süsleme;","dünya için bedenini süsleyenler, kara toprak olmuş yatıyor."]],"75":[["Aşkın ateşi yüreğimde neler eder, neler eder;","bugün bir âşık gördüm — bu derdimden haber veriyor."],["Gelin, hey dertliler, gelin; bu derdimden siz de alın;","dertli, dertlinin hâlini bilir; ya dertsizler burada ne yapsın?"],["Kimi dostun yüzünü gördü, kimi 'göreyim' diyordu;","âşık sevgilisine (ma'şûkuna) erişti; işte yine bayram ediyor."],["Bugün Mansûr olup ne yapayım — bari şeyhimin yüzünü göreyim;","maksadım buydu: ona erişeyim; âşık yine derdini söyler."],["Yunus der: âşık oldum, sevgilinin (ma'şûkun) derdinden öldüm;","yüzümü sevgiliye (ma'şûka) döndüm; gönlünü O'nunla eğler (avutur)."]],"76":[["Zavallı âdemoğlu, nefse esir (zebûn) olmuştur;","hayvan, canavar gibi sadece otlamaya kalmıştır."],["Asla ölümünü düşünmez; öleceği günü anmaz;","bu dünyadan usanmaz; gaflet aklını almıştır."],["Çocuklar öğüt almaz, yiğitler tövbe etmez;","ihtiyarlar ibadet (tâat) etmez; çetin (sarp) bir zaman olmuştur."],["Beyler yolundan azdı; yoksulun hâlinden anlamaz;","rahmet gölünden çıkmış, nefs gölüne dalmıştır."],["Yunus, sözü âlimden al; sakının zalimden;","ölümden korka durun — doğan herkes ölmüştür."]],"77":[["Bu an yüzümü (yere) süreyim; her an benim ayım (nûrum) yeniden doğar;","her an bana bayramdır; yazım kışım, yeni bir bahardır."],["Bulut, benim ayımın ışığına gölge düşüremez;","dahası, dolunluğu hiç eksilmez; nûru gökten yere doğar."],["Onun nûru, karanlığı gönlün hücresinden sürer;","öyleyse karanlık, nûrla bir hücreye nasıl sığar?"],["O ay ilkin nasıl doğduysa, bir daha (evre değiştirip) hiç eksilmedi;","kime nazar (lütufla bakış) kıldıysa, onun da ömrü eksilmedi."],["Ben ayımı yerde (gönülde) gördüm; gökyüzünde ne arayayım?","Benim yüzüm yerde (tevazuda) gerek; bana rahmet yerden yağar."],["Sözüm (gökteki) ay güneş için değil; sevenlere bir söz yeter;","sevdiğimi söylemezsem, sevme derdi beni boğar."],["O'nu vasfetsem (anlatsam), halk dünyevî bir sevgiliyi övüyorum sanır;","O'nu övmeye gerek yok; kendi nûrunu kendi över."],["Ne olmuş Yunus sevdiyse — Hakk'ı sevenler çoktur;","o, kendinden önceki sevenleri görmüştü; onun için boynunu eğer (tevazu eder)."]],"78":[["Tanrı aşkına, ey canımın canı; sana duyduğum aşk cefa olsa bile, o bana ibadettir, yeter;","senin ayrılığından (firâkından) beter, daha beter bir azap var mı?"],["Aşkının ateşi yüreğimde yandığına âlem tanıktır;","nerede bir ateş yanarsa, nişanı vardır: duman (dütün) tüter."],["Aşkın, gönül evimin iklimine (ülkesine) ordu (çeri) saldı;","canımı zaten esir ettin — düşman Tatar bana ne yapabilir ki?"],["Ecel salayım (göndereyim) iklimlere; âşıklara vasiyet edeyim;","sevgili için diyeyim: sakının — o cilveyle oynar, âşığın gönlünü bir yana atar."],["Şaşılır — bu derdime neden derman bulunmaz?","Buna kim derman bulacak — bu aşktan kişiyi kim alıkoyar?"],["Sultanların âdetidir: kullar günah işleyince,","ya o kulunu terbiye eder (edepler), ya da açık artırmaya (mezâda) verip satar."],["Yunus, 'yârden cefa gördüm' diye şikâyet etme;","bütün âşıkların ihtiyacı (hâceti), sevgilinin (ma'şûkun) katında biter (görülür)."]],"79":[["Yâr, yüreğim yarık (paramparça) — gör ki neler var;","bu halkın içinde, bize gülen(ler) var."],["Bırak, gülen gülsün; hak (gerçek) bizim olsun;","gafil ne bilsin — Hakk'ı seven(ler) var."],["Bu yol uzaktır, menzili (durağı) çoktur;","geçidi yoktur; derin sular var."],["Bu yola aşkla beraber girdik;","bizi gurbete salan(lar) var."],["Her kim yiğitse, mertçe (merdâne) meydana gelsin;","kimde hüner varsa, canını esirgemesin."],["Gözleri ağlayan (giryân), ciğeri kebap olmuş (püryân);","hayran (kendinden geçmiş) divaneler var."],["Yunus, sen burada meydan (gösteriş) isteme;","meydanın içinde (senden) yiğit (merdâne) olanlar var."]],"80":[["Aşkla gelen erenler, zehri içer de bal (nûş) eder;","topuğa bile çıkmayan çaylar, denizle savaşır (boyundan büyük işe kalkar)."],["Biz bu yoldan üşenmedik, erenlerden usanmadık;","kimseyi kötü (yavuz) sanmadık; her ne kötülük varsa, onu kalleş (kolmaş) yapar."],["Kalleşe (kolmaşa) lafını (geri) verdik; sözle yüzünü dövdük;","bilen kişiler, yaban canavarından kaçar gibi ondan kaçar (uzak durur)."],["Bu sohbete gelmeyenleri, Hak nefesini almayanları —","sürün, buradan gitsin; kalırsa çok iş (fitne) çıkarır."],["Câhildir, manadan bir şey almaz; oturur, kararı (huzuru) gelmez;","öleceğini hiç sanmaz; yüz bin yıllıkmış gibi dünya kaygısı (teşvîş) eder."],["Dağ ne kadar yüksekse, yol onun üstünden aşar;","Yunus Emrem, yolsuzlara (yol bilmeyenlere) yol gösterir ve hoş (iyi) eder."]],"81":[["O âlemlerin övüncü (fahri) Muhammed, peygamberlerin önderidir (serveridir);","aşkla salavat getir; o, günahları eritendir."],["Hak onu övdü, yarattı, sevdi, 'Habîbim (sevgilim)' dedi;","yeryüzündeki bütün çiçekler, Mustafa'nın teridir."],["Cebrail, Muhammed'i Mi'râc'a davet edince,","o, Mi'râc'ında dilediği şey, ümmetinin (iyiliği) idi."],["Sen ona ümmet olmaya bak; o seni mahrum (yoksun) bırakmaz;","her kim onun ümmetiyse, sekiz cennet onun yeridir."],["Her kim onun sünnetiyle farzını ayakta (kâim) tutarsa,","ne diyeyim — sonunda (âkıbet) sorgu sualden beridir (uzaktır)."],["Suçlu suçsuz, günahkâr — hepsi ondan şefaat umar;","o cehennemde yananlarsa, inkârcının kendi inkârı yüzündendir."],["Yunus Emrem bu sözü canının içinde (içten) söyledi;","söyleyen, çaresiz Yunus, Tapduk Emrem'in sırrıdır."]],"82":[["Yeryüzünde gezerdim; rastladım — memleketler (dolusu insan) yatıyor;","kimi ulu, kimi küçük; beli sağlam (güçlü) yiğitler yatıyor."],["Kimi yiğit, kimi ihtiyar, kimi vezir, kimi hoca;","gündüzleri gece olmuş; öylesi nice çokları yatıyor."],["Yolları doğru giderdi, elleri kalem tutardı;","dilleri bülbüle benzerdi — âlim (dânişmend) yiğitler yatıyor."],["Ulusu küçüğü ağlamış; önder (server) yiğitleri (toprağa) koymuşlar;","baş ucunda yaylar kırmışlar; kırılarak oklar yatıyor."],["Atlarının izi tozlu, önlerinde davullar (debdebe);","il ü güne (halka) hükmü geçen şu muhteşem beyler yatıyor."],["Gece gündüz, küçük çocuklar bülbül gibi söylerken,","anaları onlardan ayrılmış; mezarlarını bekler yatıyor."],["Elleri kınalı, hizmetçi kızları (karavaşları) hizmetinde;","mızrak gibi uzun boylu, gül yüzlü hatunlar yatıyor."],["Hepsi (aczle) el bağlamıştır; umudu Hak Çalap'tandır;","kimisi nişanlı kızdır; gelin alınmamış nice genç yatıyor."],["Yunus kendi hâlini bilmez; dilini Hak Çalap söyletir;","kimisi yeni gelin; ak (süt gibi tertemiz) yüzlüler yatıyor."]],"83":[["Niye dış kapıda (taş kapuda) bakınıp durursun? İçeri gir — orada neler dolaşıyor, gör;","aç gözlülük (tama') hep oturmuş; saf bağlamış, fitne düzer."],["Gel şimdi kanaate (yetinmeye) gel; gafil olma, çabucak ata bin (yola koyul);","olmaya ki ecel yetişe de ömür alışverişin yarım (fâsid) kala."],["Sen nerede olursan ol, teslimiyetle herkesten aşağıda dur (alçakgönüllü ol);","bu sözümden usanma; gör, bozguncu (müfsid) nasıl kızar (öfkelenir)."],["Onda (nefste) cimrilik ve hased (kıskançlık) durur; bunlar pek azılı dövüşçülerdir;","köklerini kaz, yabana at; sen rahat (fârig) otur, ey gam çeken (gam-güzâr)."],["Bırak şu yokluk (bahanesi) kapısını; dostluğun edebini öğren;","'sor, iste, beni iste' dersin — oysa bana gerçekten gelen, kuru sözden (kâlden) usanır."],["Kibir ve benlik (meni), nefsin komutanıdır (subaşı); birçok kişi onun yoldaşıdır;","sen onun eşi (arkadaşı) olma; buna uyan, yoldan azar."],["Riyâ (iki yüzlülük), çukur (alçak) bir yerde durur; iyice sakın — o seni ateşe sürer;","ihlâs (samimiyet) gelip hepsini yıkar; Yunus, bu yolu iyice (yavlak) sezer."]],"84":[["Bu dervişlik durağı (makamı), acayip (eşsiz) bir duraktır;","derviş olan kişiye önce (düzgün) bir dirlik (yaşayış) gerekir."],["Orada dirlik olunca, Hak'la birlik olur;","varlığı (benliği) elden bırakıp ere (ermişe) kulluk (hizmet) gerekir."],["Doğudan batıyı gören ere (ermişe) kulluk (hizmet) et;","senden hâlini soran(a karşı), iyice bir alçakgönüllülük (miskînlik) gerekir."],["Hiç değilse (bâri) alçakgönüllü (miskîn) olmaya bak; benlikten uzak yürü;","gönlünde benlik olan, dervişlikten uzaktır."],["Hak, ermiş eri 'benimdir' dedi; varlığını erde kodu (ermişte tecelli ettirdi);","erenlerin himmeti, yerden göğe uzanan bir direktir."],["Bu dervişlik beratını (belgesini), müftüler okuyamadı;","kim ne bilsin bunu — o, acayip (sırlı) bir yapraktır (varaktır)."],["Ey Yunus, ârif (irfan ehli) isen, 'anladım, bildim' deme;","alçakgönüllülüğün (miskînliğin) eteğini tut; sonunda (âhir) sana o gerekir."]],"85":[["İşitin, ey dostlar; dem evliyâ demidür (şimdi evliya zamanıdır);","ömür sürmek (gerçekten yaşamak) isteyenler gelsin; dem evliyâ demidür."],["Ezelî temeli (bünyâd) attı; altı günde dünya doldu (kuruldu);","İsrâfîl'e buyurdu; dem evliyâ demidür."],["Kırk bin kırk dört derece (tabaka); şeyhler (meşâyıh), evliyalar;","dört kapıdır, kırk makam; dem evliyâ demidür."],["Yüz yirmi dört bin seçkin (güzide) peygamber,","ümmetine buyurmuş; dem evliyâ demidür."],["Yunus Emre, âşıksın; aşka iyice dayandıysan,","âşıkları (bu deme) davet et; dem evliyâ demidür."]],"86":[["Açıkça bilin: dünyada aşksız insan yoktur;","her birinin bir şeye sevgisi var; herkes bir şeyin âşığıdır."],["Çalap'ın (Allah'ın) dünyasında yüz bin türlü sevgi var;","kendine (uygun olanı) kabul et; bak, hangisi lâyıktır."],["Biri Rahmân'ın (rahmet yolunun), biri kovulmuş şeytanın sevgisidir;","kişinin günahı da sevabı (müzdü) da, sevgisine bağlıdır (ta'allukdur)."],["Dünyada bu aşk Peygamber'in başına geldi;","aracısı (tercümanı) Cebrail, sevgilisi (ma'şûkası) Yaratan (Hâlik) idi."],["Ömer, Osman, Ali — Mustafa'nın (Peygamber'in) yârenleri (dostları);","bu dördünün ulusu (en büyüğü), Ebû Bekir Sıddîk'tır."],["Âlemlerin övüncü Muhammed, Mi'râc'a yükseldiğinde,","Çalap'tan dilediği, ümmetine azıktı (nasipti)."],["Yunus, kendi ayıbını (kusurunu) gözle; başkasını bırak;","kimsenin ayıbına bakma — bu günahtır (yazıktır)."]],"87":[["Gelin, bu canlara sorun: bedenleri (sûretleri) ne oldu da göçüp gidiyor?","Gece gündüz 'seninim' diye yaşarken, ne bahane bulup gidiyorlar?"],["Can gidiyorsa, bedeni terk ediyorsa, şaşılmaz;","bu yanlış, yalan, dedikodu değil — dosttan haber (çağrı) geldi de gider."],["Hani onun mülkü malı? Hepsini terk etmiş;","o padişahın (Allah'ın) dergâhına, yanına huyunu ve amelini alıp gider."],["Daha dost olmuşken, nice işler düzülmüşken,","açıkça bilin: can, bedenin sakalına güldü (onu küçümsedi) de gider."],["Alışveriş ederdi; bir para (pûl) için yine bozardı;","bu dünyadan bıkmış (bizâr olmuş); kolsuz gömleği (kefeni) giydi de gider."],["Bin kişi batar, bin bir kişi doğar; meğer hepsi buyrukla (Allah'ın emriyle) gelmiş;","bu dünyaya kim doyar? Ömür kadehi (peymânesi) doldu da gider."],["Dünyaya tapıp (dünyâ-perestlik edip) kendini gaflete verme;","görmez misin — bu dünyaya iyi de kötü de gelir gider."],["Bütün âlem 'ahirette göreyim' diye ümit tutar;","Yunus der: derviş olan, Hakk'ı burada (bu dünyada) buldu da gider."]],"88":[["Sözümü işit, ey gafil;","seher vaktinde (erkenden) kalk;","o kâmil (olgun) zat öyle buyurmuş;","seher vaktinde kalk."],["Horozunuz ne der, işit;","rızkınız (rûzunuz) seherde verilir;","yüzünü dostun dergâhına (kapısına) tut (dön);","seher vaktinde kalk."],["Sözümü işit, ey sağır;","ki amel terazin ağır gelsin;","Çalap'ına (Allah'ına) yalvar, O'nu çağır;","seher vaktinde kalk."],["Uyuyup yatanların hâli kötüdür (yatludur);","elleri hiçbir şeye ermez;","seherde rahmet yeli eser;","seher vaktinde kalk."],["Kuşlarla beraber kalk;","namazı imamla (cemaatle) kıl;","yalvar, gel günahının bağışını dile;","seher vaktinde kalk."],["Kur'an ve Yâsin okunsun;","kulak verip dinleyesin;","dağ kadar günahını yıkayasın;","seher vaktinde kalk."],["Hadis ve kutlu söz (kelâm) okunsun;","'Aleyhisselâm' desinler;","âşıksan, bunu açıkça bileyim;","seher vaktinde kalk."],["Cennet (Uçmak) sana helal olsun;","cennette hurilere sarılmak,","Kevser şarabını içmek;","seher vaktinde kalk."],["Miskin Yunus, gözünü aç;","kendini gafletten uyandır;","ta ki kendini (kendözünü) bilesin;","seher vaktinde kalk."]],"89":[["Sen bize bizden yakınsın; ama görünmezsin — bu perde (hicâb) nedir?","Madem güzel yüzünün hiçbir kusuru yok, üzerindeki peçe (nikâb) nedir?"],["Sen dedin ki, ey padişah: 'Yehdillâhu limen yeşâ' (Allah dilediğini doğru yola iletir);","senin ortağın (şerîkin) yok, ey şah — öyleyse suçlu kimdir, azap nedir?"],["Levh (Levh-i Mahfuz) üzerine kim yazar; saptıran kimdir, ya da sapan kimdir?","Bu işleri kim düzenler — bu soruya cevap nedir?"],["Senin adın Rahîm'dir; Rahîmliğini (merhametini) bize bildirdin;","mürşitler müjdeledi — 'Lâ taknetû' (rahmetimden ümit kesmeyin) hitabı nedir?"],["Bu işleri sen bilirsin; sen verirsin, sen alırsın;","ne dilersen yaparsın — ya öyleyse bu sorgu sual, bu hesap nedir?"],["Biz senin mürvetinden (cömertliğinden) umarız; her iş senin katından gelir;","senin o sonsuz rahmetinin yanında, bu bir avuç toprak (türâb = insan) nedir?"],["Sen bir kez 'Kün' (Ol) dedin, her şeyi var ettin;","yine sonunda bir sözle onu harap etmek (yok etmek) nedir?"],["Hani bu mülkün (kâinatın) sultanı? Madem sen bedensin, hani onun canı?","Bu göz O'nu görmek ister — bu dönüş ve sığınak (merci' ü me'âb) nedir?"],["Yunus, bu baş göz O'nu görmez; görenler de zaten haber vermez;","bu menzile (makama) akıl ermez — Rabbim, bu önümüze koyduğun serap (gibi âlem) nedir?"]],"90":[["Hakikatte her varlığın (vücûdun) canı aşktır;","ne can ki — canın içinde, o canın canı aşktır."],["Bu can, ancak cismimi (bedenimi) ayakta tutar;","asıl o candır ki, aşkın açığı ve gizlisidir (zâhir ü pinhânıdır)."],["Bütün eşya (varlıklar), bu aşkın elinde âcizdir;","ne sır ki — hepsi, aşkın başı dönmüşleridir (ser-gerdânıdır)."],["Bu aşkın nerede olduğunu kimse bilmez;","sınırını (haddini) bilenler — o sınır, aşkın ta ucudur (pâyânıdır)."],["Bazen Mecnun'un gözünden Leylâ olur;","bazen (Mecnun olup) Leylâ'nın aşk hayranı olur."],["Bazen Yâkûb'un gözünden kanlı yaş akar;","bazen (o) aşkın Ken'anlı Yûsuf'u olur."],["İsa'nın nefesinde (deminde) ölüyü diriltir;","bazen (o) aşkın İmran oğlu Mûsâ'sı olur."],["Mansûr'un dilinden 'Ene'l-Hak' (Ben Hakk'ım) diye çağırır;","Cüneyd'de ise aşkın hırkası (cübbesi) ve irfanıdır."],["Bu aşkın türlü türlü rengi çoktur;","kimi aşkla ağlayan (giryân), kimi aşkın güleni (handânı)dır."],["Canım, dinim bu aşka feda (fidî) olsun;","bana hem din hem iman, aşkın dini ve imanıdır."],["Bir Yunus değil — orada yüz bin Yunus'un canı feda olsun;","aşkın kurbanı her ne ise, sevgili kabul etsin."],["Varlığının (benliğinin) hırkasını (cübbesini) aşkla yırt (çâk et);","dal o engin denize ki, aşkın ummanıdır."]],"91":[["İlim, ilim bilmektir; ilim, kendini bilmektir;","sen kendini bilmezsin — ya bu nasıl bir okumadır?"],["Okumaktan maksat (mana) ne — kişinin Hakk'ı bilmesidir;","madem okudun da bilmiyorsun, işte bu kuru bir emektir."],["'Okudum, bildim' deme; 'çok ibadet (tâat) ettim' deme;","Hakk'ı (gerçeği) bilmezsen, bunlar boş yere koşmaktır."],["Dört kitabın manası, bir 'elif'te bellidir (özetlidir);","sen 'elif' dersin, hoca — peki onun manası ne demektir?"],["Yunus Emre der ki, hoca: istersen bin kez hacca git;","hepsinden iyisi, bir gönüle girmektir."]],"92":[["Ey dost, senin aşkının ateşi, ciğerimi paramparça, yaralı kılar;","aşkından yüreğim yanar; bu yanışım bana hoş gelir."],["Aşkının ateşine yandığımdan, gülmem ağlamak oldu;","dost, sana inleyip yalvarmam (zârî kılmam), inkârcılara savaş gibi gelir."],["Söylersem sözüm savaş olur; söylemezsem ciğerim yara;","cihan kalleşle (kallâş) doludur; her birinden bir taş gelir (atılır)."],["Gör, nice taşlar atılır; dost için başlar ortaya konur;","bu taş gelip gönüle batar; hâlinize bir hâldaş (dert ortağı) gelir."],["Bizim hâlimizden anlayan kim — aşkı inkâr eden mi?","Bizim sevdiğimiz Hak'tır; ama bu halka sanki dünyevî göz kaş (sevgili) gibi gelir."],["Nice sultanlar (selâtîn), bu aşkın elinde âciz (zebûn) düşer;","her kim bu yola düşerse, o, bu yola uysalca (yavaş) gelir."],["Erenler buna (dünyaya) kalmadı; yoluna gitti, durmadı;","Hakk'ı gerçekten sevenlere, bütün âlem kardeş gelir."],["Miskin Yunus, sözünü bil; şu gözünü dosta aç;","hangi burçtan bakarsan bak, o sultana güneş gibi nûr doğar."]],"93":[["Hocam, âşık olanların işi, âh ile inlemektir (zâr olur);","o sevgilinin (ma'şûkun) hasretinden, gözyaşı pınar olur."],["Gece gündüz inler; yani yârini görmek diler;","bu haberi işitmezler; aşksızlar habersiz (bî-haber) olur."],["Onun dîdârına (yüzüne) âşıksan, bugünü yarına bırakma;","aşkın pazarına girenler, kendinden (benliğinden) bıkar (bîzâr olur)."],["Sen benliğini (senliğini) terk et; O'nun aşkını bul;","bu aşk içinde ölenin kan bahası (diyeti), dîdâr (Hakk'ı görmek) olur."],["Âşıklar mekânsız (lâ-mekân) olur; cihanı terk eder;","madem dostla alışveriş (bâzâr) var, can da cihan da ne ki?"],["Aşka yoldaş olunca, bütün işler geniş (kolay) olur;","maksat (murat) ele geçince, dostun iline sefer olur."],["Hani gerçek âşık, hani — gelin onu arayalım;","çaresiz Yunus'un canı, dost yoluna feda (îsâr) olur."]],"94":[["Gelmeyen gelmedi; yolundan sapan, yine de secde edip tapındı;","bu imareti (kâinatı) kim yaptı — bu mülke karşı Süleyman bile nedir (ne kadar küçük)?"],["Eğriliği yaydan eğri, doğruluğu oktan doğru;","bu şehrin (insanın) içinde, hırsız (ugru) da, kadı (kâzî) da, sultan da nedir (kimdir)?"],["O sendedir, sana yabancı değil; bellidir (apaçık), mucize falan değil;","bu söylediğim sözdür, kesin delil (hüccet) değil; denizin içindeki o engin umman nedir?"],["Ham (çiğ) pişip kazan taşmadan, ruh cisme (bedene) ulaşmadan,","ana rahmine düşmeden — doğmadan ölen (kişi) nedir (kimdir)?"],["Ey Yunus Emre, sen çocukken (tıfl iken), hiçbir şey anlamazken,","bütün ilimleri sana açıp, bildirip öğreten (o güç) nedir (kimdir)?"]],"95":[["O kadar inler ki, şu bülbül öyle inler;","onu (o inlemeyi) o (bülbül) yapmaz, ancak gül yaptırır."],["Ne zaman gülde dostun cemâlini (güzelliğini) görse,","'beni deli eden şu güzelliktir' diye çağırır (feryat eder)."],["Zavallı bülbül gülde ne görür ki,","gül bahçesine karşı öyle şakır (gulgul eder)?"],["Mecnun, Leylâ'nın yüzünde ne gördü ki,","gözyaşını akıtıp su ve sel eder?"],["Şu Ferhad'ın gözüne ne göründü ki,","kayalar keserek (delerek) dosta (sevgiliye) yol eder?"],["Şah İbrahim'in (İbrahim Edhem'in) gözüne ne göründü ki,","tacını tahtını darmadağın (târumâr) eder (bırakır)?"],["Kimini kâfir, kimini Müslüman ederek —","onu kimse yapmaz, ancak O (Allah) yapar."],["Kimine dert verir, yine de asla inletmez;","kiminin dünyada derdini bol eder."],["'Kimi zengin (bay), kimi yoksul' deme;","ister zengin, ister yoksul — onu O yapar."],["Kimine giyecek bir aba (hırka) bile vermez;","kiminin atına atlastan çul (örtü) eder."],["Kimini dünyada hayvan (gibi gafil) yaratır;","kimini kendine halis (muhlis) kul eder."],["Kiminin elinden tutup Arş'a çıkarır;","kimini yere çalar, kara kül eder."],["Çaresiz Yunus'un altın (değerli) sözünü,","câhile söylemeyin — o onu kızıl (değersiz) bakır paraya çevirir."]],"96":[["Derviş olan kişiler, çoğu kez deli (sayılır) olur;","aşkın ne olduğunu bilmeyen, ona gülegelir (güler durur)."],["Sakın ona gülme; bu sana iyi değildir;","kişi neye gülerse, o başına gelegelir (gelir)."],["Âh, bu aşkın izi (eseri) her kime uğrarsa,","derdine sabretmeyen, yolda kalagelir (kalır)."],["Bir kişi âşık olsa, aşk denizine (deryâsına) dalsa,","o denizin içinde cevher (inci) bulagelir (bulur)."],["Âşık mekânsız (lâ-mekân) olur; dünyayı terk eder;","dünyayı terk edenler, dîdârı (Hakk'ı) göregelir (görür)."],["Derviş Yunus, sen de dervişleri incitme;","dervişlerin duası kabul olagelir (olur)."]],"97":[["Dervişliğe adım atan (kadem uran), her bakımdan sultan olur;","derviş ne kadar yoksul (miskîn) olsa da, onun gönlü (Hakk'a) mekân olur."],["Derviş olan bel bağlar (hizmete durur), su dolabı (tolap) gibi çok ağlar;","nerede öyle ağlayan bir dolap varsa, orası bağ bahçe (bâg u bostân) olur."],["Derviş odur ki, itten (nefisten) kaçar; it besleyen (nefsini besleyen) kanlar içer;","sen it beslemeyi de bırak; it besleyen, sonunda köpek bakıcısı (sekbân) olur."],["Dünya seven, derviş değildir; dervişliği kabul olmaz;","dervişlikten kaçanların şeyhi, doğrudan (hemân) şeytan olur."],["Yunus, eğer dervişsen, bütün dünyayı terk et;","dünya cennet (Uçmag) bile olsa, dervişlere zindandır."]],"98":[["Gönlüm yine içten seyre daldı;","dostun cemâlin arzûlar (dostun güzelliğini özler);","gönül ayrılığa (hicre) katlanamaz;","dostun cemâlin arzûlar."],["Her kim bu derde uğrarsa,","o himmeti (manevi yardımı) erde (ermişte) bulur;","perde açılıverince,","dostun cemâlin arzûlar."],["Kim gerçek mürit (talip) olursa,","bel bağlayıp yola gelsin;","şu yürek ki içinde dert ola,","dostun cemâlin arzûlar."],["Dostum beni deli etti;","aklımı fikrimi aldı;","hayali gözümde kaldı;","dostun cemâlin arzûlar."],["Önce gönlüm bana derdi:","'bana atlar, elbiseler (ton) gerek';","Mevlâ'm bana bir dert verdi;","dostun cemâlin arzûlar."],["Yunus'un sözü yerli yerincedir;","canını verene dek inler;","ta ölüp mezara (sine) girene dek,","dostun cemâlin arzûlar."]],"99":[["Erenlerin eteğini tutan, menzil (makam) alıp Hakk'a yetişen,","Muhammed'in nûruna dalan — işte o, dünyaya gönül kalmayandır."],["Burada kim aba (palâs) giyerse, orada (cennette) hulle (cennet elbisesi) giyen odur;","dilde ağızda övgüyle anılan, kimseyle alay etmeyendir."],["Burada şeytana yâr (dost) olan, varıp orada perişan (âvâr) olur;","Hazret'in (Allah'ın) huzurunda yüzü kara olan, erden (ermişten) nazar (lütuf) almayandır."],["Dünya için kederlenen, mescidi görünce gösterişe tutunan,","orada (ahirette) imansız bulunan — Allah'ı bir (tek) bilmeyendir."],["Gönlünde ikilik tutan, o malı (ikiyüzlülüğü) burada satan,","yarın (mahşerde) cehennemde yatan — burada namaz kılmayandır."],["Hurilerle beraber yatan, cennetin (Uçmak) kokusuna dalan,","orada bülbül olup öten — burada zina etmeyendir."],["Hurilerle sırdaş olan, Muhammed ile eş (yoldaş) olan,","o imanı yoldaş edinen — burada yolunu şaşırmayandır."],["Miskin Yunus yolu gözler; kendine gel (özünü devşir), behey deli;","bu gül bahçesinin (gülistânın) bülbülü, kimsenin gülünü dermeyendir (kimseye zarar vermeyendir)."]],"100":[["Yerin göğün safası (güzelliği), Mustafa'dır;","bütün ahitlerin (sözlerin) vefası, Mustafa'dır."],["Ayın dolunayı ve hilâli, onun alnı ve kaşıdır;","güneşin nûru, ziyâsı (ışığı), Mustafa'dır."],["Çalap'ın Arş'ı, onun ayağı altında Ferş (yeryüzü) olur;","cihanın zirvesi (müntehâsı), Mustafa'dır."],["Yarın mahşerde şefaatçi (Şefî') odur, şefaatçi odur;","sekiz cennetin sakası (su dağıtanı), Mustafa'dır."],["Çaresiz, âsî (günahkâr) kullara, yarın mahşerde,","şefaat edecek olan, Mustafa'dır."],["Yarın (mahşerde) peygamberler âciz kalacak;","yine de elimizden tutacak olan, Mustafa'dır."],["Yunus, yalvar, Hakk'a salavat getir;","Hakk'ın dostu, Habîb'i (sevgilisi), Mustafa'dır."]],"101":[["Bize dîdâr (Hakk'ı görmek) gerek, dünya gerekmez;","bize mana gerek, dava (boş iddia) gerekmez."],["Bu gece bize Kadir Gecesi'dir;","bırak, sabah olmasın; seher gerekmez."],["Bize aşk şerbetinden sun, ey sâkî;","bize cennette (Uçmak'ta) kevser bile gerekmez."],["Tas tas (badya) dolu dolu içelim biz;","biz (bayağı şarapla) sarhoş olmayız; humâr (içki mahmurluğu) gerekmez."],["Eğer bu dert ile hasta düşersem,","kimse bana şifa (safâlık) vermesin; tedavi (tîmâr) gerekmez."],["Yâr gerekmez, can gerekmez;","bize dîdâr gerek, başka hiç kimse (deyyâr) gerekmez."],["Yunus, aşkla sarhoş olup su kabının (susak) başına düştü;","Tapduk'una (şeyhine) seslenir; artık ona utanma (âr) gerekmez."]],"102":[["Manalı söz (keleci) bilen kişinin yüzünü, bir söz ağ (aydınlık) eder;","sözünü düşünüp pişirerek söyleyenin işini, bir söz sağ (sağlam) eder."],["Bir söz savaşı keser (bitirir); bir söz yarayı iyileştirir;","bir söz, zehirli aşı (yemeği) bal ile yağ eder."],["Sözlerini söylemeden pişir; kötüsünü (yaramazını) ayıkla;","sözünü akılla yerli yerine düşür; gelişigüzel (boş yere) söyleme."],["Gel ahî (kardeş), ey hükümdar (şehriyâr); bari sözümüzü dinle;","bir söz, bin mücevheri ve altını (dînârı) kara toprak eder (değersiz kılar)."],["Kişi sözün (söylenecek) anını bilsin; sözün kötüsünü (kemini) söylemesin;","bir söz, bu cihanın cehennemini, sekiz cennet (uçmak) eder."],["Yürü, yürü yolunca; bilginle gafil (dikkatsiz) olma;","iyice sakın — dilinden çıkan bir söz, canını dağlar (yaralar)."],["Yunus, şimdi sözü usulünce (yatından) söyle; sözü en güzel hâliyle söyle;","iyice sakın — bir söz, seni o şahın (Allah'ın) katından uzak (ırag) eder."]],"103":[["Hak, cihana (her yana) doludur; ama kimse Hakk'ı bilmez;","O'nu sen kendinden iste; o senden ayrı olmaz."],["Dünyaya inanırsın; rızka (nasibe) 'benimdir' dersin;","niçin yalan söylersin — madem dediğin hiç öyle olmaz?"],["Ahiret pek uzaktır; doğruluk (togrulık) iyi bir azıktır (yarak);","ayrılık çetin bir firâktır; giden bir daha geri gelmez."],["Dünyaya gelen göçer; herkes birer birer (ölüm) şerbetini içer;","bu bir köprüdür, üstünden geçilir; câhiller bunu bilmez."],["Gelin tanışalım (tanşuk edelim); işi kolay tutalım;","sevelim, sevilelim; dünya kimseye kalmaz."],["Yunus'un sözünü anlarsan, sözün manasını dinlersen —","sana (yararlı) bir amel (iş) gerek; burada kimse kalmaz."]],"104":[["Ne yapayım ben bu gönülle — benimle beraber durmaz;","meğer sevgilinin (ma'şûkun) yüzünü görmüş; öğüt versem de aklını toparlamaz."],["Tanrı aşkına, ey akıllılar (uslular), gönlümü bana geri alıverin;","o, gidip dostla tanıştı; bir daha bana boyun eğmez (söz dinlemez)."],["Böyle bir gönülle nasıl düzgün bir dirlik kurabilirim?","Beni yabana (ıssızlığa) bıraktı; bir gün gelip hâlimi sormaz."],["Gönlüm bana yoldaş iken, zühd ve ibadet (tâat) ederdim;","şimdi bu düzenlerim (tertîplerim) yıkıldı; gönülsüzüm, elim ibadete ermez."],["Gönül içeride dostla; ben kapıda feryat ve figan;","bin yıl inlesem (zârı kılsam), 'hâlin nedir?' diye sormaz."],["'Ey gönül, hani farz, ya sünnet?' desem,","der ki: 'Yok, kaygılanma (teşvîş yeme); bu sevgiye (aşka) amel (ibadet biçimi) erişmez.'"],["İnleyerek 'gel, boynunda ibadet borcu kalmasın' desem,","bana kızar, söver, öfkelenir; der ki: 'Ey Hakk'ı görmeyen!'"],["Ağızdan ağıza söylenen söz uğurludur; belki sizin sözünüz gönlüme tutar;","oysa ben yüz bin kez söylesem, sözüm onun kulağına girmez."],["Gönlüm de canım da, şu ikisi, el bir etti (birleşti);","yüz bin Yunus'tan vazgeçer (ferâgat eder), ama dostun yüzünden gözünü ayırmaz."]],"105":[["Niceleri bu dünyada günahını yıkayamaz;","ömrü boş yere geçer; eyvah ki, bunu sezemez."],["Birçok kişinin gözünü gaflet bağlamış;","'Hak yolundayım' der, ama bir yufkaya (en küçük şeye) bile kıyamaz."],["Bu dünya bir gelindir; yeşile kırmızıya donanmış;","kişi, yeni geline bakmaya doyamaz."],["Ey, nice arslanları ölüm alır devirir;","Azrail'in pençesine, bir yoksulcuk bile dayanamaz."],["Var şimdi, miskin Yunus, çıplak (uryân) olup yola gir;","yüz zırhlı (çokallu soyguncu) gelse, çıplak olanı soyamaz."]],"106":[["Ey bana 'iyi' diyen — oysa ben herkesten kötüyüm (yavuz);","kibirle alnımı ay, şu gözlerimi yıldız sanırım."],["Bu beden şehrimde, yarım paralık (cennete layık) bir amel yok;","amellerimin mahalleleri, baştan başa ıssız kalmış."],["Hücrede ve köşede (inzivada), Hakk'a lâyık olamadım;","kiminde dert ve ayrılık (firâk), kiminde sadece tesirli (gösterişli) söz vardı."],["Halk hep ayakta durur, ben koşup oturdum;","baş köşeye (sadra) geçtim; kalın minderde, yerim rahat (düz)."],["Madem böyle bir riyakârlık (sâlûslık) elime geçti,","artık dert, ayrılık (firâk), âh ve yanış (sûz) neyime gerek?"],["Ben mantığa sığmayan 'olmaz' sözü, marifet (irfan) ehline söylemem;","çünkü söylesem inanmaz — 'ağaçta karpuz mu bitti?' derler."],["Ben bir kitap okudum ki, onu kalem yazmadı;","onu mürekkep edip yazsam, yedi deniz yetmez."],["Ben asıl oruç-namaz için (aşk) şarabını içtim, sarhoş oldum;","gerçek tesbih-seccade için, altı telli sazı (şeşte-kopuz) dinlerim. (Aşkın sarhoşluğu, onun ibadeti olmuştur.)"],["Yunus'un bu sözünden sen mana (gerçek anlam) çıkarırsan,","Konya minaresini bir çuvaldız (kadar küçük) görürsün."]],"107":[["Seninle birliğim, senden ayrılmaz;","hayat seninledir; sensiz yaşanmaz (dirilmez)."],["Gözümün içinde, benimle beraber bakan sensin;","eğer sen bakmasan, yolum görünmez."],["Benim münâcâtım (yakarışım) sana doğrudur;","yolum sana varır; sensiz varılmaz."],["Ben kendimi senden ayrı nerede bulayım?","Çünkü sensiz ne Hak nefesi alınır, ne ömrüm sürer."],["Varlığım sendendir; ben yalnızca bir aletim;","yaratan usta (sun' ıssı) tutmasa, alet kurulmaz (kendi başına iş görmez)."],["Alet de hareket de hep senindir;","onun için, senin işine kimse karışamaz."],["Sefere çıksam, bana yoldaş olursun;","karar kılıp dursam, yine sensiz durulmaz."],["Birliğinin ötesinde, senin hiçbir ortağın (şerîkin) yok;","kim bir eksiklik getirebilir — senin hükmün bozulmaz (silinmez)."],["Âlemin halkı, senin emrin içinde âcizdir (zebûndur);","kim var ki, kulluğa boyun eğmesin?"],["Şu durmadan 'ben, ben' dediğim — eğer gerçekten bensem,","bu benliğim bana niçin verilmiş değil (neden elimde değil)?"],["Dostlar (yârânlar), çağrı (sala) var, kapı açıktır;","bu kapıya gelen, mahrum (eli boş) çevrilmez."],["Yunus bu tevhide (birliğe) gark oldu (battı), gitti;","geri dönmeye, aklı artık dirilmez (toparlanmaz)."]],"108":[["Her işte, ey Kâdir (Allah'ım), seni doğrudan bildik; bize aracı (tercüman) gerekmez;","senin bulunmadığın gönülde, din ile iman gerekmez (gerçek olmaz)."],["Ölümü (meyyitimi) şöyle kendim yıkadım; ben miskinim, insanlar arasında bir yetimim;","nefsimin itini (köpeğini) öldüreyim; bir daha gelmesin; artık onu tutmaya gerek kalmaz."],["Her kim nefsine kalırsa (uyarsa), öyle ölürse Müslüman değildir;","benden öğüt alıyorsa hayır işlesin; oyalanmasın — boşa zaman harcamak gerekmez."],["Madem kara sakal ağardı, ak çıkıp karayı örttü (yaşlılık geldi);","Çalap (Allah) kimi uyandırdıysa, o göze artık perde (tuman) gerekmez."],["Yunus derdiyle tüter; gönlünden Hak aşkı biter (yeşerir);","erenlerin eteğini tutar; öyle ki ölse, cenazesinin yıkanmasına gerek kalmaz."]],"109":[["Rızık için kaygılanma (gussa yeme); kimse kimsenin rızkını yemez;","rızık için kaygılanma; padişah (Allah) onu eksik etmez."],["Benden öğüt istersen, bildiğimden söyleyivereyim:","işte Çalap'ın (Allah'ın) buyruğu budur — oruç tutun, namaz kılın."],["'Namaz kılıyorum' diye, dervişlere inkârla (gururla) gelmeyin;","bin yıl öyle kılsan da, sırf kendi duan seni bağışlatmaz."],["Namaz kılan insanlar, eli boş (tehî) kalacak değildir;","o padişahın (Allah'ın) dergâhından, kimse mahrum dönmez."],["Bir kişinin kötü (yatlu) sözünü, varıp kimseye söyleme;","biz uludan (büyükten) işittik: fitneci (gammâz), domuzdan beterdir."],["Yunus çağırarak der: ben dervişlerin kuluyum;","bu dünyada kim var ki, sultana (Hakk'a) kulluk etmesin?"]],"110":[["Bu, acayip (eşsiz) bir hâldir; bu hâle kimse eremez;","âlimler bunu bildiğini iddia eder, ama her göz bunu görmez."],["İlimle, hikmetle kimse bu sırra eremez;","bu, acayip bir sırdır; ilme kitaba sığmaz."],["Âlemin ilmini okuyan, dört mezhebin sırrını sezen kişi bile,","bu yolda âciz kaldı; bu aşka el uzatamaz."],["Bu aşkın sırrı şaşılacak şeydir; bu aşkı öyle gönülden iste;","meğer ki Çalap (Allah) onu vere — yoksa her göz onu görmez."],["Onu o kişi görür ki, eceli gelmeden (nefsine) ölür;","bu nasibi, canına (canının kaygısına) takılmayanlar alır."],["Her kim canına (kaygısına) kaldıysa, asıl konağına (hânına) erişemeyecek;","varıp mahşerin kalabalığına düştü; orada bir can kadar bile kalmaz (tutunamaz)."],["Mustafa'dan (Peygamber'den) bir hadistir; aşkla ikrar (kalpten tasdik) buyurdu;","bunu, binde bir ârif bile bakıp gerçekten okuyamaz."],["Yunus, canını sağlam tut (berk et), bildiklerini terk et;","fenâ olmayan (benliğinden geçmeyen) sûret (kişi), o şaha (Hakk'a) ulaşamaz."]],"111":[["'Ben dervişim' diyen kişiye, bu yolda utanma (âr) gerekmez;","derviş olan kişilerin gönlü geniştir; dar olmamalı."],["Derviş, gönülsüz (benliksiz) olmalı; sövene karşı dilsiz olmalı;","dövene karşı elsiz olmalı; sıradan halkla bir olması gerekmez."],["İşini sıradan halka benzetmesin; gönlünden kaygıyı (teşvîşi) sürsün;","dervişe göre yüz bin(i) birdir; arada yabancı (agyâr/ikilik) gerekmez."],["Eğer dervişsen, bütün âlem sana tanıştır (dosttur);","boş (lüzumsuz) işi-sözü, güzel huyla değiş; arada yabancı (ikilik) gerekmez."],["Derviş olan kişilerin sermayesi, alçakgönüllülüktür (miskînlik);","alçakgönüllülükten başka bize mal, mülk, şehir (şâr) gerekmez."],["Erin (mürşidin) elini tuttuysan, ere gönül verdiysen,","ikrarla (bağlılık sözüyle) geldiysen — artık eri inkâr etmek gerekmez."],["Yunus, gördüğün eri gözünde çoğaltma — gördüğün aslında birdir;","'şudur, budur' deyip, dervişin gönlü darmadağın (târumâr) olmamalı."]],"112":[["Eğer dilim bağlı (tutulu) ise, kimse bana bir şey demez;","gönlüm ger gezgin (revende) ise, âlemde karar kılmaz (durulmaz)."],["Eğer gözüm bakarsa, baktığına akarsa (kapılırsa),","gördüğüne 'benim' derse — ateşe düşer, utanmaz (âr etmez)."],["Eğer akıl başta ise, gönülde de yerli yerinde (tuşta) ise,","ikisi bir işte (birlikte) ise, düşman bana kâr edemez (zarar veremez)."],["Düşman, benim nefsimdir; tamah ile hırsımdır;","tamaha ve hırsa uyan, temiz gönüllerde yer edemez."],["Bütün gönülleri düzenleyen O'dur; türlü nakışları yazan O'dur;","can gövdeden ayrılınca, bu diller neden konuşmaz (öyleyse konuşturan O'dur)?"],["Gönüllerde yer etmek, Muhammed'e verilmiştir (nasip olmuştur);","Mustafa'ya ümmet olan, cehennemde (Tamu'da) kalmaz."],["Öldüren O, dirilten O; Yunus, şimdi sen Hak'la ol;","Hak'tan başka hiç kimse yok; O'ndan başkası bir şeyi var edemez."]],"113":[["Bu ne derttir — şaşılır, dermanı görünmez;","ya bu ne yaradır, beresi (zahmı) belli olmaz."],["Benim gönlüm, şaşılır, aşktan usanmaz;","gider aşka düşer; bana hiç karşı gelmez (tanmaz)."],["Gönlüm döner, bana hoş (güzel) öğüt verir;","âşık olan gönül, aşktan usanmaz."],["Canına (kaygısına) kalan kişi, âşık olmaz;","canını terk etmeyen, sevgiliyi (ma'şûku) bulmaz."],["Bu aşk pazarıdır; burada canlar satılır;","canımı satarım, hiç kimse almaz."],["Âşık öyle bir kişidir ki, bu dünyanın malını,","ahiret korkusunu, bir çöp kadar saymaz."],["Bu dünyadan da ahiretten de içeride (öte),","âşığın bir yeri var; kimse bilmez."],["'Âşık öldü' diye sala verirler;","oysa ölen hayvandır (bedendir); âşıklar ölmez."],["Âşıkların meydanı, Arş'tan yücedir;","çevgânı (sopayı) çalarlar (vururlar), topu bile görünmez."],["Beyim, ârif (irfan ehli) isen, yürü yolunca;","burada başlar gider (feda olur), kanlar sorulmaz."],["Erenlerin kapısı, Hazret'in (Allah'ın) kapısıdır;","bu kapıya gelen, mahrum (eli boş) çevrilmez."],["Yunus bu denize (deryâya) gark oldu (battı), gitti;","geri dönmeye, aklı artık dirilmez (toparlanmaz)."]],"114":[["Hiç kimse bizi bilmez — biz ne işin içindeyiz;","ne hırsımız zengindir (büyüktür) bizim, ne de nefsimizin içindeyiz."],["Biz, bir kimsenin devletini (bahtını) ayıplamaya (ta'n etmeye) gelmeyiz;","ne âlimleri inkâr ederiz (münkiriz), ne de Hristiyan'ın haçındayız."],["Biz bunun (dünyanın) ne olduğunu bildik; dünyanın neyine kaldık (bağlandık)?","Arzumuz nefis için değil; biz sadece dünyayı seyre (teferrüce) çıkmışız."],["Yunus der: hey sultanım, benim başka (özge) bir şânım var;","bırak dünyanın altınını gümüşünü — biz onun ne bakırında ne tuncundayız."]],"115":[["Bu halkın binde biri bile, Rahmân'ın (Allah'ın) yoluna girmez;","gel, şeytanın yoluna girmeyen bir kişi göster (de görelim)."],["Bu halk, erkeği de dişisi de, işi uzattı (savsakladı);","Müslüman olan kişi, isyan yoluna girmez."],["Hep gafletle gafil (herkes habersiz); akıllı (âkil) gaflete ne yapsın?","Bin kez söylesen de, iyiden câhil olan, irfan yoluna girmez."],["Gönül, karanlık (zulmet) doludur; işlediği şey, bid'attır;","bu nasıl ümmet(ten sayılır) — Kur'an yoluna girmez ki?"],["Gel sen, Yunus, Allah'a yarar bir kul ara, bul;","kul ne zaman makbul olur — madem sultanın (Allah'ın) yoluna girmiyor?"]],"116":[["Bu (alışılmış) dinden (anlayıştan) başkadır (gayrıdır) bizim aşk yolumuz;","bizim asıl din ve diyanetimiz, hiçbir dış (kalıp) dinde tam bulunmadı."],["Bu din ve diyanette, dünyada ve ahirette,","yetmiş iki millet (bütün topluluklar) içinde, bizim işaretlerimiz (âyâtımız) başkadır."],["Dış (beden) suya değmeden (abdest almadan), el ayak kıpırdamadan,","baş secdeye inmeden, bizim gönüldeki asıl ibadetimiz (tâatımız) kılınır."],["Bizimki ne Kâbe ne mescit, ne rükû ne secde (gibi dış kalıplarla sınırlı);","bizim münâcâtımız (yakarışımız), Hak'la daima, hararetle (becid) sürer."],["İster Kâbe'ye varalım, ister mescide girelim,","ister suya yıkanalım (abdest alalım) — içimizdeki illet (dert) hep bizimledir."],["Su ne kadar temizlese de, madem içteki kötü huya (yavuz hûy) dokunamaz;","bizi ancak Hak'tan gelen inâyetimiz (lütuf) pâk (temiz) edebilir."],["Kimin sırrını kim bilebilir — madem bu hâle kolayca erişilmez;","yarın (ahirette) orada belli olur: kimimiz Müslüman, kimimiz mürted (yoldan dönmüş)."],["Yunus, canını yenile ki dostluğun anılsın;","bu sözü aşkla dinlersen, bizim gönlümüzdeki kudreti bilirsin."]],"117":[["Halk içinde sofuyum (sûfî); tesbih elimden düşmez;","dilim marifet (irfan) söyler, gönlüm hiç kabul etmez (içine sindirmez)."],["Boynumda icazetim (diplomam); ibadetim riyayla (gösterişle) karışık;","fikrim (endîşem) başka yerde; gözüm asıl yolu gözetmez."],["Marifet söylerim; iyiden (katı) riyakârlık (sâlûslık) ederim;","alçakgönüllülüğe dönmek için, gönlümden kibir gitmez."],["Hoş (güzel görünüşlü) bir dervişim; sabrım yok, dilimde inkârım çok;","kulağıma gireni, içim asla işitmez (kalbime ulaşmaz)."],["Dünya bir çıra (ışık), bir baş köşedir; gönlüm hep bunu (dünya itibarını) gözler;","ama ne yapayım — Hak korkusu, asla içimden gitmez."],["Görenler elimi öper, tacıma hırkama bakar;","beni şöyle sanırlar: zerre kadar bile günah işlemez."],["Dışımda (taşımda) ibadetim, hoş sohbetim, tâatim görünür;","iç pazara (gerçek hesaba) gelince, bin yıllık hilekâr (ayyâr) bile benim ettiğimi etmez."],["Görenler beni veli sanır, selam verir, önümde utanır;","oysa nice kötü iş işlerdim — sadece elim erişip gücüm yetmiyor (fırsat bulsam yapardım)."],["Dışım derviş, içim boş; dilim tatlı, sözüm hoş;","ama benim ettiğimi, dinini değiştiren (mürted) bile etmez."],["Yunus, eksikliğini Allah'ına arz et (sun);","O'nun keremi (cömertliği) çoktur; senin ettiğini O etmez (kötülüğüne aynıyla karşılık vermez)."]],"118":[["Yine aşkın elçisi geldi; meydanımız yine doldu;","sağdan sola dört yanımız, yine gezinti yeri (teferrüc-gâh) oldu."],["Yine meclisler (mahfiller) düzüldü; yine taslar (badyalar) kuruldu;","yine kadehler sunuldu; canlarımız sarhoş (esrük) oldu."],["Ev içi aşkla doldu; ulusu küçüğü âşık oldu;","canlarımız hayran oldu; perişanlığımız (dağınıklığımız) dağıldı (gitti)."],["Kimimiz Hak'tan aldı, kimimiz Hak'tan doldu;","aşkın tahtına binenimiz, kimimiz Süleyman oldu."],["Kimimiz Leylâ oldu, kimimiz Mecnun oldu;","aşktan haber sezenimiz, kimimiz Ferhad oldu."],["Meydanımız gerçek meydan oldu; canlarımız hayran oldu;","her an Arş'a seyran (yolculuk) oldu; Hazret (Allah'ın huzuru), divanımız oldu."],["Düşmüştük, O kaldırdı; birliğini bize bildirdi;","içimize aşk doldurdu; imanımız sağlam (dürüst) oldu."],["Dost nerede diye sorarsan — nerede istersen oradadır;","hem gönülde hem candadır; hiç şüphemiz (gümânımız) kalmadı."],["Yunus aşkın vasfını söyler; gerçeklere (samimilere) haber eyler;","mahrumların canı için için yanar; bizim gizlimiz (pinhânımız), aşikâr (eşker) oldu."]],"119":[["Aşk erine dünyada ipek (harîr) neyse, aba (palâs) da odur (fark etmez);","çünkü onun gönlü, kibir ve pas (kir) tutmadı."],["Aşk, amelle (eylemle) biter (yeşerir); kişi lâyık olursa, o yeter;","istersen çıplak (uryân) yürü, istersen elbise (libâs) giy (önemli olan dış değil)."],["Vazgeçmenin (ferâgat) makamına (menziline) ermek dilersen,","var, kanaat darağacında, nefsini boğazından as (öldür)."],["Nefsinin varlığını, küllî akla (akl-ı külle) ulaştır (kat);","varlığını yokluğa değiş; cevher (mücevher) ol, bakır (muhâs) olma."],["Bütün bu günahları yıkayan, alçakgönüllülük (miskînlik) imiş;","var Yunus, sen miskîn ol; gel, tamahın (aç gözlülüğün) yayını yaslayıp boz."]],"120":[["Bilenlere sormak gerek: bu tendeki can neymiş (nedir)?","Can, zaten Hakk'ın kudretidir; öyleyse damardaki kan neymiş (nedir ki)?"],["Fikir, hizmet uşağıdır (yumış oğlanı); endişe, kaygı madenidir (kânı);","bu âh u vâh (inleyiş), aşkın giysisidir; öyleyse tahta oturan han (hükümdar) neymiş (kim ki)?"],["Şükür O'nun birliğine — yokken işte bizi var etti;","madem aslında biz yokuz, mülk ve ev bark (hânumân) neymiş (neyimize)?"],["Çalap (Allah) bizi 'var, dünyayı görün' diye gönderdi;","bu dünya zaten kalıcı (bâkî) değil; mülke karşı Süleyman bile neymiş (ne kadar kaldı)?"],["Tapduklu Yunus'a sorun: bu dünyadan ne anladı?","Bu dünyanın kararı (kalıcılığı) yok; sen neymişsin, ben neymişim (ne ki)?"]],"121":[["Âşığın canına aşkı koyan, o yüce Sübhân (Allah) imiş;","O'nu canımın içinde bulmuşum; canlara da can imiş."],["Sevdiğimiz yâr, Mustafa'dır (Peygamber'dir); meyil ve vefa ondan gelir;","sıdkı (doğruluğu) tam, gönlü saf; hem bizim imanımız o imiş."],["Bu dilin sözü halk içindir; dostun sırrı (râzı) gönüldedir;","gönlün dosta söylediği — ne derse, bizim Kur'an'ımız imiş."],["Bir an gönüle yöneldim; o gizli sayfaya (varaka) baktım;","işte sırrımı halka açtım — o gönül, ucu bucağı olmayan bir umman imiş."],["Gelin ummana dalalım; arayıp cevher (mücevher) bulalım;","satalım, sarraf olalım; çünkü o, tükenmez bir maden (kân) imiş."],["Eğer bizden almazsanız, siz satın, biz alalım;","çünkü bizim bu gönlümüz, sermayeli bir dükkân imiş."],["O dükkânın açılmamasının, kokusunun saçılmamasının,","sırrının açılmamasının — kilidi, kibir ve kin imiş."],["Madem kibrin boynunu ezdin, hırsın evini de bozdun;","dükkânı süsleyip (âreste) düzdün — alan alsın, o bir maden imiş."],["Yunus da uyanmadan, kendi ölümünü düşünmeden,","bu doğru yola gelmeden — bütün işleri boş bir zan (gümân) imiş."]],"122":[["Hak'tan yine haber geldi: kullar yol azığı (yarag) hazırlasın, demiş;","toplanıp bir evliyadan el-etek tutsun (ona bağlansın), demiş."],["İşin sonu (ucı) yakındır; müftü de hacı da yoldan sapmış;","'Mi'râc'ı göreyim' diyen, alçakgönüllülüğüne (miskînliğine) sarılsın, demiş."],["Fâni dünyadan geçeriz; O'nun bâkî (kalıcı) mülküne göçeriz;","dosta armağan gerek — kişi yüklü yükünü (azığını) hazır tutsun, demiş."],["Bu saray (dünya) kalıcı değildir; er geç herkes oraya (ahirete) varır;","burada azık hazırlamayanlar, o evi (cenneti) unutsun, demiş."],["Ben şu kulumu severim: yoksul olup sabreden kulu;","ona benden bir yol açtım — Mi'râc'ıma gelsin, demiş."],["Şu zahmetle (kahırla) kazanıp, güle güle başkalarına yedirenler —","perdelerini kaldırdım; dîdârıma (yüzüme) baksınlar, demiş."],["Her kişi dosta varsın, armağanını dosta versin;","orada (ahirette) bizi anmayanlar, burada da bizi unutsun, demiş."],["'Ne bir açı doyurdum, ne bir çıplağa gömlek giydirdim,","ne de bir gönüle girdim — ya öyleyse Allah bana nasıl muamele etsin?' demiş kişi."],["Yunus'a deyin: kalksın, yüzünü toprağa sürsün (tevazu etsin);","öğüdünü kendine versin, okuduğunu tutsun (uygulasın), demiş."]],"123":[["Hakk'ı bulmak isteyenler, nefsini derviş eylesin;","Çalap (Allah) bize mürşid (kılavuz) vermiş; derviş olabilsem, derviş!"],["Nefsin yolundan geçemiyorum; aşkın şarabını içemiyorum;","gönlüm kara, onu açamıyorum; derviş olabilsem, derviş!"],["Hakk'a yakın olur muyum, rahmetine dalar mıyım,","yoksa erişemeden ölür müyüm — derviş olabilsem, derviş!"],["Bu acayip sevda gönlüme düştü; gönlüm karar kılmaz (durulmaz);","bildim ki işim baştan başa hata; derviş olabilsem, derviş!"],["Dostu tanıyana (bilişene) erişsem, dostun yolunda yürüsem,","ar ile namus kaygısını bıraksam — derviş olabilsem, derviş!"],["Bir gün işim tamamlanır; bütün ettiğim boş bir zan (gümân) çıkar;","meğer (ola ki) Hak'tan bir aman (bağış) ola — derviş olabilsem, derviş!"],["Eğer aman (bağış) verirlerse — gerçi kulluğum tamam olmadı;","ey çaresiz Yunus, hemen — derviş olabilsem, derviş!"]],"124":[["Erenlerin yolları, inceden inceymiş;","Süleyman'a yol kesen (engel olan), şu bir karıncaymış."],["O karınca söyledi, Süleyman'a 'yol (ver)' dedi;","o karıncanın söylediği (konuşması), cevabını alıncaya kadarmış."],["Kimse kimsenin yükünü (gücünü) götürmedi (taşımadı);","'yükü götürdüm' diyenlerin dediği, bir el yetişinceye kadarmış."],["Kim kime ne derse — ister hayır, ister şer;","Allah karşılığını (cezasını) verir; gel (dikkat et), yol inceymiş."],["Gönlüm bana söylerdi, 'seni severim' derdi;","gönlümün seni sevmesi, asıl dosta erişinceye kadarmış."],["Gönlüm der: 'dosta varayım, sana geri geleyim';","gönlümün bana uyması, asıl dostu buluncaya kadarmış."],["Yârenlerim der: âşığa melâmet (kınanmak) gerek;","bu benim başıma geldi; o söz, yerini buluncaya kadarmış (gerçek çıktı)."],["Âşığın gözyaşı gece gündüz dökülür, durmaz;","âşığın kan ağlaması, sevgili (hâlini) soruncaya kadarmış."],["Dört kitabın manasını okudum, öğrendim (tahsil kıldım);","aşka gelince gördüm ki — hepsi bir ulu hece(den ibaret)ymiş."],["'Ben dervişim' diyenler, haramı yemeyenler —","haramın yenmemesi, haram ele geçinceye kadarmış."],["Derler: 'falanca öldü, mülkü malı kaldı';","o malın birikmesi, sahibi (ıssı) ölünceye kadarmış."],["İki kişi konuşur: 'Yunus'u bir görsem' diye;","biri der: 'ben gördüm — o bir âşık ihtiyar(mış).'"]],"125":[["Ben dertle âh ederdim; oysa derdim bana derman imiş;","hasretle O'nu arardım; meğer dost, yanımda gizli (pinhân) imiş."],["Neredeysem düşünürdüm, göğe bakıp şükrederdim;","hasretle O'nu arardım; meğer dost, yanımda gizli imiş."],["Kendimi ayrı sanırdım; 'dost başka, ben başkayım' derdim;","beni bu hayale (ayrılık vehmine) salan, bu insanlık sıfatı (sıfât-ı insân) imiş."],["İnsanın (kâmil insanın) sıfatı, Hakk'ı yansıtır; Hak (kâmil) insanda tecelli eder, doğru bak;","bu insanın sıfatına, bütün âlem hayran imiş."],["Her kim o (kâmil) insanı bilirse, hayvan gibi bile olsa insan olur;","bütün yaratılmış kullara göre, o insan baştan başa sultan imiş."],["Bütün âlem tevhid (birlik) imiş; tevhidi bilen, Âdem'dir (gerçek insandır);","bu tevhidi inkâr eden, kendi canına düşman imiş."],["Gerçek insan olan, Hakk'ı buldu; meclis onundur, sâkî de odur;","işte bu çaresiz Yunus, aşkla Hakk'a âşinâ (tanış) imiş."]],"126":[["Sevdiğim güzeli (nigârı) ne yapayım — o benden müstağni (fârig);","ne verip de hoş görüneyim — ben iki cihandan da elimi çekmişim (fârig)."],["Hâllerimi söylemeye, kimden kime varayım?","Sözümü kime diyeyim — ben sözden de dilden de el çekmişim."],["Cihanda kim girebilir bu işin arasına?","Ya kim hüküm verebilir — bu iş sultandan da handan da bağımsız (fârig)."],["İster Müslüman olup bin yıl ibadet edeyim,","ister kâfir olayım — sevgili küfür ile imandan (bu ikilikten) münezzeh (fârig)."],["İster din ehlinin farzını gözeteyim,","ister şöhret kovalayayım — o şöhretten de dış dinden de bağımsız (fârig)."],["İster din ilminde yüz bin kez minbere çıkayım,","ister şirk besleyeyim — o şirkten de şüpheden de münezzeh (fârig)."],["O'na ne kadar ticaret ve kazanç (mekseb) göstereyim —","O öyle zengindir (tüvânger) ki, kârdan da zarardan da müstağnidir (fârig)."],["Ben O'nu yalnız kullukla nasıl sevebilirim —","O'nu seçkin de halk da sever; O ise bütün sevenlerden müstağnidir (fârig)."],["Öyle bir sevgiliye (ma'şûka) kim gönül verdiyse,","sayısız ibadet (tertîb) gerek; o, şundan bundan (her şeyden) el çekmiştir (fârig)."],["Yunus, eğer sen gerçek sevgiliyi (hakîkat ma'şûku) seversen,","dervişlikle kül ol; varlıktan da mekândan da el çek (fârig ol)."]],"127":[["Ölümü andıkça, içim yanar, özüm için için tutuşur;","ölüm düşüncesi (endîşesi), ulularla danışınca ne hoş gelir."],["Apaçık öleceğiz; gizli içimiz (hâlimiz) ortaya çıkar (ıyân olur);","teneşir tahtasına konup, halkın önünde yıkanınca."],["Hiç bilmiyorum ne yapayım, hangi yana sefer edeyim —","yakasız giysiyi (kefeni) giyip gideyim, başsız ata (tabuta) binince."],["Bana kavmim kardeşim gelir, mezara dek (sine degin) yoldaş olur;","ben mezarımda kalınca, kim bana dert ortağı (hâldaş) olacak?"],["Ben amellerimle kalırım, hâlim nasılsa öyle;","kavmim güle güle gider, eve doğru dönünce."],["Sana söylüyorum, ey paşa: başa neler gelecek —","kimi sıcaktan bağrı pişer, kimi (cennet) şarabına kanar (doyar)."],["Yarın (mahşerde) ceza (siyâset) kurulur, bütün yaratıklar (halâyık) toplanır;","kimi tek bir emirle kurtulup geçer, kimi sıcaktan (cehennemde) yanar."],["Orada cevabı ameller verir; amelsize azar (itâb) olur;","şu kişiye azap olmaz ki, burada (dünyada nefsinden) âzâd (hür) olunca."],["Yunus, şimdi sen azık (yarak) hazırla; utanmayasın, doğru bak;","bütün yaratıklar toplanıp, herkes adıyla sanıyla sayılınca (çağrılınca)."]],"128":[["Şükür Hakk'a ki, dost bize 'dostun yüzüne bak' dedi;","ben de gönlümün gözünü açtım; sultanımı apaçık (mutlak) gördüm."],["Madem Hakk'ımı gördüm, Hak'la tanış (biliş) olmuşum;","nereye baktıysam, hep görünen, baştan başa Hakk'ın tecellisidir."],["O Hakk'ın kapısı, dostları için açık, aralıktır;","O'nun dostu olmak dilersen, O'nun dostlarından bir ders (sebak) öğren."],["Bugün perdedesin (hicâbdasın); seni sana açıkça göstermezler;","'perde' (hicâb) dediğimi anla — o, dünyalıktır; seni Hak'tan görünmez biçimde uzak tutar."],["Sen kendini bilmedikçe, ere (ermişe) nazar (yönelme) kılmadıkça,","benliği (senliği) bu aradan gidermezsen — o benlik sana tuzak oldu."],["Yedi deniz, dört ırmak bile seni temiz (mismil) edemez;","çünkü işin O Hak'la olmadıysa, yine uzak kaldın."],["Evliya, Hakk'ın kapısıdır; Yunus da onun kapıcısıdır;","bu yola aşkla geldi; aşkı kendine hem durak (yurt) edindi."]],"129":[["Gel, ey gözüm, ağla; artık gülmem;","canım dosta gider; artık geri gelmem."],["Ne gam, bu dünyada bir kez ölürsem —","orada ölüm olmaz; artık ölmem."],["Ben varlığımı yokluğa değişmişim;","bugün artık cana başa (can kaygısına) kalmam."],["Sevgi (mahabbet) denizinin dalgıcı (gavvâs) oldum;","artık gerek yok — Ceyhun'a (ırmağa) dalmam."],["Aşkına yanmışım, ta kül olunca;","rengine boyandım; artık solmam."],["Bırak beni, dostun eşiğinde yatayım;","yeter, artık başka bir el tutmam."],["Yansın canım, yansın aşkının ateşine;","aksın yaşım, aksın; artık onu silmem."],["Bırak beni, için için yanışlarımla (göynüklerimle) yanayım;","ne zaman âşık olsam, artık ölmem (âşık ölümsüzdür)."],["Dilerim, beni lütfundan (fazlundan) ayırmayasın;","hocam, senden başkasını artık sevmem."],["Yunus âşıktır; sevgilisini (ma'şûkunu) ister;","artık başka hiçbir şey istemem."]],"130":[["Ey çok kitap okuyan, sen ki bana kusur (dak) bulursun;","o açık sırrı (gerçeği) bilesin diye — gel, aşktan bir sayfa (varak) oku."],["İlmin sadece yüzünü okuma; ilme göre amel et — asıl seçkin (iş) budur;","gönülden iç (bâtın) gözünü aç; âşık ile ma'şûkun hâline bak."],["Bak, ma'şûk (sevgili) ne işte (hâlde)dir — âşık da o iştedir;","ikisi bir sır işindedir; onları iki sanıp uzakta kalma."],["İkilikten geçemedin; yaşanan hâli, kuru sözden (kâlden) ayıramadın;","Hak'tan yana uçamadın; fakihlik (kitabî bilgi) sana bir tuzak (fak) oldu."],["Cübbe, hırka, taht, taç — bunlar hepsi aşka vergi (bâc) verir (boyun eğer);","nitekim Şeyh San'an (Abdürrezzak), dört yüz müridini ve elli haccını aşk uğruna terk etti."],["Onun gibi bir din ulusu bile aşk için haç öptü, çan (nâkûs) çaldı;","sen de benlik namusunu (itibar kaygısını) bırak; nefsinin itini (köpeğini) ateşe yak."],["Eğer sen kendine geldiysen, kendi sıfatının ne olduğunu bildiysen,","Hakk'a itaatkâr (mutî') olduysan — ne dersen, o zaman bana karşı haklısın."],["Öyle bir hâle gel ki kötü ünle (bed-nâm) iyi ünü (nâm) ayırt etmeyesin; seçkin de halk da sana bir ola;","ilmi tamamen bildiysen — gel şimdi, aşktan bir sayfa oku."],["Yerde gökte her şey aşkladır; dile gelen her söz, aşktan gelir;","çaresiz Yunus ne bilsin — o ne kara (mürekkep) okudu, ne ak (sayfa)."]],"131":[["Biz neye âşıksak, bütün âlemler de ona âşık;","kime 'değil' diyelim — her biri, sıdk (içten bağlılık) işinde ustadır."],["Sevgiliyi (ma'şûku) seven, O'nu sevmek zorundadır;","dostumuzun dostuna, yabancı (kötü) düşünce nasıl yakışır?"],["Sen gerçek âşıksan, dostun dostuna dost ol;","eğer böyle olmazsan, sakın 'dostum' deme — açıkçası öyle değilsin."],["Kim sana değersiz (az) görünürse, aslı yüce bir yerdedir;","onu küçük görme, büyük gör; yol (tarîk) böyle gelmiştir."],["Âşıksan, yetmiş iki millete (bütün insanlığa) kurban ol;","ki âşıklar safında tam bir sâdık (gerçek bağlı) olasın."],["Sen Hakk'a âşıksan, Hak sana kapı açar;","kendini beğenmeyi bırak, varlığının (benliğinin) evini yık."],["Seçkin de halk da, itaatkâr da âsi de — hepsi dostun (Allah'ın) kuludur;","kime aksini diyebilirsin — gel, benlik evinden dışarı çık."],["Yunus'un bu sözü (dânişi), gizli hazinenin (genc-i nihân) sözüdür;","dosta âşık olanlar, iki cihandan da el çekmiştir (fârik)."]],"132":[["Lütfeyle, bir beri bak; peçeyi (nikâbı) yüzünden bırak;","sen dolunay (ayın on dördü) müsün — yüzün, yanağın parıl parıl."],["Şu bal ağızdan çıkan söz (keleci), yüz bin şekerden tatlıdır —","bu dilin söyleyecek olsa, o dudak kıpırdayacak olsa."],["Otuz iki inci bitmiş mercan (kırmızı dudak) içinde, ey canım;","kıymeti en iyi inciden üstün, aklığı da inciden ak."],["Yüzünün karşısında bu güneş bir an bile durup duramaz;","hilâl (küçük ay), senin kaşından her an ders (sebak) ala ala geçer."],["Seni gören, pervane gibi nasıl ateşe düşmesin —","çünkü iki yandan (yanağında) o iki alevli mum (çerâk) durur."],["Aşkın zincirlerine (selâsiline) kim düşerse,","o, bedeni toprak olsa bile, artık özgürlük (âzâdlık) istemez."],["Dil, senin güzelliğini (hüsn) ve huyunu (hulk) nasıl anlatsın —","Allah, güzelliğini kötü (yavuz) gözlerden ırak eylesin."],["İşittim ki senin boyun, selviden (servi) daha yüce imiş;","daha gözüm görmeden, kulak (işiterek) boyuna âşık oldu."],["Yunus, Hakk'ın tecellisini (güzelliğinin yansımasını) senin yüzünde gördü;","ayrılmaya çare yok — çünkü Hak, sevgilinin yüzünde sende göründü (tecelli etti)."]],"133":[["Mana denizine daldık, varlığın (vücûdun) sırrını bulduk;","iki cihanı baştan başa, hepsini vücutta (insanda) bulduk."],["Bu dönen gökleri, yerin altındaki yerleri,","yetmiş bin perdeyi (hicâbı) — hepsini vücutta (insanda) bulduk."],["Yedi göğü, yedi yeri, dağları, denizleri,","cennet ile cehennemi — hepsini vücutta (insanda) bulduk."],["Geceyle gündüzü, gökteki yedi yıldızı,","Levh'te (Levh-i Mahfûz'da) yazılan sözü — hepsini vücutta (insanda) bulduk."],["Musa'nın çıktığı Tûr dağını, yahut Beytü'l-Ma'mûr'u,","İsrafil'in çalacağı Sûr'u — hepsini vücutta (insanda) bulduk."],["Tevrat ile İncil'i, Zebur ile Furkan'ı (Kur'an'ı),","bunlardaki beyanı (açıklamayı) — hepsini vücutta (insanda) bulduk."],["Biri, ikiyi, üçü; dört ile beş ve altıyı;","yedi, sekiz, dokuzu — hepsini vücutta (insanda) bulduk."],["Yunus'un sözleri Hak'tır; bütün dediği gerçektir (saddâk);","ne gördüysen hepsi Hak'kın tecellisi — hepsini vücutta (insanda) bulduk."]],"134":[["Muhammed'e bir gece, Çalap'tan (Allah'tan) Burak indi;","Cebrâil der: 'efendim, Hak seni Mi'râc'a çağırdı.'"],["'Cennetleri kendine aç; cennet de dîdâr (Allah'ın cemâli) da senindir;","seni Sübhân'ın (Allah) çağırıyor — ne yatıyorsun, hazırlan (kıl yarak).'"],["Mi'râc niyetiyle kalktı, abdestine yürüdü;","dostuna (Allah'a) secde kıldı; 'yakın, uzak' demedi (tereddüt etmedi)."],["Cebrâil Hazretleri gitti, Burak atını getirdi;","kaftanı (hil'ati) nurdandı, gözü cevher, yüzü ak."],["Ayağını bir taşa bastı; taş yerinden koptu, beraber yükselip gitti;","'dur, ey mübârek' dedi; taş öylece askıda (mu'allak) kaldı."],["Taş der: 'gelesin, bir kez daha ayağını basasın';","Resûl der: 'o Hak buyurursa, gelirim.'"],["Göklere haber oldu; yer gök sevinçle (şâdılık) doldu;","'Ahmed geldi' derler; sekiz cennet (Uçmak) süslendi."],["Bak Muhammed ne yaptı — gökleri seyretti;","Arş'a varır varmaz, ümmetini (hayra) doyurdu — onlar için lütuf diledi."],["Felekleri (gökleri) geçince, bir ses geldi: 'beri gel;","perdeleri kaldırdım — hemen cemâlime (güzelliğime) bak.'"],["'Dîdârımı (cemâlimi) sana apaçık göstereyim, besbelli;","Burak'tan in, yaya ol; Arş'ıma bir ayak bas.'"],["Melekler (ferişteler) geldiler, onu Burak'tan indirdiler;","nalınını çevirdiler; o an yaya olarak yürüdü."],["Üveys (Veysel Karanî) yerinden kalktı, Arş'ta nalını çevirdi;","Muhammed onu gördü; ayrılık (firâk), kavuşmaya (visâle) döndü."],["Dost dosta kavuşunca, yüz bin söz (kelâm) konuştular;","Peygamber ümmeti için çalıştı; mutlak Resûl (Peygamber) odur."],["Mi'râc'dan döndü, yine evine geri geldi;","geldi, gördü ki — döşeği (yatağı) hâlâ sıcacık (bunca yolculuk bir an sürmüştü)."],["Nice bin yıllık yolu, bir anda (bir demde) gidip gele —","Yunus der: kim olabilir? — o, kesinlikle Muhammed'dir."],["Ümmete 'ümmetim' diyen, ümmetin derdini (kaydını) çeken Peygamber'in;","eğer onun ümmetiysen, de ve bağlan: İslâm dini haktır — ona sımsıkı sarıl."]],"135":[["Dostun yüzüne bakmak için, iyice (key) saf bir bakış (nazar) gerek;","dostla tanışmak için, can gözünün uyanık (bîdâr) olması gerek."],["Şan-şereften (izz) ve nazdan geçerek, gösterişli düzenleri (tertîbleri) bırakarak,","varlıkları tüketerek — hatta bunun yüz bin katı fedakârlık gerek."],["Varlık (benlik), çok katı bir perdedir (hicâb); kim yıkabilir bu perdeyi —","dostun yüzünden peçeyi (nikâbı) kaldırmaya, gerçek bir er gerek."],["Sen kendine perde (hicâb) oldun; ne diye dört yana bakarsın —","kim dîdâr (Allah'ın cemâli) isterse, öne arkaya sapmaz (şaşmaz)."],["Gel şimdi perdeni yık, hırs evinden dışarı çık;","Hak başarı (tevfîk) bağışlasın — doğru niyetle gayret (hüner) gerek."],["Âşığa itibar (izzet) da, utanç (âr) da birdir — vallahi bu, şaşırtıcı (bedi') bir sözdür;","âşıksan, candan geçip gel — baş (ser) da sarık (destâr) da ne gerek?"],["Kendini elden bırak; dostun yüzüne sensiz (benliksiz) bak;","Mansûr gibi 'Ene'l-Hak' demek için — insanın yükünün hafif (sebûk-bâr), benlikten arınmış olması gerek."],["Kim dostla tanışırsa, şüphesiz (lâ-cerem) derde düşer;","âşığın canı, daima aşktan sarhoş (ser-mest) ve mahmur (humâr) olmalı."],["Sen kendini aradan çıkar; beden ve suret, candan (benlikten) arınmış kalsın;","işte orada kavuşmayı (visâl) bulursun — başka ne pazar (alışveriş) gerek?"],["Dostla tanışan can, kendinden geçip kendine kıyandır;","varlık (benlik) ordusunu (leşker) bozan kişinin, daha da çevik (çâpük) olması gerek."],["Dedikoduyu (kıyl u kâl) bırak; gücünü (mecâlini) dosta ver;","kavuşma (visâl), yoklukta(dır); her şeyden geçmek (güzer) gerek."],["Bu, gözün gördüğü değil; bu, aklın erdiği değil;","bu, dilin anlattığı (vasfettiği) değil — dilsiz (bî-lisân) bir basîret (iç görüş) gerek."],["İşit, işit, iyice işit: dostun katına sensiz (benliksiz) git;","dosta gidene, önce kendisiz (benlikten geçmiş) bir yolculuk gerek."],["Sen çoğu (bu büyük gerçeği) küçük görme; çünkü dost, senin içinden doğar;","varlığını (benliğini) yok say — bunca söze (haber) ne gerek?"],["Unut, unut hepsini; sözün özünü (hâsını) söyle;","dostu görmek dilersen, bundan başka bir baş (anlayış) gerek."],["Dünyadan da ahiretten de, türlü türlü nimetten de —","dostun yüzünü görmek için, hepsinden geçmek gerek."],["Dünya ahiret hâlleri, eş ve evlat yükü (vebâli) —","dostun kavuşmasını (visâl) dilersen, varlıktan (benlikten) sakınmak (hazer) gerek."],["Sır sözü ucuz bir boncuk değildir; gel gidelim, bırak boş sözü;","dostu baş gözü (zahirî göz) görmez — başka türlü (ayruksı) bir görüş (basar) gerek."],["Yunus, şimdi kendinden geçip yiten ol; öyle ki ne il ne şehir yolunu bulasın;","kimi 'Hak' desin, kimi 'bâtıl' — dervişin aldırmadan kale burcu gibi sağlam durması gerek."]],"136":[["'Müslümanım' diyen kişi, bunun şartı nedir bilmeli;","Tanrı'nın buyruğunu tutup, beş vakit namaz kılmalı."],["Seher vakti kalkıp başını kaldır, ellerini suya daldır (abdest al);","hem şeytanın boynunu vur, hem de nefsin ölmeli."],["Sabah namazını kılarsan, yalvarışın (niyâzın) Hak'la olsun;","ahiretteki itibarını (izzini) ve nazını, oraya varıp orada bulasın."],["Öğle namazını öyle kılasın ki, ne dilersen bulasın;","cehennemden (Tamu) âzâd olasın — kullar böyle âzâd olmalı."],["O ikindiyi kılanlar, temiz (arı) bir hayat yaşayanlar —","işte onlardır Hakk'a erenler; her an onlar Hakk'a ermeli."],["Akşam namazı üç farzdır; dağ kadar günahını temizler;","iyi amellerin, mezarında (sinde) sana mum ve kandil (şem ü çerâg) olmalı."],["Yatsı namazına hazır ol; Kâdir (Allah), hazır olanları sever;","imanının eksiğini tamamla; iman, sana öncü (pîş-rev) olmalı."],["Her kim bu sözden ders almadı, beş vakit namazı kılmadı —","bilin ki tam Müslüman olmadı; o, cehenneme (Tamu) girer."],["Cemaatin değerini bildiysen — cemaatte hazır olanlar cenneti bulur;","eğer tembellik (kâhillik) edersen, münafıklardan olursun."],["Mustafa'yı (Peygamber'i) görmez misin — nasıl vefa gösterdi;","o saflığı (safâyı) ümmeti için diledi; ümmet, ona uyarak erişmeli."],["Din gayretini güdersen, nefse muradını (isteğini) verme;","Yunus, Peygamber'e salâvâtını aşkla ulaştırmalı."]],"137":[["Dünyaya gelen kişiler, doğru yola da gelmeli;","ölümünü anarak, gece gündüz ağlamalı."],["Bu dünya, sıkıntı (kahır) evidir; hem kalıcı değil, geçicidir (fânî);","buna aldanıp kalma — tez (çabuk) tövbeye gelmeli."],["Dünyanın çokluğu nedir ki — yokluğu (geçiciliği) apaçık (eşkere) ortada;","asıl varlık sarayının, gerçekte ahiret olduğunu bilmek gerek."],["Gel şimdi bu fâniden (dünyadan) kalk, bâkîden (ebedîden) mahrum kalmadan;","ibadet (tâ'at) edip, kullar bu dünyadan ahiret için nasibini almalı."],["Cehennemden (Tamu) korkuyorsan, gel, herkesten daha alçakgönüllü ol;","bil ki o gün, herkes ince köprüden (sırattan) geçmeli."],["Sırattan geçip gitmek dilersen, ya da 'düşmeyeyim' dersen —","şu kazandığın malı, Tanrı için vermek gerek."],["Kazandığını verip, yoksulları hoş görüp,","Hak huzuruna varıp — ateşten (oddan) kurtulmak gerek."],["Kur'an 'vattakû' (sakının) der; yine 'tezra'û' (ekin) der;","tembel (kâhil) olup oturma — tez tövbeye gelmek gerek."],["Yunus'un sözü görünüşte şiirdendir; ama aslı, Kitap'tandır (Kur'an'dandır);","hadise ve dine uygun söze, iyice bil ki, sâdık (bağlı) olmak gerek."]],"138":[["Önce bize vâcip (gereken) şudur: güzel huyla amel gerek;","İslâm adı anılınca, yoldaşımız iman olmalı."],["İsrafil sûru (borusunu) çalınca, bütün yaratıklar uyanınca,","hesap sorulunca — orada Arap dili (lisanı) gerek olacak."],["Göğün perdelerini açarlar; iyiyi kötüden (yavuzdan) seçerler;","o an nereye kaçacaklar — baş kurtaracak (sığınılacak) bir yer gerek."],["Çadır (çerge) kurup otururlar; sermayemizi (amel defterimizi) getirirler;","o yargı (siyâset) meydanında, bu düzeni (tertîbleri) bilmek gerek."],["Ana baba birbirine çağrışır; kardeş kardeşten bezer (kaçar);","o Sübhân'a (Allah'a) yalvarırlar — orada yalvaracak gerçek bir er gerek."],["Bütün bunlardan (dükelinden) daha yakın olan, bu aşktır; Yunus, sakın hata etme;","aşktan sual sorulunca, cevap verecek yaşanmış bir hâl gerek."]],"139":[["Bu dünyaya gelen kişi, sonunda yine gitmeli;","o burada misafirdir; bir gün asıl yurduna sefer etmeli."],["Biz bu cihana gelmeden, o dostla (Allah'la) söz (va'de) verdik;","öyleyse ne kadar oyalanacağız — o sözümüzün vakti dolmalı."],["Sözümüzün vakti gelince, biz de O'nunla gideriz;","kişi, varacağı yere gönlünü berkitmeli (bağlamalı)."],["Gönül, dostun iline giden yola nasıl bağlanmasın (berkitmesin) —","âşık kişiler, bu yola canını bile harcamalı."],["Can neye ulaşırsa (bağlanırsa), akıl da ona harcanır;","gönül neyi severse, dil onu açıklamalı (şerh etmeli)."],["Âşık kişi, sevgilisini (ma'şûkunu) ansa (zikretse) — şaşılır mı?","Aşk başından aşınca, gönlünü inletmeli (zâr etmeli)."],["Yunus, şimdi gerçekten seviyorsan, bize O'ndan haber ver;","âşığın nişanı (belirtisi) odur: sevgilisini (ma'şûkunu) söylemeli (anlatmalı)."]],"140":[["Gel, ey dervişlik isteyen; sana ne yapman gerektiğini söyleyeyim:","şerbetleri elden bırakıp, zehiri (aguyı) içmek (nûş etmek) gerek."],["Eğitime (terbiyete) gelmek, bütün bildiklerini bir yana koymak gerek;","mürşidi (mürebbîsi) ne derse, ona uymak (tutmak) gerek."],["Sabrı ve kanaati çeke (taşıya), her gün yeniden sıkı (katı) gayret ede (tâze-kârlık);","bu yola nefsin itini (köpeğini bile) feda edeler — bu yola yüz tutmak gerek."],["Dünyadan gönlünü çeke; eliyle arpa eke;","ununa yarı (yarısı kadar) kül kata, güneşte kurutmak gerek (böyle riyazet ede)."],["O kül katılmış ekmeği ne acayip yer — nefsi isterse ancak koklasın;","ne zaman iftar ederse, orucunu üç günde bir açmak gerek."],["İşte erenlerin yaşayışı budur; bunlar ikiyüzlülüğü (ayyârlığı) bilmez;","kişi onunla erliği (olgunluğu) bulur — sıkıntıyı (kahrı) da yutmak (hazmetmek) gerek."],["Bu dünyanın yüzüne bakma; halkın sözüne aldanma;","dîdâr (Allah'ın cemâli) arzusuna dönüp, o Hakk'a yüz tutmak gerek."],["Yunus bunu kime desin — kim bir uluya (büyük zata) yönelir (kasdeder)?","Belki birimiz bunu işler (uygular); âşıklar için bunu yapmak gerek."]],"141":[["Bu dünyayı ne yapalım, nasıl davranmak gerek?","Daima aşkın eteğini bırakmayıp tutmak gerek."],["Çalap'ım (Allah'ım) bu dünyayı sıkıntı (kahır) için yaratmış;","bu yola gerçekten gelenlerin, sıkıntısını yutması (hazmetmesi) gerek."],["O yarınki (mahşerdeki) yollarda orada yoldaş isteyen,","bu dünyada dostunu (Hak dostunu) kılavuz tutmalı."],["O 'cennet, cennet' deyip kulları ona özendirdiğin (yiltediğin) —","cennetin sermayesi, bir gönül (kazanmak, gönül hoş etmek) gerek."],["Erenlerin âhına (figânına) dağ taş dayanamadı;","kalkanın demir (zırh) olsa bile, onların okları yine atılır (geçer)."],["Yunus, erin (ermişin) nazarında (bakışında) taze güller açılmış;","sen gerçek bülbülsen, o nazarda ötmek gerek."]],"142":[["Derviş olan kişinin yaşayışı (dirliği) temiz (arı) gerek;","yolda, onun namusu (iffeti) da temiz gerek."],["Benlik davasından (iddiasından) geç; sözün özünü (hâsını) söyle;","o Allah korkusundan, dervişin benzi sararık (solgun) olmalı."],["Bağrının yarası (başı) gitmesin (geçmesin), gözünün yaşı dinmesin;","her an dervişin işi, âh ile inleme (zâr) olmalı."],["Kimseye hor bakma; asla gönül yıkma;","yetmiş iki millete (bütün insanlığa), dervişliğin yardımı gerek."],["Cehenneminden (Tamu) korkmasın, hurisinden bir şey ummasın;","onun maksadı daima Hakk'ın dîdârı (cemâli) olmalı."],["Yüzünü, miskinlere (yoksul ve mütevazı olanlara) toprak eyle, ey Yunus;","hepsinden ziyade, erin (ermişin) ikrarı (sözünde durması) gerek."]],"143":[["Hayat suyunu (ömrü) ne yapalım — biz canı yağmaya verdik;","cevherleri sarraflara, madeni de yağmaya verdik."],["Bizim ilin tüccarı (bâzirgânı), hiç kâr (assı) gözetmedi;","madem kâr bizim derdimiz değil, zararı (ziyânı) da yağmaya verdik."],["Bu yolun arifleri (irfan ehli), mal (meta') satmazlar;","biz ise çıplak (uryân) gideriz — dükkânı (dünya malını) yağmaya verdik."],["Bizim pazarımızda müşteri, yokluğu (benliksizliği) satın alır;","madem iş böyle, alıcı (harîdâr), varını yağmaya verdi."],["Din ile milletin (mezhep ayrılığının) pazarını, 'sen-ben' (benlik) yağmaladı;","biz o ikiliğin arasından çıktık — 'sen-ben'i (benliği, ikiliği) yağmaya verdik."],["'Küfür ve iman' üzerine kuru söz, bu yolda bir perde (hicâb) oldu;","ondan geçip huzura erdik — küfür ile iman (tartışmasını, ikiliğini) yağmaya verdik."],["Zühd ile çok ibadet ederek çok istedik, hiç nasip (müyesser) olmadı;","hepsini terk ederek, şüpheyi (gümânı) yağmaya verdik."],["Yüz bin yıllık ömür olsa, bir kuşluk vakti kadar bile değildir;","bitmez hesaptan (sagış) geçtik — zamanı yağmaya verdik."],["Sonu olan (pâyânlu) zaman dönüşü, Yunus'u çok oyaladı;","sonsuz (pâyânsuz) devire erdi — geçici devranı yağmaya verdik."]],"144":[["Hangi sözü söylesem, dilim sonunda seni söyler;","nereye yürürsem yürüyeyim, dileğim sana doğru kaçar."],["Seni sevmeyenlere 'cansız bir surettir' desem, doğrudur (Hak'tır);","işte bu yüzden, canlılara senin gibi bir sevgili (ma'şûk) gerek."],["Bütün âleme söyledin (hitap ettin), ama hâlâ peçenin (nikâbın) ardındasın;","bir an perdesiz yürüsen (görünsen), iki cihan helâk olur (yok olur)."],["Dev ile peri, insan ile melek — her yaratık seni sever;","huri ile melek, hayran olup senin önünde (huzurunda) durur."],["Senin elinden öldürücü zehir içsem, o bana tatlı (nûş) gelir;","bilmem ne hikmeti var — o, canıma panzehir (tiryâk) olur."],["Bal ve şeker yesem, sensiz onlar canıma zehirdir (agu);","madem canımın tadı sensin, senden daha iyisini (yigrek) nerede bulayım?"],["Yüz bin eziyet (cevr ü cefâ) suretime (bedenime) uğrasa (gelse) bile,","sevincim hiç eksilmez — herkes seni sevmek diler."],["Yunus da aşkın içinde bir zerreyse, ne çıkar —","yer, gök ve felek çarkı (gökyüzü), aşk ateşiyle ayakta durur (var olur)."]],"145":[["Çalap (Allah), Muhammed'in canını nurdan yaratmış;","âleme rahmet saçmış — Muhammed'in adını rahmet kılmış."],["'Dostum' deyip yaratmış, hem onun derdini (kaydını) gözetmiş;","Muhammed'in yönünü, ümmetten yana koymuş (çevirmiş)."],["Muhammed bir denizdir, âlemi tutmuş (kuşatmış);","yetmiş bin peygamber, Muhammed'in gölündedir."],["Dünya malını elde tutmamış, hiç emanet artırmamış (biriktirmemiş);","Muhammed'in elbisesini (tonunu), terzi özenle biçip dikmemiş (sade giyinmiş)."],["Tanrı Arslanı Ali, Muhammed'in sağındadır;","Hasan ile Hüseyin, Muhammed'in solundadır."],["Yılda yetmiş bin hacı, her biri niyet eder;","gider, Muhammed'in nurunu (kabrini) ziyaret eder."],["Yunus Emre'm aşıktır, eksiklidir, miskindir (yoksuldur);","her kim Muhammed'in sofrasından (honundan) yemezse, ondan mahrumdur."]],"146":[["Âşığın nişanı şudur: benzi sararık, gözleri yaşlı;","canı aşk ateşinde yanar; âşığın ciğeri yaralıdır."],["Gece gündüz hayran yürür, aşk ateşinde yanar erir;","âşığın döşeği toprak ve kabir, yastığı taştır."],["Kimse âşığın hâlini bilmez, gönlünde ne olduğunu;","dostun yolunu süpürmek için, âşığın yüzü bir hizmetçidir (ferâş)."],["Âşık kişi miskin (yoksul) olur, gözünün yaşı durmadan akar;","malı mülkü, canı başı — âşığın hepsi aşka feda (tarâş)dır."],["Âşık gece gündüz âh eder; yolunu doğru Hakk'a çevirir;","her an gönül onun gezinti yeridir — âşığın gönlü bir Mi'râc'tır."],["Her kişi, o dosta yakın olmak için bir iş tutar;","gece gündüz, âşık her an nefsiyle savaştadır."],["Yunus der: o (kınanmaktan kaçan) şeyhliği, âşıklığa sat;","âşık iyi ad ne ister — âşığa, kötü ün (bed-nâm) bile hoş gelir."]],"147":[["Ey su, nereden gelirsin; yurdun neresi senin?","Nerede bir çukur bulursan, yatağın orasıdır senin."],["Sen yüceden çıkarsın, alçak yere akarsın;","gönlünü Hakk'a tutarsın — alçakgönüllülüğün var senin."],["Seni bulut götürür, âlemlere ulaştırır;","türlü çiçek bitirir — güzel bir ustan (üstâdın) var senin."],["Ağaçlara varırsın, köklerinden girersin;","en alttan (dun) sıra sıra yürürsün — uzun (her yere uzanan) elin var senin."],["Nerede yaş kuru ne varsa, hiçbiri sensiz olmaz;","ne ölüsün ne diri — hiç bedenin (tenin) yoktur senin."],["Kimin (bir kısmın) denize gider, kimin (bir kısmın) buhar olup tüter;","adını desen ne fark eder — güzel bir pazarın (alışverişin) var senin."],["Akıp deniz olursun, dağılıp toz (buhar) olursun;","göllerde saz (kamış) olursun — yapılan evler senin sayendedir."],["Dünyada canlı cansız her şey, sensiz olamaz;","şüphesiz cana cansın — hiç benzerin (menendin) yok senin."],["Şimdi Yunus susadı, senden içmek diler;","bir yudumun bin altına değer — ama nasılsa senin bir fiyatın (bahân) yok, paha biçilmezsin."]],"148":[["Eğer uluya (yüce gerçeğe) erdiysen, suretin nakşı (dış görünüş) sana ne?","Manaya yol bulduysan, işte bu dünya sana ne?"],["Gerçeği görünce, yolundaki her şeyi (kamusın) bırak; bu dünya davasını (iddiasını) terk et;","bu âlem sevgisini bırak — dünya için acele etmek (aşıklıcak) sana ne?"],["Sen dünyayı terk et; gel, aşk evine gir;","ileriki menzile (durağa) eriş — geri kalmak sana ne?"],["Bu bedenin sermayesi, ateş, su, toprak ve yeldir (dört unsur);","her biri aslına döner — gafil olmak (habersiz kalmak) sana ne?"],["Gece gündüz kaygı yersin (çekersin); 'ne yapayım, yoksulum' dersin;","O (Allah) cömerttir, rızkını verir — kaygı yemek (çekmek) sana ne?"],["Gerçek (arınmış) cana, puthane de meyhane de mescit oldu (her yerde Hak'kı görür);","öyleyse bir pulun bile ziyana gitmez — artık yalancılık (riya) sana ne?"],["Madem ahirete yönelişin sağlam (kavî), bu yalancı davayı (iddiayı) bırak;","bu mal ve hazine sevgisi — âşıksan, sana ne?"],["Ye, yedir, ey çaresiz; eksilirse Tanrı'n verir;","bir gün bedenin (tenin) yere girer — geride kalan mal sana ne?"],["'Benim' deyip mal biriktirirsin, bir yandan hakikat davası güdersin;","Padişah (Allah) suçunda (cezalandırmakta) ısrar etmez, bağışlar — öyleyse yoldan çıkmak (güm-râh olmak) sana ne?"],["Yunus, o aşk kâsesinden (badyasından) sen çok (iñen) sarhoş (esrük) olmuşsun;","kendinden geçmişken (bî-hod iken) Hakk'a erdin — artık ayık olmak sana ne?"]],"149":[["Dervişlerin gönlü huzurdur (safâ); bir uçtan bir uca (Kaf'tan Kaf'a) hüküm sürer;","ey, nice sultanlar, dervişlerin önünde âcizdir (zebûn)."],["Dervişlerin hâlleri yücedir, yolları Hakk'a gider;","dervişlerin Üveys'i (Veysel Karanî), Arş'ta nalını çevirdi."],["Resûl Mi'râc'a yükseldi; o ulu (Peygamber) nazar eyledi (baktı);","görün görün — dervişlerin vasfı (niteliği) ne yücedir."],["Mustafa (Peygamber) Arş'tan döndü; orada saf gönüllüler (ashâb-ı safâ) vardı;","dervişlerin sözlerini, sır sözünü dinledi."],["Resûl, huzura (tapuya) indi; elini kapıya vurdu;","'kimsin?' dediler ona — o, kendini dervişlerin miskini (mütevazı kulu) olarak andı."],["Resûl içeri girdi; yârenler (dostlar) ayağa kalktı;","âşıklar dîdâr (cemâl) gördü — dervişlerin kavuşmasını (visâlini)."],["Resûl der: 'ey Kayyûm (Allah'ım), bunlar acayip (şaşılası) bir topluluk;","dervişlerin gönlünü, bir sır denizi kılmışsın.'"],["Hak buyurur: Bunlara 'benimsiniz' dedim, bunlara 'ben sizinim' dedim;","dervişlerin malını mülkünü, hazinesini onlara unutturdum."],["Dervişlik bir sanattır (meslektir); hırkacığı kaba (mütevazı)dır;","ama dervişlerin elbisesinde (hırkasında), nice canavar (sahtekâr) dolaşır."],["Miskin Yunus ne yapsın, ne zamana dek (niçe bir) açıklasın (şerh etsin)?","O bir âşıktır — bırak kul, dervişlerin vasfını söylesin."]],"150":[["'Dost' derdim — o, benim isteğim, âşıkların dermanıdır;","aşk kadehini (câm-ı ışkı) bırakma — çünkü o, âşıkların ahdidir (peymânıdır)."],["Âşık ol; aşk ateşine pervane gibi yanmaya bak;","ateşte yanan kimseler, işte âşıkların canıdır."],["Her gece âşığın canı, Hakk'ın cemâlini görmeye dolaşır (cevlân eder);","yüce Arş (Arş-ı azîm), vakit vakit âşıkların gezinti yeridir (seyrânıdır)."],["Zahidin (sofunun) zühdüyle, makamı cennet olur;","oysa mâsivânın (Hak'tan gayrı her şeyin) hepsi, âşıklara bir zindandır."],["Sakın, azizim, aşk erine hor bakma;","âşıklar, Mevlâ'larının sırrıyla gizlidir (pinhândır)."],["Kâmil şeyhin (mürşidin) hizmetinden el çekme (fârig olma), ey Yunus;","pirine kulluk etmek, âşıkların erkânıdır (yol esasıdır)."]],"151":[["Kul, padişahsız (Allah'sız) olmaz; padişah da kulsuz değil;","kul 'yol açın!' (yort savul) diye ilan etmese, padişahı kim bilirdi?"],["Sultan daima sultandır, kul daima O'nun kuludur;","O, ezelî (kadîm) bir padişahtı — köklerin (asılların) içinde en kök (asıl)."],["Tanrı ezelîdir (kadîm), kulun hakikati de O'nun ezelî ilminde ezelî; O'ndan bir adım ayrılmadım;","kulun kim, Tanrı'nın kim olduğunu gör (kendini bil de Hakk'ı bil), anla, ey anlayışlı kişi."],["Bize birlik (tevhid) sarayını, doğru müjdenin (beşâret) ayını göster;","ikilik düşüncesinden geç; benliği bırak, ey kul."],["Şimdi gizli seyri (manevî yolculuğu), seyrin içindeki sırrı gör;","kul, bu ilahî tedbiri bilmez — bu iniş (nüzûl, ilham) kime erişti?"],["Söyle söyle hepsini: sen ne sıradan bir maden ocağısın, ne madensin;","sen, manayla dolu bir suretsin — padişahı (Allah'ı) kendinde bul (kendini bilerek O'na er)."],["Gel şimdi perdeni (hicâb) aç; yalancı kendinden ayrıl, gerçek kendine kaç;","Mi'râc'ı kendinde bulasın — bütün yollar sana gelir."],["Nereye gittiysen, ey akıllı — bütün diller, sanki bir ağızdan konuşur;","zincirleme birbirine bağlı cüzlerin (ayrıntıların) haberini, Küllî Akıl (akl-ı kül) verir."],["Yunus, bak neredesin — ne yerde ne göktesin;","edep perdesini gözet; gel şimdi gel, Hak huzurunda saygıyla eğil (tapu kıl)."]],"152":[["Bir zaman, baba belinden anaya düştü gönül (can);","Hak'tan bize izin (destûr) oldu — rahim hazinesine düştü gönül."],["Orada (rahimde) beni can eyledi, et, kemik ve kan eyledi;","kırk gün (dört on) deyince, şekle dönmeye (gelişmeye) düştü gönül."],["Orada gizli (pinhân) dolaşırdım; Hak buyruğu aman vermez;","beni yurdumdan (rahimden) ayırdılar — bu dünyaya düştü gönül (doğdum)."],["Beni beşiğe koydular, elimi ayağımı sardılar (kundakladılar);","daha baştan acısını verdiler — tuz içine düştü gönül (yeni doğanı tuzladılar)."],["Günde iki kez kundağımı çözerler, başıma akçalar (paralar) dizerler;","ağzıma emzik (emcek) verdiler — nefsin avucuna (kabzına) düştü gönül."],["Bu şeyi (beşiği) bıraktım, yürümeye azmettim;","on iki kemiğimi dizerler — elden ele düştü gönül (gezdirildim)."],["Çocukken (oğlanken) bir sultan gibi doğar; kimi elini, kimi yüzünü öper;","akıl bana yoldaş oldu — sultanlığa (kendini bir şey sanmaya) düştü gönül."],["Bu çağla (gençlikte) sakal biter; göreni güldürür (hoşnut eder);","güzellerin yanında yetişir — sevip sevilmeye (sev-sevü) düştü gönül."],["Hayırdan çok şerri sever, onu işlemeye hevesle (becid) koşar;","nefsinin dileğini kovalar — nefsin evine düştü gönül."],["Kırk beşinde suret (görünüş) döner; kara sakala ak iner;","bakıp ağarmasını (şeybetini) görünce — ak kılları yoldurmaya düştü gönül."],["Yola gider, başaramaz; eski yiğitliğe eli varmaz (gücü yetmez);","bu şeyleri bırakıp — yavaş yavaş yitmeye (yavunmaga) düştü gönül."],["Oğlu der 'bunadı, ölmüyor'; kızı der 'yerinden kalkmıyor';","kendi hâlinden hiç haberi yok — hâlden hâle düştü gönül (bunadı)."],["Ölünce şükrederler; onu mezara doğru götürürler;","Allah adını anarlar — çok şükre (şükretmeye) düştü gönül."],["Yıkamak için su getirirler; mezara koymak için kefen sararlar;","tahta ata (tabuta) bindirirler — teneşire düştü gönül."],["Eğer hayırlı amelin varsa, mezarın geniş olacak;","eğer amelin yoksa — ateşten şarap içti gönül (azap çekti)."],["Yunus, hâlini anlayıver; yolun da işte buraya (ölüme) uğrayacak;","burada daha elin yetişirken — hayırlı işlere düşsün gönül (yönelsin)."]],"153":[["Dünya içindeki şu hâl, bana çok (yavlak) acayip geldi:","gece konuk olan kişi, yine sabah hemen (fi'l-hâl) göçer (gider)."],["Eğer gerçek konuksan, gözünü aç — eğer uyanıksan;","sen bu söze tanıksan — mülk ile mal geride kalır."],["Malını başka biri (özge) yer; sen var öbür dünyada hesabını ver;","mezarın ancak bir adımlık yer — gel gör, sonunda bu kısmet (fâl) nedir."],["Gözün görürken ye, yedir; bunca özür (bahane) etme;","bu dünyada kalan hâsıl (kazanç) nedir — hayır işle, alışverişini yap, ver, al."],["Sözün doğrusunu söyleyeyim: işit, unutma, iyice sakın;","işte kıyamet yaklaştı — gönlünden boş hayal geçmesin."],["Sonra İsrafil Sûr'u çalar, ölenler yerinden kalkar;","mizan, terazi kurulur — Zü'l-Celâl (Allah) hükmünü verir."],["Sultan ile kullar bir olur; orada heybet (dehşet) çetin olur;","dahası bambaşka (ayruksı) bir hâl olur — orada kendi başına kurtulmak imkânsız (muhâl)."],["Burada Allah'tan korkmazsan, Yunus, orada seni korkuturlar;","eğer hayatın (dirliğin) doğru (hak) ise, Sırat'ı kolayca (sehel) geçersin."]],"154":[["Dünya bize gerekmez; çünkü kalıcı (bâkî) bir yapı (bünyâd) değil;","bir kul bin yıl yaşasa bile, ölünce geçen ömür bir saat bile değildir."],["Bu dünya, sıkıntı (kahır) evidir; nice ömürleri eritir;","cennet (Uçmak) hakkında caka satan (böbürlenen) kişi — cennet yalan yanlış boş laf (gaybet) ile kazanılmaz."],["Şu senin mümin kulların — dünya, onların zindanıdır;","bu dünyada mümin olan kişi, dünyada sevinçli (hurrem) ve şen (şâd) yaşayan biri değildir."],["Burada zalimlik eden, nefsini haramla doyuran (toylayan) kişiler —","yüzleri kara olarak kalkacak (mahşerde); kendi canları zaten rahat değil."],["Kim erişir O'na — gece gündüz O'na ibadet (tâ'at) eden;","cennet onlara verilir, çünkü onlar O'nun tanışıdır (biliş), yabancı (yâd) değil."],["Yunus, sen miskin bir sarhoşsun (mestânesin); kendine bak, bırak başkalarını;","dünyada riyalı (ikiyüzlü) bir hayat, kişiye iyi bir ad (ün) değildir."]],"155":[["Bırak bu dünyanın süsünü (bezeğini); bu dünya, yeldir (rüzgârdır), hayaldir;","bize ne vefa gösterecek — çünkü yok oluş (zevâl) pusuda bekler."],["Fâni ömre inanma; çünkü onun sevgisi kalıcı (bâkî) değil;","sen bakarken sultanlar bile, mülkü malı bırakıp giderler."],["İzzetin (benlik gururunun) başını kes, at; sen boş şeyleri (fuzûllığı) terk et;","onun (gururun) başını kesmezsen, aşkla yaşaman (dirliğin) imkânsız (muhâl)."],["Bunca uzun kaygılar (endîşeler), bizim yoldaşımızdı;","dost düşüncesinden fazlası, bilin ki, baştan başa boş laftır (kıyl u kâl)."],["Kendi hesabını, kendi elinle şimdiden gör (al);","yoksa mahşerde görevlilerin (serhenglerin) elinde, hâl çok (katı) kötü olur."],["Zevk ve riya dedikleri şeyin boynunu vurmadıkça (yok etmedikçe) ben,","Cömert Şah'a (Allah'a) sıdk (içtenlik) ile nasıl (kanda) kavuşma (visâl) bulabilirim?"],["Nefsinin dileğini öldür, onu teneşir tahtasına ilet (koy);","yoksa habersiz (gensüz) ölünce, gassâl (ölü yıkayıcı) sana ferman olur (seni dilediğince çevirir)."],["Her kim sana 'Hakk'a itikadın (inancın) nedir?' diye sorarsa,","tevazuyla onun ayağını öp — o soruya cevap işte budur."],["Yunus, bu doğru yol (Sırât-ı müstakîm) sana farzdır;","önünde, haşir ve neşirde (mahşerde), yaşayarak (Hakke'l-yakîn) erişilen kavuşma (visâl) gerek."]],"156":[["Dervişlik makamı, hâl içinde hâldir (iç içe manevî hâllerdir);","yoldan vazgeçme (ferâgat) makamı, derviş olana imkânsızdır (o asla bırakamaz)."],["Derviş, ilk andan (evvelki demden, ezelden) ayrılamaz;","hiç ayrılık (fürkat) olmadı — onun nasibi kavuşmadır (visâl)."],["Derviş, fitne kabını (fesat kabını) burada kırdı (uşattı);","burada harekete geçti — boş, aylak (battâl) durmadı."],["Dervişin yaşayışı (dirliği), Sırat üzerindedir (titizdir);","hesabını, zerre ağırlığına (zerre-i miskâl) kadar gördüler."],["Derviş 'Ene'l-Hak' (Ben Hakk'ım) dese, ne olur, şaşılır mı?","Her hâlükârda, bütün varlık zaten Hakk'ındır — kendinden geçmiş derviş bunu söyler."],["Derviş, gözünü ilk andan (evvelki demden, ezelden) ayırma;","Yunus, hem Âhir'i (sonu) hem Evvel'i (ilki) görmektedir."]],"157":[["Aşksızlara öğüt verme; senin öğüdünden almaz;","aşksız insan hayvanlaşır — hayvan da öğüt bilmez."],["Ehil (layık) olanlardan eksik olmayın (ayrılmayın); cahillerden kaçın;","Tanrı, cimrilerden (bahillerden) bizardır — cimri, dîdârı (Allah'ın cemâlini) görmez."],["Kara taşa su koysan, elli yıl ıslatsan,","taş yine eskisi gibidir — marifetli (hünerli) taş olmaz."],["Gerçek taştan türlü sular çıkar, dibinden neler biter;","cahilin gönlü taştan beterdir — cahil yola gelmez, hiç gelmez."],["Boz çaylak (yapalak), bir tür çaylak (devlingeç) için sabah akşam emek harcama;","onun işi küçük av (fare/böcek) tutmaktır — salsan, ördek avlayamaz."],["Şah balaban, şahin, doğan (avcı kuşlar) — onları öven, ne güzel övmüş;","doğan zayıf düşse bile, doğanlığından (asaletinden) geri kalmaz."],["O iki cihanın güneşi (Peygamber/eren), görünen (zâhir) dünyasını değiştirdi (göçtü);","cahil onu öldü sanır — oysa o hakikatte ölmez, hiç ölmez."],["Yunus, cahillerden olma; ehillerden (layık olanlardan) uzak olma;","cahil, mümin bile olsa ne çıkar — cahillikten kurtulmaz (geri kalmaz)."]],"158":[["Mana eri, bu yolda mahzun (melûl) olmaz;","manayı duyan (sezen) gönüller, asla ölmez."],["Beden (ten) fânidir, can ölmez; gidince can geri gelmez;","ölürse beden ölür — canlar ölmez."],["Cevhersiz (öz/kabiliyetsiz) gönüllere yüz bin söz söylesen,","Hak'tan nasip olmamışsa, o söz onlara nasip olmaz."],["Yârin (dostun) gönlünü gözet (sakın); o camdır, kırmayasın;","cam kırıldıktan sonra, bir daha bütün (sağlam) olmaz."],["Çeşmelerden bardağını doldurmadan bırakırsan,","orada bin yıl dursa bile, kendi kendine dolmaz."],["Şu Hızır ile İlyas, Âb-ı Hayât (ölümsüzlük suyu) içtiler;","bu birkaç yıl içinde, bunlar ölmez."],["Hak, dünyayı Peygamber'in dostluğu (hürmetine) için yarattı;","dünyaya gelen gider — hiçbiri kalıcı (bâkî) kalmaz."],["Yunus, gözün görürken azığını (yaragunu) hazırlayıver;","oraya öbür dünyaya varan geri gelmedi — hiçbiri geri gelmez."]],"159":[["Ey gafil, gözünü aç; gönlünü (hevesini) pek (yavlak) uzatma;","kendi yaşayışına (dirliğine) bak; kimsenin ayıbını gözetme (arama)."],["Öyle güzel huyla yaşa ki, ölünce ardından iyi konuşsunlar;","kalıcı hayat (bâkî dirlik) budur, canım — kötü adla (yavuz ad) gitme."],["Bir gün olur, bu dünyayı ahiretle değişirsin;","gece gündüz ibadet (tâ'at) et; ayağını uzatıp rahatça yatma."],["Bir derviş geldiğini görürsen, onun ayağına (kademine) yüz sür;","senden Allah için bir şey isteyince, kaşını gözünü çatma (somurtma)."],["Nefse uyup beş parmağını birden ağzına götürme (her şeyi kendine yeme);","birini kes (ayır), miskine (yoksula) ver — ahirette gerek olur, unutma."],["Söylediğin sözü, işittiğin gibi söyle;","kendinden akıllılık taslayıp (zîreklenip), birkaç söz daha katma (ekleme)."],["Dünya yağlı (çerb) ve tatlıdır (şîrîn); haklı insan ondan yemeli;","ama değersiz (kem) bir şeye tamah edip, kesip kemirip yutma (haram yeme)."],["Yunus, seni kim öldürür — canı veren, yine canı alır;","yarın mahşerde sen O'nu göresin — erin (ermişin) nazarından (gözetiminden) ayrılma."]],"160":[["Yoldaş olalım ikimiz;","gel, dosta gidelim, gönül;","dert ortağı (hâldaş) olalım ikimiz;","gel, dosta gidelim, gönül."],["Gel gidelim, can durmadan (çıkmadan);","sureti (bedeni) bırakmadan;","araya düşman girmeden;","gel, dosta gidelim, gönül."],["Gel gidelim, uzak kalma;","dost için azık (yarak) hazırlayalım;","durak (varılacak yer), şeyhimin katındadır;","gel, dosta gidelim, gönül."],["İli, şehri (şârı) terk edelim;","dost için inleyelim (zâr edelim);","yâri ele getirelim (kavuşalım);","gel, dosta gidelim, gönül."],["Bu dünyaya kalmayalım;","o fânidir, aldanmayalım;","bir iken ayrılmayalım;","gel, dosta gidelim, gönül."],["Biz bu cihandan göçelim;","o dostun iline uçalım;","arzu ve hevadan (nefsanî istekten) geçelim;","gel, dosta gidelim, gönül."],["Sen bana kılavuz ol;","dosttan yana yönelelim;","öne arkaya bakmayalım;","gel, dosta gidelim, gönül."],["Bu dünya kalıcı (pâyidâr) olmaz;","gözünü aç, canını uyar;","bana yoldaş ve yâr ol;","gel, dosta gidelim, gönül."],["Ölüm haberi gelmeden;","ecel yakamızı almadan;","Azrail hamle kılmadan (üstümüze gelmeden);","gel, dosta gidelim, gönül."],["Gerçek erene (ermişe) varalım;","Hakk'ın haberini soralım;","Yunus Emre'yi yanımıza alalım;","gel, dosta gidelim, gönül."]],"161":[["Ne olur, bundan böyle yola gelsen, fesadı (bozgunculuğu) terk etsen, gönül;","kâh günahına ağlasan, kâh kanaat etsen, gönül."],["İşin gücün fesat (bozgunculuk); beni hırs ateşiyle yaktın;","bir kerede yâri (dosta) iletsen, kendini yanan ateşe (aşk ateşine) atsan, gönül."],["Ne zamana dek ben sana uyayım, kendimi belaya atayım?","Ne olur, sen de gelsen (uysan), benim öğüdümü tutsan, gönül."],["Dünya, halkın düşmanıdır; asıl maksat, canların canı olan O'dur (Allah'tır);","bilin ki dünya fânidir — dünyayı terk etsen, gönül."],["Miskin Yunus, canına yapışıp kalmaz; canını kurban verir;","gelsen, Sübhân'a (Allah'a) sığınsan, doğru yola gitsen, gönül."]],"162":[["Dervişlik dedikleri, hırka ile taç giymek değildir;","gönlünü derviş eyleyen, hırkaya muhtaç değildir."],["Hırkanın ne suçu var, sen yoluna gereğince gitmezsen?","Yoluna git, yürü; erin (ermişin) yolu, gevezelerin (sahtekârların) yolu değildir."],["'Şeyhim aşkla yalın ayak, başı açık gezer' dersin;","oysa er, gerçek bir hayat kurmuştur — yalın ayak olmak, gerçek derviş olmak değildir."],["Yunus Emre'm, erene (ermişe) durmuş marifet (irfan) söyler;","yol eriyle (yol ehliyle) yoldadır — yolsuza (yoldan çıkmışa) yoldaş değildir."]],"163":[["Senin 'ben (benim)' demen, mana âleminde yöntem (usûl) değildir;","bir kapının (Allah'ın) kullarına şaşı (yan) bakmak, doğru yol değildir."],["Sen kendine yarar (faydalı olur)san, bu sözden anlam sezersen —","nereye bakarsan bak, 'bu O değil' deme (her şeyde O'nun izi var)."],["Yetmiş iki milletin (bütün insanlığın) sevgilisi (ma'şûku) da O'dur;","âşığı, sevgilisinden ayırmak, hayra yormak (doğru iş) değildir."],["Küfrünü (inkârını) atarken, sakın imanını da vurma (yıkma);","hırs, bizimle içimizde olan düşmandır — tanıdık (içeriden)dir, yabancı (el) değil."],["İşte bu sözden bir haber, kısacık (muhtasar)dır;","kendine bir er (mürşid) seç — kıtlıktan ötürü, gerçek erler bol değildir."],["Ey paşa, bu kuş dilidir (gizli/sembolik dildir); bunu ancak Süleyman bilir;","sana derim, ey hoca: bu dil, boş (anlamsız) bir dil değildir."],["Sağa sola bakmadan, Tapduk'un Yunus'u güzel söyler;","o gerçeğe (Hakk'a) âşık olanlar, baştan başa sağdır (doğrudur) — sol (eğri) değil."]],"164":[["Müşkülü (zor meseleyi) halletmek, herkesin işi değildir;","gönlünü bir kişiye (mürşide) ver — bu yolda dış (taş/zahir) yeterli değildir."],["Bu sözün manası, evliyanın sofrasıdır (ziyafetidir);","cahile yedirme — bizim şekerimiz, ona göre aş (sıradan yemek) değildir."],["Evliyanın gönlünden, Allah için istemeyi (şey'lillâh) kesme;","sana himmet (manevî yardım) eden, göz kaş (dış görünüş) ile yardım eden değildir."],["Er (gerçek mürşid) odur ki, varılacak yeri (menzili) her an gösterip dursun;","her arif (irfan ehli) bu rüyayı (düşi) yoramaz — bu herkesin işi değildir."],["Keşke burada bir yâr (dost) bulasın, canını ona feda kılasın;","inkârla gelenler, erin (ermişin) yoldaşı değildir."],["Hak gönülde tecelli etsin (görünsün), can aslını (kaynağını) bulsun diye —","gönülden mâsivâyı (Hak'tan gayrı her şeyi) sür; asıl bakış, dışa (taşa) değildir."],["Biz o aşk şarabını (bâdesini), o dostun elinden içtik;","bize o kadehi sunan, dünya dervişi değildir."],["Yunus bir doğan (avcı kuş) idi; Tapduk'un koluna kondu;","ava, şikâre (av peşine) geldi — bu sıradan bir yuva kuşu değildir."]],"165":[["Canlar, senin yoluna fedadır; bu canın kaygısı (derdi) yok;","bana, canım olan sen gereksin — cihanın kaygısı yok."],["Canlar içinde canım — sensin benim gizli hazinem (genc-i pinhân);","madem seni apaçık (ıyân) gördüm, artık gizlilik kaygısı yok."],["Canlar içinde cansın; sen bir Âb-ı Hayât (ölümsüzlük suyu)sın;","bize din ve imansın — artık iman kaygısı yok."],["Yaramı yudum, sildim; yaramın kimde dermanı olduğunu bildim;","benim derdim (kaygım) yârimdir — yaramın kaygısı değil."],["Aşkın beni faş etti (açığa çıkardı); 'saklayayım' derdim, ama —","madem seni apaçık (ıyân) gördüm, artık gizleme kaygısı yok."],["Bana derman olur mu — benim derdime kim derman olur?","Dertli olduğum hâlde sana varayım — derman kaygısı yok."],["Gelin âşık olalım, aşkta dolaşalım (cevlân kılalım);","ben sarhoş olup yatmışım — artık dolaşma (cevlân) kaygısı yok."],["Aşkının okunun temreni (demir ucu), yüreğime dokunur (saplanır);","aşk için ben öleyim — artık temren (ok ucu) kaygısı yok."],["Canı ve gönlü ne yaptım — aşkın ateşine attım;","sıdkı (doğruluğu hesaplamayı) bile unuttum — artık şüphe (gümân) kaygısı yok."],["Aşkın burcundan uçtum; dolaşıp (cevlân urup) geçtim;","ben dostla buluştum — artık dolaşma kaygısı yok."],["Denize, ummana daldım; orada sedef (inci kabuğu) buldum;","cevher (inci) alıp geldim — artık umman kaygısı yok."],["Durduğum yer Tûr (dağı) olsun, baktığım dîdâr (Allah'ın cemâli) olsun;","bana Musa('nın aracılığı) ne hacet — bende 'sen-ben' (ikilik) kaygısı yok."],["Yunus'a öğüt verirler: 'kalk, kervan göçtü' derler;","oysa ben menzile (varılacak yere) eriştim — artık kervan kaygısı yok."]],"166":[["Bir kez bir gönül yıktıysan, bu kıldığın namaz gerçek namaz değildir;","yetmiş iki millet (bütün insanlık) bir araya gelse, elini yüzünü o günahtan yıkayıp temizleyemez."],["Erenler gelip geçtiler; dünyayı bırakıp göçtüler;","havaya yükselip uçtular — bunlar hümâ (devlet kuşu)dur, kaz değil."],["Can odur ki Hakk'a erişir; ayak odur ki yola girer;","er (gerçek kişi) odur ki alçakta (mütevazı) durur — yüksekten bakan göz değildir."],["İnkârcıyı ve boş iddiacıyı (softayı), seni hiçe sayanı adam yerine koyma;","her kim gerçek âşık değilse, git bunları ahıra bağla (hayvan gibi gör)."],["Doğru yola gittiysen, erin (ermişin) eteğini tuttuysan,","bir hayır da işlediysen — onu bine katla (Allah çoğaltır), az değildir."],["Yunus bu sözleri öyle dizer ki, sanki bala yağ katar;","halka mallarını (metâ'ını) satar — yükü cevherdir (mücevherdir), tuz değil."]],"167":[["Kimseyi boş (değersiz) görme; hiç kimse boş değildir;","insanlara eksiklik gözüyle bakmak, erenlere (ermişlere) hoş gelmez."],["Gönlünü derviş eyle; dostla tanış (biliş) ol;","aşk eri, şu manada gerçek derviştir — dervişin içi boş değildir."],["Dervişi ancak derviş bilir — Hak yoluna durmuş olanı;","dervişler hümâ kuşudur — çaylak ve baykuş değildir."],["Dervişliğin aslı, candan ve iki cihandan geçmektir;","o, sultandan (Allah'tan) haber verir — bellidir, yabancı (yad) bir kuş değildir."],["Ey Yunus, Hakk'ı bilen, asla yalan söylemez;","ikilikle gelen, doğru yolu bulmuş değildir."]],"168":[["Ey dostlar, ey kardeşler, sorun bana — nerede idim?","Dinlerseniz söyleyivereyim: ezelî yurttaydım (ezelde, Hakk'ın katındaydım)."],["Ezelden beri dilimde şu var: Tanrı birdir, Resûl haktır;","âlem bunu böyle bilmezken, ben acayip bir makamdaydım (ezel makamında)."],["'Kalû belâ' (elest meclisindeki 'evet') söylenmeden, düzen kurulmadan,","Hak'tan ayrı değildim — o ulu divandaydım (Hakk'ın huzurundaydım)."],["Yere temel (bünyâd) atılmadan, Âdem dünyaya gelmeden,","efsanedeki öküz ve balık yaratılmadan — ben ezelde oradaydım."],["Eyyûb ile derde esir olup inledim, ceza (çile) çektim;","Belkîs ile taht üzerinde, Süleyman'ın mühründeydim."],["Yûnus (Peygamber) ile balık beni içine çekti — 'yuttu da' deme;","Zekeriyyâ ile kaçtım; Nûh ile tufandaydım."],["Asâ ile, Musa ile kaçıp Tûr Dağı'na çıktım;","İbrahim ile, Mekke'ye (Kâbe'ye) temel atmaktaydım."],["İsmail'e bıçak çaldım, bıçak ona kâr etmedi (kesmedi);","Hak beni âzâd etti — koçla (gönderilen kurbanla) kurbandaydım."],["Yûsuf ile kuyuda yattım, onunla çile çektim;","Ya'kûb ile çok ağladım — Yûsuf bulununcaya dek figandaydım."],["Mi'râc gecesi, Ahmed'in (Peygamber'in) nalınını Arş'ta çevirdim;","Üveys ile taç giydim, Mansûr ile urganın (darağacının) ucundaydım."],["Ali ile kılıç vurdum, Ömer ile adalet ettim;","on sekiz yıl Kaf Dağı'nda, Hamza ile meydandaydım (savaş alanındaydım)."],["Yunus, senin âşık canın, ezelî âşıklarla birlikte","o Allah'ın dergâhında, seyran edip dolaşmaktaydı (cevlân)."]],"169":[["Ey dostlar, ey kardeşler, sorun bana — nerede idim?","Aşk denizine dalarak, ummanlar denizindeydim."],["Yere temel atılmadan, yer gök meleklerle dolmadan,","Levh ile Kalem yaratılmadan — Yaratan'ın mülkündeydim."],["Beni gözeten O'ydu; her nerede olsam saklardı;","aşk urganının ucundaki kandilde, o canda (ilk nurda) idim."],["Kaygının eli erişmezdi, tasanın gözü görmezdi;","kaygı (endîşe) şehrinin dışında, ulu bir mekândaydım."],["Bu işlerle uğraşan kişi, bütün karışıklığı (teşvîşi) bıraksın;","için içinde, çok ince, güzel ve gizli (latîf nihân) bir yerdeydim."],["Benim gibi bu cihana yüz bin kişi gelse, yine az olur;","benim bu dünyaya gelişim şimdidir — önce üstadın yanında Kur'an'daydım."],["Dört kitap okunmadan, ayırıp seçmek olmadan,","dersimi (sebak) ezberledim — bu aşkı okuyan (hânende) idim."],["Padişahtan (Allah'tan) izin (destûr) oldu, bizi buraya (dünyaya) saldı;","iki cihan cennet (Uçmak) oldu — cennette Rıdvân'ın (cennet meleğinin) yanındaydım."],["Bunca zaman gökte yıldızdım; gökteki melekler bana özlem duyardı;","âlemin Cebbâr'ı (Allah) hüküm verir — ben o zaman oradaydım."],["Doksan bin Hak kelâmı, Habîb (Peygamber) ile konuşulunca,","otuz bini sır olunca — ben o sır olduğunda oradaydım."],["Bu suretten (bedenden) önce, adım Yunus değilken,","fenâda ben O idim, O bendi (ikilik kalkmıştı); bu aşkı sunanın katındaydım (aşkın kaynağındaydım)."]],"170":[["Madem Hakk'ı kendi içimde (gönlümde) buldum, şüphe (şekk) ve zan (gümân) bana ne?","O dostun yüzünü görmeyeceksem, bu gözlerim bana ne (neye yarar)?"],["Gelsin münâcât (yalvarış) eyleyen, doksan bin hâcât (dilek) söyleyen;","dışarıdan zahirî ibadet eden, görsün — dost bana ne(dir, ne yakındır)?"],["Musa olup Tûr'a çıkayım, nur olup gözden bakayım,","söz olup dilden çıkayım — artık şenlik borusu ve nağmeler (sûr u nagam) bana ne?"],["Musa varır Tûr'a çıkar, orada varır nura bakar;","oysa benim bu gözlerim, dosttan başka zerre kadar bir şey görmez."],["İşte ben kendimi dağınıklıktan topladım (cem' eyledim), o dosta iman eyledim;","O'nun birliği için namaza durdum (kâmet) — riyalı (ikiyüzlü) ibadet bana ne?"],["O dost bana 'ümmî' (okumamış) demiş, hem adımı Yunus koymuş;","dilim şeker, gövdem kamış gibi tatlı söz verir — peki bende bu söyleyen nedir (kimdir)?"],["Ümmî benim, Yunus benim; dokuz atam (dokuz felek), dört anam (dört unsur)dır;","aşk ateşine düşüp yanayım — artık çarşı pazar (sûk u bâzâr) bana ne?"]],"171":[["Ben buraya garip (yabancı) geldim; bu ilden (dünyadan) bezdim;","bu tutsaklık tuzağını koparmanın vakti geldi — koparırım."],["Bu aşk kitabını okudum, öğrendim (tahsil kıldım);","bana gerek (hâcet) yok — kendim aka (beyaza) kara (yazı) yazarım."],["Dört kitabın manası, bir elifte (Allah'ın birliğinde) tamamdır;","bana 'bâ' (ikinci harfi, ikiliği) söyletmeyin — 'bâ' dersem yoldan şaşarım."],["Bir elifi (birliği) öğrenen, âlemden arınmıştır (münezzeh);","kaygı ikliminde (diyarında), ben niçin durup gezeyim?"],["Yetmiş iki millete suçum şudur: 'Hak' dedim (gerçeği söyledim);","korku, hainliğedir (hainlere yakışır) — ya ben niçin utanıp telaşlanayım?"],["Bir çeşmeden akan su, hem acı hem tatlı olmaz (gerçek kaynak tertemizdir);","bana yakışan edeptir (ölçülü olmaktır) — ben de tek bir lüleden (musluktan) sızarım."],["Şeriat çocukları (zahir yolunun yeni başlayanları), bana nasıl yol göstersin —","ben hakikat denizinde dalgıç kuş (bahrî) oldum, orada yüzerim."],["Madem ben buraya geldim, O'nu burada (kendimde) buldum;","ben aşk uğruna Mansûr'um, darağacına geldim — kül olup rüzgârda savrulurum."],["Karanlık geceler olsa, yollar hiç seçilmese,","kılavuzum gerçek er (ermiş) olsa — ben niçin yolumu şaşırayım?"],["Dost 'bana gelsin' demiş, benim derdimi (kaydımı) çekmiş;","işte bu yüzümün karasını (kusurumu), bereketli (teberrük) armağanlar gibi sunarım."],["Dost Hazret'e (huzuruna) el bağlayıp hizmete varınca,","benden amel (ibadet) sorarsa — bu kendi amelimden utanırım (övünecek bir şeyim yok)."],["Yunus, bu kuş dilidir (gizli/sembolik dildir); bunu Süleyman bilir;","bu yolda gerçek erenin (ermişin) ne dediğini ben sezerim."]],"172":[["Ben bu cihana gelmeden, cihanın sultanının (Allah'ın) yanındaydım;","sözü gerçek, hükmü geçerli — o sultanın hükmündeydim."],["Yaratıklar buraya gelmeden, gökler meleklerle dolmadan,","bu mülke temel atılmadan — Yaratan'ın mülkündeydim."],["Yüz yirmi dört bin seçkini (peygamberi), dört yüz kırk dört derecesiyle —","o gün saadet (devlet) makamında, ulu hanedandaydım."],["Tasa beni görmezdi, kaygının eli erişmezdi;","kaygı (endîşe) şehrinin dışında, yüce bir mekândaydım."],["Yunus, bütün bu varlık, dostun (Allah'ın) katında bir zerre bile değil;","ben söz ve kelâmda idim — hem burada hem oradaydım."]],"173":[["İşte yine geldim buraya — sır sözünü apaçık (ıyân) edeyim;","bir sözle yeri göğü, hepsini hayran edeyim."],["Dilersem onu beden eyleyeyim, dilersem can eyleyeyim;","gönlümü Tûr (dağı), canımı Musa, aşkı Süleyman eyleyeyim."],["Hayat bana karşı gelse, ben hayatın boynunu vururum;","ölüm eğer gerekli (vâcib) olursa, canımı kurban eyleyeyim."],["İsa, Meryem'e (anasına) varır gibi, ben de o Hakk'a (aslıma) varayım;","o Hakk'ın lütuf (fazl) yolunda, âlemi güldüreyim (handân edeyim)."],["Azrail kim oluyor ki canıma kastedebilsin —","ben onun kastını (niyetini), yine kendisine zindan eyleyeyim (aşk canı ölmez)."],["Cebrâil kim oluyor ki benim âhıma (figânıma) hükmedebilsin —","yüz bin Cebrâil gibisini, bir anda uçururum (perrân eylerim)."],["Bizden önce gelenler, manayı gizli (pinhân) tuttular;","ben, anadan doğmuş gibi (saf/açık) geldim — onu çıplak (apaçık) edeyim."],["Yunus, senin gönül evin, Hak'kın varlığıyla (tecellisiyle) dopdoludur;","işte geldim ki, âşıklara o varlıktan (bolluktan) ihsan (bağış) eyleyeyim."]],"174":[["Bütün âlemi terk etsem de, ben dostu terk edemem;","O'ndan ayrı yarım saat bile, ben O'nsuz duramam."],["O'ndan ayrı yaşamam, benim için gerçek hayat değildir;","ezelî (kadîm) olan O'dur, beni görür — ben ise ölüyüm gibiyim, göremem."],["Huri gelip 'gönlünü bana ver' dese,","dosttan başka kimseye, ben gönlümü veremem."],["Bu ömrüm 'dost' diye geçti, ama dostun kulluğunu başaramadım;","bırakayım, O beni başarsın (kemâle erdirsin) — ben hiçbir işi kendim başaramam."],["Fenâda büsbütün O oldum, kardeş (ahî); benden bana bir şey umulmaz (kendimden geçtim);","ama ben O isem, öyleyse O nerede? — ben bu sırra tam eremem."],["Dostlar bana öğüt verir: 'O'nun yakınından uzaklaş git';","oysa ben daha da yakın varayım — O'ndan ayrı gidemem."],["Kimileri Yunus'a 'sabret, bugün(le) yarın(la)' der;","oysa ben bugünümü (şimdi) çabalayayım — bugünümü yarına ulaştıramam (erteleyemem)."]],"175":[["Ben acayip bir hâl ile geldim; kimse hâlimi bilmez;","ben söylerim, ben dinlerim — kimse dilimi bilmez."],["Benim dilim kuş dilidir; benim ilim, dostun ilidir;","ben bülbülüm, dost benim gülümdür — bilin, benim gülüm solmaz."],["O dost 'bana gelsin' demiş, 'kadeh sundum, alsın' demiş;","kadehi aldım, şarabı içtim — artık benim gönlüm ölmez."],["Ne durağım var, ne duracak yerim; hiçbir yerde kararım yok;","Hakk'a münâcât etmek (yalvarmak) için, belli (sabit) bir yerim olmaz — O her yerde."],["Durduğum yeri bana sor; gelirsen sana gösteririm;","benim gözüm, Hak'tan zerre kadar ayrı (başka) bir şey görmez."],["Tûr Dağı'ndaki bir tecelli (ilahî görünme), Musa'ya neler yaptı, gör;","Yunus der: Hak katında benim sözüm geride kalmaz (reddedilmez)."]],"176":[["Ne zaman ki kendimi bildim (tanıdım), kesin bil ki Hakk'ı buldum;","korkum, O'nu buluncaya kadarmış — şimdi korkudan kurtuldum."],["Hiçbir başka şeyden korkmam, bir zerre bile kaygılanmam;","ben şimdi kimden korkayım — korktuğumla (Hak'la) yâr (dost) oldum."],["Azrail canıma gelmez, kabir sorgucusu mezarıma gelmez;","bunlar benden ne soracak — o sorguyu sorduran ben oldum (Hak'la birim)."],["Ya ben kim oluyorum ki O'nun buyruğunu buyurayım —","O geldi, gönlüme doldu; ben O'na bir dükkân (kap) oldum."],["Dükkânın sahibi (ıssı), dükkânından, evinden uzak (hâli) değildir;","O bu eve (gönlüme) geleli, ben bu halka bir maden (kân) oldum."],["Canlılar (gönlü diri olanlar) benden el alır (bana bağlanır); cansızlar (gönlü ölüler), eri ne bilsin?","Hem verirler hem alırlar — ben bir ulu divan (meclis) oldum."],["Yunus Hakk'a saygıyla yöneldi (tapu kıldı), Hak Yunus'a kapı açtı;","kalıcı saadet (bâkî devlet) benimmiş — ben kul iken sultan oldum."]],"177":[["Âşıklara haber verin: aşka gönül veren benim;","aşka kim paha biçebilir — aşkın madenini bulan benim."],["Yer gök, bu aşkla doludur; aşksız hiçbir şey yoktur;","aşkın dalgıç kuşu (bahrîsi) olup, denizlere dalan benim."],["Deniz yüzünden su alıp, suyu göklere veririm;","bulut gibi dolaşıp (seyran edip), Arş'a yakın varan benim."],["Yıldırım olup çakan, gökte meleklere değen (tokuyan);","bulutlara hükmedip, yağmur olup yağan benim."],["Gökteki melekleri gördüm — her biri bir coşku (cünbiş) içindedir;","her biri Hak Çalap'ın (Allah'ın) zikrini eder — o ilahî sözü taşıyan İncil de Kur'an da benim."],["'Gördüm' diyen, gerçek gören değil; 'bildim' diyen, gerçek bilen değil;","gerçek bilen O'dur, gösteren O'dur — ben yalnızca aşka esir olanım."],["Sekiz cennet (Uçmak), âşıklara — onlara köşk ve saraydır;","Musa gibi hayran olup, Tûr Dağı'nda kalan benim."],["Kalem (kader kalemi) çalınınca (yürüyünce), gör; bil ki haber böyledir;","'Kalû belâ' (elest) sözünden, burada haber veren benim."],["Deli oldum, adım Yunus; aşk bana kılavuz oldu;","Hazret'e (Allah'ın huzuruna) dek, yalnız başına yüz süre süre varan benim."]],"178":[["Ezelden bu aşkı, ben bu mülke (âleme) sürüp geldim;","orada şüphesiz Bir(le bir) idim — işte yine Bir'e (Allah'ın birliğine) geldim."],["O Bir'in (Allah'ın) nuru bana, erin (mürşidin) yüzünden göründü;","can gözüyle o nuru, ben burada aramaya geldim."],["O nuru göreli, kendimi unuttum;","sanırsın ben Musa('yım) — sanki dileğim için Tûr'a geldim."],["Münâcât Tûr'u, benim için durduğum her yerde olur (her yer Sina'mdır);","bugün ben Bâyezîd('im) — işte o gizli sırra (fenâ hâline) erdim."],["Ezel benim ilimdir, Elest (elest meclisi) benim yolumdur;","ezel ile Elest'i, ben burada görmeye geldim."],["Ben ezelden beri vardım, sevgiliyle (ma'şûkla) yâr (dost) idim;","Hak beni gönderdi — âlemi görmeye geldim."],["Gökten yere yağdım, yerden göğe çok yükseldim;","Âdem'in elbisesine (insan suretine) büründüm — devrânımı (dönüşümü) sürerek geldim."],["Et ve deriye büründüm; geldim, size göründüm;","adımı 'âdem (insan)' koydum — sonra bu surette zuhûra (görünüşe) geldim."],["Aşk canımı sarhoş etti — işte bana 'Ene'l-Hak' (Ben Hakk'ım) dedirtir;","korku gönlümden gitti — aşk uğruna Mansûr'um, darağacına geldim. Bu söz, benlikten geçmiş fenâ hâlinde söylenir."],["Aşktan dertli olana, benim dermanım vardır;","aşk hastası (sayrusı) olanı yoklamak erkândır (yol gereğidir) — onu sormaya geldim."],["Mecnun'un kadehini aldım, Leylâ'nın gönlüne daldım;","madem Hakk'ı apaçık (ıyân) bildim, oradan asıl sınıra (eşiğe) geldim."],["Bil ki bundan ötesi, Padişah'ın (Allah'ın) iklimidir (ülkesidir);","dört yanım dîdâr (Allah'ın cemâli) oldu — gör, ne güzel (hûb) yere geldim."],["Bana bu aşk dolalı, adım Yunus olalı,","Padişah (Allah) apaçık (ıyân) oldu — ben O'na kulum, şükrane (şükür için) geldim."]],"179":[["Benim burada kararım (kalışım) yok; ben buraya gitmek için geldim;","tüccarım, malım çok — alana satmaya geldim."],["Ben kavga (dava) için gelmedim; benim işim sevgi içindir;","dostun evi gönüllerdir — gönüller yapmaya (onarmaya) geldim."],["Deliliğim, dostun sarhoşluğudur; ne olduğumu ancak âşıklar bilir;","ikiliğimi değiştirip, birliğe ulaşmaya geldim."],["O benim efendimdir, ben O'nun kuluyum; dostun bahçesinin bülbülüyüm;","o efendimin bahçesinde, sevinçle (şâd olup) ötmeye geldim."],["Burada dostla tanışmayan canlar, orada (ahirette) tanışamaz;","burada dostla tanışıp, hâlimi arz etmeye (sunmaya) geldim."],["Yunus Emre âşık olmuş, sevgilinin (ma'şûkun) derdinden ölmüş;","gerçek erin (ermişin) kapısında, hâlimi arz etmeye geldim."]],"180":[["Ne dersem hükmüm yürür; elimde ferman tutarım;","ne dersem hükmüm geçerlidir — çünkü sultanın (Allah'ın) hükmünü tutarım."],["İnsan ile bu cin, peri ve devler, benim hükmümdedir;","tahtımı yel (rüzgâr) taşır — Süleyman'ın mührünü tutarım (Süleyman gibi manevî saltanatım var)."],["İblis ile Âdem kim oluyor — kim kendi başına azdırabilir ya da azabilir?","Bunun hepsini, iyiyi kötüyü — hepsini O'ndan (O'nun takdirinden) bilirim (tutarım)."],["Dünya benim mülkümdür, halkı benim halkımdır;","her an benim yargım (hükmüm) yürür — yargımı güler yüzle (handân) tutarım."],["Senin gibi bir can (sevgili) varken, hâlâ Âb-ı Hayât (ölümsüzlük suyu) arayanı,","karanlığa (zulümat ülkesine) gireni — ben onu hayvan (akılsız) sayarım."],["O'nsuz olursam ölürüm, O'nunla diri olurum;","siz sanmayın ki ben hayatı, daima kendi canımdan alırım — o, O'ndandır."],["Dinim, imanım O'dur; eğer dünyada O'nsuz olsaydım,","ne puta haça taparım, ne kuru din ve iman tutarım — benim dinim baştan başa O'dur."],["Yunus der: hiç şüphe yok — fenâda O bendir, ben de O'nunum;","ben ne dersem dost tutar (kabul eder), dostun dediğini de ben tutarım. Bu, iradelerin fenâda birleşmesidir."]],"181":[["Canım, ben oradan (ezelden) buraya, ezelî bir âşık olarak geldim;","aşkı kılavuz tuttum — aşka ulaşıp geldim."],["Ben ne kuru sözdeyim (kâl ü kîl), ne de yetmiş iki dilin (mezhebin) çekişmesinde;","bu ilde bana yabancı (yad) yok — orada (ezelde) herkesle tanışıp geldim."],["Bencillik (hod-bîn) ilinden geçtim, hepsinden el çektim;","o ikilik kapısından, birliğe ulaşıp geldim."],["Yoldaşım dört kişidir: vefalım, sırdaşım;","üçüyle başım hoştur (rahattır) — birine (nefse) öfkelenip geldim."],["O dördün biri can, biri din, biri iman;","biri nefsimdir, düşman — onunla orada savaşıp geldim."],["Bir kılı kırka yardılar, birini (o ince yollardan birini) yol gösterdiler;","beni bu mülke (âleme) gönderdiler — o ince yola düşüp geldim."],["Aşk şerbetinden içtim, on iki ırmak geçtim;","denizlerin bendini (setini) yardım — ummandan taşıp geldim."],["Ben oradan (ezelden) buraya geldim, yine oraya varacağım;","oraya varacağımı, orada (ezelde) öğrenip (tanışıp) geldim."],["Azrail kim oluyor ki canıma kastedebilsin —","ben, emanetin (canın) sahibiyle (Allah'la), orada (ezelde) anlaşıp geldim."],["Aradım, bir uca (zirveye) çıktım; gezinmek (teferrüc) için eğlendim (oyalandım);","erenlerin (ermişlerin) soyunu araştırıp, o soya katılıp geldim."],["Yunus Emre'ye ne gam — âşık zaten kınanır, adı kötüye çıkar;","ben küfrümü (gaflet perdemi) imanla, o an orada (ezelde) değişip geldim."]],"182":[["Dostun elinden ölürsem, güle güle yine geri gelirim;","bu anı ganimet (değerli fırsat) bileyim — canı şükrane (şükür) olarak verip gelirim."],["Canını esirgeyen (dirîg tutan) kişi, dostun katından uzak düşer;","yüz bin canı feda kılayım — uzaklıktan beriye (yakına) geleyim."],["O dost, beni Cercis gibi yetmiş kez öldürse (Cercis defalarca öldürülüp diriltilmiştir),","bin kez daha ölsem (bile), yüz bin kez yine öne gelirim."],["Yüz bin kez doğayım batayım, dostun burcunda dolaşayım (cevlân kılayım);","hem burada olayım hem orada — buradan oraya gidip geleyim."],["Dostun burcunda doğmuşken, niçin uzağa gideyim —","o sevgi (mahabbet) göğünde, her sabah dönüp gelirim."],["Kaybolmuşum (yavı kılındım), ne çare — gece gündüz avare yürürüm;","soranlara cevap şudur: dostu isteyip arayarak geleyim."],["Bin yıl toprakta yatsam bile, 'Ene'l-Hak'ı (fenâda söylenen o hakikati) asla bırakmam;","ne vakit gerek olursa, aşkın nefesini üfleyerek canlanıp gelirim."],["İnanmayan, gel mezarıma; dostun adını söyle, çağır;","kefenimi parça parça edip, toprağımdan kalkıp gelirim."],["Dostun yolundan saparsam, geri gelişim boşa gider;","dostun varlığı benimledir — her an O'ndan bir nişan (iz) verip gelirim."],["Bundan sonra ne olacağını, her akıl açıklayamaz (şerh edemez);","âşıklara, miskin Yunus, güzel haber ulaştırıp geleyim."]],"183":[["Bin yıl vasfını (özelliklerini) söylesem, bir zerresini bile tüketemem;","bir damlada yüz bin deniz var — bir noktasını bile açıklayamam."],["Ne kursam bir benzetme yeter, ne de gönül karar kılar;","O'nu misal ile kim benzetebilir — hâşâ, O'nu bir şeye benzetemem."],["O'nun bir nakşını (resmini), suretini kim yapabilir — O, nakıştan da suretten de âzâddır (münezzehtir);","bütün akıllar sende mat olmuş — nasıl söze çekince (özür) gözetmeyeyim?"],["Akıl fenâya (yok oluşa) varınca deli olur, ne başarabilir?","Delilere çare sensin — ben de deli oldum, öyleyse ne yapayım?"],["Şimdi öğret, dil ne söylesin — şart şudur ki seni söylesin;","senin yardımın (tevfîk) erişirse, dile başka bir şey söyletmem."],["Ne diyeceksen sen de bana söyle; beni benden (benliğimden) yana bırakma;","senden dileğim şu: bana beni (benliğimi) istetme."],["Madem padişah (Allah) güçlüdür, kul da kusurlu (fuzûl işli) olsa ne çıkar —","ben seninim, bana ne gam; ister suç işleyeyim, ister işlemeyeyim."],["Madem bu denize girdim — ne kıyı var ne ada;","dört yanımdan dalga (mevc) vursa da, teknem sağlam (kavî), hiç batmam."],["Bu söz benim değil; varlık senindir — Yunus kim oluyor?","Dilime kadir (gücü yeten) sensin — sensiz dilimi kıpırdatmam."]],"184":[["Sensin Kerîm, sensin Rahîm;","Allah'ım, sana sundum elimi;","senden başka umudum yok;","Allah'ım, sana sundum elimi."],["Ecel geldi, vade doldu;","bu ömrümün kadehi doldu;","kim var ki bu kadehi içmeden kalmış?","Allah'ım, sana sundum elimi."],["Dilimin tetiği (mekanizması) bozuldu;","canım gövdemden koptu (üzüldü);","işte gözlerim süzüldü (kapandı);","Allah'ım, sana sundum elimi."],["Yıkama suyumu koydular, ısındı;","kavmim kardeşim hepsi geldi;","esen kalsın kavmim kardeşim;","Allah'ım, sana sundum elimi."],["İşte kefen giysimi diktiler;","yolum Hazret'e (Allah'a) yöneldi;","burada kalan, neyimdir benim?","Allah'ım, sana sundum elimi."],["Salacam (cenaze tahtam) geldi, sarılırım;","dört yana sala (çağrı) verilir;","halk namazıma toplanır;","Allah'ım, sana sundum elimi."],["Salacamı (tabutumu) götürdüler;","musallaya (namaz yerine) eriştirdiler;","güzel (görklü) tekbir getirdiler;","Allah'ım, sana sundum elimi."],["Buraya üşüşüp götürdüler;","orada kefeni çözüp indirdiler;","toprağımı eşeleyip üstüme örterler;","Allah'ım, sana sundum elimi."],["Toprağa indirince;","ellerini toprağa attılar;","taşlarla üstünü bastırdılar;","Allah'ım, sana sundum elimi."],["İşte beni götürdüler;","mezarıma (makbereme) getirdiler;","halka olup oturdular;","Allah'ım, sana sundum elimi."],["Cenazeden (tabuttan) çözünce;","üstüme toprak attılar (eştiler);","hepsi beni bırakıp kaçtılar;","Allah'ım, sana sundum elimi."],["Karanlık bir yerde kaldım;","o yere başka kimse varamaz;","acayip bir derde uğradım (sataştım);","Allah'ım, sana sundum elimi."],["Kabir (meşhed) doldukça dert dinmedi;","gündüzümüz gece oldu;","hâlimiz nasıl, bilmeyiz;","Allah'ım, sana sundum elimi."],["Münker ile Nekir geldi;","her biri bir soru sordu;","İlahî (Allah'ım), cevabı sen ver;","Allah'ım, sana sundum elimi."],["Beni ince yola (sırata) aldı;","Sırat köprüsüne iletti;","amelimden bana medet (yardım) yok;","Allah'ım, sana sundum elimi."],["Yedi cehennem (Tamu), sekiz cennet (Uçmak);","her birinin bir yolu vardır;","her yolda yüz bin çarşı (çârsû);","Allah'ım, sana sundum elimi."],["Yaratıklar, melekler;","ister sarhoşlar (esrükler), ister ayıklar;","afiyet (sahha) size, ey uyanıklar (ârifler);","Allah'ım, sana sundum elimi."],["Görün, zaman acayip oldu;","gönülden figan (feryat) edin;","çünkü anadan doğan herkes ölür;","Allah'ım, sana sundum elimi."],["Yunus, bu sözü artık yeter, kısa kes;","yüzünü Allah'ına çevir;","dîdârdan (Allah'ın cemâlinden) bizi ayırma;","Allah'ım, sana sundum elimi."]],"185":[["Muhammed ile birlikte Mi'râc'a çıkan benim;","Ashâb-ı Suffa (Suffe ehli yoksul sahabe) ile çıplak (yoksul) olan benim."],["Sabrı ve kanaati bunlara ben vermiştim;","kırk kişiyi bir gömleğe kanaat ettiren benim."],["O kırktan birine neşteri ben vurmuştum;","o tek kişiden kırkının kanını akıtıp ibret gösteren benim (Kırklar'ın birliği)."],["Âdem Peygamber ile, Havva yaratılmadan önce;","cennetten (Uçmak) sürülüp o müflis (yoksul düşen) olan benim."],["Musa Peygamber ile bin bir kelime (söz) konuştum;","İsa Peygamber ile göklere çıkan benim."],["İbrahim Edhem zamanında, taç ile tahtı terk etti;","Allah aşkına baktı — o sırrı sezen (duyan) benim."],["Abdürrezzak (Şeyh San'an), o derviş, beni yoldaş edindi;","Hallâc-ı Mansûr ile darağacına asılan benim."],["Ömer bin Hattâb ile çok adalet (adl ü dâd) işledim;","Ömer'in oğluyla, günah (fısk) içinde, şer'î cezaya (hadde) çarptırılan benim (Ömer'in adaleti)."],["Adımı Yunus koydum, sırrımı âleme açtım (çaktım);","Levh ile Kalem'den önce, dilde söylenen benim."]],"186":[["Gerçek Rabbim, gerçek Rabbim; senin gibisi yok, Rabbim;","günahkârım, bağışla — ey rahmeti çok olan Rabbim."],["Kullar senin, sen kulların Rabbisin; bunların günahları çok;","bunları cennetine (Uçmağına) sal, Burak'a binsinler, Rabbim."],["Ben derim ki: ey Ganî (hiçbir şeye muhtaç olmayan Allah), bu derdin dermanı nedir?","Sakın beni esirgeme — aşk ateşine yak, Rabbim."],["Ne yoksuldasın ne zengin (bay)de, ne köşk ve saraylardasın;","sen yoksulların (miskînlerin) gönlüne girdin, orada durak (yurt) edindin, Rabbim."],["Bırak beni, güzelce yanayım; kül olup ufalanayım;","o sevdiğin Muhammed'e bir çerağ (ışık) olayım, Rabbim."],["Ne ilmim var ne ibadetim (tâatim), ne gücüm var ne takatim;","meğer ki senin inayetin (lütfun) yüzümüzü ak ede, Rabbim."],["Yunus'u sen bağışla, bu günahkâr kullarla birlikte;","eğer bağışlamazsan — pek ağır bir ayrılıktır (firaktır), Rabbim."]],"187":[["Benim canım uyanıktır; dostun yüzüne bakan benim;","denize karışmak (fenâda O'na kavuşmak) için, ırmak olup akan benim."],["Irmak gibi çağlarım, kâh gülerim kâh ağlarım;","nefsimin ciğerini dağlarım — kibir ile kini yıkan benim."],["Bu nefsin ordusunu (çerisini) kırdım, burcunu duvarını yerle bir ettim;","içini tertemiz (pâk) eyledim — onun ülkesini (mülkünü) arındıran benim."],["Ben yüzümü Hazret'e (Allah'a) tuttum; o aşk eri (mürşit) gözümü açtı;","bana kendi (asıl) özümü gösterdi — 'âyet-i küll' (her şeyi yansıtan bütünün işareti, insân-ı kâmil) denen benim."],["Şah'ın (Allah'ın) dîdârını (cemâlini) apaçık gördüm, şüphesiz, besbelli;","inanmayan kâfir olsun — o dîdâra bakan benim."],["Bu işlerin hepsi (Hak'la) benimdir; bu yaz ve kış, ilahî hikmetledir;","ben yabancıyı da tanıdığı da bilirim — yerinden sarsılmadan (ırılmadan) duran benim."],["Bütün canlarda oynayan, onların damarlarında kaynayan;","her dilde söyleyen, her lisanı konuşan benim (her şeyde tecelli eden o tek hakikatin/aşkın dilidir)."],["Nemrut'un ateşini İbrahim'e ben bağ-bahçe eyledim (serinlettim);","inkâr (küfür) yüzünden doğup, o ateşi yine yakan da benim (her iki yanda da takdir eden O'dur; bu söz fenâ hâlinde söylenir)."],["O Hallâc-ı Mansûr ile 'Ene'l-Hak' (Ben Hakk'ım) derdim;","hem yine onun boynuna darağacı ipini takan da benim (bu söz benlikten geçmiş fenâ hâlinde söylenir; hem söyleten hem takdir eden O'dur)."],["O Hak Habîb'i (Allah'ın sevgilisi) Mustafa (Muhammed), Mi'râc'a sefer edince;","o an düşündüm, ey canım — o sırrı sezen (duyan) benim."],["Şimdi adım Yunus'tur, o an İsmail idi;","o dost için, Arafat'a kurban olup çıkan benim."],["Bu felek (çarh) benim hükmümdedir, her nerede oturmuşsam hükmüm yürür;","mülk benimdir, hükmederim — yapan benim, yıkan benim (bu, benlikten geçmiş fenâ hâlinde, Hakk'ın saltanatından söylenir; yapan da yıkan da O'dur)."],["Kutlu (sa'd) benim, mutlu (sa'îd) benim; Yunus da benimledir;","üstadım, ilm-i ledündür (Allah vergisi bâtınî bilgi) — o sırları sezen benim."]],"188":[["Benim gönlümü aldı, ne olduğumu bilmem;","kendimi kaybettim — arayıp kendimi bulamam."],["Gönülsüz (gönlüm alınmış) çıktım yola; hâlim dile hoş gelmez (anlatılamaz);","bir an derdimi söylemeye, dert ortağı bir dertli bulamam."],["Derdimden razıyım (şâkirim), ona güle güle rastladım;","dertlileri bulunca da, ben yine kendimi bulamam."],["Bana 'gönlünü kim aldı' deseler,","nasıl haber vereyim — ağlarım, söyleyemem."],["Benim bu gönlümü alan — bütün âlem O'nunla doludur;","nereye baksam, O'nsuz bir yer göremem (O her yerde)."],["Ayık (aklı başında) oturma, beni ayıltacak şeyler getirme;","aşkın sarhoşluğunu (esrüğini) severim — ben ayık olamam."],["Yunus'a kadeh sunan, 'Ene'l-Hak' (Ben Hakk'ım) nefesini söyleyen o sâkîden;","erenlerin yudumundan (cur'asından) içtim — artık ayılamam ('Ene'l-Hak', benlikten geçmiş fenâ hâlinde söylenir)."]],"189":[["Aşkının şarabını içeli, nerede olduğumu bilmem;","öyle kaybettim ki kendimi — arayıp bulamam."],["Engin bir okyanus (deryâ-yı umman) oldum, mücevherlere (güherlere) maden (kân) oldum;","öyle hayran oldum ki, kendime gelemem."],["Yoluna ayak basalı, varlığımı yokluk (adem) kıldım (benliğimden geçtim);","gözümden bir an bile uzaklaşma — çünkü sensiz ben var olamam."],["Güzelliğin (hüsnün) illere dolalı, bütün gönülleri hayran edeli,","dillere ne denli dolsan da, senden tam bir nişan (iz) alamam (kavrayamam)."],["Aşkınla sarhoş (mest) olalı, derdini her an bulalı,","kavuşma (visâl) nişanını alalı — artık cennetler için bile kalamam (gönlüm sadece sende)."],["Temelimi kuran O'dur; Yunus, ezelden beri adımdır;","her şeyden tadımı (zevkimi) kestim — aşkından ayrılamam."]],"190":[["Senin için canımı feda etsem, şaşılacak şey değil;","senin varlığın cana yeter — cansız kalsam bile hoştur."],["Senin yüzünü görünce, canım sana gitmişti;","senin sevgin bana yeter — her nerede olursam olayım."],["Senin tadını almayana, sözüm acayip bir laftır;","ne canım var ne diriyim — bir an bile sensiz olursam."],["Ölümsüzlük (bâkî) suyunu içmişken, ölümün tadı (çeşnisi) belirmez;","nasıl sona (zevâle) erişsin bana — severek (sevgiyle) varırsam?"],["Madem ben seni severim, ecelin eli bana erişmez;","Azrail ne zaman el uzatır — ben seninle canlanırsam (sen benim canımsan)?"],["Bedenim (suretim) düşse (ölse) bile, bana nasıl eksiklik (noksan) erişsin?","Ben senin ezelî (kadîmî) zerrenim — beden ne kadar düşüp dursa da."],["Daha Elest (ezel sözü) belirmeden, ben sana — sevgiliye (ma'şûka) âşıktım;","gözüm yan (şaşı) bakmaz — yüz bin kaba (bedene/surete) girsem de, sevgim hep sana (ruhun her hâlde sevgisinin değişmezliği)."],["Daha cihana gelmeden, canım seni sevmişti;","Yunus'a bu bir minnet (yük) değildir — ne kadar tapı (kulluk) kılsam da severek kılarım."]],"191":[["Beni boş (tehî) görmeyin; dostun yüzünü görüp geldim;","sonsuz zaman boyunca, dostla vakit sürerek geldim."],["Dilde söylenen ne varsa — kuldaki varlık Hakk'ındır;","bütün varlığım o ildedir (asıl yurdumda) — ben buraya garip (yabancı) geldim."],["Tüccarım, malım çok; elimden tutanım, üstadım Hak'tır;","zararımı kâra orada (ezelde) değişip geldim."],["Yer ve gök yaratıldı, aşkla temellendi (bünyâd oldu);","toprağa (Âdem'in çamuruna) bir baktı (nazar kıldı), o aksırdı (can geldi) — ben kalkıp geldim."],["Yedi cehennemini (Tamu), sekiz cennetin (Uçmak) hepsini gördüm;","korkudan günahımı kendimden sızdırıp (atıp) geldim."],["Âdem olup daha durmadan, nefsimin boynunu bükmeden,","yanıldım, buğdayı (yasak meyveyi) yedim — cennetten (Uçmak) sürülüp geldim."],["Nuh oldum, Tufan için; din için çok çabaladım (dürüştüm);","dinime dönmeyeni, suya boğup (gark edip) geldim."],["Sözüm yalan değildir; yüzüme bak, gözünü aç;","izim daha örtülmedi (silinmedi) — işte yoldan geçip geldim."],["Eyyub oldum; tenime cefa kıldım, canıma eziyet ettim;","Sübhân'ıma (Allah'ıma) yakardım — kurtları doyurup geldim (Eyyub'un sabrı)."],["Zekeriyâ oldum, kaçtım; varıp ağaç (kovuğuna) geçtim (saklandım);","kanımı dört yana saçtım, başımı testereyle deldirip geldim (Zekeriyâ'nın şehadeti)."],["Musa ile Tûr'a çıktım, bin bir kelime (söz) konuştum;","bu yaratıklar (insanlar) bilsinler — orada bulunup geldim."],["İsa oldum — kudretten (Allah'ın gücüyle), bir kadın (Meryem) vesile (bahâne) oldu;","Hak'tan inayet (lütuf) erişti — ölüyü diriltip geldim (Allah'ın izniyle)."],["Cercis olup defalarca yere serildim; Mansûr oldum, asıldım;","Hallâc'ın pamuğu gibi, burada atılıp savrulup geldim (aşk uğruna fenâ; 'Hallâc' pamuk atan demektir)."],["Muhammed'i bir gece Hak, Mi'râc'a çağırdı (okudu);","baştan başa, uçtan uca, onunla birlikte yüz süre süre geldim."],["Yalnız Sübhân (Allah) vardı; O, peygamberlerin canıydı;","Yunus ise gizli (pinhân) olandı — suret değiştirip geldim (bütün suretlerde tecelli eden o tek hakikattir)."]],"192":[["Ey dostlar (yârânlar), bana ilişmeyin; ben yine ne oldum, bilmem;","bana ilim ve amel (ibadet) sormayın — divane (deli) oldum, bilmem."],["Başka türlü (ayruksı) bir şey tattım, bildiklerimi unuttum;","canımı aşka attım — orada ne buldum, bilmem."],["Aklım iyice kayboldu, bütün fikrim dağıldı;","boşaldım, işte yeniden doldum — ama neyle dolduğumu bilmem."],["Aşkın beni yakıp durur, gönlüm dosta akıp durur;","kendimi bir türlü derleyemem — soluğum kesilmiş (dem-beste) kaldım, bilmem."],["Ben aşksız olamam; aşk varken ben ölmem;","aşktır hayatımın özü (hâsılı) — aşktan başkasını bilmem."],["Bu aşkla bulanığım (şaşkınım); ne sarhoşum ne ayık;","ne uyurum ne uyanığım — hayran ve sarhoşum (mest), bilmem."],["Beni 'şeyh oldu' diye, benden öğüt (nasihat) isteme;","iyi bildiğimi sanırdım — işte şimdi anladım ki bilmiyormuşum."],["Âşık Yunus, sen canını Hak yoluna feda eyle;","bu şeyhle (Tapduk'la) Hakk'ı buldum — ben başka bir şey bilmem."]],"193":[["İlk benim, son benim (Evvel ve Âhir O'dur); canlara can olan benim;","yolda şaşırıp kalanlara hazır medet (yardım) eden benim. (Bu şiir boyunca konuşan, benlikten geçmiş fenâ hâlinde Hakk'ın dilidir; kul kendi benliğinden değil, kendisinde tecelli eden Hak'tan söyler.)"],["Bir kararda (sabit hâlde) durdum; benim sırrımı kim sezer?","Cahil beni nerede görebilir — gönüllere giren benim."],["'Ol (kün)' anında bakan (nazar eden), bir bakışta dünyayı düzen;","kudretiyle saltanat kurup, aşka temel (bünyâd) atan benim."],["Bu yerleri düz döşedim, bu dağları çöksü (kazık) çakar gibi yerleştirdim;","gökleri çardak (sayvân) eyledim — onları yerinde tutup duran benim."],["Hem de — şaşılası — âşıklara ikrar, din, iman ben oldum;","halkın gönlündeki küfür ile İslam'ın (sınanışındaki) şüphe de benim. (Bütün hâllerin takdiri Hakk'a dayanır; fenâ hâlinde söylenir.)"],["Kimine emir verdim, ömrü saadetle (devletle) geçti;","yanan kömür, kızan demir — örse çekiç salan (vuran) benim."],["Kar yağdıran, buz donduran, hayvanlara rızkını veren;","şöyle bilin: o yaratığa, Rahîm ve Rahmân (merhametli ve esirgeyen Allah) olan benim. (Fenâ hâlinde, Hakk'ın dilinden.)"],["Halk içinde düzeni (dirliği) kuran, dört kitabı doğru yazan;","ak üstüne kara (yazıyı) dizen — o yazılan Kur'an benim. (İlahî sözün kaynağı, fenâ hâlinde söylenir.)"],["Dostla birliğe ulaşan, buyruğu neyse tutan;","mülkü bezeyip dünyayı düzen — o bahçıvan, işte benim."],["Dünyada ben o Rüstem'im (o yiğidim), dünya içinde yeşeren bostanım;","karşımdaki sensin (ey sevgili) — seni sende gören benim (her şeyde O'nu görmek)."],["Hakk'ın kudret eli benim (O'nun kudretinin tecelli aracı); elbette aşkın bülbülü benim;","her türlü dili konuşup, halka haber veren benim. (Fenâ hâlinde, Hakk'ın dilinden.)"],["Dilleri damakları çözen, aşk kazanını taşıran;","Hamza'yı Kaf dağından aşıran o zehirli (agulu) yılan benim (Hamza efsanesi)."],["Yağmur olup yere yağan, bulut olup göğe yükselen;","hakkı göremeyenlerin gözündeki boz (bulanık) sis, o perde (tuman) benim."],["Bunu diyen Yunus değil — söyleyen, Hakk'ın kendi zatıdır (benlikten geçen kulda tecelli eden Hak'tır);","inanmayan kâfir olur — ilk ve son (Evvel ü Âhir), işte O'dur. (Şiir boyunca konuşan, Yunus'un benliği değil, kendisinde tecelli eden Hak'tır.)"]],"194":[["Kâbe de, imanın yöneldiği o mecazî put da benim (her ibadetin yöneldiği O'dur); dönüp duran felek benim;","bulut olup göğe yükselen, yağmur olup yağan benim. (Fenâ hâlinde, Hakk'ın dilinden.)"],["Yazı yaratıp yeri donatan (süsleyen); gönlümüzün evi o ulu hânedandır;","ana babadan hoşnut olan, kulluğun değerini (kadrini) bilen benim."],["Yıldırım olup çakan; öfkelenip nefsine vuran (dokuyan);","yerin dibinde (ka'rında) gizlenen o zehirli yılan benim."],["Hamza'yı Kaf'tan aşıran, elini ayağını çözen;","nicelerini tahttan düşüren — hikmet sahibi (hikmet ıssı) sultan benim."],["Et, deri, kemik (sünük) birleştirip beden eyleyip diri tutan;","hikmet beşiğinde yatan, kudret sütünü emen benim."],["Gerçek âşık beri gelsin, doğru yolu gösterelim;","gönül şehri asıl makamdır — orada yerinden ayrılmadan (ırılmadan) duran benim."],["Yeri göğü benim diyen, batıyı (mağrıb) doğuyu (maşrık) benim diyen;","denizlere 'gel' diye çağıran — adım Yunus, o engin umman benim."]],"195":[["İlk, ezelî (kadîm), önde ve sonda, zevali (sonu) olmayan sultan benim (Evvel ve Kadîm O'dur);","yedi iklime hükmedip, yeri göğü tutan benim. (Bu şiir de fenâ hâlinde, Hakk'ın dilinden söylenir.)"],["Ben bu yeri yaratınca, yer üstüne gök durunca,","ulu deniz dalgalanınca — Nuh'a tufanı veren benim."],["'Ol (kün)' dedim, bu yer durdu; gökler de karar kıldı (yerleşti);","yüz bin türlü insan (âdem) geldi — getirip gideren benim."],["Yusuf ile kuyuya (çâha) inen, teraziye altın vuran;","kefesine bastıran — Mısır'ın sahibi (ıssı) sultan benim (Yusuf kıssası)."],["Sofî ile sofî olan, sûfî ile saf (sâfî) olan;","bel bağlayıp ibadet (tâat) eden — o Kerîm ve Rahmân (cömert ve esirgeyen Allah) benim. (Fenâ hâlinde, Hakk'ın dilinden.)"],["Kaf'tan Kaf'a hükmeden, devleri hükmüne (buyruğuna) alan;","yele binip dolaşan (seyran eden) — bu mülkün Süleyman'ı benim."],["Et ve deriyi beden (endâm) edip birleştiren, âlemlere gönül (can) katan;","Âdem'in elbisesine bürünüp, mülke (dünyaya) ayak basan benim."],["Sekiz cennet (Uçmak), âşıklara — onlara köşk ve saraydır;","Musa gibi Tûr Dağı'nda hayran olup kalan benim."],["Ben âbidim (ibadet eden), ben mâbûdum (ibadet edilen); her yerde hazırım;","zalimlerden mazlumun hakkını (dâd) alan, yoksulları (miskînleri) koruyan benim. (Fenâda âbid ile mâbûd ayrımı kalkar; her yerde hazır olan Hak konuşur — benlik iddiası değildir.)"],["Her dilde 'Tapduk' diyeyim (şeyhimi anayım); her kula inanmışım;","Yunus da kim oluyor ki — bu sözleri diyen aslında benim (kulda tecelli eden Hak'tır)."]],"196":[["Oradan (ezelden) yola çıktım, dostla birlikte geldim;","bu âleme çıkınca, acayip bir hâle geldim."],["O dost gözümü açtı, bana kendi (asıl) özümü gösterdi;","gönlümdeki sırrı söyledim — dile geldim."],["Gör, ne yüce bir yuvadan uçtum; sırrımı halka açtım;","aşkın tuzağına düştüm — yakalandım, ele geldim."],["Tuzağa düşen gülmez, âşıklar rahat olmaz;","söylerim ama dilim ne dediğini bilmez — acayip bir hâlle geldim."],["Ben buraya geldiysem de, ilime (asıl yurduma) geri gideceğim;","sanma ki buraya altın ve mal için geldim."],["Ben ne kuru sözdeyim, ne de bu yetmiş iki dilin çekişmesinde;","hâlim ahvâlim nedir — bu mülke onu sormaya geldim."],["Ne hâldeyim, ne bileyim; tuzaktayım, neye güleyim?","Garip bir bülbülüm — güle ötmeye (şakımaya) geldim."],["Gül, Muhammed'in teridir (deridir); bülbül onun yârıdir;","o gülle (Peygamber'le), ezelden cihana birlikte geldim. (Gülün, Peygamber'in terinden bittiği rivayet edilir.)"],["Mescitte, medresede çok ibadet eyledim;","asıl olgunluğa aşk ateşine yanarak, ondan sonra erdim (hâsıla geldim)."],["Kudret daha suret yapmadan, melekler (feriştehler) tapmadan,","âlemi yaratıklar tutmadan önce — ben öne, yola geldim."],["Yine Yunus'a sordum; der ki: Hakk'ın nurunu gördüm;","ilkbahar güneşi gibi, dalgalanıp doğarak geldim."]],"197":[["Erenlerin (ermişlerin) himmetini (manevî desteğini) kendime yoldaş eyleyeyim;","nereye varırsam, bütün işimi hoş (güzel) eyleyeyim."],["Bu dünyayı bırakıp gideyim; madem ahirete sefer ederim;","o cennetteki (Uçmak) hurileri kendime yoldaş eyleyeyim."],["Tene yumuşak (giysi) giymeyeyim, hepsinden el çekeyim (fârig olayım);","döşeğimi toprak edip, yastığımı taş eyleyeyim."],["Nefsin evini vurup yıkayım, hırs ile heva ateşte yansın;","bundan sonra el çekeyim — nefisle savaş eyleyeyim."],["Tenim de canım da, 'Ene'l-Hak'ı (fenâda bilinen o hakikati) hiç bilmedi;","şimdiye dek bilmedilerse, bundan sonra onları o hakikatle buluşturayım (tuş eyleyeyim)."],["Bugün burada gülen kişi, yarın ahirette orada ağlayacak;","gözyaşımı akıtıp, yastığımı gözyaşıyla ıslatayım (yaş eyleyeyim)."],["Miskin Yunus çağırarak der: yoksulların (miskînlerin) âşığıyım;","dışım derviş değilse bile, içimi derviş eyleyeyim."]],"198":[["Sıranın kimde olduğunu hiç bilmem — ölüm aramızda gezer;","âlemi bir bostan eylemiş, onun kokulu çiçeklerini (râyihasını) ölüm biçer (alır)."],["Yiğidi (genci) en güzel çağında alır; bülbül onun bağında ötmez;","kimseyi ocağında sağ bırakmaz — yiğitleri alır ölüm."],["Kiminin belini büker, kiminin mülkünü yıkar;","kiminin gözyaşını döker — bütün gücünü koparır ölüm."],["Birinin kardeşini alır, gözyaşını akıtır;","yüreğinin yarasını (bagrı başın) hiç onarmaz — hayır işleyeni bile esirgemez ölüm."],["Yiğidi ihtiyar (koca) edinceye dek, onu kendine gelmeye bırakmaz;","birini sıradan koyup gelince, gözlerini süzer (kapatır) ölüm."],["Yiğidi de ihtiyarı da alır, ananın içini (yüreğini) yakar;","kızların sarı saçını, teneşirde (ölü yıkanan tahtada) çözer ölüm."],["Yiğidin en iyisini (âlâsını) alır, anasını divane (deli) eder;","gelinlerin el kınasını, topraklara karar (karıştırır) ölüm."],["Yiğidin seçkinini (hâsını) alır, gözlerinin yaşını döker;","anasını Mecnun gibi deli eder — yürekleri yakar ölüm."],["Hani onun sevdiği yâri? — ibadetini (tâatini) temiz (arı) kıl, yürü;","miskin Yunus bunu der: ölüm, ejderhalar gibi yutar hepimizi."]],"199":[["Ey bütün dert ehli, gelin: dert de benim, derman da benim;","kâfirdeki gizli küfür de, mü'mindeki iman da benim. (Bu şiir de fenâ hâlinde, Hakk'ın dilinden; her hâlin takdiri O'na dayanır — benlik iddiası değildir.)"],["Âlemde sınamayı (fitneyi) ben koydum; ateşim Mansûr'u kül etti;","onun dilinde 'Ene'l-Hak' (Ben Hakk'ım) dedim — boynundaki urgan (ip) da benim. (Bu hakikati fenâda söyleten ve takdir eden O'dur; benlikten geçmiş hâlde söylenir.)"],["Yusuf'taki hüsn ile cemal (güzellik), Yakub'daki hüzün ile keder;","kâh dolunay (bedr) olayım kâh hilal — gökteki parlak ay (mâh-ı tâbân) benim."],["Nemrut'taki sureti yapan, İbrahim'i ateşe atan;","sonra onun bir kılını bile yakmayan — o ateş de, kül de, fesleğen (gül bahçesi) de benim. (Her iki yanda da takdir eden O'dur; fenâ hâlinde söylenir.)"],["Yunus, bu bedenimin adıdır; beden, O'nun yapısıdır (eseridir);","adımı sorarsan bil ki — cana cânân (sevgili) olan benim (asıl konuşan, kulda tecelli eden o ilahî Sevgili'dir)."]],"200":[["Ey gönül, bize kerem (lütuf) kıl, birlikte seyran (gezinti) edelim;","candan ve tenden geçip, gel sevgiliye (cânâna) doğru yola çıkalım."],["Beden nedir dostun yolunun yanında — ben o yolu asla terk etmem;","dostun cemâlini (güzelliğini) görmek için, gel canı kurban edelim."],["Bu yokluk-içinde-yokluğu (fâni dünyayı), dost için bırakalım;","asıl bekâ-içinde-bekâ (Allah'la kalıcılık) mülkünde dolaşalım (cevlân edelim)."],["Gel, mürşidin (şeyhin) eşiğini (âsitânını), canın kıblesi kılalım;","o şahlar şahının şahını (Allah'ı), gel biz de gönlümüze misafir (mihmân) edelim."],["Gel beri, yağmur damlası (katre) gibi dağılmayalım;","deniz gibi toplanıp (cem' olup), gel ummanı (okyanusu) hedefleyelim."],["Ben O'nun aşk şarabını her an (dem-be-dem) içmişim;","dostun cemâlini görmek için, gel Arş-ı Rahmân'a (Allah'ın arşına) yönelelim."],["Madem bu zayıf Yunus'a birlikte yoldaş olmadın,","ey gönül, gel o şahı (Allah'ı), Süleyman'ın tahtı gibi bizi yücelten edelim."]],"201":[["Bu fenâ (fâni) mülkünde, daha ne kadar hayran (şaşkın) kalayım;","ne zamana dek kâh gülen, kâh ağlayan olayım? (Bu uzun şiir boyunca konuşan, benlikten geçmiş fenâ hâlinde, her surette tecelli eden Hakk'ı seyreden âşıktır; sıralanan hâller, tek hakikatin bütün suretlerde görünüşüdür — kötü kişilere dönüşme değildir.)"],["Kâh feleklerde, meleklerden dilekler dileyeyim;","kâh Arş ve güneşle birlikte felek olup döneyim (gerdân olayım)."],["Adımı, yedi (kat gök), dört (unsur) ve on sekiz bin (âlemden) öteye attım;","dokuz (kat göğü) yolda bırakıp, şahın (Allah'ın) emrine uyan (fermanlı) olayım."],["Dost, kederden (terâh) ferahlık verdi; ben ondan uzaklaştım (teberrâ eyledim);","görünüşte insan olayım — hem can hem cânân (sevgili) olayım."],["Kâh bir müftü, müderris; kâh ayırt edici (mümeyyiz), kâh temiz;","kâh tedbirli (müdebbir) ama eksik (nâkıs); kâh kusurla noksan olayım."],["Kâh balığın karnında (batn-ı Hût), Yunus (Peygamber) ile söyleşeyim;","kâh Arş'a çıkayım — bir can olayım, Selmân olayım."],["Kâh en aşağılara (esfele) inip, şeytanla şerler düzeyim;","kâh Arş'ın üstüne çıkıp, seyran edip dolaşayım. (Burada bile, her hâlin Hakk'ın takdirinde olduğu fenâ görüşü dile gelir; kötülüğü onaylama değildir.)"],["Kâh bir sır olup, hem işiteyim hem söyleyeyim;","bir genç (cüvân) olup, kâh insan olayım — insan unutandır — unutkanlık (nisyân) olayım."],["Kâh akledilenler (ma'kûlât), meşru kılınanlar, ifade ve beyan;","kâh kısaltılmışlar (maksûrât) olayım, kâh Zühal'in (kederin) sahibi olayım."],["Ne zamana dek, surette insan ama sıfatta canavar olayım;","ne zamana dek tilki olayım, ya kurt ya aslan olayım?"],["Ne zamana dek tecrîd, tefrîd ve mücerred-münferid (her şeyden soyunmuş, tek) olayım;","ne zamana dek cinden ve insandan olayım, ya ne zamana dek şeytan olayım?"],["Ne zamana dek aşk meydanında nefs atını koşturayım;","ya ne zamana dek başımı top edip, aşkın çevgânı (değneği) olayım?"],["Birlikle bir olayım, birlik benimle bir olsun;","kâh dönüp derya olayım — damla (katre) olayım, umman olayım."],["Kâh cehennemde (duzahda), Firavun ve Hâmân ile birlikte yanayım;","kâh cennette varayım — gılmanla (cennet hizmetçileriyle) Rıdvân (cennet bekçisi) olayım."],["Kâh bir gazi olup, Frenk (Avrupalı) ile cenk (savaş) edeyim;","kâh dönüp Frenk olayım — unutkanlıkla (nisyân) isyan olayım."],["Kâh bilinmeyen (mechûl) olayım, reddedilmiş (merdûd) olayım, Nemrut olayım;","kâh varıp Ca'fer (Tayyâr) olayım — cennette uçan (perrân) olayım."],["Kâh yeşeren bir varlık olayım, ilimle murada eren (kâm sahibi) olayım;","kâh cahillikle (cehl) yürüyeyim — muradına ermemiş (nâ-kâm), cahil (nâdân) olayım."],["Kâh yıkayım, kâh yakayım, yeryüzünü toz gibi savurayım;","kâh varıp Arş'a çıkayım — hem şah olayım, sultan olayım."],["Herkes bu sırra eremez — bu, değerli (azîz), ledünnî (Allah vergisi bâtınî) bir bilgidir;","Hızır'ı yolda bırakıp, ben en yüce meleklerle (kerrûb) döneyim."],["Ne zamana dek dertlerle ateşlere yanıp yakılayım;","ne zamana dek şükreden (şâkir), zikreden (zâkir), misafir (mihmân) olayım?"],["Ya ne zamana dek dostla öyle bir olayım ki O ben olayım, ben O olayım (fenâda birlik);","ya ne zamana dek uzak düşüp, mahzun olayım, hüzünlere (ahzân) batayım?"],["Ateşi, toprağı, yeli (ve suyu) — unsurları aslına döndüreyim;","altı yönden (şeş cihet) çıkayım — bedensiz (bî-ten), cansız (bî-cân) olayım."],["Ne zamana dek Cercis, Müşteri (Bercîs) ve Merih (Mirrîh) olayım;","ne zamana dek Galen (Câlinûs), Hipokrat (Bukrât) ve Lokman (hekim) olayım?"],["Bu dokuz aslan (kat gök), yedi ejder (gezegen) ve dört ejderha (unsur) —","bunlarla cenk edeyim, yiğit Rüstem olayım, destan (efsane) olayım."],["Bir an huzurlu (âsûde), bir an gafletle paramparça ve ham;","bir an perişan (âşüfte) olayım — Mecnun olayım, hayran olayım."],["Gönlümün hazinesine (gencine) zahmetler (renc) erişmeden, bir yol bulayım;","yâ Hû! denize gireyim — renksiz ve boyasız (bî-reng ü bî-elvân) olayım."],["Canla ârif (irfan ehli) olup, senlik ve benliği terk edeyim;","kâh dilsiz olayım, akılsız (ögsüz) olayım, hayvan olayım."],["Madem 'söyle' derler, ne yapayım — söylemezse can ve ten yanar;","ben de inciler (dür) dökeyim — dosta bin nağmeli bülbül (hezâr destân) olayım."],["Kâr (kazanç) olayım, kârsız (bî-kâr) olayım; âriflere sır (esrâr) olayım;","kâh dönüp döneyim — söz (güftâr) olayım, Nu'mân olayım."],["Kâh varıp balçık (çamur) olayım, kâh dönüp toprak tozu (gird-i hâk);","kâh varıp gevher (mücevher) olayım — yakut olayım, mercan olayım."],["İnsanlıktan çıkayım, meleklerin mülküne uçayım;","renk (levn) olayım, renksiz olayım; kâh varlık (kevn) olayım, özsüz (bî-kân) olayım."],["Kâh bin canla Hudâ'nın (Allah'ın) emrine itaatli (mutî') olayım;","kâh dönüp isyankâr (âsî) olayım — Musa olayım, İmrân olayım."],["Kâh varıp Davud olayım, Süleyman'ın tahtına çıkayım;","kâh yine yolumu şaşırıp (güm-râh), kavuşmayı (vaslı) bırakıp ayrılık (hicrân) olayım."],["Kâh zindandan çıkayım — özgür (âzâd) olayım, bayındır (âbâd) olayım;","kâh yine kapıcı (derbân) olayım, mahpus olayım, zindan olayım."],["Darağacı olayım, amel (girdâr) olayım, darağacına asılan olayım, Mansûr olayım;","can olayım hem ten olayım — hem bu (în) olayım hem o (ân) olayım. (Aşk uğruna fenâ; benlikten geçiş hâli.)"],["Kâh çöl (beyâbân) ve viran, kâh serap, kâh toprak (türâb);","kâh yine bayındır (ma'mûr) olayım, kâh çadır (çetr), kâh gölgelik (sayvân) olayım."],["Kâh izzetle (şerefle) varıp, bahtlı (devletlü) bir mü'min olayım;","kâh varıp yerleşik (sâkin) olayım, rehber (kılavuz) olayım, rahip (ruhbân) olayım."],["Kâh dönüp sessiz (hâmûş) olayım, kâh coşayım (cûş edeyim), kâh akıl (hûş) olayım;","kâh dönüp renge bürünerek, hem bağ hem bostan olayım."],["Kâh varıp bir saz olayım, bir söz olayım, yanık (pür-sûz) olayım;","kâh varıp imkân (mümkünlük) olayım, iman olayım, ihsan olayım."],["An (dem) olayım, Âdem olayım, âlem olayım — âlemde ben;","an olayım, nefessiz (bî-dem) olayım; hem ad (nâm) olayım hem ekmek (nân) olayım."],["Yunus'a nasip, Tapduk, Saltuk ve Barak'tandır;","madem gönülden coştu (cûş kıldı), ben onu nasıl gizli (pinhân) tutayım?"],["Yunus, şimdi bu sözü sen âşığa söyle, yalnız âşığa;","ki sana ben sıdk (doğruluk) olayım — hem dert hem derman olayım."],["Kâh hâlis (saf), kâh muhlis (ihlaslı) olayım — işte Furkân (Kur'an) ile;","kâh 'Rahmânü'r-Rahîm', 'yâ Hayy', 'yâ Mennân' (Allah'ın isimlerini) diyen olayım."],["Kâh dönüp bir güneş (şems) olayım — zerremde yüz bin Arş olsun;","kâh yine taşkınlık (tugyân) olayım — âlemlere tufan olayım."],["Başı Hû (O/Allah), sonu Hû; yâ Hû, ancak Hû olayım;","ilk ve son (Evvel ü Âhir) O kalsın — ben de 'yeryüzünde olan herkes fânidir' (Rahmân 26) sırrınca fâni olayım. (Bütün bu hâller, sonunda fenâda son bulur: her şey geçer, yalnız Hak kalır.)"]],"202":[["Seni sevdiğimi, seçkin de halk da (hâs u âm) işitsin;","dedikoducular söylesin dursun — sensiz hayatım bana haram."],["Senin lezzetinden canı tat (dad) almayan,","cansız bir suret olarak yürür — âlemin hâlinden habersiz (bî-gam)."],["Ben bu an seni gördüm — nasıl sabredeyim?","Seni bir an görmeye, bütün âlem hasret (müştâk)."],["Seni seven kişiye, huri ile köşklerin (Hûr u Kusûr) ne gereği var;","seni sevmeyen cana, her makam cehennemdir (Tamu)."],["İki cihanın varlığı benim olsa bile,","sensiz bana gerekmez — iş ancak seninle tamamdır."],["Bin yıl ömrüm olsa, bu kapıda harcarım;","gerçek âşıksam, bu yolda ölmem gerek."],["Bana sen gereksen, ben kendimi ne yapayım?","Madem ben sen oldum (fenâda), bırak kendimi kaybedeyim."],["Âlemlerin arzusu, seni bulmak içindir;","ben seni bulmuşken, sensiz nasıl olayım?"],["Yunus'a çok sorarlar: nedir bu aşk sarhoşluğu (esrükliği)?","Ne yapsın — ezel meclisinde kalem öyle çalındı (kaderi öyle yazıldı)."]],"203":[["Kendimi anmaktan (kendimden bahsetmekten) vazgeçtim (fârigim);","anıp ne yapayım — ki ben neye layığım (övünecek neyim var)?"],["Benim yoldaşlığım, alışılmış edebe sığmaz;","edepsiz kişiye niçin arkadaş (refîk) olayım?"],["Cihana elsiz ayaksız (çaresiz) düşmüşüm;","bu hâlimle, mekândan (uzaydan) pek uzağım (onu aştım)."],["Beni oyalayan (egleyen) her şey (mâsivâ) döküldü, geride kaldı;","ne sarhoşum (esrük), ne humarda, ne de ayığım."],["Ne sabır ve miskinlik (meskenet) var, ne de ısrarlı (becid) bir iş;","ne adım atarım, ne de belli bir yoldayım (tarîkteyim)."],["Bugün cihana geldim, işte gidiyorum;","sanırsın bir eve kondum — sadece bir konuğum."],["Hani Yunus, hani o kımıldama (cünbiş), o hareketler?","Ne sermayem var, ne varım ne de yokum (fenâda, varlık-yokluk ötesi)."]],"204":[["Nereye dönersem, işim aşkladır;","gönlümdeki o telaş (teşvîş) odur — hem aşk benim yoldaşımdır."],["Aşksızlara için için yanar özüm; onun için sırrım (râzum) açığa çıkar (fâş olur);","âşıkları görünce, içim dışım kaynar benim."],["Bu aşk bize Rahmânî'dir (Allah'tandır), hem canımızın canıdır;","onun için şeytanla her an bu savaşım sürer."],["Benim canım bir kuştur, gövdem onun kafesidir;","dosttan haber gelince, bir gün kuşum uçar (gider)."],["Geldim, dünyayı gezdim (seyrettim); ya bugün ya yarın gittim;","ben burada oyalanamam — işim burada bitmez benim."],["Yunus der: ben âşığım, hem âşığım hem sadık;","bu başka âşıklar gibi gösterişli bir süsüm (arâyişim) yoktur benim."]],"205":[["O yâri sevdiğimi, daha ne kadar gizleyebilirim;","gönlüme sığmaz, ne yapayım — meğer onu sırrımla içimden söyleyeyim."],["Dilimi tutup (susarak) yürümem, sevgiliye olan yabancılığıma delil imiş;","yabancılık (yadlık) perdesini yakayım — utanma perdemi (hicâbumı) kaldırayım."],["O'nunla olan hâllerimi âlemlere bildireyim;","çağırarak müjdeleyeyim — âlemi üstüme toplayayım (dereyim)."],["Âşıkların gönlü gözü, sevgiliye (ma'şûkaya) açık olur;","ben gönlümü kul eyleyeyim — ola ki sevgiliye ererim."],["Canımı O'na kurban kılayım, eğer canı kabul ederse;","nasılsa öleceğim — burada nasıl diri kalayım?"],["Şükranla, canım pahasına, dost için ölürsem ne mutlu;","ölmek herkese gereklidir — ben ölmeden nereye varayım?"],["O dostla benim işim, ölmekle bitmeyecek;","amelimdir benimle birlikte varan — onu tutarak toprağıma (mezarıma) gireyim."],["Herkesin (kabirde) Münker-Nekir olup gelen, kendi amelidir;","benim amelim ise dosttu (dost sevgisiydi) — amelimi tutarak ona dayanarak varayım."],["Yunus'un dilinin söylediği, ilim ve amel sözü değildir;","dil, dostun haberini ne bilir — ben dostla nasıl bir(im)?"]],"206":[["Mademki o sevgiliyle (ma'şûkla) sırrımı bir edeyim;","müşahedeye (temaşaya) gark olayım — haykırmaya (nefîr) hakkım var."],["Kim var ki O'nu görüp de hâlini gizleyebilsin?","Göster bana o kişiyi — ben de onunla el birliği edeyim."],["Bu yaratıklar (insanlar) bana 'onu can içinde sakla' der;","bir zerresi yüz bin cihandır — söyle, onu nasıl gizleyeyim (sır eyleyeyim)?"],["Gör, Musa'ya Tûr'da bir tecelli (ilahî görünme) neler yapar;","yer gök tecelliyle dolu — ya ben nasıl sabredeyim?"],["Böyle tez bir bakışla (çâpük-nazar), bir Musa'dan yüz bin Musa doğar;","hepsi sarhoş ve hayran — ben nasıl tedbir (çare) bulayım?"],["Âşıklara, Tûr'da münâcât etmek (yalvarmak) gerekmez;","ben nerede isem dost oradadır — her yeri Tûr eyleyeyim."],["Benimle, dosttan başka hiçbir şey kalıcı (bâkî) değil;","günümü O'nun yolunda harcanmış sayayım — gecemi uykusuz sabahlayayım (şeb-gîr edeyim)."],["Hidayet (doğru yol) herkese erdi — nefsinin isteğinden (hevâ) geçmeyenler hariç;","Allah'ın yardımına (tevfîk) yüz sürüp, aşkımı aslan tutan (güçlü) eyleyeyim."],["Hakikat ehli (muhakkikler), Yunus'un kendi gözüyle gördüğünü görür;","söylediğim bir rüya (düş) değil — onu yıldız (En-Necm/hakikat) ile yorumlayayım."]],"207":[["Gezinmeye (teferrüc) çıktım, sabahleyin mezarları (sinleri) gördüm;","kara toprağa karışmış şu nazik (narin) tenleri gördüm."],["Toprak içinde ten çürümüş, mezarda gizli (pinhân) yatar;","boşanmış damar, akmış kan, kana batmış kefenleri gördüm."],["Mezarları yıkılmış, dolmuş; hep evleri harap olmuş;","hepsi dünya kaygısından kesilmiş — ne zor (düşvâr) hâlleri gördüm."],["Yaylalar yaylanmaz olmuş, kışlalar kışlanmaz olmuş;","pas (bar) tutmuş, söylemez olmuş — ağızdaki dilleri gördüm."],["Kimi zevk ve eğlencede (işret), kimi saz ve müjdede (beşâret);","kimi bela ve sıkıntıda (mihnet) — günleri gece olmuş, öyle gördüm."],["O kara gözler sönmüş (sogulmuş), ay gibi yüzler belirsiz olmuş;","kara toprağın altında, bir zamanlar gül toplayan elleri gördüm."],["Kimi boyun büküp yatmış, tenini toprağa katmış;","anasına küsüp gitmiş — öyle boyun bükenleri gördüm."],["Kimi inleyerek (zâri kılıp) ağlar, zebaniler canını dağlar (yakar);","tutuşmuş mezarlarından (sinlerinden) ateşe çıkan dumanları (dütünleri) gördüm."],["Yunus şimdi bunu gördü, onu bize haber verdi;","aklım şaştı, aklımı ancak topladım (ög dirdim) — bunları işte böyle gördüm."]],"208":[["Hak'tan bana bir nazar (lütuf bakışı) oldu — Hakk'ın kapısını açar oldum;","Hakk'ın hazinesine girdim — inci ve cevher saçar oldum."],["Saadet (devlet) tacı başıma kondu, aşk kadehini bana sundu;","susadıkça ben de her an onu içer oldum."],["Sarhoş etti, aşka düşürdü; ben ham idim, aşk beni pişirdi;","aklımı başıma topladı (divşürdü) — hayrı şerden seçer oldum."],["Benim işim hayra döndü, başım kaygıdan (endîşe) âzâd (özgür);","nefsimin başını kesip, şer (kötü) işlerden kaçar oldum."],["Nefsin başı kesildi, öldü; günah ve fesat işleri geride kaldı;","Hak'tan bana nazar oldu — kanatlandım, uçar oldum."],["Uçtum, hoş bir yere kondum; bu dünyayı kalıcı (bâkî) sandım;","ey dostlar (yârân), sonra usandım — kondum ama yine göçer oldum."],["Göçenler menzile (durağa) erişti, varıp orada karar kıldı;","ömür geçti, söz (kavil) bitti — kendi varlığımdan (benliğimden) çaresiz (nâ-çâr) oldum."],["Canım burada çaresizdi (nâ-çâr), bu zindanda kalmıştım;","'gel' dediler, oraya vardım — kendi varlığımdan (benliğimden) geçer oldum."],["Yunus Hakk'a tanışalı (bilişeli), can ve gönül verişeli,","şu Tapduk'a erişeli — gizli sırrımı açar oldum."]],"209":[["Hani bende sabır ve karar (huzur) ki senin sözünü dinleyeyim;","hani bende akıl ve idrak (bil) ki sezdirmeden seni seveyim?"],["Hani bende o havsala (kapasite) ki hâlimi kimse bilmesin;","hani bende güç ve kuvvet ki senin aşkına dayanayım?"],["Canım seni seveli, benim hâlim bambaşka hâle döner;","hani bende o hâl ki dinin usûlünü (temellerini), ilmin edebini öğreneyim?"],["İzzet (şeref), erkân (tören) ve iyi nam, aşk yolunda birer eksikliktir (noksandır);","ben iyi namı ne yapayım — madem terbiyemi (beslenmemi) aşktan alırım?"],["Sana gerçekten âşıksam, utanmak (ârlanmaklık) nedir bana;","şükranla canımı vereyim — kınanma (melâmet) giysisini giysem de."],["Zühd (zahidlik), ibadet (tâat) ve dinin usûlü, aşkın sınırının (haddinin) dışında kalır;","secde, rükû ve kıyam bile onunla kıyas (nisbet) edilemez. (Yunus bunları reddetmez; aşkın, bu biçimsel ölçülerin çok ötesinde, ölçüye sığmaz olduğunu söyler.)"],["Dostun yüzü (sûreti) bir aynadır (gözgü); bakan, kendi yüzünü görür;","benliksiz (kendüsüz) gelen gelsin — ben sırrımı ona söyleyeyim."],["Can gözüyle (gönül gözüyle) bakan, Yunus'un kendi gözüyle gördüğünü görür;","yoksa yabancı (zahirî) gözle, kimseye ne söyleyebilirim?"]],"210":[["Dosttan bana haber geldi — kalkayım, sonra varayım;","kurbanlığa bu canımı vereyim, sonra varayım."],["Şu bir iki arşınlık bezin (kefenin) ne yeni var ne yakası;","onu kaftan edip sırtıma sarayım, sonra varayım."],["Can alıcı (Azrail) elbette gelecek, 'emaneti ver' diyecek;","ben emaneti (canı) sahibine (Allah'a) vereyim, sonra varayım."],["Canım gitti, ben öyle kaldım; çaresiz (nâ-çâr) olup yola girdim;","dostların sevindiğini (şâd olduğunu) da göreyim, sonra varayım."],["Münker ile Nekir gelecek, yer gök sesle (ünle) dolacak;","ben bunlara cevabını vereyim, sonra varayım."],["Suçum çok, günahım fazla (öküş); dünyada hoşça (gönlümce) yürürdüm;","ettiklerimin hesabını vereyim, sonra varayım."],["Beslediğim nazik (narin) teni, 'terk etmem' derdim onu;","kara toprağa ben onu koyayım, sonra varayım."],["Ben bu ömür harmanını dövdüm, ürünü getirdim, işte yine;","Yunus der: bu dükkânı toparlayıp düreyim, sonra varayım."]],"211":[["'Ol' deyince olduran o Kadîr (kudret sahibi), lütfeden Sübhân (Allah) benim;","rızkını kesmeden veren, herkese sultan benim. (Bu şiir de baştan sona, benlikten geçmiş fenâ hâlinde Hakk'ın dilinden söylenir; kul kendi benliğinden değil, kendisinde tecelli eden Hak'tan söyler.)"],["Nutfeden (bir damladan) Âdem yaratan, yumurtadan kuş türeten;","kudret dilini söyleyen, zikreden Sübhân (Allah) benim."],["Kimini zahid (sofu) eyleyen, kimini fâsık (günahkâr) eyleyen;","ayıplarını örten, delil ile burhan (kanıt) benim."],["Bir kuluna atlar verip, eş ve mal çokça verip;","kimisinin tek bir pulu (parası) yok — merhamet eden Rahmân benim."],["Sonsuzluk (ebed) benim, kalıcılık (bekâ) benim; o mutlak Kadîr ve Hayy (diri olan);","Hızır yarın (mahşerde) saka (sucu) olur — onu öyle kılan Gufrân (bağışlayan Allah) benim."],["Dört türlü nesneden (unsurdan) meydana gelen — bilin, işte delil benim;","ateş ile su, toprak ve yel — onları temellendiren Yezdân (Allah) benim."],["Ete, deriye, kemiğe beden bağlayan, ten perdelerini tutan;","kudret işim çoktur benim — hem zahir (görünen) hem apaçık (ıyân) benim."],["Hem bâtınım (iç) hem zahirim (dış); hem evvelim hem âhirim (bunlar Allah'ın isimleridir);","bütün bunları yaratıp, düzenini (tertîbini) kuran benim."],["Arada tercüman (Cebrail) yok; oradaki iş bana apaçık (ıyân);","bana dili (konuşmayı) veren O'dur — o denize umman (okyanus) benim."],["Bu yeri göğü yaratan, bu Arş'ı Kürsü'yü kuran (duruda eden);","bin bir adı vardır, Yunus — o Kur'an'ın sahibi benim."]],"212":[["Bütün bu kuru töreyi (erkânı) bırakıp, birlik yolunu tutan benim;","hırs ve tamah benden uzak — onları ardıma atan benim. (Bu şiir de fenâ hâlinde, Hakk'ın dilinden söylenir.)"],["Bakan benim, gören benim; alan benim, veren benim;","ne Cebrâil ne Mikâil — İsrâfil'i de yaratan benim."],["Yedinci kat yerlerde ben, sekizinci kat göklerde ben;","bu söylenen dillerde ben — hükmü tamamlayan benim."],["Bulutu emirle oynatan, yerde bereketi kaynatan;","elimde kudret ölçeği (şiniği), halka rızkını veren benim."],["Bir kararda (sabit hâlde) durdum; benim sırrıma kim erer?","Cahil beni nerede görebilir — gönüllere giren benim."],["Himmet (manevî gayret) ordusuna çağırayım, dostun eşiğine derilsinler (toplansınlar);","Arş önünde aklımla hizmet edip duran benim."],["Gökyüzünde melekler (feriştehler) — Yunus, bunlar ne murat eder?","Melekler uslu durmazsa, Arş'a çomak (topuzlu sopa) vuran benim. (Aşkın coşkunluğunu anlatan mübalağalı bir söz; fenâ hâlinde.)"],["Deli olmuştum, Yunus; aşk bana kılavuz oldu;","Hazret'e (Allah'ın huzuruna) dek, yalnız başına yüz süren benim."]],"213":[["Ey dost, aşkının denizine gireyim, gark olup (boğulup) yürüyeyim;","iki cihan bana meydan olsun — devrânımı sürüp yürüyeyim."],["Denize gireyim, gark olayım; ne elif, ne mim, ne dal (harf/biçim) olayım;","dostun bağında bülbül olayım — gülleri toplayıp (direm) yürüyeyim."],["Bülbül olup öteyim, gönül olup canları (gönülleri) kazanayım (üteyim);","başımı elimde tutayım (canımı vermeye hazır olayım) — yoluna varıp yürüyeyim."],["Bülbül olup gideyim, ey, nice gönüller gözeteyim (güdem);","yüzümü aşkla an be an toprağa sürüp yürüyeyim."],["Şükür, dîdârını (cemâlini) gördüm, kavuşmanın (visâlin) eşiğini aştım;","bu benlik-senlik şehrini (şârını) bırakıp yürüyeyim."],["Yunus'tur aşkın avaresi, çaresizlerin çaresizi;","derdimin çaresi sendedir — dermanımı sorup yürüyeyim."]],"214":[["Sırrımı söylesem, kimse dilimi bilmez;","sabretsem, gönlüm karar kılmaz (durmaz)."],["Ey akıllılar, ey akıllılar — siz söyleyin, ben ne yapayım;","o dostun yüzünü göreli, aklım başıma gelmez."],["Böyle bir düzenle (tertîple) işim nasıl başa varsın (bitsin)?","Elimden iş kalsa (dursa) da, canımdan iş (aşkın işi) kalmaz (durmaz) benim."],["Ne akıllıyım ne deli, işim neye benzer benim;","aşk denizine gark olup, gönlüm gözüm doymaz benim."],["Bu sevgi (mahabbet) ateşi, benim yüreğimde yanıp durur;","denize gark olsam bile, sönüp eksilmez (hata kılmaz) benim."],["Yılın on iki ayı, aşk ateşi içimde işte yanıp durur;","yandıkça (öd ağacı gibi) kokum artar — devrim (zamanım) geçse de solmam benim."],["Herkes Hakk'a yol vardı, sabırla Hakk'a erdi;","aşkın aslı ateştendir — o, benim sabrımla olmaz (aşk ateşi sabra sığmaz)."],["Gönlüme nice söyledim: 'var (git), sabret, uslu otur';","o an daha beter olur — öğüdümü almaz benim."],["Bu Yunus'un sureti (bedeni) ölüp toprak olsa bile,","bilin ki bâtınımdan (iç dünyamdan) aşkın sevgisi hiç gitmez benim."]],"215":[["Senden cevr ü cefa (eziyet) gelir — ben 'ah vah' etmeyeyim;","aşkının ateşine düşmüşüm — yanıp nasıl tütmeyeyim?"],["İşte yana yana yürüyeyim, bütün ciğerim kana döndü;","aşkından divane (deli) oldum — nasıl inlemeyeyim (zâri kılmayayım)?"],["Senin aşkının denizine düşüp gark olayım (boğulayım);","elimden tutacak kimsem yok — bırakma beni, batmayayım."],["Sekiz cennetin (Uçmağın) hurileri bir araya gelse bile,","sana (ey Peygamber) ümmet olmayanı, ben onların (o bahtiyarların) arasına katmayayım."],["Yunus Emre, sen bu sözü yüz bin kez söylesen az olur;","işitenler âşık olsun — sözü pek uzatmayayım."]],"216":[["Ey ehil (yola âşinâ) olan, söyle bana — ben nasıl durulayım (yatışayım)?","Ne türlü çare (tedbir) edeyim, ya nasıl bir arzu (sagınç) düşüneyim?"],["Canımda o güzel sevgili (büt) bitmiş (yeşermiş), gönlümü O tutmuş;","hey, beni O avutmuş — başka neye bağlanayım?"],["O beni öyle etmiş ki, geceyi gündüzden seçemem;","teni alsın, canı kazansın (utsun) — bırak, ben O'na aldanayım (kanayım)."],["Ben bir gevherim (mücevher), madenim (kânım) O; ben bir kulum, sultanım O;","aklım ve canım, gönlüm O — O'ndan niçin usanayım?"],["O'nsuzluğum bana haram; bütün sermayem (nakdim) O'ndan tamamdır;","bunun gibi lütuf ve keremi, nerede bulup dinleyeyim?"],["Bana 'Yunus' diyen O'dur, benim bağrımı delen O'dur;","beni bensiz (benliksiz) koyan O'dur — bırak ben O olayım, öyleyse bu 'ben' nedir? (Fenâda benlik silinir, yalnız O kalır.)"]],"217":[["Dost yüzüme bakalı, ben şahı (Allah'ı) görüp geldim;","o yücelerin yücesine, şüphesiz (bî-gümân) erip geldim."],["Sarhoşluğuma (esrikliğime) bakma, adımı deliye takma;","sarhoşluğum ezeldendir — o ilahî işreti (meclisi) sürerek geldim."],["Ezelden beri bilirdim, Elest'te (elest meclisinde) 'Belâ (evet)' dedim;","o ezelî (kadîm) denizden, sel olup akıp geldim."],["Senin ilahî işretine (meclisine) ermişim, davet çağrısını (sala) bekleyip durmuşum;","canı, dini ve imanı, şükrane (şükür) olarak verip geldim."],["Nur bana (ölüyü dirilten) İsa oldu, erenler dua kıldı;","kaç kez topraktan yeniden ayağa kalkıp geldim."],["Mansûr 'Ene'l-Hak (Ben Hakk'ım)' der; der ki: suretini (bedenini) ateşe yak;","deyin, darağacına gelsinler — ben darağacını (kendi fenâ darağacımı) kurup geldim. ('Ene'l-Hak', benlikten/suretten geçiş, fenâ hâlinde söylenir.)"],["Yunus'tan haber sormayın; dost nerede ise oraya varın;","haberi, O'nu gören verir — ben O'nu görüp geldim."]],"218":[["Zaman geçti, devir döndü;","sala verildi, kudse gidelim;","bu cihana gelen gitti;","sala verildi, kudse gidelim."],["Salihler (iyiler) kalmadı, gitti;","bu cihanı fesat (bozgun) tuttu;","bu cihanın işi bitti;","sala verildi, kudse gidelim."],["Şeytanlar (şeyâtîn) fırsatını buldu;","gönül kararıp öldü;","iyi (huzurlu) yaşam kıtlaştı (kesat oldu);","sala verildi, kudse gidelim."],["Âlimler okur ama bildiğini tutmaz;","halkı görür ama gözetmez (kollamaz);","gönüllerde safa (huzur) yeşermez;","sala verildi, kudse gidelim."],["İyiliği emretmek (emr-i ma'rûf), bu ana zar zor kaldı;","bid'at (sonradan çıkan) gelip sünnet öldü;","nasipli (bahtlı) nasibini aldı;","sala verildi, kudse gidelim."],["Ey Yunus, sen sözünü bil;","kendi hâline bir bak (nazar kıl);","ölüm gelmeden önce öl (nefsini öldür);","sala verildi, kudse gidelim."]],"219":[["Bana yüz bin cefa (eziyet) kılsan,","senden yüzümü döndürmem;","canımı dahi alırsan,","senden yüzümü döndürmem."],["Seni canla severim,","fermanınla kul olmuşum,","Kur'an ile and içerim:","senden yüzümü döndürmem."],["'Kiliseye gir' desen, girerim;","'çanı (nakûs) çal' desen, çalarım;","âşıklara biçimsel hesap (kalem) yoktur:","senden yüzümü döndürmem. (Bu, sevgiliye mutlak teslimiyeti anlatan mübalağalı bir sözdür; başka dine yöneliş değil — âşık, O'ndan dönmeyeceğini söyler.)"],["İsa mısın, Musa mısın,","ya da Ken'anlı Yusuf musun?","Vallahi sen canların canısın:","senden yüzümü döndürmem."],["Yunus, eğer gerçek âşıksam,","Hak yoluna sadıksam,","hizmetlere layıksam:","senden yüzümü döndürmem."]],"220":[["Ben bu yurttan (buralı) değilim; burada durup ne yapayım?","Nice tutsaklık tuzağını kopardım — gidiyorum."],["Ben o kimseyim ki melek bana baş eğer (Âdem'e secde sırrı);","Allah ile ahdim (sözüm) var — o ahdimi gözetirim."],["O ahdimi yerine getirdim; işte, benim işim kimindir (O'nundur);","daha ne zamana dek ben burada nefsin elbisesini (bedeni) giyeyim?"],["Aslında padişah olan kişiye, nefse köpek bakıcısı (sekbân) olmak yakışmaz;","öyleyse ne yapayım — ben de bu bedende sıkıntının (mihnet) tadını tadarım."],["Babamı yedi (kat gök) derler, anamı dört (unsur) bilirim;","oysa babam anam aslında birmiş — niçin tasa (gussa) yutayım?"],["Yedi ile ikiden, on sekizden, on dörtten,","on ikiden, on birden öteye adım atarım (bütün âlem katlarını aşarım)."],["Ben nice sağlam (iyi) işleri yolda bırakıp gitmişim;","o ağacın dalını budar oldum — hâlâ budarım."],["Yedi zindan kapısını, Yunus sıyrılıp (soyunup) çıktı;","artık sensiz kalmayayım — ben tasadan (gussa) bitkin düştüm (yadarım)."]],"221":[["İlk adım Yunus'tu; adımı 'âşık' koydum (taktım);","utanma ile edebi (alışılmış kaygıları) bıraktım — geride öyle bir nam bıraktım."],["İzzette (şerefte) kalmışken, bana âşıklık nedir?","Ben kendi elimle yüzüme kara çaldım (rezilliği seçtim)."],["Elimde, tekke yapacak bir köşe (bucak) yok;","âşıkların ev-barkını (yükünü), bir bohça gibi boynuma astım (her şeyi bıraktım)."],["Benim gibi bir tüccar, hangi tüccar sırf hayalle (sagınç) zenginleşir?","Bir pula gücüm yetmez — oysa Mısır'ın bütün malını yüklenmişim (çatmışım)."],["İsa, yanındaki yarım iğne yüzünden Hazret'e tam yol bulamadı;","öyleyse benim bunca dileğimle (yüküyle), yüküm (rahtım) nereye sığar?"],["Âşıklar mezhebinde (yolunda) Yunus utandı (şermisâr oldu);","gerçek âşık sevgiliye (ma'şûka) erdi — ben ise dünyaya kaydım."]],"222":[["Aşkın denizine girdim, dalgıç kuş (bahrî) gibi yüzer oldum;","denizleri gezerek (geşt edip), Hızır gibi dolaşır oldum."],["Cemâlini (güzelliğini) düşte (rüyada) gördüm, yazın kışın çok aradım;","dağda taşta bulamadım — denizleri süzer (tarar) oldum."],["Deniz balığına sordum — ona ermek (haberi) ırak (uzak) değil;","kırık gönlün (gönül sınığının) içine girdim — gönülleri onarır (düzer) oldum."],["Gönlümüz ulu bir şehir (şâr) oldu — o şehir gibisi nerede var?","Hazinesinden gevher (mücevher) aldım — dükkânın yüzünü bezer (süsler) oldum."],["Ben o dükkâncının kuluyum, cevherlerle doluyum;","dostun bağının bülbülüyüm — daldan (budaktan) gül düzer oldum."],["O dalda iman biter (yeşerir); iman bitince şüphe (gümân) gider;","gece gündüz işim hep budur — nefsime bir Tatar (amansız akıncı) oldum."],["Canım bu tene gireli, altına (paraya) hiç bakmam (önem vermem);","ayaklar altına düştüm — toprak gibi tozar oldum (alçakgönüllü oldum)."],["Tenim yol boyu toprak gibi tozar; nefsim yine de beni önden sürükler;","nefsin burcunu (kalesini) yüce (sağlam) gördüm — kazma aldım, onu kazar oldum."],["Kaza kaza yere indim; gör bu kara yüzlü (utanmaz) nefsi —","Peygamber'e bile saygısı yok; onun bağlarını (bendlerini) bozar oldum."],["Bu nefisle dünya fânî; öyleyse dünyaya gelen herkes hani (nerede)?","Beni aldattın, ey dünya — işlerinden bezdim (bîzâr oldum)."],["Yunus kalktı, yola girdi — bütün gurbetleri (gariplikleri) yanına alarak;","kendi ciğerimin kanıyla, hâlimin anlatısını (vasf-ı hâlimi) yazar oldum."]],"223":[["Bu cihana gelmeden, sevgiliyle (ma'şûkla) bir idim;","'Kul hüvallah (De ki: O Allah birdir)' sıfatlı, izsiz (bî-nişân) bir nur idim. (Ruhun, ferdîleşmeden önce ilahî birlikteki aslı anlatılır.)"],["O an ki orada hayat vardı, Hak ile birlik vardı;","o sonsuz (pâyânsuz) çağda, ne Musa ne Tûr idim (henüz hiçbir suret yoktu)."],["Hazret'te (Allah'ın huzurunda), o ölçüsüz (bî-kıyâs) kudrette O'nunla birlikteydim;","ne ortağım (şerîkim) vardı, ne kimseyle başka dosttum."],["Yer gök yaratılmadan, 'Kalû Belâ' (elestte 'evet') denmeden,","Levh ile Kalem çalınmadan (yazılmadan), Mi'râc'a (yükselişe) kadir idim."],["Nice kez geldim gittim, birçok suret (biçim) yarattım;","bu şimdiki devirde, Yunus suretinde göründüm. (Bu, tek hakikatin çağlar boyu çeşitli suretlerde görünüşüdür; ruh göçü değildir.)"]],"224":[["Beni buraya gönderen, ne işe geldiğimi bilir;","bu dünyada kararım (durmam) yok — gidiyorum, bir hizmet için geldim. (Bu şathiyede de konuşan, benlikten geçmiş fenâ hâlinde, peygamberlerde ve her surette tecelli eden o tek hakikati seyreden âşıktır.)"],["Dünyaya çok gelip gittim, erenlerin (ermişlerin) eteğini tuttum;","kudretin sesini (ününü) işittim — kaynayıp coşkuya (cûşa) geldim."],["Sert sözle gönül yıktım, ateş olup canları yaktım;","sırrımı âleme çaktım (açtım) — bu halkı seyre (temâşâ) geldim."],["Ben terzi İdris oldum, Şît oldum, bezi dokudum;","Davud'un güzel (görklü) sesiyle, âh edip inlemeye (nâlişe) geldim."],["O ay yüze âşık oldum, bal ağıza saçı (nisâr) oldum;","kara göze nazar kıldım (baktım) — siyah olup kaşa geldim (sevgilinin güzelliğine karıştım)."],["Musa oldum, Tûr'a vardım; koç olup kurbana geldim;","Ali olup kılıç salladım — meydana güreşe geldim."],["Deniz kenarındaki ova, kuyuda işleyen kova;","İsa'nın ağzındaki dirilten dua olup, ben işe geldim."],["Ay oldum, âleme doğdum; bulut oldum, göğe yükseldim;","yağmur olup yere yağdım — nur olup güneşe geldim."],["Kuru sözden (kâl ü kîl) geçenlere, yolda gözünü açanlara,","anlayıp hakkı seçenlere — gerçek bir vakıa (görüntü) olup düşlerine geldim."],["Dertlilerin dermanı benim, o marifet (Allah bilgisi) madeni (kânı) benim;","İmran oğlu Musa benim — Tûr Dağı'ndan aşıp geldim."],["Yolum, sana varan bir durak (turak) oldu; seher vakti söyleyen, Hak'tır;","Yunus Emre'nin dilinde, Hak olup dile düştüm (geldim). (Yunus'un dilinde konuşan, onun benliği değil, kendisinde tecelli eden Hak'tır.)"]],"225":[["Ey bana 'derviş' diyen — bende ne dervişlik var?","Dervişliğin yeşil yaylasında, benim hâlim (hareketim) kış gibi kısır."],["Kendimi beğenip görürüm, sallana sallana yürürüm;","kin, kibir ve düşmanlık (adâvet), gönlümü almış benim."],["Derviş adını edindim, dervişin giysisine büründüm;","yola baktım, utandım — hep işim yanlış benim."],["Şeyhim herkesten ulu, yolda uludan ulu;","oysa gönlüm kaygılıydı, nefsim ise rahattaydı (âsâyiş) benim."],["Hırkamı, tacımı (dış işaretleri) gözetirim; oysa bozuk (fâsid) işler işlerim;","her yanımdan gizlerim — bin bir bozuk iş benim."],["Yoldan haber sorarlar, söylerim, inanırlar;","kalbimi saf (temiz) sanırlar — vay, ne zor (düşvâr) bir hâlim var benim."],["İçime bakarsan, yarım paralık (buçuk pulluk) bir şey yok;","dışımın gürültüsünden (gavgâsından) ise âlemler dolmuş benim."],["Yüzüm (sûretim) halka güler — hani ya Hakk'a kulluk?","Bu yaşayışıma bakınca — hep işim yanlış benim."],["Yunus der: ey dostlar (yârenler), ey benim gerçeklerim, erenler;","bu yoldaki gerçek hâller, benim için Allah'a kalmış (O'nun hükmüne bırakılmış)."]],"226":[["Denizler bir kadeh dolusu olsa, benim susuzluğum kanmaz;","inlememi yenemem, gözümün yaşı dinmez benim."],["İşte yine sevgili (ma'şûk), Mansûr'un kadehini (fenâ kadehini) elime sundu;","dört yanımdan ateş vurdular — kimse hâlimi bilmez benim."],["Yana yana kül olup, sen sevgilinin (ma'şûkanın) yoluna;","günde bin kez yansam bile, dosttan yüzüm dönmez benim."],["Canım, aşkın kazmasına (külüngüne) Ferhad olup başımı koydum;","sürekli taşları keserim — oysa Şirin'im (sevgilim) beni hiç sormaz."],["Gel bizimle varalım, ta ki bahçelere giresin;","bostanlarım bayındır (ma'mûr) olmuş — ama yabancı (agyâr), benim gülümü dermez (toplayamaz)."],["Bizim ilin bahçeleri — bülbülleri durmadan öter;","taze gülleri açılmış — benim gülistanım (gül bahçem) solmaz."],["Yunus der: ey sultanım, aşk ateşine yandı canım;","dermanını verirsen, artık benim canım ölmez."]],"227":[["Beni öyle (göründüğüm gibi) sanmayın — ben kendi asıl özümden geldim;","ya da kendi gönlümle (isteyerek) bu kafese (bedene) girdim."],["Bu kafesi parçalayayım, hırs ile hevesi yıkayım;","bu nefsi zayıf kılayım — ta ki aslıma (kaynağıma) ulaşayım."],["Aslımın ne olduğunu bilmem — baba zaten bir bahanedir (ikincil sebep);","ezelden, ana karnında kan ile beslenip dirildim (asıl kaynağım bedensel değil)."],["Aşım artık kan değil — hırs ve heva (nefsanî istek) yoldaşım;","kuşum (ruhum) Hazret'e (Allah'a) uçar — ben ancak bir süreliğine tene girdim."],["Kâh ibadette (tâat) bir mü'minim, an be an münâcâttayım (yalvarıştayım);","kâh harabatta (mecazî meyhane/tekke) bir rindim (kalenderim) — ben acayip, çelişkili bir 'kolmaş' (ele avuca sığmaz biri)yim."],["Bana hikmetle (derin bir gözle) bak — ki sana apaçık (ıyân) olayım;","çünkü ben bu surette (bu biçimde) yüz bin türlü göründüm. (Tek hakikatin sayısız surette görünüşü.)"],["Yunus Emre, sen zindanda (bedende) kalmayacaksın;","zindan nerede, ben nerede — ki kimin malını yemişim de hapse düşeyim?"]],"228":[["Eyyub'um gibiyim, gönlü dertliyim — derde derman isterim;","âşığım, gönlü hastayım — cana cânân (sevgili) isterim."],["Yakub'um gibiyim — Yusuf için ağladım, ayrılık (firâk) çektim;","Yusuf'um — zindan içinde, Rahmân'ın lütfunu (fazlını) isterim."],["Musa'nın Tûr'una vardım, dostun cemâlini (güzelliğini) görmeye;","aklım ansızın (nâgeh) o an gitti — Sübhân'ın (Allah'ın) sırrını isterim."],["Bir mekâna varmışım ki orası benim yurdum değil;","Hızır ile karanlığa (zulmete) erdim — Âb-ı Hayat'ı (ölümsüzlük suyunu) isterim."],["Amel defterimi yüklendim, yola koyuldum (azm-i râh ettim);","istenen menzile (maksuda) varmak için, Hak'tan emir ve ferman isterim."],["Yunus Emre'yim — kimse hâlimi hiç bilmedi;","hâlimi arz etmek (sunmak) için, bir irfan ehli (merd-i irfân) isterim."]],"229":[["Kullukdan uzak olma — bir gün sultanı görürsün;","cemâlini (güzelliğini) gösterir — bir gün hayran olursun."],["'Gel beri, kulum' deyip, kalbine bir nazar (bakış) salıp,","ebedî kadehi (câm-ı ebedî) sunup — bir gün hayran olursun."],["Talip (mürit) ırmak gibidir, mürşit (rehber) deniz gibi;","gezip yol almayı (seyr ü seferi) hoş gör — bir gün ummanı (okyanusu) bulursun."],["Tenin kısmetini (payını/ölümü) aldıysa da, canın vahdeti (birliği) bulacak;","derdin varsa, ne olmuş — bir gün derman bulursun."],["Çaresiz, zayıf Yunus — neyi kıskanırsın (hased edersin)?","Bütün eşyalarını (esbâbını) döküp, bir gün çıplak (uryân) kalırsın."]],"230":[["Bugün sohbet bizim oldu — 'biz, bizim' diyen gelsin;","aşk bize balını (şehdini) içirdi — içip yutan gelsin."],["Kanaat hırkasının içinde, selâmet (esenlik) başını çektim (sığındım);","melâmet (kınanmışlık) gömleğini biçtim — ârif olup giyen gelsin."],["Bu aşk meydanında çağırdım, bir ses (âvâz) ettim;","müezzinlik bizim oldu, imam oldum — bana uyan gelsin."],["Bu ummanda çok türlü gevher (mücevher) vardır, ele girmez;","paha biçilmez inci kolay bulunmaz — cana başa kıyan gelsin."],["Suretin nakşını (dış görünüşü) silmekle, gönül mülkü temiz olmaz;","rahmet suyu akar, çağlar — gönlün kirini yıkayan gelsin."],["Ey dostlar, sözümü işitin: gündüzümü gece ettim (uykusuz geçirdim);","ben kendi özümü (benliğimi) kaybettim — bu Hak yola giren gelsin."],["Miskin Yunus onu (o hakikati) görmüş, eline bir divan (kitap) da almış;","âlimler onu okuyamamış — bu manadan sezen (tuyan) gelsin."]],"231":[["Biz dünyadan gider olduk — kalanlara selam olsun;","bizim için hayır dua edenlere selam olsun."],["Ecel belimizi büker, dilimizi söyletmez olur;","hasta iken hâlimizi soranlara selam olsun."],["Tenim ortaya açıla, yakasız gömlek (kefen) biçile;","bizi temiz (arı) bir biçimde yıkayanlara selam olsun."],["Azrail canımızı alır, damarda kanımız kurur;","kefenimizi serdiklerinde, saranlara selam olsun."],["Dostumuza gider olduk, tam maksadımıza eremedik;","namaz için üstümüze duranlara selam olsun."],["Bir sözdür araya söylenir; kimse bu yaraya dayanamaz;","bizi mezara (makbereye) götürüp koyanlara selam olsun."],["Buraya gelenlerin hepsi gider; asla dönülmez bir yola gider;","bizim hâlimizden haber soranlara selam olsun."],["Âşık odur ki Hakk'ı seve, Hak da derdine deva kıla;","bizim için hayır dua edenlere selam olsun."],["Miskin Yunus sözü söyler, gözü kanlı yaşla doldu;","bilmeyen bizi ne bilsin — bilenlere selam olsun."]],"232":[["Seni gören o göz, başka neye baksın;","seni sezen (tuyan) o can, tende ne karar etsin (nasıl dursun)?"],["Aşkına düşen âşık, her an derdine yanar;","ona derman, sana kavuşmaktır (vaslındır) — hekim ne tedavi (tîmâr) etsin?"],["Senin aşkın, ey ezelî şahım, bütün varını yoklukta bırakmış;","bu işareti (remzi) sezen âşık, yokluğu (fenâyı) avlasın (şikâr etsin)."],["Sen muhtaç olmayan (ganî) bir sultansın, sınırsız ve sonsuzsun;","vasfın kaleme sığmaz — dil (seni) nasıl saysın (şümâr etsin)?"],["Bu tadı (çeşniyi) tadana, bu gevheri yutana;","derdine düşen cana — hekim ne tedavi etsin?"],["Sana gerçekten kul olan, gönlünü sana veren;","seni kendinde bulan — artık nereye sefer etsin (gitsin)?"],["Bu sırrı sezen hani — canı iyice ârif (irfan ehli) ise;","gevher madeni (kânı) açıldı — alana haber etsin."],["Bu yolda sağlam (muhkem) durduk, nefsin boynunu vurduk;","sen şaha gönül verdik — düşman (şeytan) ne zafer kazansın?"],["Şimdi Yunus, Hazret'te iyice yüzü kara (utanmış) kalmış;","madem iflas etmiş (müflis), bir şeyi yok — neyle alışveriş (bâzâr) etsin?"],["Bu Yunus ne etsin, bu yola nasıl gitsin?","Gönlünü sana verip, gözlerini özlemle mahmur (humâr) etsin."]],"233":[["Ezelden (evvel kadîmden) geldim — yer gök yaratılmadan;","Arş, Kürsü, Levh ve Kalem hiç anılmadan önce."],["Dostla sohbetteydim, içeride halvetteydim;","Âdem ne kadarcık bir nesnedir — daha hiç anılmadan önce."],["Yüz yirmi dört bin can, benim canımın içinde;","gizli Muhammed canı (Nûr-ı Muhammedî) ise, bizden daha içeride."],["Hem canlar ona (o nura) bir perdedir; o, nur içinde nurdur;","aşk orada ezelîdir (kadîm) — canlar ayrılmadan önce."],["Aşk, Hakk'ın varlığıdır; yerin göğün bayındırlığıdır;","aşk bizi kendi parıltısı (pertev) etti — her birimiz o birliğimizden bir ışık."],["Önce Âdem'i yarattı, sonra peygamberleri;","en son Muhammed'in nuru, içimizden parladı (balkıdı)."],["Âdem babadan beri — veli, evliya, nebi;","Hak, Ahmed'i (Muhammed'i) her yönden şereflendirdi."],["Yetmiş bin yıl önceden, Muhammed'i yarattı;","Hak bizzat kendisi âşık oldu — bir yıldız vesile (bahâne) oldu. (Yaratılışın ardındaki ilahî sevgi anlatılır.)"],["O yıldız ki vardı — Âdem'in canı nerede idi (o zaman)?","Ya bunca peygamber — ağızdan anılmadan önce neredeydiler?"],["Âlimler bunu bilmez, her akıl ona ermez;","Yunus'a bu bir hidayettir — üstadımızdan (Tapduk'tan) keşfolundu."]],"234":[["Gözüm seni görmek için, elim sana ermek için,","bugün canımı yolda koyayım (vereyim) — ki yarın seni bulayım."],["Bugün canımı yolda koyayım — ki yarın karşılığını (ıvâzını) veresin;","cennetini (Uçmağını) bana gösterme — cennet için hiç arzum yok."],["Bana cennet (Uçmak) neme gerek — gönlüm asla ona bakmaz;","işte benim bu ağlayışım, kardeş (ahî), bir bahçe (bâg) için değil."],["'Cennet, cennetim' deyip mü'minleri özendirdiğin o cennet —","bir ev ile birkaç huri — kucaklamaya hevesim yok benim."],["Burada da bize oğul, kız, eş (çift ü helâl) verdin;","benim arzum ondan da geçti — benim âhım, dîdârın (cemâlin) içindir."],["Onu (cenneti) sen sofulara ver — bana seni gerek, seni;","ben seni nasıl terk edeyim, şu bir ev ve çardak için?"],["Yunus sana hasrettir — ona kendini göster;","işin zulüm değilse, sana varmam için adalet (dâd) eyle."]],"235":[["Niçin sen, (kötülüğü emreden) nefs-i emmâreyi bu gafletten uyandırmazsın;","Muhammed'in şeriatının gülünü (güzel rehberliğini) kendi yüzüne (kendine) sürmezsin?"],["Binlerce türlü hikmet yanında söylense de,","bedbahtlığın (şekâvet) pamuğunu, asla kulağından çıkarmazsın (sağır kalırsın)."],["Günahının çokluğunun uğursuzluğundan (şûmundan), imanının gülleri soldu;","niçin onları, inayet (lütuf) suyuyla her an sulamazsın?"],["O çok günahların, işte seni hasta (sayru) etti;","çaresiz, niçin varıp bu derde çare sormazsın?"],["Dostlarından utanıp, günahı gizlice işlersin;","seni yaratan Hâlik (Allah) hazır — niçin O'ndan utanmazsın?"],["Habîb'inden (sevgilin Peygamber'den), o derdinin tabibinden utanmazsın;","ne dilersen işlersin — meğer Hak'tan hiç utanmazsın."],["Senden önce olanları (öncekileri), kendi elinle mezara (sinleye) koydun;","bunu böyle görüp dururken, ölümünü niçin düşünmezsin?"],["Mustafa'yı (Peygamber'i) işittin ki bu yeryüzünde o bile kalmadı;","bunu böyle bilirken, ahiret hazırlığını (yarağını) niçin yapmazsın?"],["Yunus, sözünü kime söylüyorsun, ya kimin kaygısını çekiyorsun?","Halka öğüt edersin — ya kendini niçin o öğüde tutmazsın?"]],"236":[["Aşkın izini (eserini) sezen, sınırlayıcı din ve mezhep ayrımını aşar;","kendini yok sayan (benlikten geçen), mezhep-din ayrımı mı gözetir? (Aşka eren, biçimsel ayrılıkları aşar; imandan vazgeçmez.)"],["Aşk kime ererse, onda 'başkalık' (benlik) bırakmaz;","kendiliğinden (benliğinden) sıyrılan, aşktan zerre kadar ayrılmaz."],["Cennetten (Uçmaktan) umudu yok, cehennemden (Tamudan) korkusu yok;","kendi benliğini yitirip, artık hayrı şerri (ödül-ceza hesabını) elden bırakan. (Allah'ı ödül için değil, kendisi için sevmek.)"],["'Ben O'yum' demek, ancak benlikten geçmişe yakışır (revâ); onu benliğiyle (egosuyla) söyleyen yanılır (hatâ);","gerçek olan, kendi isteğini (rızâsını) terk edip, hesapçı aklı bırakıp aşka uyandır. ('Ben O'yum' sözü yalnız benliğin yok olduğu fenâ hâlinde geçerlidir; egonun değil.)"],["Âşıkları sorarsan — onlar mezhepsiz, belli bir millet (taassubu) gütmez (sınırlayıcı ayrılıkların üstündedir);","sakın — hâlâ gece-gündüz (dış ayrımları) sayıp duran, yolda takılıp kalmıştır. (Bu, taassubu/bölünmeyi aşmaktır; imanı bırakmak değil.)"],["O yolda, artık küfür ile iman, kâr-zarar hesabına geçmez (alışveriş konusu olmaz);","benlik levhasını (varlığını) silen kişi, bu kâr-zarar hesabından kurtulmuştur (fârig). (Kasıt: çıkar gözetmeden sırf Allah için sevmek; imanla küfrü eşitlemek ya da şeriatı kaldırmak değil.)"],["Yunus, sen benliğini (egoyu) gider; her ne olursa, onu dost (Allah) eyler;","acizliğini bil, sus (ebsem ol) — git, aşkın rengine boyan (kendini aşkta erit)."]],"237":[["Bu dervişlik yoluna aşkla gelen gelsin;","ya da dervişliğin ne olduğunu bir zerre (azıcık) sezen gelsin."],["Hele biz, bu yola riya (ikiyüzlülük) ile gelmedik;","bu melâmet (kınanmışlık) giysisini bizimle giyen gelsin."],["Gözüyle gördüğünü (başkasının kusurunu) eteğiyle örtsün (bağışlasın);","bu yol çok ince (zorlu) bir yoldur — yüreği dayanan gelsin."],["Büyük küçük erenler, bizi sevenler demiş ki:","geriye dönüp kaymasın — Allah'ı seven gelsin."],["Bu sözü (iddiayı) söyleyenden, bize bir nişan (kanıt) gerek;","sözün özü (muhtasarı) budur — canına kıyan gelsin."],["Yunus, kimse sırf sözle ehliyete (gerçek makama) geçmedi;","iş budur — kişi bütün varlığını (vücudunu) ortaya koymalı; öyle ortaya koyan gelsin."]],"238":[["İnsanlar fânî dünyayı ne yapsınlar,","Allah sevgisi varken?","Ya başka nereye gitsinler,","o dost (Allah) sevgisi varken?"],["Allah ile olan kişinin,","işi ihsan (güzellik) olur;","başka kaygıyı (teşvişi) ne yapsınlar,","Allah sevgisi varken?"],["Allah için, şu halka bir bakın:","güzel Hakk'ı (Allah'ı) istemezler;","ya malı mülkü ne yapsınlar,","Allah sevgisi varken?"],["Ey âşıklar, bu sözü dinleyin —","Allah sizi ondan nasiplendirsin;","ya oğlu kızı ne yaparsın,","Allah sevgisi varken?"],["Yunus, sen kendini (beğenip) görme;","ibadet et, ondan mahrum kalma;","başkasına (gayrısına) gönül verme,","Allah sevgisi varken."]],"239":[["Dervişlerin yoluna sıdkıla (içtenlikle) gelen gelsin;","Hak'tan başka (özge) her şeyi gönlünden süren gelsin."],["Dervişler dedikleri, tükenmez bir maden (kân) olur;","seçkin-halk, kul-sultan — bu madenden alan gelsin."],["Derviş (güneş gibi) batar doğar, her nefesi göğe ağar (yükselir);","ben doğruyu söyleyeyim — canına kıyan gelsin."],["Dervişlik bir lokmadır — yerden gökten ulu (büyük);","bu azametli (kocaman) lokmayı yutup sindiren gelsin."],["Dervişin gözü açık, gece gündüz uyanık (ârif);","bu söze Tanrı'm tanık — bakmadan gören (kalp gözüyle gören) gelsin."],["Dervişin kulağı uyanık (sak) — dersini (sebak) Hak'tan işitir;","dil-dudak kımıldamadan, sözü işiten (kalp kulağıyla) gelsin."],["Dervişin eli uzundur — inkârcının (münkirin) gözünü çıkarır (inkârını alt eder);","doğuya batıya dümdüz uzanır — elini uzatmadan her yere eren gelsin."],["Dervişler Hakk'ın dostu — canları Hak ile mest (sarhoş);","aşkın mumunu (şem'ini) yaktılar — pervane (kelebek) olan gelsin."],["Bu miskin Yunus'a bak — dervişlik ede geldi;","asıl şikâyeti nefsindendir — nefsini öldüren gelsin."]],"240":[["Şükür, şükür o Çalab'a (Allah'a) — maksudıma (dileğime) erdim bugün;","bunca zaman özlemişim (müştaktım) — pîrimin yüzünü gördüm bugün."],["Kaygı beni almıştı, canım zebun (âciz) olmuştu;","pîrimin yüzünü gördüm — o kaygıyı sürdüm (kovdum) bugün."],["Gelsin yardan (sevgiliden) ayrı düşen, gurbetle bağrı pişen (yanan);","dostun bahçesi içindeki aşk meclisine (bezmine) girdim bugün."],["Görün görün bu saadeti (devleti), bu aşkla gelen müjdeyi (beşâreti);","dostun bağı içinde ben aşk çadırını kurdum bugün."],["Yunus der: yârin (dostun) kuluyum, dost bahçesinin bülbülüyüm;","bundan böyle (şimden girü) söyleyeyim — gül bahçeme (gülzârıma) erdim bugün."]],"241":[["Ey dostlar, ey kardeşler — ecel erişir, bir gün ölürüm;","işlerime pişman olup, bir gün kendime gelirim (aklımı başıma toplarım)."],["Ellerim yanlarıma konur, dilim söz söylemez olur;","amelim karşıma gelir — ne ettiysem, bir gün görürüm."],["Çocuk (Kur'an okuyan) hocaya gider, dosta düşmana sala (cenaze çağrısı) verilir;","o dört tekbirli (cenaze) namazıyla, bir gün vaktimi (ömrümü) tamamlarım."],["Giysim beş karış bezdir (kefendir), tenimi yılan-çıyan yer;","yıllar geçer, mezarım (sinim) çöker — bir gün unutulup kalırım."],["Başıma (mezar) taşı (hece) dikerler, ne sabahı bilirim ne geceyi;","ey âlemlerin ümidi olan efendi (Allah'ım), bir gün sana tümüyle ferman olurum (boyun eğerim)."],["Yunus Emre, sen bu sözü (işini) daha tamamlamamışsın;","bırak yürüyeyim, ne yapayım — bir gün üstadıma (Tapduk'a) gelirim (dönerim)."]],"242":[["Suretten (dıştan) sıfata (iç manaya) gel — yolda safâ (gönül arılığı) bulasın;","hayallerde (kuruntularda) kalma — yoldan mahrum kalırsın."],["Bu yolda çok acayip (şaşırtıcı) şey var — sen onları asıl acayip sayma;","asıl acayip oradadır — dostun yüzünü göresin."],["Aşk kuşağını kuşan, dostun yoluna var;","mücâhede (nefisle savaş) çekersen, müşâhadeye (ilahî görüşe) erersin."],["Buradan aşkın şehrine, üç yüz deniz geçerler;","üç yüz denizi geçince, yedi cehennemi (Tamu) bulursun."],["Yedi cehennemde yan, her birinde kül ol;","kendi varlığını orada bırak — o zaman başka (yeni) bir varlık bulursun (benlik ölür, yeni varlık doğar)."],["Hakikattir Hakk'ın şehri (şârı) — kapıları yedidir;","dergâhında, yüz türlü kudret görmen gerek."],["İlk kapısında bir kişi durur orada;","sana der: 'teslim ol, gel — miskinlik (benlikten geçme, fenâ) bul.'"],["İkinci kapısında iki aslan vardır orada;","nicelerini korkutmuş — sakın sen korkma."],["Üçüncü kapısında üç ejderha (evren) vardır orada;","sana hamle ederler (saldırırlar) — sakın geri dönme."],["Dördüncü kapısında dört pîr vardır orada;","bu söz sana bir remizdir (gizli işaret) — bak ki sana kılavuz (delil) bulasın."],["Beşinci kapısında beş rahip (ruhban) vardır orada;","türlü mallar (metâlar) satar — sakın onlardan alma (kanma)."],["Altıncı kapısında bir huri (Hûr) oturur orada;","sana der: 'gel beri' — sakın ona varma."],["Çünkü oraya varır, o huriyi alırsan;","bir küçük nasip (vâye) uğruna, asıl yoldan mahrum kalırsın."],["Yedinci kapısında yediler (erenler) oturur orada;","sana 'kurtuldun' derler — gir, dostun yüzünü göresin."],["İçeri girince, dostun yüzünü göresin;","Ene'l-Hak ('Ben Hakk'ım') şerbetini, dostun (Allah'ın) elinden içesin. (Bu, benliğin yok olup yalnız Hakk'ın kaldığı fenâ hâlidir; egonun tanrılık iddiası değil, Hak'tan gelen bir lütuftur.)"],["Şu söylediğim söz (keleci), senin varlığından dışarıda değil;","tefekkür edersen (düşünürsen), hepsini kendinde bulursun (bu yolculuk içeridedir)."],["Yunus bu sözleri, Hakk'ın varlığından (Hak'tan) söyler;","bu hakikatin madenini (kaynağını) istersen — onu miskinlerde (benlikten geçmiş alçakgönüllülerde) bulursun. (Sözün kaynağı, Yunus'ta tecelli eden Hak'tır.)"]],"243":[["Felek (gökyüzü) yokken, canlarımız vardı;","biz o vakit dosttuk (Allah ile) — Azrail (ölüm) daha yabancı (agyâr) iken."],["Nice yıllar biz orada toplanmıştık, canların madeninde (kânında);","hakikat âleminde, marifet (Allah bilgisi) söylenirken."],["Çalap'ın (Allah'ın) aşkı candaydı, bu tanışıklık (bilişlik) o zaman vardı;","Âdem-Havva neredeydi — biz O'nunla yâr (dost) iken?"],["Sonradan (dün) saf (sâfî) Âdem geldi, dünyaya ayak (kadem) bastı;","İblis (şeytan) o an onu aldattı — cennette (Uçmak'ta) gezerken."],["O vakit biz uçardık, dolaşıp (cevlân urup) göçerdik;","nurdan şarap (mecazî: ilahî aşk) içerdik — Hak bizi ziyafetle toylar iken."],["Canlar orada tanıştı, o an gönüller kaynaştı (alıştı);","âlem halkı birbirine karıştı — denizler kaynarken."],["Şükür, bu (vuslat) anına geldik, dostları burada bulduk;","tuz-ekmek birlikte yedik (dostluk kurduk) — aşkın demini (zamanını) oynarken (kutlarken)."],["Ne oğul vardı ne kız — orada biz bir (vâhid) idik;","hepimiz komşuyduk — nur dağını yaylarken (ilahî nurun yakınında konaklarken)."],["Ne gök vardı ne yer, ne üst (zeber) vardı ne alt (zîr);","Yunus, dosttan haber ver — aşkla için için yanarken (göynerken)."]],"244":[["Aklım başımdan gidiyor, şaşırıp (kendimden geçip);","yanıyorum, aşkın ateşine (oduna) düşüp."],["Canıma ateş (od) bıraktın, gece gündüz yanar;","yanıyorum alev alev (yalap yalap), tutuşup."],["Aşktan ne (zarar) var, eğer kırıldıysam (yenildiysem);","aşkla uğraşıp (güreşip) de kim kırılmadı (yenilmedi) ki?"],["Sevgilinin (ma'şûkun) cemâline (dîdârına) âşık ol;","aşkla sarmaşıp (kucaklaşıp), sen de sevgili (ma'şûk) ol."],["Yunus, canını aşka ver — şükran (nişanesi) olarak;","kimse, ısrarla isteyip durmakla yâri (sevgiliyi) bulmaz."]],"245":[["Gönül hayran olmuş — aşkın elinden;","ciğer (kebap gibi) kavrulmuş (biryân) — aşkın elinden."],["Niceleri tac ve tahtı, mal ve mülkü;","bırakıp çıplak (uryân) kalmış — aşkın elinden."],["Kendimin (özümün) sabrı ve kararı kalmadı;","gözüm ağlar (giryân) olmuş — aşkın elinden."],["Karlı dağlar zerre zerre eridi;","deniz, kabarıp umman olmuş — aşkın elinden."],["İbrahim Edhem, tac ve tahtı bırakıp;","yeri (hamam) külhanı olmuş — aşkın elinden. (Tahtını bırakıp en alçak yerlerde yaşayan zâhid.)"],["Ne güzel (zihî) Mansûr ki, sevgilinin (ma'şûk) yolunda;","başı darağacına (ber-dâr) asılmış — aşkın elinden."],["Mecnun, Leyla'nın yüzünde ne gördü;","ki başı dönmüş (ser-gerdân), şaşkın olmuş — aşkın elinden?"],["Züleyha, Yusuf'un yüzünde ne gördü;","ki işi feryat (efgân) olmuş — aşkın elinden?"],["Bülbül, sevgi (mahabbet) derdine düşeli;","dili (sesi) neşeyle şakır (handân) olmuş — aşkın elinden."],["Yunus Emre'm, bu hasrete, bu ağlayışa (zâra);","acayip bir konuk (mihmân) olmuş — aşkın elinden."]],"246":[["Sakın, gönlünü dünyanın payına (nimetine) verme;","dünyaya gönül veren, bir gün onun yemine (tuzağına) düşer."],["Bu dünya, insanları yutan bir ejderhadır (evren);","bize de gelip, bir gün kendi ziyafetinde (bizi) yutar."],["Görmez misin, toprak — seçkinleri (büyükleri) kucaklamış (mezarda) yatar;","bizi de, bir gün onun gibi koynuna alır."],["Yuvası doğan (yırtıcı kuş) elinde olan o kuş —","orada nasıl güvenle dursun? Bir gün kendi yaylasına (asıl yurduna) kaçıp gider. (Dünyanın pençesindeki can, asıl yurduna kaçmalı.)"],["Miskin, çaresiz Yunus — erenin (ermişin) eteğini tut;","ta ki seni Hakk'a iletsin — bir gün onun soyuna (manevî topluluğuna) katıl."]],"247":[["Kişinin kendini bilmesinden daha iyi ne var?","Kendini bilen kişi, hepsinin içinde seçkindir (güzin)."],["Kişi çok bilmeli, öğüt almalı (dinlemeli);","'menzile (manevî durağa) ereyim' diyen — bilirsin ki oraya hüzünle, gözyaşıyla erer."],["Bu yol çok (yavlak) uzaktır, dünya ona bir tuzaktır;","bu tuzağa uğrayan, kılavuzunu (rehberini) bırakmasın."],["'Emin (güvende) olayım' diyen, ya da emniyet isteyen —","şu kuru sözü (kâl ü kîl) bıraksın, yüzünü toprağa sürsün (tevazu etsin)."],["Kim erene (ermişe) hizmet ederse, o azaptan kurtulur;","kim erin (ermişin) yüzünü görürse, mutlaka bağışlanır (yarlıganır)."],["Yunus bir haber verir — işitenler sevinir (şâd olur);","'hazineye (gence) ulaşayım' diyen, erenin (ermişin) izini izlesin (takip etsin)."]],"248":[["'Allah'ın ortağı yok (lâ-şerîk)' diye okursun — sonra (yaşayışınla) ortak katarsın;","'Bir'e iki demeyi, kimden fetva (izin) alıyorsun?"],["Din ile imanın temeli (bünyâdı), doğruluk ile gerçekliktir;","o tamam olmayınca, neyle din kurarsın (çatarsın)?"],["Madem Kur'an gökten indi, onu Allah buyurdu;","ondan (asıl manadan) haber versene — oysa hâlâ kitabı papağan gibi tekrarlıyorsun (ötersin)."],["Tertiplenmiş kitapları okursun, nice gramer-sözdizimi (binâ vü i'râb);","oysa sende ilahî korku-ümit (havf ü recâ) yok — sanki duygusuz bir hayvan (davar) gibisin."],["İlim okumak, bilmek — aslında kendini bilmektir;","öyleyse kendini bilmezsen, bir hayvandan betersin."],["İlim okumanın manası, ibret (ders) anlamak içindir;","madem ibret almıyorsun, anlayıp görmeden taş atarsın (körü körüne eleştirirsin)."],["Mustafa (Peygamber) on iki bin hadis topladı;","onu işittin — oysa şerh (açıklama) ile sadece söz satarsın (laf edersin)."],["Riya (gösteriş) ile namaz kılarsın, günahın çok, hayrın az;","dinle, söz nereye varır — böyle gidersen cehennemde yatarsın."],["Halka fetva verirsin — ya sen niçin ona uymuyorsun?","İlmin var, amelin yok — hâlâ günaha batarsın."],["Sen fakihsin (fıkıh bilgini), ben fakir (yoksul) — sana bir itirazımız yok;","ihlasla (samimiyetle) gelirsen, bizden bir şey kazanırsın (ütersin)."],["Bu kurulan düzeni (tertibi/yolu) 'başkalaştı (bozuldu) mu' dersin;","hayır, sen başaramazsın (kavrayamazsın) hoca — kuru kaygıdan (endişeden) tükenirsin."],["Miskin Yunus bu sözü, aşk âleminden söyler;","bilmeden (onu yargılayıp) söyleme — yoksa ona kendinden (kendi kuruntundan) katarsın (çarpıtırsın)."]],"249":[["Hak, kendi kudretinden bir gevher (cevher) yarattı;","gevhere bir nazar (bakış) kıldı — o gevher, O'nun heybetinden (azametinden) eridi."],["Yedi kat yeri, o gevherin nurundan yarattı;","yedi kat göğü, o gevherin buğusundan (buharından) yarattı."],["Yedi denizi, o gevherin damlasından yarattı;","dağları, o denizin köpüğünden sağlam (muhkem) kıldı."],["Muhammed'i, yaratılmışlara olan şefkatinden yarattı;","Ali'yi de, mü'minlere olan lütfundan (fazlından) yarattı."],["Gayb (görünmeyen) işini kim bilir — meğer Kur'an'ın ilminden bilinir;","Yunus, o gevherin denizinden içti, manen esridi (kendinden geçti)."]],"250":[["Eğriliğini bırak, doğru yola gel;","kibir ile kini içinden çıkar — erenden (ermişten) nasip alasın."],["Elinle (sadaka olarak) ne verirsen, ancak o seninle öteye gider;","ben söylesem inanmazsın — oraya varınca görürsün."],["Gönülde pas oturur, orada seni yitirir (yolundan eder);","içeride şah (Allah) oturur — oysa pas yüzünden giremezsin; göreceksin bunu."],["İç âlemin on iki hücresi (odası), yedi kapısı (dervâzesi) vardır;","orada iki dilber (güzel/değerli hakikat) var — onları bilmezsin ki varıp sorasın. (İç âlemin gizli odaları anlatılır.)"],["Git, kardeşini öldür; bir de avradını (eşini) boşa;","anana nikâh kıydır — ki Hakk'ı apaçık (ıyân) göresin. (Bu tamamen sembolik bir şathiyedir, asla harfî değildir: 'kardeş' = insanla birlikte doğan nefs/ego, onu öldür; 'eş' = dünya ve dünya hevesi, ondan vazgeç; 'ana' = aslın/öz benliğin, ona dön. Bu iç temizlikle Hak apaçık görünür.)"],["Çaresiz, miskin Yunus — sen aşktan dem vurur, âşıklık iddiası kılarsın;","dosttan haber gelince, yüz süre süre (tevazuyla) varasın."]],"251":[["Gelin bugün yanalım — yarın (ahirette) yanmamak için;","ölelim (daha) ölmemişken (nefse ölelim) — yeniden (manen) ölmemek için."],["Günahımızı tartalım, âhımızı (pişmanlığımızı) artıralım;","hesabımızı kendimiz görelim — (mahşerde) hesaba çekilmemek için."],["Erenlere (ermişlere) gidelim, eteklerini tutalım;","bugün böyle edelim — yolda kalmamak için."],["Bak da dünyaya gör, niçin geldiğini bil;","şu fânî dünyaya mağrur olmamak (aldanmamak) için."],["Yunus, dünyanın tadı yok — madem adı 'fânî' (geçici) imiş;","Muhammed onu 'zindan' dedi — biz ona aldanıp sevinmeyelim diye."]],"252":[["Aşk ilinin (diyarının) haberini söylesem, işitir misin;","yoldaş olup bu yola, sen de benimle gider misin?"],["O ilin bahçesinin şerbeti, zehir (agu) olur;","o zehri kadeh bile tutmaz — onu içip yutar mısın (acıya katlanır mısın)?"],["O ilin azığı (zavadası), seni tutup götüren cefâdır (eziyettir);","şekeri başkasına sunup, sen kendin zehir tadar mısın?"],["O ilde ay-güneş olmaz, ay küçülüp batmaz (zaman yoktur orada);","zamana bağlı düzenleri (tertibleri) bırakıp, vakit saymayı (şumârı) unutabilir misin?"],["Senlik-benliği (ikiliği/egoyu) bırakıp, yokluk (fenâ) evine girip;","aşktan içip esriyerek, kendi varlığını terk edebilir misin?"],["Şu tenin terkibi (yapısı): ateş, toprak, yel ve su;","Yunus, sen asıl özünü gör — yalnızca suda toprakta mısın (bedenden mi ibaretsin)?"]],"253":[["Aşkın denizine dalayım, bir zaman dalgıç (gavvâs) olayım;","seni daima isteyeyim, bir zaman seyyah (gezgin) olayım."],["Her bir meclise (mahfile) varayım, sırrımı her dile söylemeyeyim;","sırdan haber verenlere, bir zaman konuk (mihmân) olayım."],["Senin yolunda Mansûr olayım, Ene'l-Hak ('Ben Hakk'ım') deyişini söyleyeyim;","sana kavuşmanın (vaslın) darağacına asılıp, bir zaman ber-dâr (asılmış) olayım. (Ene'l-Hak, benliğin yok olduğu fenâ hâlinde Hakk'ın dilinden söylenen sözdür; egonun iddiası değildir.)"],["Aşkın ateşine (oduna) yanayım, derdinin suyuna kanayım;","gördüğümü sen sanayım (her şeyde seni göreyim), bir zaman hayran olayım."],["Kanlı yaşımı akıtayım, bağrımın yarasını (başını) artırayım;","ta ki nakkaşımı (beni yaratan Ressam'ı) bulunca — bir zaman seyran (temaşa) edeyim."],["Leyla ile Mecnun olup, Ferhad ile taşlar yontup;","Abdürrezzak (Şeyh San'an) gibi aşkla yanıp, bir zaman ağlayan (giryân) olayım."],["Benliğimi (egomu) benden uzaklaştırayım, senin kokunu duyayım;","bunca zaman ben kul iken, bir zaman sultan olayım (benlikten geçip ruhun sultanlığına ereyim)."],["O dost bana benden yakındır; hikmet bilen, Hakk'ı bulur;","hikmet ilmini okuyup, bir zaman bilge Lokman olayım."],["Miskin Yunus, gözünü aç, yüzünü Hazret'e (Allah'a) sür;","kâmil mürşidin (rehberin) yoluna, bir zaman kurban olayım."]],"254":[["Âşıklara ne söyleyeyim — aşkın haberinden tatlı (şîrîn) ne var?","Aşkla dinleyene, birer birer söyleyeyim."],["Aşksızlara aşktan haber söylemek, yazıktır (hayftır);","kim gerçek âşıksa, ben sırrımı (râzımı) ona söylerim."],["Başlangıçta yer-gök yoktu, ama aşkın temeli (bünyâdı) vardı;","aşk ezelden ebedîdir (kadîm) — var olan ne varsa aşk getirdi."],["Ezelî meclis (bezm) (elest) günü, kim dostun yüzünü gördüyse;","o kişinin canı âşıktır — aşkın haberini ondan sor."],["Aşkı hiçbir şeye benzetemem (mesel bağlayamam);","ne dünyada ne ahirette, hiçbir şey aşkın yerini tutmaz."],["Aşkın haberi bir emanettir, sakın onu koru, aman;","oturup her rastgele yerde, aşkın sözünü söyleme."],["Cevhercilerin (kâmillerin) katında kural böyledir:","değerini bilmeyenlere, gevherini (mücevherini) göstermez."],["Yunus'un anlayışı (havsalası), sînesi (göğsü) aşkla dolmuş;","derdini gizleyemedi — artık gizlisiz (açıkça) aşkın dilini söyler."]],"255":[["Sen daha canından (benliğinden) geçmeden, cânân (sevgili) arzu edersin;","belinden zünnârı (içindeki küfür/benlik kuşağını) kesmeden, iman arzu edersin."],["'Men arefe nefsehu (nefsini bilen Rabbini bilir)' dersin — ama o kişi değilsin;","yine de meleklerden (melâik) daha yükseğe çıkmayı (seyranı) arzu edersin."],["Yeni yetme bir çocuk gibi, eteğini at edinip oynarken;","ele henüz çevgân (cirit değneği) almadan, meydanı (gerçek oyunu) arzu edersin."],["Sen kendini bilmedin — sadefte (inci kabuğunda) nasıl bir gevhersin (incisin);","Mısır'da sultan iken (Yusuf gibi), Ken'an'ı (yurdunu) arzu edersin (kendi değerini görmezsin)."],["O ezel âleminde, ebedini (sonsuz nasibini) gözetmedin;","kanatların (per ü bâlün) bitmeden (çıkmadan), uçmayı (cevlânı) arzu edersin."],["Yetmiş yedi perde var — daha dostunu arzulama;","onların yedisinden geçmeden, yakîn (kesin bilgi) arzu edersin."],["Otuzu gözde durur, otuzu gönüldedir;","kalan onu da bilmeden, Hakk'ı görmeyi arzu edersin."],["Sen buraya bir iş için geldin, işte yine öteye döneceksin;","henüz tam kul olmadan, sultan olmayı arzu edersin."],["Yunus, sen bu derde düştün — Eyyub gibi sabret;","oysa derde katlanamıyorsun, hemen derman arzu edersin."]],"256":[["İlmine (bilgine) gark olup (batıp), ben kendimi bilemem;","dille söyleyip de, senin sıfatına erişemem (seni anlatamam)."],["Sıfatın dile gelmez, nerede olduğunu (kandalığını) kim bilir;","senin sanatını (sun'unı) söylemeye, ben layık olamam."],["Hem evvelsin (ilksin) hem âhir (son), bütün yerlerde zâhirsin (görünürsün);","sensiz hiçbir makam (yer) yok — ben niçin seni göremem?"],["Seni görmeden deli oldum, yanıldım, günah kıldım;","aklımı, usumu kaptırdım — esridim (kendimden geçtim), ayılmam."],["Madem beni esrittin, canımı gönlümü alıp götürdün;","beni senden ayırma — sana kavuştum, artık yabancı (yad) olmam."],["Canı bana sen verdin, alınmasını Azrail'e bildirdin;","yine de emaneti (canımı), senden başkasına veremem."],["Ey Yunus'u yaratan — aradan perdeyi (hicabı) kaldır;","yolunda ben sadığım (doğruyum), yalan iddia (da'vî) etmem."]],"257":[["Bunca gönülleri alan sen — cihana sultan mısın?","Hükmün canlar içinde — can içinde can mısın?"],["Nazarın (bakışın) bin can alır, derdin yürekte kalır;","gören kendinden geçer — âşığa kıyan (onu can veren) mısın?"],["Uçan kuşlar ürker (uçunur), esen yel seni görse durur;","devler hükmüne girer — Belkıs-Süleyman mısın (cinlere, rüzgâra hükmeden)?"],["Yüzünden güneş tutulur, ay doğmaya utanır;","gören heybete (görkemli bir korkuya) kalır — Ken'anlı Yusuf mısın (güzelliğiyle ünlü)?"],["Ölü seni görse dirilir, kalıbına (bedenine) can gelir;","topraktan ses (âvâz) gelir — Meryem oğlu İsa mısın (ölüleri dirilten)?"],["Aşkın dine (gönüllere) coşku (şûr) salar, aslana zincir vurur (vahşiyi ehlîleştirir);","katı taşı mum eyler — çağın Ferhad'ı mısın (taş delen âşık)?"],["Aşkın Hakk'a eriştirir, can gözü dîdârı (cemâli) görür;","görenler baş eğer — İbrahim Edhem misin (tahtını bırakan veli)?"],["Yüzün dîdâr (cemâl) nurudur, saçın Mi'râc gecesidir;","gören canını unutur — âlemin övüncü (Fahr-ı âlem, Hz. Muhammed) sen misin?"],["Yunus, sevdiğini gözet, Hak yolunu iyice izle;","sırrını (râzını) gönülde gizle — yoksa sadece söze (lafa) mı kaldın?"]],"258":[["Bu ömrümü boş yere harcamışım ben;","canımı gör, ne büyük ateşe atmışım ben."],["Kimsenin kimseye etmediğini;","onu ben kendime etmişim ben."],["Amelimin yükünü (rahtını) topladım, götürdüm;","bütün kârımı (assımı) zarara satmışım ben."],["Cihanda bir kırık saksı (değersiz şey) uğruna;","gevherlerimi (mücevherlerimi) zarara satmışım ben."],["Amelim ne varsa, hep riyadır (gösteriştir);","şaşılacak şey — ihlası (samimiyeti) unutmuşum ben."],["Gecesi nereye varır (ömrü ne zaman biter), kimse bilmez;","oysa ben, bitmez tükenmez dünya arzusunu (tûl-ı emeli) uzatmışım ben."],["Herkes ömrünü boş harcamaya sürdü (tüketti);","ne kazandığım (ne ütmüşsem), zarardan bellidir benim."],["Zehre (aguya) bal diye parmak uzattım;","aşıma (yemeğime) öldürücü zehir (zehr-i kâtil) katmışım ben."],["Çaresiz Yunus'un günahı çoktur;","yine de O'nun dergâhına (kapısına) yüz tutmuşum ben (rahmetine sığınmışım)."]],"259":[["Dostun yüzünü görünce, bu can nasıl karar (sükûnet) kılsın;","o an yüz bin zâhid (sofu), din ü imanını yağmaya verir (vecd içinde biçimsel kaygılarını unutur). (Bu, doğrudan ilahî görüş karşısında biçimsel ibadetin coşkuyla aşılmasıdır; imandan dönmek değil.)"],["Âşıkları kınamayın (ta'na urmayın), hangi hâle dönerlerse dönsünler;","müşâhadeye (ilahî görüşe) gark olan, artık kendine hâkim (ferman) olamaz."],["Can ile gönül, anlayış ile akıl, aşkın dalgasına (mevcine) gark olunca;","o kişi artık günahı, sevabı, kârı-zararı nasıl ansın (hesaplasın)? (Aşka dalan, çıkar hesabını aşar.)"],["Canında iç gözü olmayan kişi, dostun yüzünü göremeyecek;","gözsüz (kör) olan, bu cihanın ne renkte olduğunu nasıl anlasın (fehm etsin)?"],["Yüz bin hükümdar ve sultan, dostun yüzünü görünce;","tahtını, izzetini (şerefini), askerini, ev-barkını terk eder."],["Âşık ne kadar harap (kendinden geçmiş/yıkık) ise, velayeti (ermişliği) o kadar artar;","çünkü gizli hazine (genc-i nihân), daima virânededir (benlikten geçmiş gönüldedir)."],["Ayne'l-yakîn (görerek kesin bilgi) ile gören kişi, gözünü dostun yüzünden ayırmaz;","bu sevginin dışında duran (âşık olmayan), onu nasıl görebilsin?"],["Bu aşkın harareti (kızgını), Yunus'u dilini tutmaya bırakmaz;","yine de dil, âşıkla ma'şûkun (sevgilinin) sırrını (râzını) tam (dürüst) söyleyemez."]],"260":[["Ben o eşsiz inciyim (dürr-i yetîm) ki, ummân (okyanus) beni görmedi;","bir damlayım (katre), ama ummâna göre, ben o ummânım. (Bu, benliğin yok olduğu vahdet/fenâ dilidir: damla, ilahî deniz ile birdir; egonun tanrılık iddiası değil.)"],["Gel, acayip (şaşırtıcı) dalgayı gör, gizli deryayı (deryâ-yı nihân) gözle;","işte — sonsuz deniz (bahr-i nihâyetsiz), bir damlada gizlidir (pinhân)."],["Mansûr, Ene'l-Hak ('Ben Hakk'ım') tevhidini söylemezdi;","eğer dostun (Allah'ın) zülfü (çekişi) beni aşkın darağacına çıplak (uryân) asmasaydı. (Ene'l-Hak, benliğin yok olduğu fenâ hâlinde, yalnız Hakk'ın var olduğunun ikrarıdır; bunu söyleten de bizzat Hak'tır.)"],["Bu çokluk âleminde (kesret) sen Yusuf'sun, ben Yakub;","o birlik âleminde (vahdet) ise — ne Yusuf var, ne Ken'an (ayrılık/isim kalmaz)."],["Mecnun, burada bu dünyada Leyla'nın adını ölçülü (mevzûn) sözle söylemeden önce;","ben orada (birlik âleminde) ne Leyla idim, ne de başı dönmüş (ser-gerdân) Mecnun."],["'Yunus'un harfleri (Y-N-S) birleşmeden, can henüz kuyuya (bedene) düşmeden;","aşkın tadıyla mest (sarhoş) geldik, yine mest gideriz buradan. (Ruh, 'Yunus' adından ve bedene girmeden önce de vardı.)"],["Adımın 'Yunus' olması, şu bedensel varlığımın belâsıdır (perdesidir);","zâtımı (asıl özümü) sorarsan — Sultan'a göre, ben o Sultanım. (Bu da fenâ/vahdet sözüdür: 'Yunus' adı-bedeni bir perdedir; benlik yok olunca geriye yalnız ilahî 'ben' kalır. Egonun iddiası değil, kendisinde tecelli eden Hakk'ın diliyle söylenmiştir.)"]],"261":[["O can ölecekken, sen ona can (hayat) olursun;","ölmüş gönül dirilir — senin bulunduğun yerde."],["Ölmek, hayat olsun; gönül ölümsüz bir dirilik bulsun;","yaralı (başlu) gönül onulsun (iyileşsin) — merhemi sen olasın."],["Senin bulunduğun gönüller, her an canını yeniler;","işte bunlardır ölmeyenler — hâkimi sen olasın."],["Senin bulunduğun makamda, orada adalet ehli (ehl-i dâd) olur;","o divanda (mecliste) zorbalık olmaz — sultanı sen olasın."],["Can bedenden uçunca, menzilinden (durağından) göçünce;","o cihana geçince — göze apaçık (iyân) olursun."],["Tozunu yel almasın, bir zerre bile kıpırdamasın (yok olmasın);","âşığın canı ölmesin — ma'şûku (sevgilisi) sen olasın."],["Yunus, sen âşıksan, aşka uygunsan (muvafıksan);","korkma, vuslata ulaşansan — ne olursan ol (olasın)."]],"262":[["Hâlim acayip oldu — bu aşkın elinden;","yolumu göremez oldum — bu aşkın elinden."],["Bütün bu âlemin tacı iken — işte,","aşkın elinden, ayaklar altında bir tozum (gubârım)."],["Garip bir bülbül gibi ağlarım (zârî kılarım);","gözümün yaşı akar — bu aşkın elinden."],["Solmuş yaprak (gazel) gibi benzim sarardı;","kararıp düştüm — bu aşkın elinden."],["Yarın mahşerde ben yakamı yırtarım;","ne çok feryat ederim — bu aşkın elinden."],["Dağlar taşlar erir — bu aşkın elinden;","denizler coştu (cûşa geldi) — aşkın elinden."],["Nice bin peygamber, aşka tutulmuş (giriftâr);","yer ü gök dopdolu — bu aşkın elinden."],["Sıkıntımı (gücümü) görenler, çağırıp 'gel (bak)' derler;","benim çilem nedir (ne büyüktür) — bu aşkın elinden."],["Yârin vaslından (kavuşmasından) başkasını ne yapayım;","boyum (kad-bâlâm) büküldü — bu aşkın elinden."],["Yunus, sen Tapduk'una dua kıl;","aşkın elinden, öldürücü zehri (zehr-i kâtili) içersin (aşkın acı şarabını)."]],"263":[["Gönül, sen bu seferden (yolculuktan) usanmadın;","Çalab'ım (Allah'ım) seni tehlikeden (hatardan) saklasın."],["Kişi, bir başkasının kahrını (eziyetini) çekeceğine;","gidip onun gözüne (nazarına) görünmemek daha iyidir (yeğdir)."],["Doğduğumdan beri, gurbet bağrımı doğradı;","ciğer kanı, damardan sızar damlar."],["Vatan diken oldu, gurbet ise gül bahçesi (gülistan);","zehir içmek, şeker kamışından (tatlıdan) daha iyi (yeğ) oldu."],["Gevher (mücevher) dedikleri, hüner ilmidir (marifettir);","hünerli kişiye, hüner gevherden daha değerlidir (yeğdir)."],["Yunus, göğsünü açıp dosta giderken;","Çalab'ım (Allah'ım) seni tehlikeden saklasın."]],"264":[["Benim gönlümü alan o sevgili, bana din-mezhep (taassubunu) bıraktırdı;","onu gören kişiye, ne gönül kalır ne can (benlik erir). (Bu, âşığın sevgilide benliğini yitirmesi, biçimsel/mezhepsel bağlardan geçmesidir; imanı bırakmak değil.)"],["Hâlimi sezmeyenler, bana 'dinini bıraktı' der;","oysa canı-gönlü (benliği) kalmamış (fenâda erimiş) biri, neyle din (biçimini) beslesin? (Dışı değil, benliği erimiştir; reddetme değil, yokoluştur.)"],["Suretimdeki (bedendeki) varlığım, canım ile gönlümdü;","bana aşkı bağışlayan, hepsini (benliğimi) bıraktırdı."],["Aşkın çavuşu (serhengi), beni hiçbir şeye bağlı bırakmaz;","aşkın o birlik âleminde ne 'İslâm' ne 'din' ikiliğiyle, küfür ile iman ayrı ayrı anılmaz. (Âşık Bir'de eridiği için bu ikilik aşılır; küfürle iman eşittir ya da din kalkar demek değildir.)"],["Orada (aşk makamında), aşkta kendini yitiren can için, zorlama bir şart-farz yükü kalmaz;","dil cevap sözünü söyler — ama bu dil onu nasıl tam bilsin? (Kasıt: aşka dalan, her şeyi sevgiyle yapar, dış bir yük olarak değil; şeriatın kalktığı anlamına gelmez.)"],["Aşk hiçbir şeye benzetilemez (mesel bağlanmaz); aşkın işi hesaba gelmez;","dostluk (Allah dostluğu) ticaretinde, kâr-zarar (assı-ziyân) anılmaz (hesaplanmaz)."],["Beni benlikten (egodan) kurtardı, varlık (benlik) defterimi sildi (yudu);","hayrı şerri (ödül-ceza hesabını) elden bırakan, artık ne korku (havf) ne ümit (recâ) gösterir. (Allah'ı cehennem korkusu ya da cennet umuduyla değil, sırf kendisi için sevmek.)"],["Elden her egoca işi bıraktırdı, O'na niteliksiz (kayıtsız/sıfatsız) baktırdı;","bizim hâlimizde, ad ile nişan (bireysel kimlik) anılmaz (erir)."],["Yunus'tan haber sormayın — dost neredeyse, o oradadır;","yüz bin gevherden (mücevherden) vazgeçip (fârig), aşk denizine dalandır o."]],"265":[["Erenlere muhib (dost) iken, niçin münkir (inkârcı) oldun?","Tatlı canını iyice koru — erenlerin okları yaydan çıkmadan önce."],["Erenlerin bineği, ilahî kahırdır (heybettir); ilahî gayret de onların hil'atıdır;","erenlerin yayı serttir (katı), okları kayadan bile geçer (manevî güçleri büyüktür)."],["Bize muhib (dost) olanları, Hak'tan dileriz (onlara dua ederiz);","dönüp münkir (inkârcı) olanları ise, çabucak (tîz) aradan çıkarırlar."],["Burada el-ayak öpülür, görenin canı kapılır;","garip (yolcu) misafir edilir — tekke (zaviye) ile mescitte."],["Zehir (agu) içerse bal (nûş) olsun, şarap (süçi) içerse hoş olsun;","Yunus ile yoldaş olsun — Allah'ına giden gelsin."]],"266":[["O dost bize gelmezse, ben kendim dosta varayım (gideyim);","cevr ü cefâyı (eziyeti) çekerek, dostumun yüzünü göreyim."],["Sermayemiz bir candı, onu da bu aşk aldı;","ne sermaye var ne dükkân — pazara neyle varayım?"],["Dükkân ve pazar kurulmuş, dost içine girmiş gezer (gönülde dolaşır);","günahım çok, gönlüm bunu sezer — ben dosta çok yalvarayım."],["Gönlüm der 'dost benimdir', gözüm der 'dost benimdir';","gönlüm göze der: 'sabret — bir an içinde haberini vereyim.'"],["Hakk'ın nazar kıldığı (lütfettiği) cana, saygıyla tek gözle bakmak gerek;","Hakk'ın nazar kıldığı kişiyi, ben nasıl yereyim (kötüleyeyim)?"],["Tapduk bu Yunus'a der: bu aşk Hakk'a ermeli;","O, hepsinden (kamudan) yücedir — ben O'na nasıl ereyim?"]],"267":[["Ey gönül, bir an, bir vakit, dünyadan usanmaz mısın;","bunca bozuk (fâsid) işle, yüzünden (kendinden) utanmaz mısın?"],["Sen kendini hoş ve temiz (arı) tut, Yâr'dan (sevgiliden) af dile (istigfar et);","iman bilgisine bağlanıp, din giysisine bürünmez misin?"],["Ey malını sahteye (kalba) satan, gevherine (incine) değersiz pullar katan;","kârı (assıyı) zarara satan — gerçek kâra uzanmaz mısın?"],["Dünya gayretine düşkün (mübtelâ), kendini günahlar içinde bıraktın;","din yolunda gönül hasta (sayru) — ciddiyetle Hakk'a dayanmaz mısın?"],["Ölmez (ebedî) vuslat şarabını içen, masiyyet (günah) denizini geçen;","meyhaneden (gafletten) ayrılmaya azmedip, mescitlere (ibadete) kanmaz (yönelmez) mısın?"],["Yeri göğü seyran eden, Arş ile Kürsü'de dolaşan (cevlân uran);","Yunus'un katında, ey gönül, bir an eğlenmez (durmaz) mısın?"]],"268":[["Beni öyle hayran eyle ki, aşkın ateşine (oduna) yanayım;","nereye bakarsam, gördüğümü sen sanayın (her şeyde seni göreyim)."],["Sultanım beni çağırdı, işte canım yola çıkıp gider;","benliği (egoyu) elden bıraktı — burada nasıl eğleneyim (oyalanayım)?"],["Senin kokunu duydu canım, bu cihanı terk ettim;","acaba mekânın nerede — ya da ben seni nerede arayayım?"],["Dört mezhebin (hepsinin) âşığıyım, canım yedi mezhebi (ayrımı) aştı;","bırak beni, söyletme — bu yollarda gerçeğe uyanayım. (Bu, bütün mezhepleri seven, mezhep taassubunu aşan kuşatıcı sevgidir; mezhepleri/dini reddetmek değil.)"],["Yedi cehennem dedikleri, bir âhıma bile dayanamaz;","sekiz cennet beni alıkoyamaz — burada niye eğleneyim?"],["Sekiz cennet sunulsa, yetmiş bin huri gelse;","bu canımı aldatamaz — burada nasıl aldanayım?"],["Senin haberin dilde söylenir, ama izin (eserin) asla bulunmaz;","yüzünden perdeyi kaldır — cemâline (dîdâruna) yanayım (göyüneyim)."],["Hikmet ilmini sadece okuyanlar — bunlar aşktan yoksundur (fakirdir);","ben Mansûr oldum, asın beni — hep dillerde söyleneyim. ('Mansûr olmak' = benliğin yok olduğu fenâya ermek ve onun gibi Hak uğruna ölüme hazır olmaktır; egonun tanrılık iddiası değil.)"],["Bu sözü Yunus kendi söylemedi — cana dostun sesi (âvâzı) doldu;","münafığın (ikiyüzlünün) gözü kördür — ya ben ona nasıl göstereyim? (Sözü söyleten, Yunus'un benliği değil, gönlünü dolduran dostun sesidir.)"]],"269":[["İlâhî, bana öyle bir aşk ver ki, ben benliğimi bilmeyeyim;","kendimi yitireyim — kendimi arayıp da bulmayayım."],["Beni öyle hayran eyle ki, gece gündüz bilmeyeyim;","seni daima isteyeyim — başka hiçbir nakşa (surete) kalmayayım."],["Benden benliği (egoyu) al, götür; içimi Sen'likle (Sen'inle) doldur;","buradayken öldür beni (nefse öldür) — ki oraya (ahirete) varıp manen ölmeyeyim."],["Söylesem dile gelmez (anlatılamaz), kimi bana söver, kimi güler;","bâri (hiç değilse) dertle yanayım — hâlim dile gelmesin (gizli kalsın)."],["İşte yana yana yürüyeyim — ciğerim kana gark oldu (battı);","aşk cana bir ok vurdu — nasıl ağlamayayım (zârî kılmayayım)?"],["Bırak ben yanayım, tüteyim, dostun bahçesinde yiteyim (kaybolayım);","bir gül olup biteyim (yeşereyim) — açılıp bir daha solmayayım."],["Mansûr gibi beni darağacına çıkar, kendini öyle apaçık (ıyân) göster;","bu canı kurban kılayım — aşka münkir (inkârcı) olmayayım. (Mansûr gibi dâra çekilmek = Hak uğruna, benliğin yok olduğu fenâ hâlinde ölüme hazır olmaktır.)"],["Aşktır bu derdin dermanı, aşk yoluna verdim canı;","miskin Yunus der: yâ Ganî (ey muhtaç olmayan Allah'ım) — bir an bile aşksız kalmayayım."]],"270":[["Taştın yine, deli gönül — sular gibi çağlar mısın;","aktın yine, kanlı yaşım — yollarımı bağlar mısın?"],["Ne edeyim — elim yâre (sevgiliye) ermez, derdime çare bulunmaz;","ilimden (yurdumdan) avare oldum — beni burada eğler (alıkoyar) misin?"],["Yoldaşımı yitirdim, bağrımın yarası (başı) onulmaz (iyileşmez);","gözlerimin kanlı yaşı — ırmak olup çağlar mısın?"],["Ben yoluna toprak oldum, sen uzaktan (aşuru) bakarsın;","şu karşıma göğüs gerip yolumu kesen, taş bağırlı (taş yürekli) dağlar mısın?"],["Yol kesen (harâmî) gibi, yoluma çapraz (arkurı) inen karlı dağ;","ben yârimden ayrı düştüm — sen de yolumu bağlar mısın?"],["Karlı dağların başında, salkım salkım kümelenen bulut;","saçını çözüp (yas tutar gibi), benim için gizli gizli (yaşın yaşın) ağlar mısın?"],["Yunus'un canı esridi (mest oldu), yoldayım — illerim (yurdum/sevdiklerim) hani (nerede)?","Yunus seni düşte (rüyada) gördü — hasta (sayru) mısın, sağlıklı mısın?"]],"271":[["Canların canını (Allah'ı) buldum — bu canım yağma olsun;","kâr-zarardan artık geçtim — dükkânım yağma olsun."],["Ben benliğimden (egomdan) geçtim, gözümün perdesini (hicabını) açtım;","dostun vaslına (vuslatına) ulaştım — şüphem (gümânım) yağma olsun."],["Benden benliğim gitti, bütün mülkümü dost tuttu (sahiplendi);","Lâ-mekân (mekânsız Allah) kavminden oldum — mekânım yağma olsun."],["İkilikten usandım, aşkın giysisine büründüm;","derdin hanında (konağında) kandım (doydum) — dermanım yağma olsun (derde derman istemem)."],["Varlık (benliğim) sefere çıkınca, ardından dost bize geldi;","virân (yıkık) gönül nurla doldu — cihanım yağma olsun."],["Bitmez arzudan (sagınçtan) geçtim, yaz-kıştan usandım;","bütün bostanların başını (kaynağını) buldum — bostanım yağma olsun."],["Bağlılıktan (ta'alluktan) koptum, o dosta doğru uçtum;","aşkın divanına (meclisine) düştüm — kendi divanım yağma olsun."],["Yunus, ne hoş söylemişsin — bal ile şeker yemişsin;","balların balını (Allah'ı) buldum — kovanım yağma olsun."]],"272":[["Kıyamet gününü anıp,","o gün için ağlaşalım;","o gün, kınanma (hesap) günüdür —","o gün için ağlaşalım."],["O gün yerler yarılır,","bütün ölenler dirilir,","bütün günahlar sorulur —","o gün için ağlaşalım."],["O gün gök çatlar,","insan ona nasıl katlanır?","O gün kim korkmaz ki —","o gün için ağlaşalım."],["Âh, o günün korkuları,","masumları bile yaşlandırır (kocaltır);","ya suçluların (mücrimlerin) hâli nice olur —","o gün için ağlaşalım."],["O gün şiddetli feryat (efgân) olur,","erkek dişi çıplak (uryân) olur,","bütün ciğerler kavrulup biryân olur —","o gün için ağlaşalım."],["Ey Yunus Emre, yola gir;","hâlden habersiz kardeşin hâli ne olur?","Meğer derman (kurtuluş) Hak'tan ola —","o gün için ağlaşalım."]],"273":[["Sübhân (Allah) bizi uyandıracak, nice zaman mezarda yatmış iken;","canlar yeniden teni isteyecek, onu terk edip gitmiş iken."],["Gör Hâlik'in (yaratanın) inayetini (lütfunu), o sonsuz deryasını;","bunca günah işlemişken, bize yine de dîdârını (cemâlini) gösterecek."],["Hakk'ın inayeti çoktur, daima kullarına erer;","Nemrut ateşe atmışken, Allah Halil'i (İbrahim'i) sakladı (korudu)."],["İnayeti kime ererse, o kul iken sultan olur;","Yusuf'u işitmedin mi — onu tüccara satmışken, sonra Mısır'a sultan oldu?"],["Aşkla yola gelsen, Yunus (peygamber) gibi olsan ne olur;","balık (balina) onu yutmuşken bile, o ibadetini (tâatini) terk etmedi."],["Ahdini (sözünü) yerine getir, gönlünü saf (safâ) eyle;","Arş'a Mi'râc etmişken bile, hani Muhammed Mustafa — o da göçtü?"],["Hani peygamberler ve evliya — bütün veliler geldi geçti;","Kaf'tan Kaf'a (dünyanın bir ucundan diğerine) hükmetmişken, hani Davud ile Süleyman?"],["Malın ne kadar çok olsa da, ecel sana elini uzatır;","bu dünyaya batmışken (servete gömülmüşken), Karun ne kâr (assı) etti?"],["Bana kulak ver, bir haberim var, sana söyleyeyim;","Arş'ta makam tutmuşken (yüce bir mevkideyken) bile, Allah Azâzîl'i (Şeytan'ı) lanetledi."],["Dosttan bela gelince, Eyyub gibi sabret;","bunca bela çekmişken, onun teni nasıl da sıhhat buldu (sağlığına kavuştu)?"],["O kıyamet gününü anınca, Yunus'un canı titrer mi?","İman ve Kur'an yoldaşıyla, son menzile (durağa) ermişken titremez."]],"274":[["Hey dostlar, hey kardeşler — nasıl edeyim, ne edeyim ben?","'Sen benim kulum değilsin' derse, ne edeyim ben?"],["Başım hor (zelîl) ve aldanmış (magbûn) kalsa, orada yaşım (gözyaşım) hiç dinmese;","mahşer günü içim dışım ateş (nâr) olursa, ne edeyim ben?"],["Suç anılınca özüm yanar (göyner), gözüm kanlı yaşla dolar;","yarın Hak katında yüzüm kara olursa, ne edeyim ben?"],["İçim bozuklukla (fesâd) dolu — hey hoca (efendi), suçumu bağışla;","cehennem bile benim için yer (mesken) olursa, ne edeyim ben?"],["Ben bozukluk (fesâd) içinde kaldım — Yunus der: derdim arttı;","mezara (sineye) varınca, kabrim dar olursa, ne edeyim ben?"]],"275":[["Bende amel (hayır), ibadet (tâat) yok —","ben ne edeyim, ne eyleyeyim?","Kıyamet günü kopunca —","ben ne edeyim, ne eyleyeyim?"],["Dost (Allah) bana sual edince (sorunca),","aklım başımdan gidince,","utanma (hicâb) derdi beni gark edince —","ben ne edeyim, ne eyleyeyim?"],["Helâle (helal olana bile) hesap olunca,","harama azap olunca,","isyanla (günahla) yüzüm kara —","ben ne edeyim, ne eyleyeyim?"],["Yetmiş bin zebânî (cehennem meleği) çekip,","cehennemi (Tamu'yı) mahşerde getirince,","suçlulara (mücrimlere) heybet (korku) salınca —","ben ne edeyim, ne eyleyeyim?"],["Cehennem bir kez silkinince (kabarınca),","âsîlere (isyankârlara) öfke (kîne) edince,","yâ Rab, o güne erişince —","ben ne edeyim, ne eyleyeyim?"],["Âşıklar maksuda (dileklerine) erince,","ârifler dostun yüzünü görünce,","bense öyle bir suçlu (mücrim), yüzü kara —","ben ne edeyim, ne eyleyeyim?"],["Yunus Emre'm, derdin şiddetli (katı);","bir ibadeti bile hayra geçmez (yeterli gelmez);","Hakk'ın inayeti (lütfu) olmazsa —","ben ne edeyim, ne eyleyeyim?"]],"276":[["Ey benim ömrümün kuşu (canım), bir gün nereye varırsın?","Ecel avlayıp yutar — bir gün eline (avucuna) düşersin."],["Gelip göğsüne konar, tutuşup canın yanar;","bir kadeh şerbet (ölüm şerbeti) sunar — içip kanarsın (bitersin) bir gün."],["Görmeye gelenleri, hâlini (hatırını) soranları,","sevgili dostları (yârânları) — bir gün görmez olursun."],["Dostların gelir, seni defne acele ettirirler;","giysilerini (tonlarını) soyarlar — bir gün çıplak (uryân) kalırsın."],["Tahta ata (tabuta) binip, Hızır gibi ölümsüz olamayıp;","şu kara yerin (toprağın) altına girer, yatarsın bir gün."],["Tene yeterince bakım (tîmâr) eyle, bu cana asıl azık (yarak) hazırla;","yoksa şu yılana çıyana mezarda bir gün nasip (yem) olursun."],["Münker ile Nekir (mezar melekleri) gelir, hâllerin zor (düşvâr) olur;","kendi dilinde sual sorarlar — bir gün cevap verirsin."],["Yunus Emre'm, ne edersin, kaçıp nereye gidersin?","Erenlerin sohbetine, bir gün gelmez olursun (ölüm seni kesmeden değerini bil)."]],"277":[["Acaba şu yeryüzünde var mı ola,","böyle garip (kimsesiz) benim gibi?","Bağrı yaralı, gözü yaşlı,","böyle garip benim gibi?"],["Anadolu'yu (Urum'u) ve Şam'ı gezdim,","yukarı illerin (diyarların) hepsini;","çok aradım, bulamadım —","böyle garip benim gibi."],["Kimseler garip (kimsesiz) olmasın,","hasret ateşine (odına) yanmasın;","hocam (efendim), kimseler olmasın —","böyle garip benim gibi."],["Dilim söyler, gözüm ağlar,","gariplere özüm yanar (göynür);","meğer gökteki yıldızım bile —","böyle garip benim gibi."],["Ne kadar bu dertle yanayım,","ecel erişir, bir gün ölürüm;","meğer ancak mezarımda bulayım —","böyle garip benim gibi."],["'Bir garip ölmüş' derler,","üç gün sonra ancak fark ederler (duyalar);","soğuk suyla yıkarlar —","böyle garip benim gibi."],["Hey Emre'm Yunus, çaresiz (bî-çâre);","derdine çare bulunmaz;","var, şimdi gez şehirden şehire —","böyle garip benim gibi."]],"278":[["Seni arayıp nerede bulayım — ey gönül, sen neredesin?","Nerede bir virâne (yıkık/benlikten geçmiş yer) varsa, vallahi gönül, sen oradasın."],["Ey gönül, sana uyalı (uyduğumdan beri) yüzümün suyu (itibarım) kalmadı;","sana rahmet gelsin — nerede olursan ol, Allah'ın divanında (huzurunda)sın."],["Bir an aydınlık (rûşen) olursun, bir an perişan yürürsün;","âlemlere ad ve nişansın (ünlüsün) — ama derde esir, çaresiz (dermânde)sin."],["Bir an âbid (ibadet eden), bir an zâhid (sofu), bir an âsî (isyankâr), bir an itaatkâr (mutî');","bir an gelir ki ey gönül, ne dinde ne imandasın (vecd içinde biçimsel kalıpların ötesinde, Hak'ta erimişsin; dinsizlik değil)."],["Aşk başımdan aşınca, dalgalanıp (mevc urup) taşınca;","bir an gelir ki ey gönül, mescit ile Kur'an'dasın (ibadete dönersin)."],["Kayseri, Tebriz ve Sivas, Nahçıvan ve Maraş, Şiraz;","gönül, sana Bağdat bile yakın — bütün âlemlerde Allah'ın divanında (huzurunda)sın."],["Yunus, şimdi yalnızca Hakk'a kulluk et, gözünün yaşını boşuna akıtma;","ister bugün ister yarın — sen Hak için bir kurbansın (kendini O'na ada)."]],"279":[["Eğer aşkı seversen, gerçek can olursun;","gönüller tahtına sultan olursun."],["Dünyayı seversen, sadece mihnet (sıkıntı) bulursun;","ne zamana dek eskiye (geçiciye) hasret çekersin?"],["Cihan eski (köhne) bir saraydır, sen de onun beyisin;","ne zamana dek eskiye (geçiciye) hasret çekersin?"],["Dünya muradı (arzusu), zehirdir (agudur), bal değil;","ne zamana dek zehire (aguya) parmak banarsın (batırırsın)?"],["Kanatsız kuş gibi yabanda (Hak'tan uzakta) kaldın;","kanatlı kuşlara (erenlere) nasıl erişirsin?"],["Diken olma, gül ol — erenin (ermişin) yolunda;","diken olursan, ateşte (oda) yanarsın."],["Hak, namazı niyaz (yalvarış) için buyurdu;","niyazdan gafil olursan, vay sana!"],["Bu yolda sana erenden (ermişten) bir asâ (dayanak) gerek;","dayanacaksan, o asâya dayan."],["Erenlerin nefesini (sözünü) kendine asâ (dayanak) edin;","eğer nefsine uyarsan, mahvolursun (fenâsın)."],["İbadetlerin başı, dünyayı (dünya hırsını) terk etmektir;","eğer mü'minsen, buna inanasın."],["Babanın ananın hakkını zayi ettiysen (gözetmediysen);","nasıl yeşil donlar (cennet giysileri) giyip süslenesin?"],["Eğer komşu hakkı boynundaysa (komşunu incittiysen);","yarın ahirette cehennemde sürekli (bâkî) kalırsın."],["Yunus bu sözleri erenden (ermişten) aldı;","sana da gerekirse, onları alasın."],["Gönüle gireni, 'mutlu oldu (gönendi)' derler;","sen de gönüle gir ki, mutlu (gönenmiş) olasın."]],"280":[["Ey dost, seni seveli aklım gitti, şaşkın kaldım ben;","pınarları terk edip, denizlere daldım ben."],["Aşkının bir zerre ateşi (odı), denizleri kaynatır;","aşkın ateşine düştüm, tutuşup yandım ben."],["Aşk olan o canda, orada gussa (tasa) olmaz;","bu aşk bana geleli, gussam gitti, güldüm ben."],["Bülbül de kızıl (kırmızı) gülün yüzüne âşık olmuş;","ben de erenlerin yüzünü gördüm — bin nağmeli (hezâr destân) bülbül oldum ben."],["Bu aşkı bana verdin — ben kendi kendimi ne yapayım?","İçim dışım nurla doldu, dosta âşık oldum ben."],["Nefsinin putunu (bûtın) kırmazsan, bütün ibadetin boştur (abestir);","onu kırmaya çareyi, işte şimdi buldum ben."],["Dünyanın cefasını (eziyetini) çekmek, sonunda vefâ (kavuşma) imiş;","cefayı bedel olarak vererek, seni satın aldım ben."],["Bir kuru ağaçtım, yol üzerine düşmüştüm;","dost bana bir nazar kıldı (bir baktı) — taze bir genç (cüvân) oldum ben."],["Yunus, sen âşıksan, 'miskin' adını (etiketini) bırak;","ama hepsinin en seçkinini (ihtiyârını), gerçek miskinlikte (benlikten geçmede) buldum ben."]],"281":[["O zaman bir (Bir'le bir) olursun, ayrılıktan (ikilikten) kurtulursun;","bu kapıya cansız (benliksiz) gel — kalıcı (bâkî) bir hayat bulasın."],["Canı (benliği) tutarak gelirsen, 'canım var' dersen;","canı (benliğini) hesaba katarsan — bütünüyle kuruntudasın (boş arzudasın)."],["Burada ne kuruntu (sagınç), ne hesap (şumâr) — ya burada kim kalır ki?","Madem sefer böyle düştü, sürekli yolda olman gerek."],["Dertle gelmeyince, dermana erişemezsin;","bir canı (benliği) yolda bırakırsan, yüz bin can bulursun."],["Fânî (geçici) arzuda kalma, kalıcı (bâkî) hazineyi (genci) hedefle;","o zaman yüz bin cihanda, gizli (bâtın) hazineyi bulursun."],["Aşkın tadını (dadından) tadarsan, dinin yalnızca dış/zâhir yüzünü aşarsın (iç özüne erersin);","o zaman ayrılığın ateşinden (odından) kurtulursun. (Bu, biçimi reddetmek değil, biçimin ardındaki iç hakikate ermektir.)"],["Bu yolda yavı git (kaybol), her türlü menzilde (durakta);","söylenen her dilde, adın unutulmalısın (benliğin erimeli)."],["Ey Yunus, hani aklın? — dilin gizlisiz (açıkça) söyler;","bu yolun sonu (pâyânı) yok — sen nerede dolanıp durasın?"]],"282":[["İlâhî, derdimin dermanı sensin;","günahkâr kulların bağışlayanı (gufrânı) sensin."],["Senin emrinle döner felekler (gökler);","hem ayın hem güneşin devranı (dönüşü) sensin."],["Halil'in (İbrahim'in) hullesi (şeref giysisi), Yakub'un âhı (iniltisi);","Yusuf'un bağı (bendi) ile zindanı sensin."],["Musa'nın Tûr Dağı'ndaki münâcâtı (yalvarışı),","İsa'nın göklerdeki seyranı (gezişi) sensin."],["Gözümün nuru ve gövdemin hayatı;","gönüller tahtının sultanı sensin."],["Yunus Emre'm dersini (sebakı) senden okur;","elindeki defteri, divanı (kitabı) sensin."]],"283":[["Ey gönlümün eğlencesi (avuncu), söyle bana — ne eyleyeyim?","Aşkından avare oldum — derdimi kime söyleyeyim?"],["Fânî mülkten (mülk-i fenâdan) geçeyim, o dostun iline (diyarına) uçayım;","aşkın ummanına dalayım, denizlerini kaynatayım."],["Aşk canıma ateş (od) vurdu — âşıklar yanıma gelsin;","aşkın sofrasını (hânını) dökeyim, âşıkları toylayayım (ağırlayayım)."],["Aşkın bağına girince, soluma sağıma baktım;","türlü yemişlerini (meyvelerini) yiyip, güllerini koklayayım (yıylayayım)."],["Gece gündüz âh u zâr (inilti) edeyim, il ü şârda (her yerde) âşık olayım;","kanlı yaşımı dökeyim, ağlayıp inleyeyim (zârılıklar eyleyeyim)."],["O güle âşık olayım, cihana çığlık (gulgule) dolsun;","bin nağmeli (hezâr destân) bülbül olup, dostun bağında konaklayayım (yaylayayım)."],["Miskin Yunus, âşıkların gerçek hayatını (dirliğini) yaşamadın;","bâri (hiç değilse) gücüm yettiğince, onların soyunu (hâllerini) anlatayım."]],"284":[["Beni senden ayırma, ey Yaradan;","bu yaradan (yaranın acısından), düşüp ölürüm ben."],["Öldüğüm için gussa (tasa) mı çekerim?","Canımı yine Yaradan (Allah) alacak (O'na dönerim)."],["'Öldü' deseler, kaygımı çekseler;","bir kuş olup (ruhum) aradan çıkayım (uçup gideyim)."],["Şu gözlerime 'ağlama' derim;","yine de akından karasından (bütün gözden) kanlı yaş akıtır."],["Göl eylemediğim yer mi bıraktım (gözyaşımla)?","Her dereden seller (siller) akıttım."],["Ben bir kuldum, sen sultandın;","aradaya (bu dünyaya/ayrılığa) düştüm, bilmem nereden."],["Varıp şeyhin eşiğine kul olayım;","yüz bin parçadan kendime bir abâ (yün hırka) dikeyim."],["Emre'm Yunus'un muradı (isteği) budur:","yârine ersin, aradan (ikilik) çıksın (kalksın)."]],"285":[["Ey dostlar, ey kardeşler — 'öleceğim' diye korkarım;","ölmemi umursamam — asıl 'ettiğimi (yaptığımın karşılığını) bulurum' diye korkarım."],["Bir gün gözüme görünür, ayıbım (kusurum) yüzüme vurulur;","kaygıdan deli olmuşum — 'ne edeyim ben, ne kılayım' diye."],["Eğer gerçek bir kul olsaydım, O'na kulluk ederdim;","'yarın orada (ahirette) güleyim' diye, bu dünyada ağlardım."],["Bu dünyaya yalnızca nefsime kulluk etmeye geldim;","'azaptan kurtulayım' diye iyi amel işlemedim."],["Ey çaresiz, miskin Yunus — günahın çok, ne yaparsın?","O Allah'ıma sığındım — '(ben) de affederim' dedi."]],"286":[["Dost gönlümü yağmaladı — bundan böyle (şimden girü) ne olsa gerek?","Derdi (aşk derdi) canımı ateşe bıraktı — bundan böyle yansa gerek."],["Derdinle canım yanar, ömür geçer, devran döner;","günler geldikçe benzin (yüzün) solar — bundan böyle solsa gerek."],["Bu ne şaşılası bir serüven (ser-güzeşt) — bağrımızda bir yara açtı;","gözlerimden kanlı yaş — bundan böyle aksa gerek."],["Evliya (ermiş), Hakk'ın sırrıdır — alnındaki Allah nurudur;","onu seven, âh u zâr (inilti) — bundan böyle etse gerek."],["Sen hocasın (efendisin), ben bir kulum — ebedî kullukta kalayım;","bu sözümü bütün âlem — bundan böyle bilse gerek."],["Fenâ (yokluk) sarayından göçüp, bekâ (kalıcılık) sarayına geçip;","aşkın şarabından içip — bundan böyle kansa (doysa) gerek."],["Görün ki Yunus ne etti — varıp ilahî huzura (hazrete) gitti;","o bir damladır, ummana (okyanusa) karıştı (benliği Hak'ta eridi, fenâ) — bundan böyle dolsa gerek."]],"287":[["Bugün Mansûr (Hallâc) gibi oldum — beni darağacına asacak (ber-dâr eden) varsa, beri gelsin;","'İnnî ene'l-lâh' (Kur'an'da 'şüphesiz ben Allah'ım' — benlikten geçip Hakk'ın diliyle) okudum — inkâr eden varsa, beri gelsin. (Ego'nun ilahlık iddiası değil; benliği yok olmuş âşıkta yalnız Hakk'ın söylemesidir.)"],["'De ki: hepsi Allah'tandır' (Kur'an) — vallahi O'nsuz değilim;","ben Hak'la Hak olmuşum (benliğim Hak'ta erimiş, O'nunla var olmuşum) — beni 'gayrı/başka' sayan varsa, beri gelsin. (Ego Tanrı olmuş değil; benlik fenâ bulup yalnız Hak kalmıştır.)"],["Levh ile Kalem'de (Levh-i Mahfûz'da) yazılan tevhidin düzenini (tertîbini) okurum;","ilm-i ledün (Allah vergisi gizli ilim), seyr ü sülûk (manevî yolculuk) — bunda söz söyleyecek varsa, beri gelsin."],["Bir (tek) Tanrı'nın Peygamberi — ben haberi (bilgiyi) ondan aldım;","bir tek Tanrı'ya ve Peygamber'e ikrar eden (inanan) varsa, beri gelsin."],["'Men arefe nefsehu fekad arefe Rabbehu' (nefsini bilen Rabbini bilir — hadis);","bunu bildim, O'nu buldum (kendimi tanıyıp Hakk'ı buldum) — inkâr eden varsa, beri gelsin."],["İnkârcılar, münafıklar 'onu öldürelim' dermiş;","beni ancak Yaradan öldürür — yoktan var eden, var edip yok eden (Allah) — buna karşı çıkan varsa, beri gelsin."],["Beni öldürüp külümü göğe savuracak varsa gelsin;","ben 'Küntü kenz'im (kudsî hadis: 'Ben gizli bir hazine idim'), gizliyim (mahfîyim) — onu açığa çıkaracak varsa, beri gelsin. (Bu, fenâda Hakk'ın gizli hazinesinin âşıkta tecellîsidir; ego'nun iddiası değil.)"],["Gâzî benim, şehit benim, ölen de öldüren de benim (birlik/fenâ hâlinde her sûrette tecellî eden Bir gerçeğin dilinden; ego 'her şeyim' demiyor);","sabah akşam o dostla alışveriş (bâzâr) eden varsa, beri gelsin."],["Bütün cihan O'nun gufrânıdır (rahmetinin tecellîsidir), bütün âlem O'na hayrandır;","Yunus da O'na hayrandır — bunu benimle tekrar edecek varsa, beri gelsin."]],"288":[["Ey bizimle yâr (dost) olup dosta giden, beri gelsin;","kendini yok edip, canını (benliğini) terk eden, beri gelsin."],["Boş sözü (kâl ü kıyli) terk edelim, doğru yolu isteyelim;","hem cevherin (gevherin) madenini (kânını) bulalım — cevher alan, beri gelsin."],["Cevher (gevher), bu canın maksududur (amacıdır); canın maksudu da onun Mansûr'udur;","maksut (Hakk'a kavuşmak) için Mansûr (Hallâc) gibi darağacına asılan (benliğini feda eden), beri gelsin. (Burada 'asılmak', ego'nun fenâ yolunda feda edilişidir.)"],["Maksuda (amacına) ermek dilersen, her işte çok hizmet et;","sen benliğinden (senliğinden) usan — Hakk'ın cemâl nuru (nûr-ı dîdâr) olan, beri gelsin."],["Kendini (benliğini) gizleyenler (yok edenler), onlar Hakk'ın yüzünü görürler;","Hakk'ın yüzünü görmek dilersen — ikrar eden (bunu kabul eden), beri gelsin."],["Yunus, gel, hâlini anlat; ne olduğunu (ahvâlini) bildir;","aşk derdi canını ateşe bıraktı — derman eden (deva verecek) varsa, beri gelsin."]],"289":[["O yâre karşı ağlayıp inleyen (zârî kılan) benim;","o dildâra (gönül alana) karşı gönülden can veren benim."],["Geceler sabaha dek hayran ve mestim (sarhoşum);","O'nun dîdârına (cemâline) karşı bekleyen (muntazır) olarak."],["Seher vakti kalkıp ağlayıp inlerim (zârî kılarım);","sanırsın gül bahçesine (gül-zâre) karşı öten bir bülbülüm."],["İlahî aşk (ışk-ı İlâhî) canımı alalı,","Mecnun gibi avare (başıboş) olan benim."],["Cemâlinin (güzelliğinin) mumuna (şem'ine) pervâne gibi,","ateşe karşı kanadımı (per ü bâlimi) yakarım."],["O'nun aşkının şarabını içeli (nûş edeli),","yâre karşı beni çekerek yüreğime erişir."],["Bugün aşkının yolunda Mansûr (Hallâc gibi) benim;","yürüyüp dönerek (çarh urup), şu darağacına (dâra) doğru sema ederim. (Aşk uğruna benliğini feda eden âşığın hâli; ego Mansur olmuş değil.)"],["Dostun bahçesinde çaresiz (bî-çâre) bir bülbülüm;","varıp şu yâre karşı haber vereyim."],["Âşık Yunus bugün gurbette kaldı;","ki aşkı, dildâra (sevgiliye) karşı onu söyletir."]],"290":[["Severim ben seni candan da içeri (canımdan da derin);","yolum geçmez bu erkândan (esastan) içeri."],["Nereye varsam, gönlüm seninle dolu;","seni bundan (gönlümün içinden) daha içeri nereye koyayım?"],["Beni bana sormayın — ben bende değilim (kendimde değilim);","sûretim (bedenim) boş gezer, giysinin (tonun) içinde."],["Beni benden alana (benliğimden alan Allah'a) elim erişmez;","sultandan (Hak'tan) daha içeri (öteye), kimin ayağı (kademi) basabilir?"],["Tecellîden (Allah'ın belirmesinden) kimine bir nasip (pay) erişti;","kiminin maksudu (amacı) bundan da içeri (daha derinde)."],["O dostun nazarı (bakışı) kime dokunduysa,","onun içindeki şu'lesi (ışığı) güneşten de içeri (parlaktır)."],["Senin aşkın beni benden (benliğimden) almıştır;","ne tatlı (şîrîn) bir dert bu — dermandan da içeri (devadan da tatlı)."],["Şeriat ile Tarîkat, Hakk'a varan için bir yoldur;","Hakîkat ile Mârifet, ondan daha içeri (daha derindedir)."],["Süleyman kuş dilini (mantıku't-tayrı) bilir, dediler;","ama Süleyman'dan da içeri (daha derinde) bir Süleyman var."],["Aşkın erine (eren'ine) doğru sülûk eden (manevî yolculuk yapan) için,","dinin zâhirî biçiminin içinde/ötesinde nice iç yol (mezheb) vardır. (İç hakikatte mezhep ayrımları aşılır; din terk edilmez.)"],["Dinini (yalnızca dış kabuğunu) terk edenin işi görünüşte küfürdür;","ama bu ne acayip küfürdür ki — imandan da içeri (imandan daha derindedir)? (Bu, gerçek dinsizlik değil; âşığın biçimi aşıp öze ermesidir — sıradan biçimsel imandan daha derin bir iç hakikat. Dinin reddi kastedilmez.)"],["O Sevgili, hiç nişanı (izi/belirtisi) olmayan bir dilberdir (güzeldir);","bütün nişanlardan içeri (öte) bir nişan olur mu? (O, her işaretin ötesindedir.)"],["Meğer Yunus'un gözü dosta tuş oldu (denk geldi/dostu gördü);","öyle ki kapıda kaldı — ama gönlü ondan da içeri (daha derinde)."]],"291":[["Asıl vatanın (Hakk'a dönüşün) sevgisi (hubbü'l-vatan) aklıma düştü — 'hey dost' diye diye, gideyim;","oraya varan orada kalır — 'hey dost' diye diye, ben de kalayım."],["O Azrail gelir tutar — anaya babaya bile ayrıcalık (assı) tanımaz;","şu tahta ata (tabuta) bineyim — 'hey dost' diye diye, gideyim."],["Halvetlerde (inzivada) meşgul olayım, daima açılıp gül olayım;","dostun bağında bülbül olayım — 'hey dost' diye diye öteyim."],["Şu beş-on arşın bezi sırtıma kefen ederler;","şu dünya giysilerini dikip giyeyim — 'hey dost' diye diye."],["Mecnun olup yürüyeyim, yüce dağları büriyeyim (dolaşayım);","mum olup eriyeyim, yanayım — 'hey dost' diye diye."],["Günler geçe, yıl döne — üstüme mezarım (sinlem) çöke;","ten çürüye, toprak ola, toz olayım — 'hey dost' diye diye."],["Yunus Emre, var yoluna git — inkârcılar (münkirler) senin yoluna girmez;","dalgıç kuşu (bahrî) olup dostun gölüne dalayım — 'hey dost' diye diye."]],"292":[["Hak'tan gelen şerbeti içtik — elhamdülillah;","şu kudret denizini geçtik — elhamdülillah."],["Şu karşıki dağları, meşelikleri (mîşeleri), bağları;","sağlıkla, safâyla (esenlikle) aştık — elhamdülillah."],["Kuruyduk, yaş (taze) olduk; ayaktık, baş olduk;","kanatlandık, kuş olduk, uçtuk — elhamdülillah."],["Vardığımız illere (diyarlara), şu safâlı (huzurlu) gönüllere;","Baba Tapduk'un mânâsını (öğretisini) saçtık — elhamdülillah."],["Beri gel, barışalım — yabancıysan (yadısan) tanışalım (bilişelim);","atımız eyerlendi, koştuk (eştük) — elhamdülillah."],["Anadolu'ya (Rûm'a) indik, kışladık; çok hayır ve şer işledik;","işte (uş) bahar geldi, geri göçtük — elhamdülillah."],["Dirildik, pınar (bınar) olduk; biriktik (irkildik), ırmak olduk;","aktık, denize dolduk, taştık — elhamdülillah."],["Tapduk'un huzurunda (tapusında), kapısında kul olduk;","miskin Yunus ham (çiğ) idik — piştik (olgunlaştık) — elhamdülillah."]],"293":[["Sakın (zinhâr), gönül evinde kötü düşünce (yavuz endîşe) tutma;","başkası için kuyu kazan, sonunda kendi düşer."],["Nefsinin beğenmediğini başkalarına (ayruklara) yakıştırma;","başkalarına yakıştırırsan, bil ki işin şaşar (ters gider)."],["Kendine yakıştırmadığı kötülüğü (yaramazı) başkasına yakıştıran kişinin,","adı Müslüman'dır, ama özü adına uymaz (sözde Müslüman, özde değil)."],["Koymadığın (senin olmayan) şeyi uzanıp alıp götürme;","koymadığını götürmek, kötü (yatlu) işe düşürür."],["Bu dünyada üç kişi Hakk'ın dîdârını (cemâlini) görmez:","biri kavgacı (dikçi), biri dedikoducu (kovcı), biri de büyüğe (âmire) gammazlık (iftira) edendir."],["Yunus'un bu nasihatini (öğüdünü) tutan, kötü (yatlu) olmaz;","baştan başa dinlersen, birçok faydalı öğüttür."]],"294":[["Hoştur eğer aşkın ateşinde (odına) yana yana yürürsem;","öyleyse yanmadan nasıl olabilirim — madem aşk ateşi cana düştü?"],["Canım aşkın külhanıdır (ocağıdır) — çekinmeden ateşini vur;","ocağa ateş bırakınca, kamış suyu şeker olur."],["Her ham (çiğ) şey, ateş olmayınca pişmez;","benim hayatım (dirliğim) hamdı — aşk ateşi (olgunlaşmama) vesile (bahane) oldu."],["Bu işler tamamlanınca, ma'şûkla (sevgiliyle) halvet (baş başa kalma) olur;","ma'şûkun yüzünü gören kişi, yanıp tükenmelidir (benliği erimeli)."],["Aşkın ateşinde yanarsa, o kişiye saadet (devlet) olur;","acı dumanı (tütünü) çıkınca, bu ev (hâne) aydın olacak."],["O dostla alışverişimiz (bâzârumuz), şu son zamandan beri değil;","daha bu cihana gelmeden, sevgiliyi (ma'şûkayı) severdik. (Bu, ruhun ezelde — bu dünyadan önceki âlemde — Hakk'a duyduğu sevgidir; bedenle ön-yaşam değil.)"],["O ateşe razıyım — günde bin kez yansam da;","gör, pervâne (kelebek) mumun önünde nasıl can feda eder."],["Aşkta ne kadar yanarsam, bana o kadar tatlı (şîrîn) gelir;","canım feda olsun, beni bu aşk ateşine atana."],["Aşkın sultanı Tapduk'tur, Yunus bu kapıda bir dilenci (gedâ);","dilencilere (gedâlara) lütuf etmek de, sultana yakışan bir kuraldır (kâidedir)."]],"295":[["Vücut (beden), hikmetin sırrı içinde bir binadır;","gönül bir temeldir (bünyâd) — asıl değerli sermaye (nakd), o temelin içindedir."],["Gönül sultandır, can onun hâkimi (veziri) — bütün işler ona kurban;","dil de bir tercümandır — Allah'ın kudreti içinde yürür."],["Gönül tahta oturur, Kaf'tan Kaf'a (her yere) hükmeder;","nefis uzakta durmuş — eğilimi (meyli), eğlence (işret) içinde."],["O nefs ki cana uyar görünür — onu mânâdan anlıyor sanma;","her an ona (nefse) uymayanı bil ki — Allah'ın inayeti (lütfu) içindedir."],["İlk kapı Şeriattır; ondan geçince Tarîkat;","gönlün evi Mârifettir (irfandır); aşk, Hakîkatin içindedir."],["Şeriat tatlıdır (şîrîn), işitene hoş gelir;","kişi ne dilerse, o Şeriat içinde (onun çerçevesinde) yapar."],["Tarîkat canın yoldaşıdır, işi can iledir;","Tarîkata giren kişi, gece gündüz ibret (uyanıklık/tefekkür) içindedir."],["Mârifet (irfan) gönül iledir, gece gündüz yakarışla (zârıyla);","söylesem dile gelmez — sıfatların sırrı (sırr-ı sıfat) içindedir."],["Hakîkat aşktır, ayandır (apaçıktır) — o açık beyânı kişi görsün;","Hakîkatin giysisini (donını) giyen, ağır bir şeref kaftanı (hil'at) içindedir."],["Şeriat, sûret (biçim) evidir — ibadete (tâate) güçlü (kavî) girer;","ünü (çavı), kulluk (ubûdiyyet) içinde âleme yayıldı."],["Tarîkat cana gelir, ibadetine canını (bütün varlığını) verir;","ona girmeyen, işte bu saadetten (devletten) yana ziyan eder."],["Hakîkate erenler, Hakîkati bulanlar —","canları ne bahtlıdır, hep muhabbet (sevgi) içinde."],["Her kim Şeriatı bilip, hem okuya (öğrene) hem kıla (uygulaya);","o kişi, gece gündüz ibadet (tâat) içinde, er (ermiş) olmaya layıktır."],["Eğer ibadet (tâat) kılmazsa, üstada (mürşide) varmazsa;","Şeriattan (şer'den) olmazsa — adı lanet içindedir."],["Şeriat ona der: 'O ad (Müslümanlık adı, ona) boştur (abestir)';","onun makamı, şu ahirette ateştir (oddur)."],["Her kim Tarîkata girerse, malını terk etmeli;","bu Tarîkat içinde, yola dosdoğru can vermeli."],["Eğer doğru durmazsa, malını terk etmezse;","yola can vermezse — sohbet (manevî meclis) içinde bir şey sezmez (anlamaz)."],["Tarîkat onun gerçekten değildir — o, yolunu kederli (melûl) kılmış;","Hak onu kabul etmez, rahmet içinde kendine yer bulmaz."],["Eğer dalgıç kuşu (bahrî) olmazsa, denize dalmazsa;","manevî seyrânı bilmezse — onun için bu yolda kıymet yoktur."],["Mârifet, gönül şehridir — makamını manevî yoklukta (fakrda) bulur;","bu Mârifet içinde, bir dalgıç (bahrî) gerek, bir dalgıç."],["Mârifet ondan ıraktır (uzaktır), o durak (makam) onun değildir;","işi çok (yavlak) olsa da — bu ad (Mârifet adı) içinde ona bir pay yoktur."],["Her kim Hakîkati sürerse (peşine düşerse), Allah'ın kahrını ve lütfunu bir görür;","bu Hakîkat içinde, yol alır, dosdoğru durur."],["Eğer doğru durmazsa, yoluna ermezse;","Allah'ın kahrını hoş görmezse — adı, gerçek ad içinde yok sayılır."],["Hakîkat onun değildir, o saadet (devlet), o nasihat de onun değildir;","önce sonra, en sonunda — kendini mât (yenik) bulana dek."],["Bunlar dört menzildir (duraktır) — sakın gevşersen utan, ey ledün (gizli ilim) makamını tutmak isteyen;","o kişidir menzile (asıl durağa) eren — muradına tam ermiş olarak."],["O menzile (durağa) erenin, dört nişanı (alâmeti) vardır;","o nişanı (alâmetleri) yerine getirenin yeri, rahmet içindedir."],["Sûretini (dış hâlini) halka düzgün tutar, Hakk'ın yolunda iz sürer;","yükselip o semâvât (gökler) içinde manevî seyir eyler."],["İşi tevekkül (Allah'a güven) ola, aşı (azığı) kanaat ola;","başı (önderi) inayet (Allah'ın lütfu) ola — rahmet nuru (nûr-ı rahmet) içinde."],["Dedikoduya (kıyl u kâle) mecal (imkân) yok — o bir hâldir, ona boş söz (kâl) yok;","ona asla (hergiz) ölüm (ecel) yok — ezel-ebed (öncesizlik-sonsuzluk) içinde."],["Bunca sözler (âvâzlar), boş değil, hakiki iştir — söylediğim mânâlı sözlerdir;","bu vilâyet (velîlik diyarı) içinde, Tapduk, Yunus'u gözetir."]],"296":[["Erene (ermişe) ererek âşık oldum;","eri (ermişi) görerek Hakk'ı buldum."],["Ere (ermişe) erdim, erde maksudumu (aradığımı) buldum;","dışarıdan (taşradan) sorarak bulamadım."],["Nereye baktıysam, er (ermiş) oturur (oradadır);","yüzümü yere sürerek (tevazuyla) gönlünü aldım."],["Canlara bütün nasip (pay), Hak'tan imiş;","yalnızca Kâbe'ye varmakla olmazmış. (Dış ibadet inkâr değil; asıl nasibin Hakk'ın lütfundan, gönülden geldiği vurgusu.)"],["Kâbe, senin eşiğindir (erenin/gönlün eşiğidir) — öyle bil;","yol alıp oraya varmakla (yalnızca dış yolculukla) bulamadım. (Asıl Kâbe, Hakk'ın bulunduğu gönül/eren eşiğidir; maddî Kâbe inkâr değil.)"],["Beni eskiden gören, bir pula (paraya) saymazdı;","şimdi gören, parmakla (saygıyla) gösterir."],["Bir göl idim, erenler nazar kıldı (bir baktı);","dört yana ırmaklar akan bir deniz oldum."],["'Yunus' diye bir ses (ün) geldi, ayağa kalktım (turdum örü);","kulağımı çağrıya vererek, gözümü açtım (uyandım)."]],"297":[["Gönül, ma'şûkunu (sevgilisini) bulmayınca nasıl huzur bulur (dölenir)?","Kimse, gönlünü sevgiliye vermeden (gönülsüz kalmadan) âşık olur mu?"],["O'nu seven gönüldür, seni esir eyleyen de gönüldür;","sen kendin âzâd (özgür) olmayınca, kimi âzâd edersin?"],["Boynu zincirli geldik, iyice esir olduk;","hâlimizi bilmeyince, er (ermiş) nazar etmedi (bir bakmadı)."],["Bir yandan ararlar, onu başka (ayruk) bir şey sanırlar;","sen satın almayınca, onun değerini (bahâsını) ne bilirsin?"],["Onun bedeli (bahâsı) canımdır — malla davarla alınır şey değil;","sevenler kendilerini vermeyince, sevgili (sevdük) ele girer mi?"],["Bu kayıttan (kaygıdan/bağdan) geçmezsin — cana (sevgiliye) nasıl âşıksın?","Irmaktan geçmeyince, deryadan ne alırsın?"],["Kendinde (benliğinde) durarak, dostu nerede bulursun?","Sen virân (yıkık) olmayınca, O Allah seni imar etmez (yeniden bina etmez)."],["Sözü Yunus'tan işit — kibirlenme, öğüt tut;","harap (yıkık) olmadıkça, imar olmazsın (gönlün bayındır olmaz)."]],"298":[["Vuslat (kavuşma) hâlini bilenlere, hâlimin vasfını (niteliğini) söyleyeceğim;","Hakîkate erenlere, yedi türlü nişan (alâmet) gerek."],["Bu yedisinden biri eksik olursa olmaz;","bu sarp (çetin) yola varanlara, biri bile eksik olmamalı."],["İlk nişanı (alâmeti) budur: hiçbir milleti (topluluğu) yermez (kötülemez);","yerenler kendi yermesinde kaldı — yerme, yerilenlere değmedi (zarar vermedi)."],["İkinci nişanı budur: nefsini hiç semirtmez (şımartmaz);","sakın (zinhâr), siz nefsine kul olanlardan olmayın."],["Üçüncü nişanı budur: bütün heveslerden geçer;","hevesler gevşek kişiyi yolda bırakır — yol varanlara yetişemez."],["Dördüncü nişanı budur: dünyadan arınmış (münezzeh) ola;","dünya seni mânen hasta (sayru) eder — böyle hastaların ne kaygısı (umuru) olur?"],["Yunus yedi nişan dedi, fakat (evet) üçünü gizledi;","onları da, gelip halvette (baş başa) soranlara söyleyivereyim."]],"299":[["Kimde gerçek erlik (ermişlik) varsa, onu miskinlikte (alçakgönüllülükte/benlik terkinde) buldular;","yüksekten gururla bakanlar, merdivenden (nerdübândan) düştüler."],["Yüksekte gururla gezen gönül, an be an (dem-be-dem) yoldan sapar;","içinde ne varsa, o dış yüze (taş yüzine) sızar (belli olur)."],["Ak sakallı ihtiyar pîr bile, kendi hâlinin nice olduğunu bilmez;","bir gönül yıkarsa (bir kalp kırarsa), hacca gidip boşuna emek harcamasın."],["Sağır, sözü işitmez, gündüzü gece sanır;","âlem aydınlık (münevver) olsa da, inkârcının (münkirin) gözü kördür."],["Gönül, Çalap'ın (Allah'ın) tahtıdır — Çalap gönle baktı;","kim bir gönül yıkarsa (bir kalp kırarsa), iki cihanda da bedbahttır (talihsizdir)."],["Sen kendini ne sanırsan (kendin için ne istersen), başkası (ayruk) için de onu san (iste);","dört kitabın (Tevrat, Zebur, İncil, Kur'an) mânâsı, varsa, budur."],["Bildik: gelenler geçmiş, konanlar geri göçmüş — her şey geçici;","kim gerçek mânâyı sezerse, aşk şarabından içmiştir."],["Yunus yoldan sapmasın, yüksek yerde gururla durmasın;","sevdiği Allah'ın dîdârı (cemâli) ise, mezar (sinle) ve Sırat azabını görmesin."]],"300":[["Sana bir söz söyleyeyim — canın varsa dinle;","aklın sana yardım ediyorsa, hiç tamah (açgözlülük) etme."],["Kötülük (yavuzluk) etme, lanet işitmeyesin;","iyiliğin (eylüğün) varsa, senden sonra (ardından) iyi söylensin."],["Kötülükten (yavuzluktan) ne hayır çıktı — ya iyilikle (eylükle) kim menzile erişti?","İyilik Hakk'a yaraşır — sende ikrar (iman) varsa."],["İkrar (iman), erin (ermişin) yardımcısıdır — varsa, yeri cennettir (Uçmak);","cimri (bâhil), yüz bin gözü olsa da, cenneti (uçmağı) görmez."],["Mânâda (irfanda) getirmişler: gerçek yâr (dost), kardeşten üstündür (yigrektir);","eğer doğru (sadık) bir dost ise, oğuldan bile tatlıdır."],["Karşındaki gerçek dostun hizmetinde (tapusında) baş eğ (saygıyla eğil);","çaren (imkânın) varsa, ciğerini çıkarıp ona yedir (uğruna her şeyini ver)."],["Dostunu eğri (yanlışta/dargın) gördünse, neyin varsa ver, gerisini bırak;","işittiysen, bu büyüklerden kalma bir atasözüdür (meseldir)."],["Ekmek (etmek) yiyip tuza ihanet etmek (nankörlük), o alçakların (nâ-merdlerin) işidir;","tuzun hakkı varsa, ekmek onu cezasız bırakmaz."],["Çok söz, hayvan yüküdür; az söz, erin (insanın) güzelliğidir (görkidür);","canında cevher (gevher/öz) varsa, bilene bir söz yeter."],["Miskin Yunus delidir, bu sözünden de bellidir;","ey dostlar (yârenler), eksikliği (kusuru) varsa ayıplamayın."]],"301":[["Ey kopuz ile çeşte (saz) — aslın nedir, ne iştesin?","Sana bir soru sorarım — söyleyiver bana, işte (hemen)."],["Der ki: aslım ağaç, birkaç koyun kirişi;","gel işretimi (çaldığım nağmeyi) dinle geç — aklını boşa (beleşde) bırakma."],["Bana 'haram' derler — oysa ben hırsızlık (mahsulü) değilim;","madem aslım temiz (mismil/helal), kirişte ne varmış haram olacak?"],["Bana 'kiriş' dediler, 'aşka giriş' dediler;","adımı aşk verdi — ben hilede (kolmaşda) durmam (yalanla işim yok)."],["Sevinçle (şâdılıkla) geldim, işte bu âleme doldum;","mürüvvet (cömertlik) meclislerine dizildim — beni bu düşe (dünya rüyasına) koydular."],["Ağaç dirildi (canlandı), kirişle (telle) bir oldu;","aşk denizine daldı — bu işte kaçacak bahane yok."],["Mevlâna'nın sohbetinde, sazla işret (sema) oldu;","ârif mânâya daldı — çünkü melek (ferişte) hep onunla beraberdir."],["Meleği (ferişteyi) anmaktan, maksat (murâd) nedir bilesin:","o, gece gündüz seninle beraberdir, her işinde."],["O meleklerin adı Kirâmen Kâtibîn'dir (amelleri yazan şerefli melekler);","yazmaktan usanmazlar, yaz kış yorulmazlar."],["Biri sağ omzunda, biri sol omzunda;","biri iyiliğini (hayrını) yazar, biri her şer hareketini."],["Kâğıtları tükenmez, ne de mürekkepleri;","kalemleri aşınmaz — o işte (yazmakta) süreklidirler (kâ'imdirler)."],["İster meyhaneye varsın, ister puthaneye (büt-hâneye) girsin;","bunlar (melekler) seni kaydeder (gözetir) — sen bu işte gafilsin (habersizsin)."],["Yunus, şimdi Sübhân'ı (her kusurdan uzak Allah'ı) gönülde vasfet (an/öv);","bu kopuz ile çeşte (saz), ârif için Hak'tan ayrı değildir."]],"302":[["İstediğimi (Hakk'ı) buldum — apaçık (eşkere), can içinde;","dışarıda (taşrada) arayan, oysa O kendi içinde gizlidir."],["Daimîdir (kâ'imdir), hiç ayrılmaz — O'nsuz kimse dirilmez (yaşamaz);","yine de adım adım yeri ölçer — kendisi, akıp giden her can içinde."],["Bu tılsımı (sırrı) bağlayan, her dilde söyleyen;","yere göğe sığmayan — bu can (gönül) içine girmiş. (Yere göğe sığmayan Hak, mü'minin gönlüne sığar; bu, kalbin ilahî kabiliyetidir.)"],["Hırsızlar arasında sanki hırsız olmuş — kendi kendini yakalar;","ceza sahnesi (sahne) kendisi olmuş — kendi, zindanın içinde. (Birlik hâlinde her sûrette tecellî eden Bir gerçeğin görünüşü; Hak'la kötülüğün özdeşliği değil.)"],["'Tutun!' diye çağırır — hırsız da aynı anda çağırır;","bu ne şaşılası hırsız — bu çağıranın içinde. (Aynı birlik görüşü: Bir gerçek hem çağıranda hem yakalanada görünür.)"],["Ceza (siyâset) meydanında, kalabalıktan (galabadan) bakan O'dur;","cezanın kendisi (siyâset) olmuş — meydana girmiş. (Yine birlik görüşü.)"],["Kudret kılıcını almış, nefsin boynunu vurmuş;","nefsini öldürmüş (depelemiş) — elleri kan içinde. (İç savaşta nefsin öldürülüşü.)"],["Hasta (sayru) olmuş inler, Kur'ân'ın sesini (ününi) dinler;","Kur'ân okuyan kendisi — kendisi, Kur'ân'ın içinde. (Birlik görüşü; Hak okuyanda da okunanda da tecellî eder.)"],["Yüce yüce Arş'ı kurar, kendini orada bezer (süsler);","gör, nasıl gezinir (cevlân eder) — bir hırka, bir çul (palâs) içinde. (Hem yüce Arş'ta hem derviş hırkasında tecellî.)"],["Türlü türlü imaret (yapı), köşk ve saray yapan O'dur;","kara peçe (nikâb) takınmış — bir külhanın (hamam ocağının) içine girmiş. (Hem sarayda hem külhanda tecellî.)"],["Baştan ayağa dek, Hakk'ın nuru seni tutmuş (kaplamış);","Hak'tan ayrı ne vardır — şüphede (gümânda) kalma. (Her şey varlığını O'ndan alır, O'nun tecellîsidir; yaratılış 'Tanrı'dır' demek değil — Hak münezzehtir.)"],["Bir isen (birliği arıyorsan), birliğe bak — ikiliği elden bırak;","bütün mânâyı, doğruluk (sıdk) ve iman içinde bulursun."],["Orucuna güvenme, namazına dayanma (onları gurur vesilesi yapma);","aşkın nâzı ve niyâzı (yakarışı) içinde, bütün ibadet kişiye bir kusur (tak) gibi görünür. (İbadet terk değil; ibadetiyle övünüp ona güvenmek yerine Hakk'ın lütfuna dayanmak.)"],["Oruç, namaz, gusül ve hac — âşıklara bir perdedir (hicâbdır);","âşık, seçkinlerin seçkini (hâssü'l-havâs) içinde, ondan o perdeden arınmıştır (münezzehtir). (Bu, ibadeti bırakmak değil; en ileri âşığın, biçimlere takılıp onları gaye edinmek yerine içlerindeki öze — Hakk'a — ermesidir; biçim, ancak ona gönül kaptırılınca perde olur. Âşık için ibadet, Hakk'a açılan saydam bir kapıdır.)"],["Gönül şehrine girdim, onun denizine (bahrine) daldım;","aşkla seyrederken (manevî yolculukta), can içinde Hakk'ın izini buldum."],["O izi izledim (takip ettim), sağıma soluma baktım;","çok acayip (şaşılası) şeyler gördüm — cihanda benzeri yoktur."],["Şah (padişah) olup oturur, kula buyruğunu tutturur (emrini uygulatır);","fermanını buyurur — küfür fermanı (görünen inkâr) içinde bile. (Olan her şey — inkâr dahi — O'nun her şeyi kuşatan takdiri içindedir; Hak küfrü emretmez/onaylamaz — bu, kazâ-kader sırrıdır.)"],["Yunus, senin sözlerin — bilenlere — mânâdır;","senin sözünü, çağlar boyunca (devr-i zaman içinde) söyleyecekler."]],"303":[["Can ol, can içinde (Hak'ta) — şüphede (gümânda) kalma;","istediğini (Hakk'ı), yakın zamanda bulursun."],["Rükûda secdede öylece kalma, amellerine (yaptıklarına) dayanma;","ilim ve amel, aşkın nâzı ve niyâzı (yakarışı) içinde erir (gark olur). (İbadeti terk değil; onunla övünüp güvenmek yerine, sevgi içinde Hakk'a teslim olmak.)"],["İkiliği terk et, birlik (vahdet) makamını tut;","canların canını (Hakk'ı), işte bu hayat (dirlik) içinde bulursun."],["Oruç, namaz, zekât, hac — en ileri âşık için, övünç vesilesi yapılırsa, sanki suç (cürm) ve günah (cinayet) gibidir;","manevî fakir, seçkinlerin seçkini (hâss-ı havâs) içinde, bundan âzâddır (özgürdür). (İbadeti bırakmak değil; onu kendi 'marifeti' sayıp benlikle ona güvenmekten arınmaktır. Fakir, ibadetini yapar ama hiçbir hak iddia etmez, her şeyi Hakk'ın lütfu bilir.)"],["Şeriat, Hakîkat ordusunda bir koruyucudur (muhafızdır);","senin için korunur — o Hakîkat ordusu içinde Şeriat, hep yürürlüktedir. (Yani önceki beyitler Şeriatı kaldırmaz; Şeriat, yolun vazgeçilmez bekçisidir.)"],["Canların canını (Hakk'ı) bulasın, sen de gerçek can olasın;","aşkla seyrin/ferahlığın (teferrücün), Hakk'ın dîdârı (cemâli) içinde ola."],["Yunus, ayne'l-yakîn (görerek) görmüştür — Mecnun olmuştur;","Hakke'l-yakîn (yaşayarak kesin biliş) içinde, Bir ile bir olmuştur. (Bu, fenâ hâlinde benliğin Hak'ta erimesidir; birlik bilinci — özdeşlik/panteizm değil.)"]],"304":[["Derviş olan kişiler, ne acayip (güzel) yaşar;","yolun gereği (takazası) şudur: herkesle bir (uyum içinde) olmak."],["İkilik (ayrılık/ikiyüzlülük) etmeye, hiç yalan söylemeye;","âlem bulanırsa (karışırsa), bulanmadan (durulukla) dura."],["Ne acayiptir o kişi ki, her şey karışsa da bulanmadan dura;","öyle o sağlamlığı istersen, er (ermiş) ile yoldaş ol."],["Er ile yoldaş olan, gönülden iyi (key) olur (gerçek olur);","eğer yoldaşlık dille (sözle) olsaydı, bütün âlem yoldaş olurdu."],["Dilden (sözden) sana bir şey gelmez, gönül suyla yıkanmaz;","gerçekten (içtenlikle) gelenleri, bir kılla (incecik bir bağla) yederler (çekip götürürler)."],["O kıl kopsun (üzülsün) diye, gece gündüz onu çekerler;","oysa o, ömrünü oraya bağlamış (berkitmiş) — bir kılla yedilir (gider)."],["O kılı ince (önemsiz) sanma, bu yolu boş (güzâf) sanma;","erenler her biri bir hâl ile geçti geldi."],["Her kimin hâli gerçekten hâllendiyse (olgunlaştıysa), o bey oldu, ona hizmet edildi;","Yunus, sen kul olmaya bak — bey (efendi), kuluyla söyleşir (konuşur)."]],"305":[["On sekiz bin âlemin halkı, hepsi Bir'in içinde (Bir'den);","Bir'den başka kimse yok — her dilde bu söylenir. (Hepsi varlığını Bir'den alır — tevhid; yaratılış 'Tanrı'dır' demek değil.)"],["Hep bir olur, O'nu birlerler (bir bilirler); hep O'na giderler;","her dil O'nu söyler — her bir menzilde (durakta)."],["Her göz O'nu gözler, ama kimse O'nun nişanını (işaretini) veremez;","gören kim, görmeyen kim — müşkül (şaşkınlık) içinde kaldık."],["Kim O'nu apaçık (ıyân) görebilir, kim O'nun nakşını (resmini) ve nişanını söyleyebilir?","Sözü 'Len terânî'dir (Kur'an: 'Beni asla göremezsin') — Musa'ya, Tûr'da söylenen."],["O'nu kimseden ayrı görme — her şeyle beraber (bile) gör;","bütün âlem O'nunla doludur — karada (berr) ve denizde (bahr). (O'nun tecellîsi/varlığı her yeri kuşatır; eşya 'Tanrı'dır' demek değil.)"],["Sidretü'l-Müntehâ'dan (Mi'raç'ın en uç sınırından) öteye geçen,","nur durağı (menzil-i nûr) içinde, hiçbir nişan (haber) söyleyemedi (o âlem anlatılmaz)."],["Doksan bin kelimesi var: otuz bini avam ve havas için (genel),","otuz bini yalnız havasına (seçkinlere), otuz bini de en gizli sırlar içinde."],["İşte odur o gizli söz — ârif onu gece gündüz söyler;","huriler ve köşkler (Hûr u Kusûr) içinde bile, hiç nişan (dışa işaret) etmesin (o sır anlatılmaz)."],["Yunus, sen dilersen — 'dostu göreyim' dersen;","O, görenlere apaçıktır (ıyândur) — işte, gönlün içinde."]],"306":[["İsrafil sûru (kıyamet borusunu) üfler, yeryüzü dürülür (devşirilir);","kara ve deniz (berr ü bahr) harap olur, felek çarkı silinir (yok olur)."],["Kimse burada kalmaya, hepsi oraya vara;","o Padişah'ın (Allah'ın) önünde, Hak terazisi (mizan) kurula."],["Bütün işler (ameller) ayan olur (açığa çıkar), ne yabancı ne tanıdık (yâd-biliş) kurtulur;","'Gel, falan oğlu falan' diye her bir kula seslenilir (çağrılır)."],["Bütün yaratılmışlar (halâyık) kalkar, yeryüzünü dolu tutar;","Padişah (Allah) hüküm verir, hepsi mahşere dek sürülür."],["İkinci nefha (üfleyiş) ile kıyametin dehşeti (hevli) kopar;","üçüncü nefha içinde, yerlerin yüzü yarılır (açılır)."],["Bin bin sınıf (halk) sıraya dizilir — ama âşığa korku (havf) ve haksızlık (hayf) yok;","yarın mahşer gününde, 'Yevme yünfehu' (Kur'an: 'Sûra üfürüleceği gün') borusu çalınır."],["Yunus, azığını (yaragını — tevhid ve ibadetini) hazırla, yolun korkulu olduğunu iyice anla;","gömgök katran denizi (cehennem), Sırat ise kıldan ince gerilir."]],"307":[["Kimse bu nazara (aşkın bakışına) dayanamaz — aşkla kim güreşebilir (pençe vurabilir)?","Bu nazara karşı duran, ev barkını (hânumânını) suya batırır (her şeyini yitirir)."],["Kişi elini aşka uzatınca, aşkın okuna kim dayanabilir?","Gökyüzündeki melekleri bile, aşk yere indirdi."],["Gör, Hârût ile Mârût neydi — ilahî huzurda (Hazret'te) birer melekti;","nasiplerini aşka kaptırıp, makamlarını Zühre'ye (Çoban yıldızına) verdiler. (Aşk uğruna düşen iki melek.)"],["Abdestimiz, namazımız; ibadetimiz (tâatimiz) doğruluktur;","kâmeti (namaza duruşu) aşkla bağladık — safımızı kim ayırabilir? (Aşk, ibadetin canıdır.)"],["Mescit ve medresenin oluşu, tertemiz (pâk) cemaatin kılınışı;","insanların saf saf durması — hep aşkın şükranesidir (şükrüdür), bunun için. (İbadetin özü aşktır.)"],["İçimde aşk ateşi (odı) yanar, onun hasadı (ürünü) gönlümde;","aşk ateşinin dumanından (tütününden), Yunus'un benzi sararır."]],"308":[["Âşıklar, dostu bırakıp nereye varsın?","Dostsuz bir konut (serâ), âşıklara zindandır."],["Âşık, gözünü dostun yüzünden ayırmaz (ırmaz);","onun için canı, gece gündüz avaredir (başıboş)."],["Ma'şûk (sevgili), yüz bir türlü yol gösterir;","öyleyse âşık, bir karara (tek bir durakta) nasıl dursun?"],["Ma'şûkun sınırının (haddinin) sonu (pâyânı) yoktur;","onun için âşık, il ü şâra (hiçbir diyara) sığmaz."],["Ne güzel (zihî) devlet (saadet), ne güzel mutluluk, ne güzel aşk —","kim burada bu dünyada o dostla işini başarırsa (kavuşursa)."],["Kim burada dostla tanışmadıysa (bilişmediyse),","hayatı (dirliği) kederdir (gamdır) — çaresiz (bî-çâre) kaldı."],["Dostun ismini burada (şimdi) tutmaya bak (an), Yunus;","işini yarına (ahirete) bırakırsan, o işin Hakk'a (hesaba) varır."]],"309":[["Git, dertle yana yana yürü — dermana (devaya) erişinceye dek;","aşkla kulluk et — Sultan'a (Allah'a) erişinceye dek."],["Sular gibi akıp git (seyreyle), bir yerde durma (karar etme);","alçak (aşağı) yerlere doğru ak — ummana (okyanusa/Hakk'a) erişinceye dek."],["Gayet hor ve hakir (aşağıda/alçakgönüllü) ol — başta (önde) Halil (İbrahim) olasın;","sen de İsmail gibi kendini kurban (Hakk'a teslim) edinceye dek dayan."],["Eyyüb gibi sabret, Yakub gibi çok ağla;","sen de Yusuf-sıfatlı (Yusuf gibi), Kenan iline (vuslata) erişinceye dek dayan."],["Yunus, sen bu cevheri (gevheri/irfanı) cahile (nâdâna) harcama;","o madene (kâna/kaynağa) erişinceye dek, bu yolda neler çektin hatırla."]],"310":[["Bu cihanda mekânsızım (bî-mekânam) — menzilim, yurdum (turağum) orada o âlemde;","sultanım — tacım, tahtım, cennet giysim (Hulle) ve Burak'ım orada."],["Sanki Eyyüb'üm — bu sabrı buldum; Cercis'im — bin kez öldüm (öldürülüp diriltildim);","bu mülke (dünyaya) yalnız (tenhâ) geldim — azığım (yaragum) tümüyle orada. (Âşık, peygamberlerin hâllerini — sabır, fedakârlık — kendinde duyar; onlar 'olduğu' iddiası değil.)"],["Sanki Yusuf'um — pazara (bâzâra) geldim (satıldım); Mansûr'um — bu darağacına (dâra) geldim;","arslanım — ava (şikâra) geldim, ama (velâkin) yatağım asıl inim orada. (Yusuf'un gurbeti, Mansûr'un aşk-şehadeti/fenâsı; ego 'onlarım' demiyor.)"],["Sanki bülbülüm — işte öterek geldim; dilimde bir ilahî ferman (menşûr) tutarak geldim;","miskimi (müşk) burada satmaya geldim; bir geyiğim — otlağım asıl mer'am orada. (Ruhun bu dünyada garip oluşu, asıl yurdunun o âlemde olması.)"],["Kim ne bilsin ben ne kuşum — ben şu ay yüzlü güzele (Sevgili'ye) yakınım (tutaşım);","ezelden (öncesizden) sarhoşum ben — kadehimi (ayagum) orada ezel âleminde içmişim. (Ruhun ezelde — bu dünyadan önce — Hakk'ın aşk şarabını içişi; bedenle ön-yaşam değil.)"],["Deliyim, öğüt (pend) tutmam; rastgele (degme) yere gitmem;","işte bu dünya sözünü işitmem — kulağımı oraya o âleme tutmuşum (yöneltmişim)."],["Sır sözü açığa (eşkere) çıkmaz; orada bir ateş (od) yanar ama görünmez (belirmez);","gece gündüz yanar, sönmez (söyünmez) — bu benim kandilim (çerâgum) orada."],["Bu mülke (âleme) bir talim (öğreti) verdim, hem yedi kez gezindim (yedi kat göğü dolaştım);","Muhammed'in nurunu (Nûr-ı Muhammedî'yi) gördüm — bu benim asıl mekânım orada. (Ruhun manevî yükselişi ve Nûr-ı Muhammedî müşahedesi; maddî kozmik iddia değil.)"],["Yunus bu tefekküre (fikrete) daldı, bütün cihanı arkaya attı (arda saldı);","vallahi hoş bir lezzet (tat) aldı — tatmışım, dimağım asıl zevkim orada."]],"311":[["İşte, yine bu canımıza bir nazar (ilahî iltifat) oldu;","Muhammed, dinimize ve imanımıza bir temel (bünyâd) attı."],["Peygamberlerin başı (serveri), dinin direği Muhammed;","gör, bu madenimize (kânumuza) ne cevherler (gevherler) koydu."],["Gelin, elimiz erer iken (gücümüz varken) amel (iyilik) edelim;","ecel (ölüm) birdenbire (ansuzın) erer — bize haber bile vermez."],["Eyvah (dirîgâ), bizde amel (iyilik) olmazsa ne yaparız?","Öfkeyle (hışm) gelip, bu kefen giysimize yapışırlar (tutarlar)."],["Sorgucular (kabir melekleri) gelir, sorgu ve hesap sorarlar;","karanlık mezar (sin) içinde, yanımıza otururlar."],["Ölüm gerçektir (Hak'tır), bilirsin — niçin gafil (habersiz) olursun?","Azrail, bu günahlı bedenimize (tenimize) kasdedecek (yönelecek)."],["Miskin Yunus bu sözü kendinden söylemez;","Hak Çalap (Allah), dersini (sebağını) dilimize verdi."]],"312":[["Yine bu taze bahar rüzgârı (bâd-ı nev-bahâr), hoş bir tarzda esti yine;","yine kışın soğukluğunun taşkınlığını (fuzûlluğunu) kesti yine."],["Yine ölçüsüz (bî-kıyâs) rahmeti, yine işret (neşe) bir dost (dem-sâz) oldu;","yine bu yeni yaz geldi, kutlu ayağını (kademini) bastı yine."],["Yine yeni hazineden, cihan yeni bir şeref kaftanı (hil'at) giydi;","yine yeni can verildi — ot ve ağaç yeşerdi (filizlendi) yine."],["Ot ve ağaç (şecer) ölmüştü — dirilerek yine biter (yeşerir);","inkârcılara (müşriklere) bu yeter bir delildir (nükte) — Hak, neslini yine var etti (dirilişe işaret)."],["Yine ova ve çayırlık (merg-zâr), bu coşkun (esrük) sular hoşça akar;","cihanlara saçı (nisâr/armağan) saçtı — bütün âlem yine dostundur (Hakk'ındır)."],["Yine yeryüzü donanıp (süslenip), kat kat olup renge bürünüp;","bülbül güle karşı ötüp, canını dala (budağa) astı yine."],["Sözüm yaz kış için değil — ma'şûk (sevgili/Hak) daha derin bir maksat için geldi;","yeniden bağışlamak (af/lütuf), Padişah'ın (Allah'ın) muradı (kasdı) oldu yine."],["Yine Yunus kendinden geçip, ar ve namusu (utanç kaygısını) yıkıp;","âşıkların yudumundan (cur'asından), ulu bir kadeh içti yine."]],"313":[["Bu dünyanın misali (örneği), bir değirmene benzer;","gaflet (habersizlik) onun sepeti, bu halk da öğütülen tane (buğday)."],["Değirmene varırsın, değirmenciyi sorarsın;","o unu öğütene, Azrail derlermiş."],["Oluktan akan su, Hakk'ın varlığıdır (her hareketin kaynağı); veliler (evliya) ise çarkın mili (iği);","çarkı (değirmen çarkını) felek çarkına benzetene, âferin (ne güzel benzetmiş)."],["Sonra o çarkın yeri, o çıngırağın (çakıldak) ipleri;","senin kaygındır (endişendir) — bulaşık (karmakarışık), tasayla perişan."],["Çıngırak (çakıldak) gece gündüz öter, onu (taneyi) öğütüp döver;","o mukadder gün gelir, belki bu gündür — ömür ise ziyana (boşa) geçti."],["Bu yer, alt taş gibi kımıldamaz, sabit (kâ'im) durur;","bu gök, üst taş gibi — her an (dem) dönmesi gerek."],["Kimileri durmuş, gece gündüz sıralarını (nevbet) bekler;","kimileri beklemez, rindçe (aldırışsızca) öne atılır."],["Toza bulanmış yatar, yaşı yetmişe varmış ihtiyarlar (kocalar);","sıra (nevbet) gelince yönelir (uğrar) — hem yaşlıya (pîre) hem gence (cüvâne)."],["O değirmenin tuncu (göbek mili), bütün gücü (yükü) o taşır;","işte bu dünyanın son ucu (sonu), fenâ üstüne fenâ (yokluk) olacak."],["O sepetin teknesi (yalağı), sonunda ölüm döşeğidir;","tane (buğday) bitince, unun da tükenmesi gerek."],["Un ambarı (unluk), senin mezarındır (sinindir) — sakın kabir (gûr) azabından;","Mustafa (Peygamber) böyle dedi, Kur'an'a inanırsan."],["Ne kadar bu temsilleri (benzetmeleri) söyleyip durursun gezerek?","Yunus, sen derdin için dermana (devaya) çalış (sa'y et)."]],"314":[["Bir Tanrı hâsını (Allah'ın seçkini/mürşidi) tut (bul);","gel, erenlere ikrar et (bağlılık sözü ver);","gönlünün pasını (kirini) silsinler;","gel, erenlere ikrar et."],["Ahdini (sözünü) öyle bir sağlamlaştır ki,","hem malın olsun hem yol eşyan (rahtun);","gayretin (cehdin), Hakk'ı bilmek olsun;","gel, erenlere ikrar et."],["Erenler, Tanrı'nın hâsıdır (seçkinidir);","gönülden pası (kiri) silerler;","muamelesi (alışverişi) dost (Hak) iledir;","gel, erenlere ikrar et."],["Gönlünün karmaşasını (teşvîşüni) gider;","kaba (hoyrat) nakşını (dış görünüşünü) süsleme;","can kuşunu (ruhunu) uçurmadan (ölmeden);","gel, erenlere ikrar et."],["Bu uzun kaygıdan (endîşeden) geç;","nefsini ezip (uşatıp seni) erdirsin;","dosta (Hakk'a) dışarıdan (taşradan) bakma, içinde ara;","gel, erenlere ikrar et."],["Bu can sana kalıcı (bâkî) kalmaz;","oraya varan, geri gelmez;","son anda gelen pişmanlık fayda (assı) etmez;","gel, erenlere ikrar et."],["Bu dünyayı elden bırak;","ahirete azık (yarak) hazırla;","erenlerden uzak (ırak) olma;","gel, erenlere ikrar et."],["Eğer Allah'ı seversen,","o Şah'a (Allah'a) hoşça niyaz et (seslen);","vallahi Hak sana rahmet eder;","gel, erenlere ikrar et."],["Yunus, sen pişman olmadan,","ölmeden ere (ermişe) eriş;","bu dünya sana gülmeden (aldatmadan);","gel, erenlere ikrar et."]],"315":[["Sana derim, ey dost (kişi):","kalk, sabah (irte) namazına;","eğer ölü değilsen,","kalk, sabah namazına."],["Müezzin ezan okur,","Allah'ın adını çağırır;","dininin temelini (bünyâdın) yıkma;","kalk, sabah namazına."],["Kuşlar uçup yükselir (pervâze),","ağaçlar tesbih okur (Hakk'ı anar);","ey himmet (manevî yardım) alan kardeşler,","kalk, sabah namazına."],["Namazı kıl, zikret (Hakk'ı an);","elini kaldır, şükret;","öleceğini düşün (fikret);","kalk, sabah namazına."],["Namaz kıl, azık (yarak) olsun;","ahirette gerek (lazım) olsun;","mezarında (sinünde) bir kandil (çırâk) olsun;","kalk, sabah namazına."],["Namazı imanla kıl;","şüpheyle (gümânıla) yatma;","emniyetle (emânıla) gidesin (göçesin);","kalk, sabah namazına."],["Can da çıkıp gidecek,","ten (beden) de öylece cansız kalacak;","Derviş Yunus, sen de","kalk, sabah namazına."]],"316":[["Bana bir imaret (yapı) göster ki sonu virân (yıkık) olmasın;","o malı kazanmaya bak ki, senden geriye dünyada kalmasın."],["Altının, malın dökülür (dağılır), durumun başkasının (vârisin) eline kalır;","senden geriye kalan mal, bil ki sana fayda (assı) etmez."],["O mal ki Halil'indir (İbrahim'in gibi) — onu hayırlara (iyiliklere) yöneltirler;","o mal ki Karun'undur — sahibi (ıssı) hiç rahat bulamaz."],["İsrafil sûrunu (kıyamet borusunu) üfler, dağlar yerinden kalkar;","bir karıncanın bile hesabını, bin Süleyman bir araya gelse veremez (herkes kendinden sorulur)."],["Bu dünya hep sahipsiz (ıssuz) kalır, altını malı dökülür;","herkese kalıp (sebil olup) yiter — sahibi (ıssı) asla (hergiz) bulunmaz."],["Hey Yunus Emre, ölünceye dek, var, doğru yolunda yürü;","dünyasını terk edenler, yarın ahirette Hazret'te (Hakk'ın huzurunda) ölmez (ebedî dirilir)."]],"317":[["Ben dost için ağlarsam, gözümün yaşını kim siler?","Böyle acayip (eşsiz) bir dertle, benim yaşım nasıl dinsin (dursun)?"],["Ey dostlar (yârânlar), beri gelin, hâlimi (ahvâlimi) anlatayım;","hiç kimse var mı ki bu derdime derman ola?"],["Bütün âlem gelse, O'nsuz derman olmayacak;","derdime kim derman olur — madem gönlümde sevilen O'dur?"],["Ölüp mezara (sine) girsem de, etim tenim çürümez;","çünkü ben dünyadan sevgiyle (sevmekle) giderim."],["Dostlarım (yârenlerim) bana der: 'Onu (Yunus'u) artık görmeyiz';","sûretim (bedenim) ayrılığa (fürkâte) düştü — bir menzilden (duraktan) bir menzile göçüyor."],["Bir gözü yaşlı ârife rastladım, der ki: 'Ağla';","burada çok ağlayan kişi, orada (ahirette) güle güle gider."],["İlm-i sâbıktan (Allah'ın ezelî ilminden) önce, daha Elest bezmi belirmeden (Kur'an: ruhların 'Rabbin değil miyim?'e 'evet' dediği an);","ben o idim, o ben idi — şimdi bu bağ nasıl kesilsin? (Bu, ruhun ezelde — Elest'te — Hak'la kurduğu sevgi bağıdır; ayrı bir varlık olarak ön-yaşam ya da özdeşlik değil.)"],["O kıyamet pazarında, her kula kendi başının kaygısı (derdi) düşer;","O'nu seven (âşık) ise kaygılanmaz — çünkü O, mahşer meydanında (arasâtda) onunla beraberdir."],["O dostla benim işim, ölünce bile bitmeyecek;","bu nasıl biter — madem gönülde dost sevilir?"],["İsrafil sûru (kıyamet borusunu) çalınca, her kişi 'nefsim, nefsim' diye kendi derdine bağıracak;","ben Yunus'u hiç anmayayım (kendimi düşünmeyeyim) — o an dilime Tapduk (şeyhim) gelsin."]],"318":[["Ne güzel tatlı huylu bir dilber (Sevgili) ki, bu an yurdu (turağı) candadır (gönüldedir);","madem dost, can evini alır — kendi özü oraya hemen sığar (gönle dolar)."],["Can içinde dostu bulan, başka (ayruk) yerde ne istesin?","O'nu dışarıda (taşra) arayanların ömrü, dağınık (perakende) geçti."],["O kişi ki aşkın aynası (gözgüsü), bizi kendinde gösterir (aşk aynasında hakikat görünür);","gönlü aşkla sarhoş (esrük), Hakk'a âşık — bu çaresiz (dermânde), esir olmuş."],["O'nu bana sorarsan — benim yönüm dosttan (Hak'tan) yanadır;","hangi hâlde yürürsem yürüyeyim, sevgim (mihrim) günbegün artar durur."],["Bu bedende (sûretde) başka kim varsa, yönünü başka yana döner;","benim varlığımı (benliğimi) dost aldı — burada kalan, yalnızca izimdir (eserimdir). (Benliğin Hak'ta erimesi — fenâ; yokluk değil.)"],["O'nu bana soranlara, nasıl bir nişan (işaret) söyleyivereyim?","Bu aşkın yurdu (turağı) nerede — dille kim söyleyebilir?"],["Ne güzeldir o ilahî saadet (devlet) — kime yoldaş olursa;","o kişi ki ömrünü, bu yerde bu mekânda, dostla (Hak'la) sürdü."],["Dosttan (Hak'tan) yana giden kişi, benliğini (kendüligin) bırakmalıdır;","dünyaya tutunup gelen kimse (harîf), bu dîvanda (Hakk'ın huzurunda) geçmez (kabul görmez)."],["Ne tatlıdır, gel gör ki — ihtiyarlar (kocalar) aşkla yiğit (genç) olur;","sarhoşluğu (esrükliği) ayılmadan, bu meydanda ne coşku (şûr) eder."],["Yunus, gel gör âşıkları — nasıl benlikten yitip gitmişler (yavu varmışlar);","dünyayı da ahireti de elden bırakıp, ne verende ne alanda (çıkar hesabının ötesinde). (Hakk'ı, cennet beklentisinin bile ötesinde, kendisi için sevmek.)"]],"319":[["Mânâ beratını (ilahî sözün fermanını) yine elimize aldık;","Padişah (Allah), Hak sözünü dilimize verdi."],["Hak sözlerini söyler, canları hayran eder;","cahiller, bu bizim manevî seyrimize giremezler."],["Sırrımıza ermezler, pek (inen) yoldaş olmazlar;","herkes (degmeler), bu bizim hâlimize hâldaş (hal arkadaşı) olmaz."],["Hâlimize hâldaş ol, yolumuza yoldaş ol;","müşkülün (zorluğun) açıklığa kavuşsun diye, büyüğümüze (mürşidimize) baş eğ."],["Bu bir gizli hazinedir (genc-i nihân) — sofiler burada ne arar?","Nice ördek, nice kaz, gölümüze hoşça iner (talipler buraya gelir)."],["Şu Bâkî'ye (ebedî Allah'a) kulluk ettik (tapduk), dünyayı elden bıraktık;","ahireti kabul ettik — büyüğümüze (mürşidimize/Tapduk'a) şükrederiz (şâkiriz)."],["Yunus, sen dalgıç kuşu (bahrî) ol, nur denizine dal;","bu Hak sözlerini al ki, madenimize (kânumuza/kaynağa) eresin."]],"320":[["Seni göreni hâli döner — nişansız (izsiz), bî-nişâna (belirsize) benzer;","bütün halkı sarhoş ettin, kadehi (peymâne) saf (katıksız) içirdin."],["Sen bunca sıfatla gizli (pinhân) iken, ey server (ulu);","âşıkların devletisin (saadetisin) — cihana meşhur (ünlü) oldun."],["O'nu işiten kulak, suskun (ebsem) oldu, uyanık (sak) kaldı;","bütün gönüller, mutlaka kesinlikle o delile (bürhâna) 'doğrudur' (saddâk) dedi."],["Sana toplanan (sende birleşen) birlik (vahdet) — işte odur ebedî hayat (dirlik);","Senden başkasını (ayrugı) bildik ki — hepsi kuru bir efsane (geçici)."],["Senin hikmetin uzaktır (erişilmez), sen canlara duraksın (yurtsun);","senin yaktığın kandil (çerâk), bildik ki ebedî yanar."],["Sen hâsların (seçkinlerin) kapısısın (bâbısın), âşıkların kitabısın;","salt (mutlak) dîdâr (cemâl) kapısısın — seni görenler, sana göre birer mahlûktur (yaratıktır)."],["Yerin göğün ayakta (kâyım) durması, denizlerin dalga (mevc) vurması;","cennet ve hurinin oluşu — hepsinde vesile (bahâne) Sensin. (Her şey Sen'den/Senin için var; eşya 'Tanrı'dır' demek değil.)"],["Daha yer gök yokken, bütün söz henüz hükümsüzken (yaratılmamışken);","âşıklar, o bî-nişân (izsiz) Sübhân'a (Allah'a) kulluk ederlerdi (taparlardı). (Ruhların, yaratılıştan önceki âlemde Hakk'a kulluğu; bedenle ön-yaşam değil.)"],["Senin kaşın, yay kurmadan, durmadan ok atar (aşk oku);","İsrafil sûru (kıyamet borusunu) üflemeden, nice canlar aşkla uyanır."],["Bu göz, kendi özünü göremez; senin nişanın (izin), bir nişan (işaret) vermez (sen ize sığmazsın);","Yunus'un aklı sana ermez — büsbütün (inen) divane (deli) oldu."]],"321":[["Muhammed'in övgüsünü (medhini) baş üstüne (en yüce saygıyla) edelim;","zira o Muhammed, Arş'ın (ilahî tahtın) üstüne yürüdü (Mi'raç)."],["Arş'ına ayak (kadem) bastı — işte o, Allah'ın Resûlü'dür (ben böyle tanıklık ederim);","bütün bu putlar (sanem), baş aşağı (ser-nigûn) yere (Ferş'e) düştü."],["Bir taşa nazar kıldı (baktı), mucizesiyle taş yarılır;","üstünde türlü nakışlarla, Tâ ve Sîn ve Yâ (Kur'an'ın esrarlı harfleri) çıktı."],["Taş, onun elinde dile geldi: 'Sen gerçek Resûl'sün (Hak Resûl)' dedi;","onun için (bu mucize yüzünden), taş üstünde taş bırakmadılar (putlar yıkıldı)."],["İnkârcılar (kâfirler), Muhammed'e üç kez zehir (agu) verdiler;","birini kuzuyla yedi, ikisini de yemeğinin üstüne."],["O Allah'ın Resûlü, meğer zehri (aguyı) şeker etti;","arı gibi (zenbûr-vâr) vızıldayarak, dertle, gözyaşların üstüne salâvât getir (Peygamber'e dua et)."],["Yunus Emre'm, sen yine Mustafa'ya (Peygamber'e) selam et;","o da onu, yüzüyle, baş üstüne (saygıyla) karşılasın (eda etsin)."]],"322":[["Hak yolunu gözlüyorsan (arıyorsan),","gel, dostlarla birlikte aşkla yanalım;","âşığın izini izliyorsan,","gel, dostlarla yanalım."],["Bu dünyanın vefası yok,","büsbütün (küllî), sayısız (bî-‘aded) cefası var;","bunun hiç vefası yoktur;","gel, dostlarla yanalım."],["Hep yana yana (aşkla) bulmuşlar,","Hakk'ın dîdârına (cemâline) ermişler;","seferin (yolculuğun) hazırlığını (kaydın) görmüşler;","gel, dostlarla yanalım."],["Dünyada ne yapacağını sanırsın?","Boş hevesle (hevâda) gezdiğin yeter;","derde derman isteyelim;","gel, dostlarla yanalım."],["Hani baba, hani ana (göçtüler);","bu dünyanın geçici (fenâ) olduğunu bildin;","cana, orada (ahirette) rahat gerek;","gel, dostlarla yanalım."],["Ey çaresiz (bî-çâre) Yunus, hemen;","dost yoluna kurban gerek;","canını ver, cananı (Sevgili'yi/Hakk'ı) iste;","gel, dostlarla yanalım."]],"323":[["Kimin neyi var ki sana verip, işini (kılıncını) yürütsün (sana bir şey katsın)?","Bütün âlem senin hükmündedir — kim el karıştırmayı (müdahaleyi) bilebilir?"],["Veren de alan da sen olunca, kim bir kıpırtı (cünbiş) edebilir?","Kıymet de alıcı (müşteri) da senin — her malını (meta'unı) satmak senin elinde."],["Bütün hazineler senin — kime dilersen ona verirsin;","kimin haddine (zehresine) ki, izinsiz (destûrsuz) el uzatsın?"],["İki cihanın varlığını, kudret eli tutar durur;","hiç kimseye, sensiz bir adım atmaya yol yoktur."],["Bütün âlemler üzerine, hayrı (iyiliği) ve şerri (kötülüğü) sen düzenledin (yasadın);","rahmet ve gazap (hışm), her birini kendi aslına (lâyık olduğu yere) katmaya yöneliktir (havaledir). (Hayrı da şerri de yaratan/takdir eden O'dur; rahmeti iyiye, gazabı kötüye âdil karşılıktır — Hakk'ın şerri onaylaması değil, her şeyi kuşatan takdiridir.)"],["Senin yardımın (tevfîk) ve lütfun (inâyet) olmasa, kim bir hayra vesile (sebep) olabilir?","Nerede bir fitne (karışıklık) varsa, senin gücün onu harekete geçirmeye ya da durdurmaya yeter."],["İblis ve şeytan kim oluyor ki orada haddini aşsın (fuzulluk etsin)?","Sen her şeyi yerli yerine koydun — kul (insan), kulluk etmeye geldi. (Şeytan bile O'nun izni/düzeni dışında bir şey yapamaz — Hakk'ın egemenliği; şeytanın mazur görülmesi değil.)"],["Ey dostlar (yârânlar), bu sözü gönül kulağıyla dinleyin;","birlik (vahdet) şarabını tatmak için, canın dudağı saf (hâlis) gerek."],["Birlik (vahdet) diyenin yanında, hiç 'sen-ben' demek (ikilik) yoktur;","bu tevhidi söylemek için, Yunus'un dilini sen yumuşattın. (Birlikte benlik ikiliği erir — fenâ; Yaratan-yaratılan ayrımının silinmesi/panteizm değil.)"]],"324":[["Her kime ki dervişlik bağışlanır,","kalbi kötülükten gider, pâk (temiz) olur, gümüş gibi parlar."],["Nefesinden (sözünden), darda olana (müşkile) amber (güzel koku) tüter;","dalından (budağından), il ü şâr (memleket) meyve verir (yemişlenir)."],["Yaprağı, dertli için derman olur;","gölgesinde, çok adımlar (kademler) işler (gezer/sığınır)."],["Âşığın gözyaşı da bir göl olur;","ayağından saz (kamış) bitip kamışlanır (ney gibi yetişir)."],["Bütün şairler, dost (Hak) bahçesinin bülbülüdür;","Yunus Emre, aralarında bir turaç (güzel sesli kuş) olur."]],"325":[["Aşk şarabını tatmayınca, aklım başıma gelmedi;","gerçek ere (mürşide) erişmeyince, nerede (ne hâlde) olduğumu bilemedim."],["Öyleyse bir âşık, kolayından ne zaman oluşur (hâsıl olur)?","Erin (mürşidin) eteğini tutmayınca, kimse menzile (makama) ermedi."],["Âşığın gönlünde çok yol var, o yolda bin türlü hâl var;","küfr ile imanı satmayınca (ikiliğini aşmayınca), kimse bu yolu anlamaz. (Bu, imanı bırakmak değil; benliğin kavradığı 'küfür-iman' ikiliğinin biçimini aşıp içteki öze — Hakk'ın doğrudan yaşanışına — ermektir.)"],["Bülbül nasıl güle âşıksa, kula nazar (iltifat) Hak'tan olur;","bir söz (keleci), gönüllerde bitmeyince (olgunlaşmayınca), dile gelmez."],["Haydi, din iman gerekiyorsa, bu dünyada iyi (eyü) yaşa;","bugün burada işin bitmeyince (tamamlanmayınca), yarın orada (ahirette) işin bitmez."],["Gönlümdeki bu sırrı (râzumı) esirgemem, size söylerim;","âşıklar, aşk malını (metâ'ın) satmayınca (sunmayınca) nasıl dayansın?"],["Çaresiz (bî-çâre) Yunus'un sözünü, gerçek (key) bir âşık anlamalı;","o, kuş dilidir (sırlı dildir) — ne yapsın, ötmeyince (söylenmeyince) dinlenmez."]],"326":[["Âşıkları, Hak cehennemde (Tamu'da) yakmaz;","bunlar (âşıklar), O'nun cennetine (uçmağına) baş eğmez (cennet sevdasıyla değil, Hak için severler)."],["Yedi cehennem (Tamu), bir 'ah'a (âşığın iç çekişine) dayanamaz;","yedi deniz, aşk ateşini (odını) söndüremez."],["Âdem gibi Hakk'ın buyruğunu tutmazsan,","üç yüz yılda bile gözyaşını dindirmez (Âdem gibi tövbeyle ağlamak gerek)."],["Nuh gibi bin yıl cefa (eziyet) çekmeyince,","O, tufanında seni gemiye bindirmez."],["İsmail gibi kurban olmayınca (kendini teslim etmeyince),","O, kimse için gökten koç indirmez."],["Musa gibi çobanlık etmeyince,","O, 'Kelîm'im (kendisiyle konuştuğum)' deyip seni Tûr'a göndermez."],["Huyun (hulkun) Muhammed gibi olmayınca,","O, Hakk'ın dîdârını (cemâlini) sana göstermez."],["Yunus, sen bu kuru (boş) iddiayı (davayı) bırak;","vay o kişiye ki, Allah onu gönülden uyandırmaz."]],"327":[["Bir Şah'a (Allah'a) kul olmak gerek ki, asla azledilmez (mazul olmaz) olsun;","bir eşiğe (Hakk'ın kapısına) yaslanmak gerek ki, kimse onu elden almaz olsun."],["Bir kuş olup uçmak gerek, bir kıyıya (öteye) geçmek gerek;","bir şerbetten içmek gerek ki, içenler ayılmaz olsun (aşk sarhoşluğu)."],["Çevik bir dalgıç kuş (bahrî) olmak gerek, bir denize dalmak gerek;","bir cevher (gevher) çıkarmak gerek ki, sarraf (cevherci) onu bilmez olsun (paha biçemesin)."],["Bir bahçeye girmek gerek, hoş bir seyir (teferrüc) kılmak gerek;","bir gül koklamak (yıylamak) gerek ki, o gül asla solmaz olsun."],["Kişi âşık olmak gerek, ma'şûku (Sevgili'yi) bulmak gerek;","aşk ateşine (odına) yanmak gerek ki, başka (ayruk) ateşe (cehenneme) yanmaz olsun."],["Bir şölen (toy) vermek gerek, bir aslı (soyu) araştırmak (soylamak) gerek;","bir söz söylemek gerek ki, kimse onu bilmez olsun (sırlı söz)."],["Kişi Hakk'ı bilmek gerek, Hak'tan haber almak gerek;","diriyken (zindeyiken) ölmek gerek ki, oraya (ahirete) varınca ölmez olsun. ('Ölmeden önce ölmek' — benliğin fenâsı; ebedî hayatın kapısı.)"],["Miskin Yunus, var sessizce (dek) otur, yüzünü Hazret'e (Hakk'ın huzuruna) çevir;","Tapduk gibi bir er (mürşid) getir ki, dünyaya bir daha hiç gelmez olsun (öyle ender)."]],"328":[["Ey aşk delisi olan, neden dağınık (perakende) kaldın?","Seni deli eden (Sevgili), yine sendedir, sende (gönlünde)."],["Dünya da ahiret de o Hak'tır (O'nunla doludur); yer gök, mutlaka O'nunla (tecellîsiyle) doludur;","hiç dış gözlere görünmez — kim bilir hangi nişanda (nasıl bir izle bilinir)? (Her şey O'nun tecellîsidir/O'ndandır; eşya 'Tanrı' değil — O görünmez ve münezzehtir.)"],["Her kim 'O'nu dış gözle gördüm/kavradım' derse, ateşte yanması gerek (O kavranamaz);","her kim O'na şüphe (şek) getirirse, ne dindedir ne imanda. (O, dış gözle görülüp kuşatılamaz — ama varlığından şüphe de küfürdür; iki uç da yanlış.)"],["Meyhaneye varsam bile, O'nsuz bir yer göremedim;","külhana (hamam ocağına) girsem bile, yine O'na rastladım (her yerde O'nun tecellîsi var)."],["Her kim kendi bedeninde (cisminde) aradıysa, düşmanını (nefsini) kendi içinde buldu;","ona ne dünya ne ahiret, ne fayda (assı) ne ziyan kalır (çıkarın ötesinde)."],["Kimine 'kaç' der, kimine 'dur (sebat et)' der;","kaçanla beraber kaçar, durana da beraber durur (O her şeyle beraberdir — Hakk'ın her yere şâmil oluşu)."],["Kullarını 'hırsız' (ugrı) diye yakalatan (giriftar eden) O'dur;","yardım (meded) edip yetişen de O — yine zindanda (mahpusla) beraberdir. (Hakk'ın her sûret ve hâle şâmil oluşu/iradesi; panteizm değil.)"],["Derler ki: 'Miskin Yunus, niçin deli oldun sen?'","Bu sırrı (her yeri kuşatan ilahî hakikati) sezince, ne akıl ne anlayış (fehm) kalır."]],"329":[["Aşk ateşi (odı) canıma düştü, beni yakıp tutuşturmaya;","yedi denizin suyu, susuzluğumu (susalıgum) gidermeye yetmez."],["Yedi denizin suyu, susamış âşığın canına ne yapar?","Bana şeyhimin (mürşidimin) yüzü gerek — görünce baş eğmek için."],["Şeyhimi göreyim, baş eğeyim, el bağlayayım (kavşurayım), karşısında durayım;","kendimi derleyip toplayayım (direm divşürem) — dostun (Hakk'ın) diyarına göndermek için."],["Dost, yüreğe bir yara vurdu — yaram iyileşmez (onulmaz), ne çare?","Şu gönlümün düştüğü yere, elim onu geri çevirmeye ermez (gücüm yetmez)."],["Erin (mürşidin) nefesi onu geri döndürür — Tanrı hâsı (Allah'ın seçkini/kâmil mürşid) erişince;","gönüllerden pası (kiri) siler, yerine nur doldurur."],["Hem elimi alıp kaldırır, beni sevindirip (şâd edip) güldürür;","gönlüme rahmet doldurur — er (mürşid), Hakk'ı bildirmeye (tanıtmaya) geldi."],["Yunus, yalan iddiayı (davayı) bırak; gel, gönlünü arıt (temizle), mâsivâyı (Allah'tan başkasını) bırak;","gönlünün evini tertemiz (kız) eyle — dost gelince konuk etmek için."]],"330":[["İçimde bir dert oldu, dervişlere söyleyeyim;","dervişlerin adımı (kademi), her işe uğurludur (mübarektir)."],["Her kimin ki bir derdi var, derman isteyip gider;","benim dermanım Sen'sin — bağrımdaki yaralara (başlara)."],["Aşktan ders (sebak) alırsın, hem onu çok iyi (key katı) bilirsin;","dervişlere hizmeti nasıl reva (uygun) görürsün (onlara hizmet gerek)?"],["Aşkının cefasından (eziyetinden) gece gündüz ağlarım;","akan pınar (bunar), gözden inen yaşlara ne benzer (denk olur)?"],["Cana bir tuzak kuralım, belki (şâyed) aşk ele geçer;","aşkı nasıl avlarlar — onu tutmuş olanlara soralım."],["O öyle havadan (uçucu) gelir — tuzak (duzak) ilmini kim bilir?","Bu hiç konmamış (konmaduk) kuşlara, nasıl tuzak kuralım?"],["Yunus, gönlünü alanı (Sevgili'yi) sen kime söyleyesin?","Soracaksan şimdi sor — onu (Hakk'ı) bulmuş olanlara."]],"331":[["Diri (zinde) âşık-kulun hükmü (sözü), canlara geçer;","aşkın sofrasında (hânında) yiyenlere, meze (nukl) ve şarap eksilmez."],["Şu harap dünyanın sürekli işi, istemektir (taleptir);","kendini bulanlara (kendini tanıyanlara), o harabelikleri (yıkıklığını) gösterir."],["Aşk dilde kolaydır (genez), aşkı bilen azdır;","'âşığım' diyenlere, dünyayı da ahireti de terk gerek. (Ahireti terk = cennet beklentisini bile bırakıp Hakk'ı kendisi için sevmek; ahireti inkâr değil.)"],["Dünyayı elden bırak, Hak'tan uzak (ırak) olma;","varlığını (benliğini) yıkayıp arıtanlara (fenâ bulanlara), asıl sermaye O'nun kendisi olmuştur. (Benlik silinince Hak, kişinin tek hazinesi olur.)"],["Bundan yüce, bundan değerli (ıssı) bir makam yok — orada ne sevinç (şâd) var ne keder (gam);","'davete (salaya) geldim' diyenlerin, bu işin ağırlığından ödü patlamalı (öyle çetin bir hâl)."],["Gel şimdi Miskin Yunus, yolunda yalancı olma;","bilirsin, aşk, yalan söyleyenlere kanmaz (aldanmaz)."]],"332":[["Bugün meydanda âşık oldum;","meydanda gerçek (key) pehlivan benim."],["Bu an, aşkın suyuyla 'gayrı'yı (Allah'tan başkasını) yıkadım;","irfan içinde, ne acayip bir ârifim (fenâ ile gelen mârifet)."],["Bugün aşk denizinin (bahrinin) dalgıcı (gavvâsı) oldum;","ummanın içinde cevherler (gevherler) buldum."],["Bugün harabat (aşk meyhanesi) ve melamet (kınanmayı göze alma) benim;","manevî seyir (seyrân) içinde yürüyen, o benim."],["Her ne kadar dış görünüş (sûret), küfür giysisi (tonını) giymişse de,","gönül, canı iman içinde görür. (Dış görünüş aldatıcı olabilir — melâmet ehli imanını gizler; öz ise imandır; küfrü onaylamak değil.)"],["Eğer ârif isen, bil ki yapan (bânî/usta),","dükkânın (yaratılışın) içinde yine kendisidir. (Yaratan, yarattığında tecellîsiyle hazırdır; eşyayla özdeş/panteizm değil.)"],["O'nu isteyen çoktur, ama (velâkin);","konuklar (mihmân) arasında, mahrum (yoksun/hâlâ susuz) olan benim."],["Yunus, bu âlem senin aşkınla ayakta durur (kâ'imdir);","onun için, devran (dönen âlem) içinde döner durur."]],"333":[["Kimseyi düşman tutmayız — yabancı (agyâr) bile bize dosttur (yârdur);","nerede bir ıssızlık varsa, o bize mahalle ve şehirdir (her yerde gönül huzuru)."],["Bizim adımız miskindir — bizim düşmanımız kim olabilir?","Biz kimseye kin tutmayız — bütün âlem (kamu) bize dosttur."],["Bize önder (pîşrev) Kur'an'dır, yurdumuz (vatan) cennettir;","Hak o cehennemi (Tamu) tutuştursa da, o bize gül bahçesinin gülüdür (âşığa cehennem korku vermez)."],["Biz ahiret kaygısını (gamın) çekince, gece gündüz 'Yâ Hû' (Ey Allah) deyince;","Hak'tan yana yönelince, bize denizde bile yol vardır."],["Dünya, kocamış (karı) bir kadındır (avret) — niceleri yoldan çıkarır;","sürün gitsin o hilekârı (ayyârı) — onu sevmek bize utançtır (ardur)."],["Dünya (dünyaya bağlanmak), seçkinlere (hâslara) haramdır, ama hamlara (olgunlaşmamışlara) helaldir;","biz bu dünyayı dost tutmayız — o dünya bize murdardır (pistir). (Burada söz konusu olan dünya sevgisi/bağlılığıdır; kâmiller ondan el çeker, ham olanlar henüz o ölçüye çağrılmaz.)"],["Yunus der: 'Allah' deriz, Allah'a kapılmışız (tutulmuşuz);","O'nun dergâhına (kapısına) yüz tutarak, bize hep bir ikrar (tasdik) vardır."]],"334":[["Bende bu hâl üzerine, acayip (eşsiz) bir aşk geldi;","gönlümü taht eyledi, canımın üstüne oturdu (gönle hükmetti)."],["Sen sultansın, ben kulum; sen gülsün, ben bülbülüm;","hükmün âleme yeter — ne varsa, kulun üstüne (her şeye hükmün geçer)."],["İlkbahar olunca, ağaçlar donanınca (süslenince);","gör, bülbüller gül üzerine nasıl övgüler (medh) yağdırır."],["Âşıkları görürsün — halkın içinde gezerler;","öyle kişi var ki gözü görmez — yolun üstünde oturduğu (apaçık önünde olduğu) hâlde."],["Yunus, 'sözler söyledim' diye böbürlenme (nükte etme);","daha iyi (yigrek) söyleyen vardır — el üstünde el (güç üstünde güç) vardır."]],"335":[["Bu kışın karanlığı (zulmeti) gitti, bahar yaz ile geldi;","yeni bitkiler (nebâtlar) bitti, hepsi nazla dalgalandı (mevc urdı)."],["Yine çayırlık (merg-zâr) oldu işte, yine gül bahçesi (gül-zâr) oldu;","müzikte sazla, taze (ter) ezgiler (nagme) düzer oldu."],["Dosttan hoş bir haber geldi — bağ ve bostan yarattı;","bülbülleri, sırlarıyla (râz ile) sanki ilim okur, bin destan söyler."],["Kim görmüş baykuşun gül bahçesine (gülistâna) girdiğini?","Leylekler, ince/güzel (latîf) bir sesle zikredemez."],["Ne kadar saklarsan sakla, sahte bir inci tanesi (dür-dâne) gerçek cevher (gevher) olmaz;","keklik keklikle uçar, şahin (bâz) daima şahinle."],["El kuşu (av kuşu) elden ele, gül kuşu (bülbül) gülden güle;","baykuş viraneyi (yıkıntıyı) sever, şahinler uçuşla (pervâz ile) yaşar."],["Nerede bir leş (gevde) varsa, akbabalar (kerkesler) oraya üşüşür;","papağanlar (tûtîler) ise yiyeceğini (evin) şekerde bulur — kafeste bile."],["Her kişi kendi dengini (tuşın) kendine eş etti:","sadıklar ikrar (tasdik) ile, sufiler namaz ile."],["Cahil, münafık, münkir (inkârcı) — hepsi kendi aklına razıdır (şâkir);","âşıklar (Hakk'ın) dîdârını (cemâlini) sever, ârifler ise niyaz (yakarış) ile."],["Dervişlik dedikleri, dilde (sözde) bir haber değildir;","Hak ile Hak olana (benliği Hak'ta erimişe), orada bir menzil (makam) düzülür. ('Hak ile Hak olmak' = benliğin fenâ bulup yalnız Hakk'ın kalması; ego'nun 'Tanrı'yım' demesi/panteizm değil.)"],["'Ben dervişim' deyip yalan iddiada (davi) bulunanlar,","yarın (ahirette) Hakk'ın dîdârını gözle göremeyecek."],["Bir gönül kırdıysan, ilim ve amel ne fayda (assı) eder?","Ârifin bir gönül yapması (alması), hac (hicâz) ile birdir (eşdeğerdir)."],["Ulu divan (mahşer mahkemesi) kurulacak, orada kulluk sorulacak;","bin kibir (tekebbür), bir garibi (kimsesizi) hoş tutmaya (nevâz) denk olmaz."],["Eğriler eğri ile, doğrular doğru ile;","yalan yalanı sever, gammazlar (fitneciler) gammazla."],["Kimi dükkânından (tezgâhından) bakar, kimi zevkleri (hoşlukları) sever;","kimi bir paraya (pûla) muhtaç, kimisi de canıyla oynar (cân-bâz)."],["Kula bir şey nasip (kısmet) olunca, sultan onu elinden alamaz;","Zülkarneyn (âb-ı hayatı arayan) ne yapabildi — Hızır ve İlyas ona erişmişken? (Nasip olan, sahibine erişir.)"],["Görmez misin İbrahim Edhem'i — tahtını terk etti;","Hak katında, bir eski çul (palâs) ile seçkin (hâs) oldu."],["Bu dünyaya güvenme (inanma), dünyayı benim sanma;","niceleri 'benim' demiş — giderken (ölürken) yalnızca ham bir bez (kefen) ile giderler."],["Aşk yağmurunun damlası, gönül göğünden damlar;","sevgi yeli, o yağmuru ayaz (açık hava) ile götürür."],["Yunus, şimdi gam yeme (kederlenme), 'ne yapayım, ne edeyim' deme;","ezelde (öncesizde) ne yazıldıysa (takdir edildiyse), kişinin başına o gelir. (Ezelî takdire — kadere — teslimiyet.)"]],"336":[["Bu cihan mülküne (dünyaya), 'geldim, gelmedim' deme;","velinin (evliyânın) eteğini tut, sakın (zinhâr) elinden bırakma."],["Gafil (habersiz) olma, ömür geçti, nice yılın aşıldı (geçti);","aşktır kaynayıp taştı — 'buldum, bulmadım' deme."],["Aşk, durmayan (bî-karâr) bir denizdir — canını aşka yüzdür;","denizde bir su kuşu (bahrî) vardır — 'yüzdüm, yüzmedim' deme."],["Gemi denize girdi, bir zaman gezindi (cevlân urdı);","bir gün gemi battı (gark oldı) — 'bozdum, bozmadım' deme."],["Denizde hakikatler (hakâyık) var, balıklar gezinir (cevlân urur);","Yunus, denizin dalgasına (mevc), 'daldım, dalmadım' deme."]],"337":[["Âlem düşman olsa bile, beni dosttan ayıramaz (ırımaya);","dost nerede ise ben oradayım — düşmanlık bizi ayıramaz."],["Dost ehli (kâmiller) bizimle, hem dost burada — bize ne gam (keder)?","Düşman yüz bin gayret (cehd) etse de, dostun meclisinde (mahfilin) duramaz (oraya giremez)."],["Düşman bana ne yapabilir — işim gücüm dosttan (Hak'tan) yana;","dostun makamı can içinde (gönülde), düşmanın eli oraya erişemez."],["Sultanlar orada âcizdir (güçsüz) — O ne gönülde ne canda kuşatılır;","iki cihanda mahrumdur (yoksundur) o kişi ki, dostun yüzünü göremez."],["Dost kime kapı açarsa, düşmanı onun elinden kaçar;","Yunus'un ağzı cevher (güher) saçar — bunu her ârif söyleyemez (dirimeye)."]],"338":[["Hayatımın (dirligüm) ne olduğunu, kılı kılına anlatayım;","uzak yakın işitsin — seçkin ve halk (hâs u âm), hepsi birlikte."],["Seçkin ve halk, itaatkâr (mutî) ve isyankâr (âsî) — hepsi dostun kuludur;","kullar yola düşmeyince, Şah'a (Allah'a) kim varabilir?"],["Dosta gidenin yolu, gönlün içinden geçer;","ben bir amel (iş) etmedim — tek işim gönüle girmekti."],["Dosta giden kişiler, kendilerini (kendözini) unutur (benlikten geçer);","ben nereye varırsam, beni ileten (Hak) bilir. (Hakk'a giden benliğinden geçer — fenâ.)"],["Sen-ben (senlik-benlik) olunca, iş ikilikte kalır;","ikiliği tutan kişi, Bir ile nasıl birleşsin (birike)? (Benlik ikiliği erimedikçe vahdete erilmez — fenâ; panteizm değil.)"],["Bundan böyle dostla ne olacağını bilmem;","şimdiye dek ömrüm, boş bir sevda ile geçmiş."],["Bu kıssam (hikâyem) uzundur — nasıl bitiririm bilmem;","hangi bir eksikliğimi (kusurumu) dile getirebilirim?"],["Yetmiş iki milletin (bütün toplulukların) ayağını öpmek gerek;","ma'şûka (Sevgili'ye/Hakk'a) yaramak (hoş gelmek) için, bütün milletle hoş geçinmek gerek. (Hak için herkesi sevmek — mezhep taassubunu aşan evrensel sevgi; imanı bırakmak değil.)"],["Yunus âşık mıydı — bugün vuslata (kavuşmaya) erse yeter miydi?","Âşık, yarınki vaatle (sözle) karar eder mi (sabreder mi)?"]],"339":[["Ma'şûkumu (Sevgili'mi/Hakk'ı) isteyerek, şu cihanın içinde;","yerde ve gökte (zemîn ü âsmân) çokça gezindim (teferrüc kıldım)."],["Bütün âlemi gezdim — Arş'ı, Levh'i (Levh-i Mahfuz), Kalem'i;","kitap ilmini (ilm-i kitâb) dahi, delil ve açıklama (beyan) içinde."],["Çok gayret (cehd) edip aradım, yeri göğü taradım;","hiçbir mekânda bulamadım — O'nu insanın içinde (gönlünde) buldum. (İnsanın kalbi, ilahî tecellînin mahallidir; insan 'Tanrı' demek değil.)"],["Varlığın (vücûd) denizine girdim, onun dibine (ka‘rına) daldım;","aşkla seyrederken (manevî yolculukta), can içinde (Hakk'ın) izini buldum."],["O izi hoşça izledim, sağıma soluma baktım;","öyle acayipliklere (şaşılası şeylere) erdim ki, cihanda benzeri yoktur."],["Ansızın (nâ-gehân) bir yüz gördüm — onunla hiç söz yok (anlatılamaz);","sırrını söylesem olmaz — dile (lisân) sığmaz."],["Yüzünü görünce, özümü (benliğimi) ona verdim;","beni benden aldı (iletdi) — hayranlık (şaşkınlık) içinde kaldım. (Benliğin Hak'ta erimesi — fenâ ve hayret hâli.)"],["Yunus Emre yok oldu, bütün varlığı (benliği) yok oldu;","O'ndan başka (artuk) bir şey yok — şüphede (gümânda) kalmayın. (Bu, benliğin tümüyle erimesi — fenâ; 'O'ndan başka yok' = fenâ hâlinde yalnız Hakk'ın kalması, her şeyin O'ndan oluşu — panteizm değil.)"]],"340":[["Dilime bir söz geldi, ölüm üzerine söyleyeyim;","ister Sünni Müslüman olsun, ister zalim — ölüm herkese gelir."],["Cana ecel (va‘de) erince, yukarı Han'a (yüce Hakk'a) çıkar;","ayağımı gererler, ellerimi giysimin kolları (yen) üstüne koyarlar (ölü serilir)."],["Beni tertemiz (arı) yıkasınlar, mezarıma (meşhedüme) koysunlar;","kâfirler bile, hâlime bakıp acısınlar (esirgeye)."],["Vay, hâlim ne olur — ahvâlim (durumum) bilinmezse?","Yılan, çıyan, karınca — dilimin üstüne üşüşür."],["Beni götürüp mezara (sine) koysunlar, sonra yine eve dönsünler;","malım üstüne onca (nice) kavga (savaş) kursunlar (mirasıma çekişsinler)."],["Ey Yunus, 'sözler söylüyorum' diye böbürlenme (nükte etme);","nice bilenler var — elimin üstünde el (benden üstünü) vardır."]],"341":[["Sanatın en iyisi (yigregi), madem namazmış — hoş bir meslek (pîşe);","namaz kılan kişide, kötü (yavuz) düşünce (endîşe) olmaz."],["Seherde (tanlacak) kalk gel, elini suya vur (abdest al);","üç kez salâvât getir, sonra (andan) güneşe bak (gün doğunca namazına dur)."],["Allah'ın buyruğunu tut, namazını kılıp git;","namazını kılmadan, sakın (zinhâr) işe gitme."],["Evinde, helâline (eşine) beş vakit namazı öğret;","öğüdünü tutmazsa, sana günah (yazuk) yok — boşa gitmiş olur."],["Namaz kılmayan kişinin kazandığı, hep haram;","bin altın parası (kızılı) olsa, birisi bile işe gelmez (ahirette fayda etmez)."],["Namaz kılmayana sen 'Müslümandır' deme;","böylesi gerçek Müslüman olmaz — bağrı (yüreği) taşa dönmüştür."],["Yunus, şimdi namazını bırakma, sen kılmaya bak;","birdenbire (ansuzın) ecel erer, ömür sona (başa) erer."]],"342":[["Bu gece bir ay gördüm — bütün burçlardan yüce;","gönlümü, canımı sarhoş etti (esritdi) — hâlim nasıl, bilmem."],["O nur, Muhammed'in nurudur (Nûr-ı Muhammedî), Halîlullah'ın (İbrahim'in) sırrıdır;","sanırsın ki cennetten (Uçmak'tan) bir pencere (deriçe) açıldı."],["O ayın alevinden (şu‘lesinden), âlem aydınlandı (münevver oldı);","gönlümdeki kandili (çerâgı), ulu hoca (büyük üstad) yaktı."],["İddiacı (müddeî/öze ermeyen softa), gözüne girsek de bizi görmez;","isterse yüz kez Kâbe'ye, ulu hacca varsın. (Öze ermeden, yalnız dış ibadet manevî görüşü vermez; hac değersiz demek değil.)"],["Âşıklar, yüzlerinden bellidir — benizlerinden (renklerinden);","her kim âşık olmadıysa, kuru bir ağaca benzer."],["Kuru ağacı ne yaparlar — kesip ateşte (oda) yakarlar;","bülbüller ötünce, sıra (nevbet) turaca (dürrâca) gelmez."],["Yunus'u öven övsün, söven Yunus'a sövsün;","o, keçeyi suya salmış (kendini akışa/Hakk'a bırakmış) — sabah akşam ne fark eder."]],"343":[["Yine yaz günleri geldi,","söyle bülbülcüğüm, söyle;","bütün çiçekler süslendi (zeyn oldı),","söyle bülbülcüğüm, söyle."],["Kış çıkınca bahar geldi,","canını gafletten uyandır;","her diyar cennete döndü,","söyle bülbülcüğüm, söyle."],["Ağaçlar yeşil giysi (ton) giydi,","kuşlar kanatlanıp (pervâz urup) uçar;","nefesin canlar bağışlar,","söyle bülbülcüğüm, söyle."],["Aşkla bir coşkunluk (cûş) eyle,","gönlünden karmaşayı (teşvîşi) gider;","çıkıp gül bahçesine (gül-zâra) karşı,","söyle bülbülcüğüm, söyle."],["Kuru dikende gül biter,","özleminden (hasretinden) yine erir (yiter);","benden beter mi dertli oldun?","söyle bülbülcüğüm, söyle."],["Bülbül, güle âşıktır;","âşığın hâlini kim bilir?","güle karşı, hoş bir aşkla,","söyle bülbülcüğüm, söyle."],["Kudret hazinesi (haznesi) açıldı,","âleme rahmet saçıldı;","cennet giysileri (hulle tonları) biçildi,","söyle bülbülcüğüm, söyle."],["Şeyhim orada (andadur), ben burada;","canım tende karar (huzur) bulmaz;","ağlayışım (zârılığum) gece gündüz,","söyle bülbülcüğüm, söyle."],["Kanatlarını açabilirsin,","açıp uçabilirsin;","deryaları geçebilirsin,","söyle bülbülcüğüm, söyle."],["Yuvandan yavrunu aldılar,","seni divane (deli) kıldılar;","'zaman böyle olur' dediler,","söyle bülbülcüğüm, söyle."],["Eyvah, ömrümün hepsi (varı) geçti,","bu gül bahçesini (gül-zârı) bırakıp gidersin;","Yunus'un can yoldaşı (mûnisi), yâri,","söyle bülbülcüğüm, söyle."]],"344":[["Senin aşkınla âşıklar yansın, yâ Resûlallah;","aşkının şarabını içip kansın (doysun), yâ Resûlallah."],["Şu seni seven kişi, yoluna başını koymuş;","iki cihanın güneşi sensin, yâ Resûlallah."],["Şu seni sevenlere şefaat eyle onlara;","mümin olan bedenlere (tenlere) can sensin, yâ Resûlallah."],["Sübhân (Allah) seni öyle sevdi ki, herkese (kamuya) sultan oldun;","canım yoluna kurban olsun, yâ Resûlallah."],["Şu dîdâra (cemâle) âşığım, şu gül bahçesine (gül-zâra) bülbülüm;","seni sevmeyen, ateşe (nâra) yansın, yâ Resûlallah."],["Derviş Yunus'un canı sana adanmış — sen âlemin şefaat madenisin (kânı);","iki cihanın sultanı sensin, yâ Resûlallah."]],"345":[["Dosttan haber kim getirdi — seher (şafak) yellerine sorun;","Hak Çalap'ım (Allah'ım), kullarına ayrılık yazmasın (bititmesin)."],["Vay, bu ayrılığın firâkı (acısı) — dünya kime bâkî (kalıcı) kaldı?","Hak Çalap'ım sâkî (kadeh sunan) olmuş — kullarına kadeh sunar."],["O kadehin içi doludur — onu içen deli olur;","o hocanın (üstadın) talipleri, bil ki yollarına bel bağlamış."],["Hocanın talipleri çoktur — bundan (benden) aşağısı (kemteri) hiç yoktur;","kimin mürşidi Hak ise, insanların (nâsun) hilelerine (âllerine) uymaz."],["Nefsine karşı (muhalif) duran kişinin gözyaşı durmadan akar;","burada nefse uyan kişi ise, Kevser göllerine dalamaz."],["Kevser havzına dalanlar, ölmeden önce ölenler ('ölmeden önce ölmek' — benliğin fenâsı);","nefsini düşman bilenler, Tûbâ (cennet ağacı) dallarına konar."],["Tûbâ dalından (talından) uçanlar, yüce makamları geçenler;","tertemiz şarabı (şarâben tahûr — cennet içkisi) içenler, dünyanın ballarına banmaz (dünya zevkine eğilmez)."],["Bu mânâyı kimse almaz (anlamaz) — oraya varan yine gelmez;","bu dünyaya kimse kalmaz — gelen, kendi iline (memleketine/ahirete) göçer."],["Ey miskin Yunus, ne yapsın — derdini kime söylesin?","Bir an (dem) bu dünyanın hâllerini bir sınasın (denesin/gözlesin)."]],"346":[["Neredeydin, nereden geldin, ey divane?","Gözünü aç, bu gafletten uyan hey."],["Kafile geçti, sen gaflette bulundun (uykudaydın);","sakın, sermayeni ziyana (zarara) verme."],["Hani baban, hani anan, oğul kız nerede?","Zaman (zamâne) kime vefa edecek?"],["Gerçekten (hakîkat) bilirsin, bir gün ölürsün;","ya niçin kendini (özün) şüpheye (gümâne) verirsin?"],["Hakk'a kulluk etmekten kaçarsın;","ya niçin (dünyanın) yardımcılarına (avâne) kulluk edersin?"],["Hak için verecek bir paran (pûlun) yok;","ya niçin onu kâr-zarar (assı ziyâne — dünya kazancı) için verirsin?"],["Yunus, sen nefsini Müslüman sanma;","meğer şimdiden sonra onu büsbütün imana getiresin."]],"347":[["İçin dışın murdar (kirli) iken, aşk seninle ne yapsın?","Gönlünün gözü uyur iken, aşk seninle ne yapsın?"],["Âşıklara yoldaş olup, sadıklara yâr olmadın;","ölmeden önce ölmedin ('ölmeden önce ölmek' — benliğin fenâsı) — aşk seninle ne yapsın?"],["Dünya gözünü parlatıp (rûşen edip), gönül gözünü kör eyledin;","gönlüne karanlık (zulmet) dolunca, aşk seninle ne yapsın?"],["Bize gerçek (girçek) derviş gerek — cihan iddia (davâ) ile doldu;","yalan iddiada bulunursan, aşk seninle ne yapsın?"],["Dervişliği sanma ki sadece dış görünüş (sûret) düzmekle olur;","işin sadece dilde (sözde) ise, aşk seninle ne yapsın?"],["Yunus Emre, hoş bir dertle (aşk derdiyle) gel, devranını (ömrünü) sürmeye bak;","doğru yola gitmezsen, aşk seninle ne yapsın?"]],"348":[["Kime ki dost (Hak) gerekiyorsa, ne yapacağını söyleyeyim:","kendini (kendözini) terk etsin (benlikten geçsin), kendine ne olacağını hiç düşünmesin. (Benliğin fenâsı.)"],["Âşıklara âdettir (resimdir) dost önünde kurban olmak;","her âşık, aşkın canını almasını bir lütuf (minnet) sayar."],["Her kim âşık olmadıysa, hilenin (mekr) elinden kurtulamadı;","aşk hepsini eritir — dünya ve ahiret belasını (sıkıntısını)."],["Her can layık değildir dost yolunda harcanmaya;","her âşık, dosta kurban olmayı umut (ümît) eder."],["Dosttan (Hak'tan) yana giden kişi, kendinden (kendözinden) geçmek gerek;","dost, can şehrini yağmalar — gönül kalesini alır. (Benliğin Hakk'a teslim edilip erimesi — fenâ.)"],["Dost yoluna yönelene (gönülene), geri dönmek olmayacak;","bilmez misin, bütün bunlar (kamusı) senden geriye kalacak?"],["Madem âşığın payı kahrın iniltisi (nâlesi), tek çare sabretmektir;","âlemdeki aşk meyhanesinde, gel, sâkîsinin sunduğunu iç (nûş eyle)."],["Zahir gözü (sûret gözi), dostun meclisinin nerede olduğunu ne görsün?","Bu âşıkların iniltisini (nâlesini) işiten, can kulağıdır."],["Bu dünyada, dosttan başka (artuk) Yunus bir şey (nesne) sevemedi;","bilmez misin, gayretsize (aldırışsıza) dost da düşman da güler?"]],"349":[["Bana 'namaz kılmaz' diyen — ben namazımı kılarım;","kılsam da kılmasam da, o Hak benim niyazımı (yakarışımı) bilir."],["Hak'tan başka kimse bilmez — kâfir kim, Müslüman kim;","ben namazımı kılarım — Hak, nâzımı (içli yakarışımı) kabul ederse."],["O nâz, dergâhta (Hakk'ın kapısında) kabul olur — mânâ şarabından içer;","perdesiz (hicâbsuz) can gözünü açar — dost, gözümü kendi siler (içten görüşü O verir)."],["Dost burada, apaçık (bellü beyân) — dostun dîdârını (cemâlini) ayan gördüm;","bu hikmet ilmini sezen, bana doğru yönelir (azmeder). (Bu, gönül gözüyle müşahede — Hakk'ın zatını dış gözle görmek değil.)"],["Gönül gözü uyanık (bîdâr) — nereye baksam yâr (Sevgili) vardır;","kimde akıl-anlayış (fehim) varsa, o bilir benim sözümü. (Uyanık gönle her yerde Hakk'ın tecellîsi görünür; panteizm değil.)"],["Gizli sözü açıklayıp (şerh edip), türlü ince mânâlar (nükteler) söyleyip;","her ârif, bu benim gizli sırrımı (râzumı) açıklayamaz."],["Sözümün mânâsına erin, bî-nişândan (izsiz Hak'tan) haber verin;","dertli âşıklara sorun, bu benim derdimi ve yanışımı (sûzumı)."],["Dert, âşıkların dermanıdır — dertli âşıklar zengindir (ganîdir);","Kadîr ve kudretin (Allah'ın) sesidir (ünidür) — işiten, benim sesimi (âvâzumı) tekrarlar."],["Dost isteyen bana gelsin, dostu ona göstereyim;","sözüm baştan sona budur — ben kendimi (kendözümi) bilirim. ('Kendini bilen Rabbini bilir' — nefsini bilmek Hakk'ı bilmeye götürür; kendini tanrılaştırmak değil.)"],["Yunus, şimdi Hakk'ı söyle — inkârcı (münkir) sana itiraz eder (dakı dutar);","Hak sofrasını (hânını) pişir, sun — ârifler benim tuzumu (sözümün tadını) tatsın."]],"350":[["Allah sana bir gün ecel çavuşunu (serhengini) gönderir;","gelir, gözüne görünür, benzinin rengini soldurur (azdura)."],["Sana der: 'Emanetini (canını) ver — Sahibi (ıssı), götürmemi diliyor';","emaneti senden alır, seninle savaşını (cengini) eder."],["Emaneti (canı) senden alır, gövdeni öylece boş bırakır;","günahlar boynunda kalır, nefsin kendi narasını (gülbengini) atar."],["Malın çoksa, ey paşa, hısımın akrabanın (kavmun) paylaşır (üleşe);","seni mezara (sine) götürürler — yerinin ne dar (teng) olduğunu görürsün."],["Seni mezarında (sinünde) koyarlar, 'menzilin mübarek olsun' derler;","üstüne çabuk çabuk (tîz tîz) bu dünyanın toprağını (hâk) ve taşını (seng) örterler."],["Karanlık yerde olursun, amelinle (yaptıklarınla) kalırsın;","ah ederek, sonunda çok kez pişmanlık çengini (sazını) çalarsın (boşuna)."],["Yunus, var şimdi tövbe kıl — can sendeyken (yaşarken) amel (iyilik) et;","âşıksan, dervişlerin kemerini (palhengini) kuşanmaya bak."]],"351":[["Huzuruna (tapuna) bir sorum var, ey dervişlerin ulusu (ecesi);","şeyhler (meşâyıh) ne buyurur — yolun haberi (anlatımı) nasıldır?"],["Soruya cevap ver — doğru (savâb) olsun diyelim;","aşk evinin bacası, ışığını (şu‘le) kime gösterir?"],["İlk (evvel) kapı şeriattır — emri ve yasağı (nehyi) bildirir;","her bir Kur'an hecesi, günahlarını yıkar (yuya)."],["İkincisi tarikattır — kulluğa bel bağlar (kuşanır);","yolu doğru varanı, hocası (mürşidi) bağışlar (yarlıgaya)."],["Üçüncüsü marifettir (irfandır) — can ve gönül gözünü açar;","mânâ sarayına bak — yüceliği Arş'a değin (kadar) varır."],["Dördüncüsü hakikattir — er (ermiş), kimseye eksik (kusurlu) bakmaz;","gündüzü bayram, gecesi Kadir (gecesi) olur."],["Bu şeriat güç (zor) olur, tarikat yokuş olur;","marifet sarp (dik) bir tırmanıştır, hakikat ise en yücesidir."],["Dervişin dört yanında, dört ulu kapı gerek;","nereye (kancaru) bakarsa, gecesi gündüz olur."],["Ona (o dördüncü kapıya) eren dervişe, iki cihan keşfolur (açılır);","o hocaların hocası (en yüce üstad), onun sıfatını (niteliğini) över."],["Dört hâl (kapı) içinde, derviş bir terbiye (siyâset) çekmeli;","yolcunun (yol erinin) yavrusu (acemisi), menzile (makama) ermez, geride kalır."],["Kırk kişi bir ağacı dağdan indiremezken,","ya bunca mürit, bunca dost (muhib), Sırat'ı nasıl geçecek?"],["Küfür okunu atarken, sakın imanını vurma (vurmaktan sakın);","aceleyle (yilüp) gücünü kırıp, çömleğin (güvecen) boşalıp herkese saçılan bir sebil (boşa akan su) olmasın. (En ileri hâlde, cüretli/birlik dilini — şathiyeyi, biçim ötesi 'küfrü' — söylerken, dış imanını yıkmaktan sakın; iç hâl dış imanı kaldırmaz.)"],["Dört kapıdır, kırk makamdır — yüz altmış menzili (durağı) vardır;","ona erene, velîlik (vilâyet) derecesi açılır."],["Âşık Yunus, sözlerini 'imkânsız/saçma' (muhâl) diye söylemez;","bu şairlerin ulusu (kocası), mânânın yüzünü gösterir."]],"352":[["Hakk'ın nuru, âşıklara her an inmez (nüzûl) mi?","Kime ki o iniş (nüzûl) değmez, o Hak'tan yoksun (mazul) değil mi?"],["'Kalpten kalbe' (mine'l-kalbi ile'l-kalb) yol var demiş erler (ermişler);","her gönülden gönüle, doğru (rast) bir yol değil mi?"],["Kargayla bülbülü bir kafese koysalar,","birbirinin sohbetinden daima bezgin (melûl) değil mi?"],["Öyle ki karga, bülbülden ayrılmak diler;","bülbülün de gönlünde, maksadı (isteği) o değil mi?"],["Cahil ile ârifin meseli (benzetmesi), şuna benzer:","cahilin yanında, apaçık (ma‘lûm) iman bile, gizli (mechûl) değil mi (görünmez)?"],["Işık (melametî derviş) ile Danişmend (âlim), her zaman birbirine kötü (sû'i) işler eder;","Danişmend, Işık'a der: 'Bu, şeriatsız (bî-şerî‘at) değil mi?'"],["Ârif, yetmiş iki milletin (bütün toplulukların) sözünü bilir (anlar — mezhep taassubunu aşan kavrayış);","Yunus Emre'nin sözleri, her zaman usûl (köke/esasa dayalı) değil mi (yani temelsiz/şeriatsız değil)?"]],"353":[["Aşkın tüccarı (bâzirgânı) — sermayesi candır;","canına kıyan (canını feda eden) yiğidi (bahadur) gördüm."],["Ne güzel yiğit (bahadur) ki, canını terk eder;","himmet (manevî güç) giyeni, kılıç mı keser?"],["Hepsini (kamusın) bir gör, en aşağıyı (kemterin) er (ermiş) gör;","çul (palâs) giyeni hor (alçak) görme."],["Hızla (tîz) en yüceye (fevka'l-'ulâya) çıkarırlar — bil ki;","İsa gibi dünyayı bırakanı."],["Hızla (tîz) yerin dibine (tahte's-serâya) indirirler;","şu Karun gibi dünyayı kovalayanı."],["Âşık olanın bir nişanı (işareti) vardır;","apaçık (bellü) alâmeti, melamettir (kınanmayı göze almaktır)."],["İlim ve amele mağrur (gururlu) olma;","Hak, kefen soyanı (görünüşte en düşkünü) bile kabul etti (lütfu deyledir, amelle övünmek değil)."],["Atlası (ipek kumaşı) bıraktı, çulu (palâsı) giydi;","sırrı sezen İbrahim Edhem böyle yaptı."],["Madem Mansûr (hakikati) gördü, 'o benim' (Ene'l-Hak) dedi;","onu ateşte (oda) yaktılar — işittin onu. (Bu söz, benliği fenâ bulmuş hâlde — yalnız Hakk'ın diliyle — söylenmiştir; ego'nun 'Tanrı'yım' demesi değil.)"],["Ateşte (oda) yaktırdın, külünü savurdun;","seni seveni (âşığını), öyle mi gerek (böyle mi olmalı)?"],["Sakın (zinhâr), ey Yunus, 'gördüm' (hakikati gördüm) deme;","'gördüm' diyeni darağacına (dâra) çekerler. (Birlik müşahedesini açıkça ilan etmenin tehlikesi/ihtiyat.)"]],"354":[["O dilber (Sevgili), gözlerime ne zaman değdi (tutaş oldı),","gönlümü canımı ona verdim — aşkı bana yoldaş oldu."],["Gönlüm der 'ben onun kuluyum', canım der 'ben onun kuluyum';","hangisi üstün (yig), hiç bilmem — bu ikisinden bir çekişme (savaş) oldu."],["Bu ikisi arasında, devletin (bahtın) benim olduğunu bildim;","hiç danışmam (görüşmem) yokken, başım onunla hoş oldu (mutlu oldum)."],["Onunla bir an (dem) yaşamak, bin yıllık ömrümden yeğmiş (üstünmüş);","ondan ayrı geçen her günüm, yüreğimde bir yara (baş) oldu."],["Nereye (kancaru) baksam, gözüme görünen O'dur;","önüm, ardım, sağım, solum — her köşe (künc), O'nun gözü kaşıyla doldu. (Âşığın uyanık gözüne her yerde Sevgili'nin/Hakk'ın tecellîsi görünür; panteizm değil.)"],["Hızır ve İlyas değilken, ölümsüz bir hayata (dirliğe) rastladım (sataşdum);","hiç yemez içmez iken, içim tıka basa yemekle (aş) doldu (manen doydum)."],["Onu seven âşıkların sıfatını (niteliğini) söylersem:","onun aşkının urganında (ipinde), koyundan da uysal (yavaş) oldu."],["Nice aslan, aşka boyun vermemek için iddia eder (davi kılar);","senin aşkının zincirinden, en azgın (kızan) önce uysal (yavaş) oldu."],["Bütün âlemin gönlünde, O'nun sevgisi (mahabbeti) vardır;","bil ki onu candan sevmeyenin imanı taş oldu (katılaştı)."],["Senin aşkının ateşi (odı), sakın (meger) kimseye sıçramasın;","bir zerresi Yunus'a değdi — cihan içinde (her yerde) açığa çıktı (fâş oldı)."]],"355":[["Yer gök yaratılmadan, Hak bir cevher (gevher) eyledi;","o cevhere nazar kıldı (baktı), onu eritip inci (dür) eyledi."],["Cevherden buğu (bug) çıkardı, buğudan göğü yarattı;","göğün süsünü (bizegin), çok yıldızlar eyledi."],["Göğe söyledi, 'dön' dedi; 'ay güneş yürüsün' dedi;","suyu boşlukta asılı (muallak) bıraktı, üstünde yeri eyledi."],["Yer çalkalandı, durmadı, bir an (dem) karar kılmadı (durulmadı);","yüce yüce dağları, Hak ona çöksü (sabitleyici çivi) eyledi."],["Azrail gökten indi, bir avuç toprak aldı;","dört melek (ferişte) onu yoğurdu, bir peygamber (Âdem) eyledi."],["Can gövdeye erince, aksırdı, ayağa kalktı (öri turdı);","o anda (demde) elini kaldırıp, Hakk'a şükür eyledi."],["Allah, Âdem'e der: 'Madem bu ana (deme) erdin;","bu dünyada ne dedin — dilin neyi söyledi?'"],["[Âdem:] 'Yok iken var eyledin, toprak iken can verdin;","kudret diliyle andın (beni var ettin), dilimi söyler eyledin (konuşturan sensin).'"],["Bu söz Hakk'a hoş geldi — kulunu aziz eyledi;","gönlünden ne geçtiyse, verdi, hazır eyledi."],["Bu sözü Yunus'a, candan (içten) kim haber verir ki —","meğer ki o lütuf sahibi (Allah), ona nazar (lütufla bakış) eyledi."]],"356":[["Çalap (Allah), Âdem'in cismini (bedenini) topraktan var eyledi;","Şeytan geldi, Âdem'e secde etmeyi (tapmagı) ar (kibrine yediremedi) eyledi."],["Der: 'Ben ateşten (oddan), nurdan; o ise bir avuç topraktan';","bilmedi ki Âdem'in içini (özünü Hak) cevher (gevher) eyledi."],["Âdem'in zahirini (dışını) gördü, bâtınına (içine) bakmadı;","bilmedi ki Hak, Âdem'i halka (yaratılmışlara) baş (server) eyledi."],["Kırk yıl kalıbı (cesedi) yattı, adı âlemi tuttu;","gör, şeytan kininden (bugzından) ne fitneler eyledi."],["Âdem toprak [olarak] yatmıştı, adı âlemi tutmuştu;","İblis'in fikrine (düşüncesine) bak — sözde (ya'ni) hüner (marifet) eyledi."],["O yürüyen atları, Âdem'in üstüne sürdü;","Âdem'e hile (mekr) ulaştırıp, sözde (ya'ni) zafer eyledi."],["Âdem'in göbeğinden, Çalap onu yarattı;","'yeter (Vaff)' deyip [o] ayağa kalktı (turı geldi), onlar geçip gitti (güzer eyledi)."],["Madem Âdem'in ahdi (devri) geçti, Mûsâ'nın vakti geldi;","bu işler, İblis'te pek derin (yavlak) bir iz (eser) bıraktı."],["Mûsâ, Hak'la münacat (yakarış) etmek için Tûr'a yöneldi (gönüldi);","bir su aktığını gördü — Mûsâ ona nazar (dikkatle baktı) eyledi."],["Mûsâ der: 'Göreyim, bu su nereden (ne yirden) gelir;","böyle [durmadan] akarsa, [her yeri] alt üst (zîr ü zeber) eder.'"],["Mûsâ ileri vardı — lanetli (la‘în İblis) oturmuş ağlar;","o su, onun gözyaşıymış — bir pınar (bınar) olmuş."],["Mûsâ, lanetliye sordu: 'Ağlaman nedendir?';","'Ağlamadan ne yapayım,' der, 'işim perişan (zâr).'"],["[İblis:] 'Mukarrebdim (yakınlardandım), Mûsâ, o Hakk'ın dergâhında;","[beni] kaldırıp yere vurdu, işimi (hâlimi) şer (kötü) eyledi.'"],["[İblis:] 'Bilmez misin, Mûsâ, ben neden ayrıldım?","Şunlar aklıma (ögüme) düştü, beni perişan (humâr) eyledi.'"],["[İblis:] 'Var, söyle, yâ Mûsâ — bana rahmet eylesin';","tövbe edip, işine (hâline) güzelce istiğfar (bağışlanma diledi) eyledi."],["Mûsâ, dileğine (hâcete) erdi, Hak'la münacata [vardı];","emaneti (İblis'in ricasını) unuttu, sözü kısa (muhtasâr) tuttu."],["Hak, Mûsâ'ya söyledi: 'Emaneti (ricayı) unuttun';","o nidaya (sese), Mûsâ canını nisar (feda) eyledi (kendinden geçti)."],["[Hak:] 'Var, söyle, yâ Mûsâ — ona rahmet edeyim:","madem istiğfar etti, Âdem'e secde etsin.'"],["Mûsâ, lanetliye geldi, Hakk'ın buyruğunu söyledi;","'secde'yi işitince, [İblis] döndü, inkâr (reddetme) eyledi."],["[İblis:] 'Ben O'ndan umardım, derdime derman kıla;","dahası derdimi arttırdı — sözde (ya'ni) tedavi (tîmâr) eyledi!' (acı bir istihza)"],["[İblis:] 'Ben ona secde edecek olsaydım, o vakit ederdim;","şimdi o zaten (hod) toprak olup, alt üst (zîr ü zeber) olmuş.'"],["Âdem, İblis kim ola — işi işleten Çalap'tır (asıl fâil Allah'tır);","ayı güneşi yaratıp, gece ile gündüzü (leyl ü nehâr) eyleyen O'dur."],["İblis'ten [çıkarılacak] mânâ nedir — cahillik hep bizden (kul tarafından)dır;","bu sözden ne sezdin — [Hak onu] sırların sırrı (sırr-ı esrâr) eyledi."],["Çalap der: 'Şu kula benden inayet (lütuf) olursa,","ne şeytan [onu] azdırabilir, ne de kimse [ona] bir şey yapabilir (kâr eyledi).'"],["Altı bin yedi yüz yıldan [öte] geçen Âdem'i,","Yunus dile getirdi — sözü kısa (muhtasâr) tuttu."]],"357":[["Âşık mıdır o — maşuk (sevgili) için canını vermeyen?","Akıllı (âkil) mıdır o — dünyayla birlikte O'nu (Hakk'ı) isteyen?"],["Âdem [oğlu] mudur o — ömrünü kullukta (Hakk'a hizmette) geçirmeyen?","Ârif midir o — kârı zararı (sûd u ziyânı) anlamayan?"],["Âlim midir o — ilmine layık ameli olmayan?","Cahil midir o — aşka iki cihanı satan (yani bu, cahillik değildir)?"],["Âbid (ibadet eden) midir o — taat ve ihlas (samimiyet) işlemeyen?","'Fâsık (günahkâr)' demeyin, kendini suçlu bilene (alçakgönüllüye)."],["Esrik (mest) midir o — kadehi dosttan (Hak'tan) içmeyen (nûş itmedi)?","'İyi' demeyin, gafletle nefse uyana."],["Gönül müdür o — hikmeti tefekkür etmeyen (düşünmeyen)?","Ya göz müdür o — yaş yerine kan dökmeyen (aşkla ağlamayan)?"],["Miskin Yunus'un sermayesi yoktur, ey Allah'ım (İlâhî);","ancak (illâ) bir sevendir — seni, [senin verdiğin] aşkla seveni."]],"358":[["Biz bizi bilmezdik — bizi [Hak] kendinden var eyledi (varlığımız O'ndandır);","bizi aşikâr (görünür) kıldı, kendini gizli (pinhân) eyledi. (Varlığımızı Hak'tan alırız; O yaratışta tecellî eder, kendi münezzeh/görünmezdir — panteizm değil.)"],["Biz [O'nunla] beraber gizliydik (pinhân) — 'sen ve ben'den (ayrılıktan) öteydik;","mutlak ve şüphesizdik (bî-gümân) — [Hak] bizi de şüphesiz eyledi. (Ruhun ezelde, Hakk'ın ilminde — 'elest' âleminde — ferdî ikilikten önceki hâli; bedenli bir ön-varlık değil.)"],["Toprağı ölçüp biçti (kadarladı), sûreti (şekli) çizgiyle (hat) bağladı;","dört âleti (dört unsuru) yerleştirdi, adını 'insan' eyledi."],["Âdem'i yarattığında, biz hepimiz (kamu) bunu biliyorduk;","bu hepsini — seçkini (hâs) ve sıradanı (âm) — bir madenden (kaynaktan) eyledi."],["Asıl madende (asl-ı ma‘den — kökümüz olan kaynakta) idik, kaygısız ve zengindik (ganî);","o izsiz (bî-nişân) âlemde, [Hak] bizi öylece akıttı (revân eyledi — bu dünyaya gönderdi). (Ruhun ezelî kaynağı; bedenli bir ön-hayat değil.)"],["Gör Çalap'ın lütfunu (fazlını) — âsinin (isyancının) gönlünü [bile] yıkmaz;","bin bin kerem ve lütufla, [Cebrail'i] tercüman (vahyin tercümanı) eyledi."],["Hepsi (kamu) bir yere gider — kimse [oraya] nasıl (niçesi) ulaşır?","İki birdir, bir olur — gör, neden [Hak onu] bir eyledi. (Çokluğun birlikte — tevhidde — eriyip görünmesi; Yaratan-yaratılan ayrımını silmek değil.)"],["Madem nefs bir perde (havâle) oldu, her (degme) yola dağıldık;","azık (nevâle) tatlı geldi — [bu] 'sen ve ben'i (ikiliği) doğurdu."],["Ne 'sen ve ben', ne falan (fülân) — ne [bunlardan birini] tutsa, yalandır;","dünyanın kirine (çirkine) kalan işi, [Hak] şüphe (gümân — boş bir vehim) eyledi."],["Âdem'den bugüne (buna degin), [kulun] ne [bağımsız] eli var ne gücü (yegin);","giymeyi ve yemeyi, [Hak] bir taneden (tek kaynaktan) eyledi."],["Elest'te (bezm-i elestte) biliyorduk — göz açtık, 'Belî (evet)' dedik;","Yunus'la başkalarını (gayrını), [Hak] hepsini birden (o ezelî anda) eyledi. ('Elestü bi-Rabbiküm — Ben sizin Rabbiniz değil miyim?' misakı, A'râf 172.)"]],"359":[["Benim gibi (bencileyin), sevdiğimin yüzünü gören kişi;","deli olur, dağlara düşer, kendini (kendözini) yitirir (yavu kıla)."],["Seni bir kez görmenin şükranesini (şükrünü) kim yerine getirebilir (yitüriser)?","Hâşâ, onu gören kişi, gözünü [ondan] nasıl (niçe) ayırır (ırısar)?"],["Onun cemâlinin (güzelliğinin) düzenini (tertîbin), dille kim söyleyebilir?","Onun [güzel] tavrının (kılıncı) tuzunu (lezzetini), canın damağı (cân tutağı) tatmalı (dada)."],["Kişi neyi severse, dilindeki söz o olur;","elimde olmadan (gensüz), gönlümü alanın sözünü söyleyesim gelir."],["Böyle tatlı (şîrîn) bir tavırla (kılınç), nereye baksam;","sözünü, yetmiş iki millete (bütün topluluklara) ulaştırırdı (geçüriserdi)."],["Hiç kimse, kendi çabasıyla (geniyile) dostuna (Hakk'a) âşık olmadı;","âşıkların yıldızını, [Hak] mahabbet (sevgi) burcuna koymuş (aşk O'nun lütfudur)."],["Dertsizlere (aşk derdi olmayanlara), benim sözüm kaya yankısına benzer;","hâldaş (aynı hâli yaşayan), hâldaşının gönlündeki o sırrı (râzını) bilir."],["Her kim seni severse, canı ebed (sonsuza dek) diri kalır;","her an (dem), gecesini gündüzünü senin aşkınla geçirir."],["Zühre (gökyüzünün çalgıcısı Venüs), Yunus'un gözüyle gördüğünü görseydi;","çengini (harpını) elden bırakıp, sazını unuturdu."]],"360":[["Dosttan haber soran kişi [ciddidir] — dostun işi boş söz (güzâf) değil;","iyi bilin, bu dünyada dostsuz (Hak'sız) kişi mahrumdur (yoksundur)."],["Kimdir ki dostun yüzünü göre, 'dost, dost' diye canını vere;","o an (şolok dem) o dosta erer, bütün karmaşayı (teşvîşi) unutur."],["Dostun işi şaşılası (aceb) bir iştir — canın denizini tutuşturur (alevlendirir);","cansızlara (ruhsuzlara) bir rüya (düş) gibidir — keşke sen bu rüyayı yorabilsen."],["Aşkın şevkinden (coşkusundan) âlem doldu — bu âşıklar ondan geldi;","aşksız biten çiçek soldu — hayatın (dirlik) hoşluğu (tadı) aşkladır."],["Ben onu nasıl anlatayım — yüz bin canı [bile] kabul etmez;","ona layık hayat (dirlik) hani, ona layık iş yoktur."],["Kim ona değer (bahâ) biçebilirse, [aşk] onu kendine çağırır (kıgurur);","bana devlet (baht/saadet) ondan erdi — Hümâ kuşuna (talih kuşuna) ihtiyacım yok."],["Can nedir ki dostun önünde — her dilde (kamu dilde) fetva (hüküm) budur;","gel, bu meydanda göresin — dostu sevenin başı [çevgân topu gibi] bir toptur (âşık başını/canını ucuza verir)."],["Dostu seven âşıklara, aşk canların durağıdır (turak);","aşktır yere göğe direk (kâinatın direği/varlık sebebi) — gerisi (ayrugı) hep laf kalabalığı (söz öküşi)."],["Yunus, şimdi [herkes] 'sen ben' derken — âşıklara 'sen ve ben' yoktur;","onu sevmek yokluktadır (benlikten geçmektir — fenâ) — bırak o başka türlü (ayruksı/ikilikçi) bakışı."]],"361":[["Herkesin (kamuların) zenginliği (baylığı), aslında yokluktan gelir (geçicidir);","bunca varlık (mal) varken bile, gönlün darlığı (sıkıntısı) gitmez."],["Dünya malına batmış, ölümün hâline bakmaz;","Karun'un malına ermiş — aman, ne çetin (düşvâr) bir iş (hâl)."],["Bu dünya kime kaldı, kimi nasiplendirdi (ber-hûrdâr kıldı)?","Süleyman'a bile, onun zevki (ber-hûrdârlığı) kalmadı."],["Süleyman zembil (sepet) ördü, kendi emeğini yedi;","onlar (peygamberler), bununla (bu tevazuyla) peygamberliği buldular."],["Gel şimdi miskin Yunus, varını (malını) Hakk'a harca;","gördün [ya], bu dünyanın varlığı (malı) elinde kalmaz."]],"362":[["O Çalap'ımın (Allah'ımın) aşkı, bağrımı (yüreğimi) yara (baş) eyledi;","gönlümü aldı, sırrımı açığa çıkardı (fâş eyledi)."],["Asla (hergiz) gözümden gitmez, dilimden hiç eksilmez;","Çalap, kendi nurunu gözüme tuş eyledi (gösterdi)."],["Can gözü onu gördü, dil ondan haber verdi;","can içine oturdu, gönlümü Arş (ilahî taht) eyledi. (Kalp, Hakk'ın tecellî yeri oldu — 'mü'minin kalbi Rahmân'ın arşıdır'; Hakk'ın bir mekâna sığması/panteizm değil.)"],["Cana bir kadeh sundu, can kana kana (doya doya) içti;","kadeh (peymâne) dolu geldi, canımı sarhoş (serhoş) eyledi."],["Canımız sarhoş (esrük) oldu, dilimiz (lisânumuz) inci (dür) döker;","o Çalap'ımın aşkı, beni derviş eyledi."],["Onun (aşkın) kandili (çerâgı) canda yanar, durağı (yeri) gönüllerdedir;","gönül de, can da, aşkla coştu (cûş eyledi)."],["Ben ne zaman (kaçan) derviş olayım, ya 'Hakk'a kulum' diyeyim?","Benim gibi yüz bin [kişiyi], aşk hırka giydirdi (derviş etti)."],["Yunus şimdi avunur, dostu görüp sevinir;","erenlerin meclisinde (mahfilinde), aşk coşkusunu (cünbiş) gösterdi."]],"363":[["O dost (Hak), benden yana baktı — nasıl, hiç bilmem;","işte bu vücut (beden) şehrine, bir hoş nazar (lütufla bakış) bıraktı."],["Gözümü O'nun yüzünden nasıl ayırabilirim?","Bin türlü tavrıyla (kılınç), gönlümü öylece kaptı."],["Kimden öğüt istesem, bana sabır gösterir (sabret der);","[oysa] sabrımın perdesini, muhabbet (sevgi) ateşi (odı) yaktı."],["Sabırla benim işim nasıl başa varacak (tamamlanacak)?","Şu dostumun iltifatı (nüvahtı), canıma can bıraktı (yeniden diriltti)."],["Sevilen, seveniyle birlikte (bile) kalkar (dirilir) yarın (mahşerde);","benim işim [ise] yarına kalmaz — bugün [beni benlikten] soydu (soyakdı). (Kişi sevdiğiyle haşrolur; ama aşk beni şimdiden tüketti.)"],["Yunus, dostunu (Hakk'ı) canından sever, şunun için:","kişi neyi severse, canı ona uyar (benzer)."]],"364":[["O müezzin ezan okudu (banladı); [kul] kalkıp kamet eyledi;","yüzünü Hazret'e (Hakk'ın huzuruna) tuttu, dönüp niyet eyledi."],["Elim Hazret'e bağlı (namaz duruşunda), dilim Fatiha okur;","belini büküp, Hakk'a hoş bir rükû eyledi."],["Şu benim ibadet yerim (hâcet-gâhum), meğer Tûr dağı oldu;","Mûsâ gibi, bu gönlüm hoş bir münacat (yakarış) eyledi."],["Gözüm bir sûret (ilahî güzelliğin tecellîsini) gördü, yüzüm secdeye vardı;","namaz düzenim (tertîblerüm) yıkıldı, zahidliğimi (zühdümi) mat etti. (İbadetin özü olan iç müşahede/aşk, o vecd ânında dış şekli aştı; namazın iptali değil.)"],["Ne dua kılabilirim, ne selam, ne zikir ve tesbih edebilirim;","bu beş vakit namazımı, aşk yağmaladı (gâret eyledi). (Vecd ânında aşk, dış şekilleri kendine aldı — iç, dışı bir an için örttü; namaz farzının reddi değil.)"],["Gör, aşk Yunus'a ne eyledi — hoş sözler (haberler) söyledi;","o bir âşıktı — maşukla (Allah'la) alışveriş (dâd u sited) eyledi."]],"365":[["Tecellilerinin (ilahî zuhurlarının) nuruna, bedenimin dağları (tagları) dayanamaz (döymez);","çünkü (zîrâ) bedenimin gemisinin bağları sağlam (muhkem) değil. (Tûr'da dağın Hakk'ın tecellîsiyle parçalanması gibi.)"],["Ey damladan (katre) denizler (derya) düzen, can kuşunun ayak bağını (pâ-bend) koparan;","yüz bin denizi yüzdüren — gel, bu zamanları (çağları) [seninle] sürelim."],["Sevgili (dildâr) için, gönül şehrini temizle (pâk eyle), [Hak'tan] gayrısından arıt;","çünkü o, sultanın (Hakk'ın) tahtıdır — buraya kargaları (zâg — bayağı bağları) koymazlar."],["Vatan sevgisi (Hubbü'l-Vatan — asıl/manevî vatan, ruhun ilahî kökü) anıldıkça, zerrece güvenli yer (me'men/huzur) kalmaz;","âşığın yüreğinin yağı (iç varlığı), her an gözünden sızıp [yaş olur] (özlemle erir)."],["Akıllının (âkil) eli [ona] ermez, erse de dile gelmez (anlatılamaz);","dertlinin hâlini dertli bilir — hasta (sayru/aşk hastası), sağlamların (dertsizlerin) hâlini ne bilsin?"],["Maşukluğun (sevilenliğin) hil'atini (şeref kaftanını) her kime giydirdinse,","onun gözüne, en yüce cennetin (Firdevs-i a‘lâ) bahçeleri zerrece gelmez (cenneti bile istemez, seni ister)."],["Yunus, güzelliğinin (hüsnün) kitabını bir hoş seyretmiş (temâşâ eylemiş);","orada âşıklara seslenir (sala) — dağ üstüne dağlar kor (üst üste yığar)."]],"366":[["Kadehi doldur, bize sun — aşk şarabından, ey sâkî;","o büyük kâseden (badya) bize gerek — ondan şeyh de, fakih (fıkıh âlimi) de içsin."],["Sohbetimiz ilahîdir, sözümüz Kevser suyudur (âbıdur);","şahımız şahlar şahıdır (Allah'tır), çalgımız [ise] dostun firâkı (ayrılığı)dır."],["Kim ki bir an (dem) [bu ilahî] sohbete erse, müftü [de] müderris [de] mat olur (geçilir);","bu bir ilahî devlettir (saadettir) — ondan içen, bâkî (ölümsüz) oldu."],["Hırka ve takke [tek başına] yol vermez, [âlim] cübbesiyle (fereci) âlim olunmaz;","din ve dindarlık (diyânet) olmayınca, bunca kâğıdı (varakı/kitabı) ne yaparsın?"],["Yedi mushafı (Kur'an'ı) okudun, saf (sâfî) bir ibadet (taat) gösterirsin;","madem amel etmedin (uygulamadın), istersen yüz bin [daha] oku [boş]."],["Bin kez hacca vardıysan, bin kez gaza (cihad) ettiysen;","bir kez [bile] gönül kırdıysan (sıdunısa), istersen yüz yıl yol dokur [boşa gidersin]. (Gönül kırmamak, salt dış amellerden üstün; hac/gaza değersiz demek değil.)"],["Gönül mü üstün (yig), Kâbe mi üstün — söyle bana, ey aklı eren;","gönül üstündür, çünkü Hak, durağını (makamını) gönülde tutar. (Gönlü dış Kâbe'den üstün tutar; Kâbe'yi hor görmek değil.)"],["Hak, komşuyu ve gönülleri Resul'e (Peygamber'e) ısmarladı (emanet etti);","Miraç gecesi, dostla (Hak'la) bu söz (keleci) de [söylendi]."],["Yunus, senin işin budur: ululların (ermişlerin) eteğini tut;","temiz (pâk) olmak dilersen, gönüllerde bâkî (kalıcı) ol."]],"367":[["Büyükten (uludan) işittik: önce (evvel) er (ilk varlık) yaratıldı;","o kadîm (en eski) er, Padişah'ın (Allah'ın) birliğini ilk [o] bildi."],["Bunca yıl, bunca zaman, biz şüphesiz (bî-gümân) işittik:","Çalap, kendi yaratışıyla (sun'ından), o er üzerinde Rablığını gösterdi (onu var edip Rabbi oldu). (Hakk'ın ilk varlık üzerindeki yaratıcı Rablığı; yaratılanın Tanrı olması değil.)"],["Derler ki o bir kuştu, hikmeti çoktu (öküşidi);","iki cihanın ârifi, o kuştan ibret (ders) aldı."],["O kuşun her bir yönü (tüyü), yüz yirmi dört bin [idi];","önce o kuş uçup, rahmet gölüne (denizine) daldı."],["Gölden geri dönünce, bir dala (budak) kondu;","silkindi — her bir yönden (tüyden) bir damla (tamla) su döküldü."],["O suyun her birinden, [Hak] seçkin (güzin) bir can yarattı;","o canların her biri, burada peygamber oldu."],["İlk temel (bünyâd) atıldı, dünya altı kez doldu;","yedincisi buydu — bu Âdem [o zaman] yaratıldı."],["Âdem topraktandı, Azâzîl (İblis) ateşten (oddan)dı;","işittik [ki] Azâzîl, Âdem'e baktı [ve] güldü (küçümsedi)."],["Âdem'e secde [emri] geldi — [Hak] der: 'ayağına eğilin (inün kademe)';","bütün melekler (firişte) eğildi, Azâzîl dimdik kaldı (secde etmedi)."],["Der: 'Ben ateştenim, yüz bin yıl [ayrıca] ibadet (taat) edeyim';","[oysa] huzurun (Hakk'ın) buyurduğunu [yapmak yerine], kendi ibadetini öne sürdü (arza kıldı)."],["O yaratılmışın (Âdem'in) varlığından [dolayı], Padişah'ın (Allah'ın) birliğinden [dönüp];","şu bir söz (ret) yüzünden, sürüldü, lanetlendi (la‘net oldı)."],["Her kim kendini [bir şey] gördü (benlik etti), üstadı İblis oldu;","kişi ne bulduysa, miskinlikle (alçakgönüllülük/benlikten geçmekle) buldu."],["Eksikliğimi Hak bilir — aşkı bana O verir;","Yunus'a bir tîmâr (deva) kıl — aşk, beni benden aldı (benliğimi giderdi — fenâ)."]],"368":[["Sana ibret (ders) gerekse, gel bu mezarları (sinleri) gör;","taş olsan [bile], bunlara bakıp görünce erirsin."],["Şunlar ki malları çoktur — gör, hâlleri ne oldu;","sonunda bir gömlek (gönlek) giymiş — onun da yenleri (kolları) yok (kefen)."],["Hani 'mülk benimdir' diyen, köşk ü sarayı beğenmeyenler?","Şimdi bir evde (mezarda) yatarlar — üstleri taşlar olmuş."],["Bunlar [artık] eve girmezler, zühd ü taat (ibadet) kılmazlar;","bu beyliği [bir daha] bulmazlar, çünkü devranları (zamanları) geçti."],["Hani o tatlı (şîrîn) sözlüler, hani o güneş yüzlüler?","Bunlar öyle kaybolmuş (gâib) ki, hiç izleri (nişânları) görünmez."],["Bunlar bir zamanlar beyler idi, kapıcılar tutarlardı;","gel şimdi gör — beyi mi, kullarını mı, ayırt edemezsin (ölüm hepsini eşitledi)."],["Ne girecekleri bir kapı var, ne yiyecekleri bir yemek;","ne görecekleri bir ışık var — gündüzleri gece (dün) olmuş."],["Bir gün, ey Yunus, senin de 'ben [şuyum]' (benven) deyişlerin [geride] kalır;","seni de böyle eder — nasıl ki bunları etti."]],"369":[["O geçidin (Sırat'ın) korkusu, işte beni yoldan koydu (durdurdu);","herhangi (degme) kişi geçemez — [Hak] köprüsünü kıldan [ince] kıldı."],["Yerde gökte o dostun (Hakk'ın) hikmetleri sonsuzdur (bî-pâyân);","hikmetine daldığımdan beri, işte beni sözden (kâlden) [öte] koydu (sustu)."],["O lanetli (Şeytan), öküzü hileyle (âl) azdırmaya indi;","[ama] Hak Çalap, öküzü bir sinekle âciz bıraktı (elden kodı). (Büyüğü küçükle alçaltan ilahî kudret.)"],["Öküz, [dünya] taşını [sırtında taşır], taşı bir balık götürür;","balık suyun içinde — [Hak] onun temelini (binâsın) yele (havaya/hiçe) dayadı (yilden kodı). (Halk kozmolojisi; her şeyin nihayet Hakk'ın tutuşuyla durması.)"],["Cehennem iyice (key) karanlık, Cehennem yerin dibinde (tahte's-serâ);","[teslim olmuş] kula artık (ayruk) sorgu yok — [Hak] kulu sorgudan (su'âlden) [muaf] kıldı."],["Dosta âşık olanın gücü (iradesi), [ancak] O'nun sözüne yeter;","gücü O'nun sözüne yeten, kendi sözünü dilden [çekip] bıraktı (sustu)."],["Dostun eteğini tutan, dostla (Hak'la) alışveriş (bâzâr) eder;","dostla alışveriş eden, [dünya] alışverişini elden bıraktı."],["İşittin [ya], Meryem oğlu (İsa), dostuna (Hakk'a) varırken (yükselirken);","gör, sonunda yarım bir iğne, İsa'yı yoldan koydu (alıkoydu). (En küçük dünya bağı bile yükselişi engeller.)"],["Yunus der: 'dostu (Hakk'ı) gerçekten severim' [demekle yetinme] deme;","dostu gerçekten sevenler, benliğini (egosunu) elden bıraktı (fenâ — gerçek sevginin nişanı)."]],"370":[["Ben kendi içimde (bende) seyr ederken (manevî yolculuk), şaşılası bir sırra erdim, ey kardeş (ahî);","bir siz de görün — dostu (Hakk'ı) kendi içimde gördüm, ey kardeş. (Hakk'ın tecellîsini arınmış gönülde görmek — 'kendini bilen Rabbini bilir'; kendisinin Hak olması değil.)"],["İçimde baktım, içimde gördüm — benimle [birlikte] 'ben' olanı;","sûretime (bedenime) can olanın kim olduğunu bildim, ey kardeş. (Varlığımın aslı/canı olan Hakk'ı tanıdım; benliğimin Hak olması değil — her şey varlığını O'ndan alır.)"],["Aradım, O'nu buldum — [o hâlde] o 'ben' isem, ya ben hani (nerede)?","Kendimi O'ndan ayırt edemedim — birden (bir kezden) 'O' oldum, ey kardeş. ('O oldum' = benliğin Hak'ta tümden erimesi, geriye yalnız O'nun kalması — fenâ; benliğin gerçekten Tanrı olması/panteizm değil.)"],["'Sûret (beden) [sadece] topraktır' diyeni, gönlüm kabul etmez;","bu toprağın cevherini (içindeki ilahî özü), Hazret'e (Hakk'ın huzuruna) ulaştırdım, ey kardeş."],["İnkârcı (münkir) kişi onu sezmez, dertlilerin canı sezer;","ben dostun bahçesinin bülbülüyüm — o bahçeden (ilahî asıldan) geldim, ey kardeş."],["Maşuk (Sevgili/Allah) bizimledir, beraber — kıl kadar bile ayrı değil;","uzak sefer (yolculuk) bizden [geride] kaldı — dostu yakın buldum, ey kardeş. (Hakk'ın yakınlığı — 'şah damarından yakın', Kaf 16; panteist bir özdeşlik değil.)"],["Her bir yol nereden bana [gelsin de], her yana dağılayım?","Bu seferim kutlu (uğurlu) oldu — hoş bir menzile (durağa) erdim, ey kardeş."],["O zaman Mansûr'dum (Mansur idim) — işte yine buraya geldim ben;","külümü yak, yele savur — ben 'Ene'l-Hak' (Ben Hakk'ım) dedim, ey kardeş. (Bu söz, benliği tümüyle fenâ bulmuş hâlde — kulun 'ben'i silinip yalnız Hakk'ın 'ben'i o dilden söylediği için — söylenmiştir; Yunus'un 'Mansûr'dum' deyişi de bu fenâ makamıyla özdeşleşmedir. Ego'nun 'ben Tanrı'yım' iddiası/panteizm/hulûl değil.)"],["Ne ateşte yanıp dağılırım, ne darağacına çıkıp boğulurum;","işim bitince [yürüyüp giderim] — ben [bu dünyaya] bir gezinti (teferrüc) için geldim, ey kardeş."],["Yoksul iken zengin (mun‘im) oldum — kâinat (kevn ü mekân) benim oldu;","doğudan batıya, baştan başa (ser-te-ser), yere göğe doldum, ey kardeş. (Hak'ta erimiş canın, O'nun her şeyi kuşatan hakikatine katılması — sınırlı ego'nun gerçekten kâinat/Tanrı olması değil.)"],["Nasıl ki ben kendimi bildim, dilediğim Hakk'ı buldum;","korkum, O'nu bulana kadardı — korkudan kurtuldum, ey kardeş. ('Kendini bilen Rabbini bilir' — nefsini bilmek Hakk'ı bilmeye götürür; kendini tanrılaştırmak değil.)"],["Yunus, seni kim öldürür — [canı] veren, canı yine [kendi] alır;","bu canlara hükmedeni (egemen olanı) kim olduğunu bildim, ey kardeş. (Canların tek sahibi, alıp vereni Hak'tır.)"]],"371":[["Önceden (evvel) de vardı, canımda bu aşk ateşi (odı);","açığa vurmazdım (eşkere itmezdim) — bilirdim ki onu dost (Hak) koydu."],["Dört kitabı (Tevrat-Zebur-İncil-Kur'an) şerh eden [bile], aşka çare bulmadı;","ne beyler, ne sultanlar, ne müderris, ne kadı."],["Yer gök sabit (kâ’im) durur, kımıldamaz; yeller eser [ama] sarsamaz;","her şey sağlam (muhkem) olur — temeli (bünyâdı) aşk olunca."],["Aşk anadan doğmadı, kimseye kul olmadı;","hükmüyle esir eder — tanıdığı (biliş) da, yabancıyı (yad) da, hepsini."],["Günde bin kez yanarım, razıyım ben o ateşe (oda);","çünkü (zîrâ) şekerden tatlı (şîrîn) bana, senin aşkının ateşi."],["Aşka Mecnun olanlar, kâr-zarardan (assı-ziyân) vazgeçmiştir (fârig);","sıcaktan soğuktan korkmaz — öyleyse (pes) [cehennem] ateşini ne bilsin (umursamaz)."],["Ezelden (öncesizlikten) beri benim fikrim, zikrim 'Ene'l-Hak' (Ben Hakk'ım) idi;","daha o Bağdatlı Mansur (Hallâc) doğmadan [bile]. (Bu söz, benliği fenâ bulmuş hâlde — kulun 'ben'i silinip yalnız Hakk'ın 'ben'inin o dilden söylediği — ezelî birlik hâlinin dile gelişidir; ego'nun Tanrılık iddiası değil. Bu fenâ bilinci, hiçbir fertten — Mansur'dan bile — önce, zamanüstü bir hakikattir.)"],["Aşk ateşi (odı) coştu (cûş eyledi), canımı hoş eyledi;","kimse söndüremez, canımda yanan ateşi (odı)."],["Aşkın çengine (tuzağına) düşenin işi melamet (kınanma) olur;","onun için kötü adlıdır (bed-nâm) miskin Yunus'un adı (âşık, kınanmayı göze alır — melamet yolu)."]],"372":[["Sana gönül veren kişi, iki cihanı [da] unutur;","gözünü senden çeviren (ıran) kişi yalan söyler — âşık değildir."],["Bu fani dünyayı (fenâ) terk etsin, o ebedî olanın (bekâ) kaygısını gözetsin;","ne mutlu (zihî devletlü) o cana — [Hakk'a] yüz akıyla (şerefle) varan kişiye."],["Benliğini (kendüligin) terk etsin, senin yolunda can versin;","sen sultana (Hakk'a) eren kişi, sorgusuz (sorısuz) cennete (uçmaga) girer."],["Her kim bu dünyadan geçerse, aşkın kadehini dolu içer;","dostun gülünü deren kişi, canını aşka saçı [gibi] saçar."],["Can neymiş ki dostun yolunda — âşık onu [feda etmekten] çekinmez;","canını Hakk'a veren kişi, bu [bir] canla bin can alır."],["Canını şükran (şükrâne) [olarak] versin, yüzünü ayaklara sürsün;","Hak'tan haber soran kişi, erenlerin gönlüne girer."],["Akıl gitsin, hayran (şaşkın) olsun, dünyada ser-gerdan (başı dönmüş) olsun;","aşka gönül veren kişinin küfrü [bile] iman olur. (Âşığın aklı aşan kendinden geçişi/salt şekli umursamayışı, onda en derin imana döner; gerçek inkâr değil.)"],["Bozuk (fâsid) işleri terk etsin, dervişleri [hizmeti] kendine iş edinsin;","dostun haberini duyan kişi, gözünden yaşları akıtsın."],["Gözlerini ağlatır (giryân), ciğerini kebap (biryân) eder;","gönülleri hayran eder — aşk izi (eseri) olan kişi."],["Madem dünyayı fani (fenâ) bilirsin, ne [diye] döne döne yatarsın (gaflette)?","Dostun yolunu soran kişi, doya doya uyku (gaflet) uyur mu?"],["Şu, 'dost nerede (kanda)?' diye soran — nerede dersen, O oradadır (andadır);","gerçek âşık olan kişi, maşukla (Sevgili'yle) seyran (temaşa/birliktelik) hâlindedir. ('Nereye dönerseniz Hakk'ın yüzü oradadır', Bakara 115 — O her yerde mevcuttur.)"],["Miskin Yunus, bu dünyanın zahmetine (sıkıntısına) sabret;","sen sultana (Hakk'a) eren kişi, türlü cefaya (eziyete) katlanır."]],"373":[["İşitin, ey dostlar (yârânlar);","eve dervişler geldi;","can[ımızı] şükran (şükrâne) [olarak] verelim;","eve dervişler geldi."],["Her kim yüzünü gördü,","kendini (benliğini) indirir (alçaltır);","iç ilimden (ilm-i bâtın) söyler (öter);","eve dervişler geldi."],["Dervişler uçan kuşlardır,","deniz kıyısında kışlarlar;","ne mutlu (zihî devletlü) o başlar (kişiler);","eve dervişler geldi."],["Dervişler yüzü ak (itibarlı) kişilerdir,","görenler deli olur;","içleri (bâtını) Arş'tan [bile] yücedir (gönül, Hakk'ın tecellî yeri);","eve dervişler geldi."],["Seydi Balum'un (bir erenin) ilinden,","dilinden şeker damlar (tatlı sözlü);","dostun bahçesi yolundan;","eve dervişler geldi."],["Kulun Yunus arkadaşsızdır (ögürsüz),","kimsesi yok, yalnız;","canımız [onlara] feda (fidî) olsun;","eve dervişler geldi."]],"374":[["Dinin imanın varsa, dervişleri hor görme;","bütün âlem, dervişleri görmeye hasret (müştak) durur."],["Ay ve güneş, dervişlerin sohbetine hasret (müştak) durur;","melekler (firişte) tesbih okur, dervişleri zikreder (anar)."],["Hristiyanlar (tersâlar) huzuruna (tapuya) gelir, hükümdarlar (hükm ısları) âciz (zebûn) olur;","dağlar taşlar secde kılar — dervişleri görünce."],["O âlemin övüncü (Fahr-i âlem) Mustafa, o doğruluk ve saflık madeni (ma‘den-i sıdk u safâ);","ondan (Peygamber'den) vefa istersen, dervişleri incitme."],["İncitirsen, ah ederler — ömrünün gülünü kuruturlar;","gözsüz (kör) olursun, [seni] yederler (sürüklerler) — ki dervişleri [değerini] bilesin."],["Dervişin oku uzağa (ırak) atar, 'hey' demeden cana batar;","gafil olma — yetişir, tutar; dervişleri hor görme."],["Yer gök der: hırka hakkı için, himmetleri (manevî güçleri) bâkî olsun;","madem Padişah (Allah) sâki oldu, dervişleri [aşkla] sarhoş edecek (esridiser)."],["Gökten inen dört kitabı günde bin kez okusan [bile];","vallahi, dervişleri sevmezsen [Hakk'ın] cemalini (dîdâr) göremezsin. (Sırf okumak değil; Hakk'ın dostlarını sevmek de gerek.)"],["Bahtlılar (devletlüler) bizi sever, her an hâlimizi sorar;","inkârcıların (münkir) gözü kördür — dervişleri görmez."],["Yunus der: bu aşk geldi, ölmüş canımı diri kıldı;","'sen ben' demek dilden kalktı (kesildi) — dervişleri görünce. ('Sen-ben' ikiliğinin silinmesi — fenâ.)"]],"375":[["Bu yolun menzili (varışı) uzak (ırak) — bu yola kim varır?","Bu hâlin müşkili (zorluğu) çok — bunu kim başarır?"],["Bu yola azık (yarak — tevhid/ibadet) gerek, az olsun çok olsun;","iyice demir [gibi] bir yürek gerek, bu sarp (dik) yola girmek için."],["İman aldatıcıları (aldaguçları — imandan saptıranlar), bilin, bu yolda çoktur;","nefsine uyanların yüz karası (utancı) gitmez."],["Bu yolda yetmiş bin riya (iki yüzlülük) ordusu (çeri) vardır, bilin;","o orduyu kırmak için, nefsini öldürmüş bir er gerek."],["Doğruluk mancınığı [ve] istiğfar (tövbe) taşıyla;","[taş] doğru gitti, atıldı — nefsin kalesi yıkıldı."],["Kimde doğruluk varsa, bil ki [o doğruluk] 'âr'ı (benlik kaygısını/sahte benliği) öldürür;","gerçek erin sermayesi, iki cihana yarar."],["İnce Sırat köprüsü, bu yolda kolay (genez) imiş;","dosta (Hakk'a) giden kişinin çaresi, doğruluktur."],["Yunus, şimdi [bir] çağrıdır (sala) — gel, yokluğa (benlikten geçmeye — fenâ) gidelim;","göz, eğer layıksa, Hakk'ın cemalini (dîdâr) görür."]],"376":[["Aşkın ateşi (odı) cana düştü, yürek yağını eritti;","heves-hevesin (hevâsetün) kökünü kesti, bağını (bahçesini) ateşte yaktı."],["Kahır (zorlama) kazmasıyla, canda cefa ocağını kazdı [söküp attı];","himmet eri (mürşit), nefsimin boynuna bıçağını çaldı (nefsi kesti)."],["Rahmet suyuyla, gönlümün evini tertemiz (ap-arı) yıkadı;","hizmet kapısından, ona şükür kadehini (ayagını) sundu."],["Her kim bizi yererse (kınarsa), Hak onun dileğini versin;","vurmaya niyet edenin, [ben] düşüp ayağını öperim. (Kötülüğe iyilikle karşılık.)"],["Kim bize taş atarsa, ona güller saçılsın (nisâr olsun);","kandilime (çırâguma) kasteden[in], Hak [onun] kandilini yandırsın. (Taşa gülle karşılık; düşmana hayır dileme.)"],["Miskin (zayıf) gönlün vücudu, aşkın elinden iki büklüm oldu;","tövbe kapısından, ona iman değneğini (tayagını) sundum (destek verdim)."],["Gel şimdi, ey miskin Yunus, hevesini (hevâseti) elden bırak;","Çalap'ım, bize kanaat bıçağını rızık (nasip) eyle (hırsı kessin)."]],"377":[["Gerçek âşık olanların canı, yalnızca (hemen) dostu (Hakk'ı) sever;","kibrini, kinini unutur — canını maşuka (Sevgili'ye) terk eder (bırakır)."],["Gerçek âşık öğüt dinlemez, çünkü (zire) öğüt fayda (assı) etmez;","öğütle yatışmaz (karar itmez) — o, Sübhân'ı (Allah'ı) bulmak ister."],["Gerçek âşık olanların yüzünde [bir] nişan (iz) olur;","gece gündüz durmadan akar, gözlerinin yaşının kanı."],["Bütün (cümle) bu âlemin sevdiği, bu din ile bu imandır;","vallahi, aşksız gerekmez o din ile o iman (din-iman aşkla tamamlanır)."],["[Sevgili] bir uca [dünyanın öbür ucuna] varsa [bile], âşığın canı [ondan] ayrı değildir;","sorun bütün âşıklara — [can] onu kıl kadar [yakın] bilir."],["İlk ve son olan (Evvel-âhir), diri ve her şeyi tutan (Hayyü'l-Kayyûm) [Allah], âşıkların maşuku idi;","aklın varsa hesap et — bu [dünyevî] aşkın devranı (çağı) geçecek (bâkî olan Sevgili kalır)."],["Her kim 'âşığım' deyip [de yalnız] hasretle [vakit] geçirirse;","onun gözü perdelidir (hicâblı) — aşkın gizli [hakikati] (nihânı) ona görünmedi."],["Yunus, yüzünü âşıkların ayağından kaldırma;","yüz bir canı feda (fidî) eyle — sultanı (Hakk'ı) orada bulursun."]],"378":[["Erenler bir denizdir — dalmak için âşık gerek;","denize girip inci (gevher) almak için, dalgıç (bahrî) gerek."],["Yine biz dalgıç (bahrî) olduk, denizden inci (gevher) aldık;","incinin kıymetini bilmek için, sarraf (değer bilen kâmil) gerek."],["Yürü, sus (epsem ol) — ne aracılık (simsârlık) satarsın?","Bu sırra ermek için, Ali gibi [bir] er gerek."],["Muhammed Hakk'ı bildi, Hakk'ı kendi içinde gördü;","Hak her yerde (cümle yirde) hazırdır (mevcuttur) — görmek için göz gerek. (Hakk'ın her yerdeki tecellîsini iç gözle görmek — 'kendini bilen Rabbini bilir'; O münezzeh olduğu hâlde tecellî eder, panteizm değil.)"],["Rızkını Hak'tan dile — 'nahnu kasemnâ' (biz [rızkı] taksim ettik, Zuhruf 32) gizlidir (pinhân);","gözün perdesini (hicâb) silmek için, nefsini bilmiş [bir] er gerek."],["Bu sözü (nefesi), âşıkların hükmüyle söyledim;","bir karara durmak (sebat etmek) için, cimriliksiz (bâhıllıksuz/cömert) [bir] er gerek."],["Âlimler kitap düzer, karayı (mürekkebi) aka (kâğıda) yazar;","[oysa] bu [hakikat] kitabının suresi, gönüllerde yazılır."],["Yürü, hey riyakâr sofu (sûfî zerrâk) — ne riyakârlık (sâlûslık) satarsın?","Hak'tan başka (artuk) kim ola ki, kula dilek vere (yalnız Hak verir)?"],["Hakk'ın durağı (makamı) gönüldedir, ayetleri Kur'an'dadır;","aşk burcunun kulesi, canda — Arş'tan [bile] yukarıdadır. (Gönül, Hakk'ın tecellî yeri; aşkın makamı yaratılmış Arş'ı bile aşar — bir mekâna sığma/panteizm değil.)"],["Öyle deli olmuşum ki, geceyi gündüzden ayıramam (bilmem);","yüreğimde işledi, aşk okunun yarası."],["Gel şimdi, miskin Yunus, erenlerin eteğini tut;","hepsinin (cümlesi) çaresi, miskinlikte (benlikten geçmekte) yoklukmuş (fenâ)."]],"379":[["Padişahlar padişahı, o Ganî (hiçbir şeye muhtaç olmayan Allah);","[kendi] emriyle bize canı gönderdi (viribidi)."],["Ateş (od), su, toprak [ve] yeli (yil) birlikte [aldı];","bunlarla bedeni (teni) bina etti (bünyâd eyledi)."],["Yetmiş iki türlü dil (lisan/topluluk) yarattı;","aralarında Müslümanı üstün koydu."],["Biz Müslümanlara, Muhammed ümmetine,","din ile imanı bir hil'at (şeref elbisesi) olarak verdin."],["Can nurdandır — [eğer] nura karışırsan (asıl kaynağa dönersen),","sûret (beden) fani olur diye [onu] kusur sayma (üzülme)."],["Zekeriya'nın bir ağaca sığınmasıyla,","onu testereyle (bıçgu) ikiye biçtirdin (yardırdın). (Zekeriya'nın, kovalayanlardan ağaca sığınıp ağaçla birlikte biçilmesi rivayeti.)"],["Eyyub'un bedenini (tenini) kurda yedirdin;","sabırla, o da dermanını (devasını) buldu."],["Yakub'u ağlatıp gözlerini aldın (kör ettin);","Yusuf'u [ise] sen Mısır'ın sultanı ettin."],["Herkese (kamuya), ibret (ders) için söz söyletir;","o Sübhân (Allah), Yunus'u da söyletir."]],"380":[["Ne zamana kadar (niçe bir), bu bedeni, [onun] boyunu posunu (kaddile kâmeti) besleyeceksin?","Dünya zevkine düştün, kıyameti unuttun."],["Topraktan yaratıldın, yine yerin (yirün) topraktır;","toprak olacak kişiler, bu [dünyalık] gösterişi (alâmeti) ne yapar?"],["Yüce saraylar yapan, akıllı (uslu) değil delidir;","sonunda (âkıbet), herkesin yapısı (imâreti) viran (harap) olur."],["Çalış (düriş), kazan, ye-yedir, bir gönül kazan (ele getür);","bir gönlün ziyareti, yüz Kâbe'den üstündür (yigrek). (Gönlü/insanı salt dış hac ziyaretinden üstün tutar; Kâbe/haccı hor görmek değil.)"],["'Keramet sahibiyim' deyip halka riyakârlık (sâlûslık) satan;","[gerçek] keramet[i] varsa, [önce] nefsini Müslüman etsin (teslim alıp ıslah etsin)."],["Nefsini Müslüman eden (teslim alan), Hak yolda doğru giden;","yarın (mahşerde) ona, Muhammed'in şefaati olacak."],["Yüz bin peygamber gelse [bile], hiç şefaat fayda etmez;","vay, eğer Allah'ın inayeti (lütfu) olmazsa (Hakk'ın lütfu olmadan şefaat bile kâr etmez)."],["Yunus, şimdi sen de gerçeklerden (samimi olanlardan) olmaya bak;","meğer gerçek erenler, herkesin [asıl] ziyaretiymiş."]],"381":[["Aşkın beni benden aldı (benliğimi giderdi — fenâ),","bana seni gerek seni;","ben gece gündüz yanarım,","bana seni gerek seni."],["Ne varlığa (zenginliğe) sevinirim,","ne yokluğa (yoksulluğa) üzülürüm (yirinürem);","aşkınla avunurum,","bana seni gerek seni."],["Aşkın âşıkları öldürür,","aşk denizine daldırır;","[ilahî] tecellîyle doldurur,","bana seni gerek seni."],["Aşkının zincirini [bir] koparayım (üzem),","deli olup dağlara düşeyim;","gece gündüz düşüncem (endîşem) sensin,","bana seni gerek seni."],["Eğer beni öldürseler,","külümü göğe savursalar;","toprağım orada [yine] haykırır (çağıra):","bana seni gerek seni."],["Sufilere sohbet gerek,","ahilere ahiret gerek;","Mecnunlara Leyla gerek,","bana seni gerek seni."],["Ne cehennemde (Tamu) [bir] yer edindim,","ne cennette (Uçmak) köşk kurdum;","senin için çok ağladım,","bana seni gerek seni."],["Cennet cennet dedikleri,","bir ev ile birkaç huri;","isteyene ver onu —","bana seni gerek seni. (Âşık, cennetin nimetlerinden öte Hakk'ın kendisini ister — menfaatsiz sevgi; Hakk'ın vaad ettiği cenneti hor görmek değil.)"],["Yusuf, eğer senin hayalini,","bir gece düşte (rüyada) görseydi;","[bütün] mülklerini terk ederdi —","bana seni gerek seni."],["Adımı Yunus diye çağırırlar,","gün geçtikçe ateşim (odum) artar;","iki cihanda da maksudum (gayem) [sensin],","bana seni gerek seni."]],"382":[["Dilsizlerin haberini, kulaksız [bir kulakla] dinlemeli;","dilsiz-kulaksız [olanın] sözünü anlamak için, [özel/uyanık] bir can gerek."],["Dinlemeden anladık, [onlar] söylemeden [biz] dinledik (sözsüz/manevî anlayış);","gerçek erin bu yolda sermayesi, yokluktur (benlikten geçmek — fenâ)."],["Biz sevdik, âşık olduk; sevildik, maşuk olduk;","her an yeni bir dirlikteyiz (hayattayız) — sizden kim usanır (bıkar)?"],["Yetmiş iki dil (millet) ayrıldı, aramıza söz (ayrılık) düştü;","biz [ise] o [tek sevgi] bakışıyla baktık — ne avamı (âm) ne seçkini (hâs) hor gördük. (Sevgi bakışı, millet/mezhep ayrılığını aşar; kimseyi hor görmeden.)"],["Ey Yunus, şimdi amma (velî) — yerde gökte dopdolu (dolu);","her bir taşın altında, bir İmran oğlu Mûsâ [vardır]. (İlahî sır/velîlik, her şeye sinmiştir.)"]],"383":[["Nasihat (öğüt) kandilinden bir işaret göründü;","bedenimin içindeki canım, ona doğru süründü (yöneldi)."],["Nefsimin ejderhası dönüp bana saldırdı (haml itdi);","kanaat 'dur!' (hay) demezse, gerçekten yer çöker (insan batar/kaybolur)."],["Kanaati [kendine] yardımcı (yar) edin, nefsin dileğine uyma;","hakikate eresin — yerini buldun, artık dur (sebat et)."],["Kanaat denileni eğer sen tutmazsan,","nefsine uyarsan — git, ser-gerdan (başı dönük/şaşkın) ol [bakalım]."],["Yunus, Hakk'ın tecellîsini şair dilinden söyler;","canda [bir] cevher (öz) varsa, Hak'tan yana yöneldi (yürindi)."]],"384":[["Ömrüm, sen beni aldattın (kandırdın);","âh, ne edeyim seni, ömrüm;","beni kımıldayamaz (deprenimez) [hâlde] bıraktın;","âh, ne edeyim seni, ömrüm."],["Bütün varım hep sendin (sen idin);","canımın içinde can idin;","hem sen bana sultan idin;","âh, ne edeyim seni, ömrüm."],["Gönlümü sana oyalardım (eglerdim);","'gül' deyip [seni] koklardım (yıylardım);","kendimi garip hissedip ağlardım;","âh, ne edeyim seni, ömrüm."],["Buraya gelen, gidecekmiş (giderimiş);","dünya işi hep (cümle) yalan;","ömrünü yitiren (yavı kılan) ağlar;","âh, ne edeyim seni, ömrüm."],["İyiliğim, kötülüğüm (hayrım şerüm) yazılacak;","ömrümün ipi kopacak (üzülüser);","sûret (beden) gidip dağılacak (bozulacak);","âh, ne edeyim seni, ömrüm."],["Keşke (bârî) [beni] bırakıp kaçmasan;","göçebe (göçgünci) gibi göçmesen;","ölüm şarabını içmesen;","âh, ne edeyim seni, ömrüm."],["Bir gün ola, sensiz kalayım;","kurda kuşa yem (öğün) olayım;","çürüyüp toprak olayım;","âh, ne edeyim seni, ömrüm."],["Miskin Yunus, bilmez misin?","Yoksa [hiç] bakmaz (nazar kılmaz) mısın?","Ölenleri anmaz mısın?","Âh, ne edeyim seni, ömrüm."]],"385":[["Bu, gülecek bir yer değil — ağla, hem de pek katı (çok);","Azrail seni kovalar; canın [çıkış] alâmeti ağırdır (katı)."],["Burada kalacağını sanma — oraya (anda/mezara) hazırlıksız (gensiz) varırsın;","kıyameti görene dek, mezarda (sinde) o kadar (anca) yatarsın."],["Mal mülkten ayrılıp, mezara (sine) varıp durursun;","Münker ile Nekir gelip, katı (sert) [bir] sorgu (su'âl) edecek."],["İki melek (ferişteh) iner, gelip karşına konar;","günahlarını yazar, amel defterini (biti) boynuna asar (sala)."],["Günahlarını tartarlar, sonra Sırat'a götürürler (ilteler);","Zebânîler (cehennem melekleri) tutar, feryatlar (figânlar) katı (şiddetli) olur."],["İsrafil suru çalar (üfler), yaratıklar (halâyık) kalkıp gelir;","başı açık, yalınayak — sıcaklar (ıssılar) katı (şiddetli) olur."],["Baba (ata) oğula bakmaz [olur], ana kıza [bakmaz];","şu gün bize [de] gelecek — mahşer meydanını (arasât) unutma. (O gün herkes kendi derdine düşer — Abese 34-37.)"],["Yunus, günahın çoktur — ağlarsan yeridir (hakdır);","yarın (mahşerde) sana, Muhammed'in şefaati gerekir."]],"386":[["Kime gönül verdiysem, benimle yâr (dost) olmadı;","hâlimi bilip derdimi sorup, bana vefalı (vefadâr) olmadı."],["Meğer Hak'tan [bir] takdir (kader) idi — gönül sana âşıktı;","hiç kimse benim gibi (bencileyin), [bu] derde tutulmadı (giriftar olmadı)."],["Şikâyetim aşktan değil, kendi talihimden (tâli'ümden)dir;","kendi yolunu aramayan cahildir — o, [gerçek] er olmadı."],["Aşk, büyük (ulu) bir hil'attir (şeref kaftanı) — Çalap [onu] birkaçına verdi;","nicesi [de] mahrum kaldı, aşktan haberdar olmadı."],["Aşk, büyük (ulu) bir nazardır (ilahî bakış/lütuf); âşığın canı, [Hakk'ın] dîdârına [hasret]tir;","aşkı olmayan gönüller, viranedir — şehir (şâr) olmadı."],["İbrahim'e Nemrud'un ateşini (odın) gülistan (gül bahçesi) eyleyen, aşktır;","aşktan bir nazar (bakış) erince, [ateş] gül bahçesi (gül-zâr) oldu, ateş (nâr) olmadı. ('Ey ateş, İbrahim'e serin ve esenlik ol', Enbiyâ 69.)"],["Yer ile gök, Muhammed'in dostluğu (sevgisi) için yaratıldı;","'Levlâk' buna delildir — onsuz (ansuz) yer gök olmadı. ('Sen olmasaydın felekleri yaratmazdım' hadis-i kudsîsi.)"],["Aşkta sıkıntılar (kahırlar) çok olur; aşk erine [benlik] kıskançlığı/davası (gayret) imkânsızdır (muhâl);","Yunus, âşık olduysan — âşıklarda [bu] utanç (âr) olmadı."]],"387":[["Müslümanlar, zaman (zamane) kötü (yatlu) oldu;","helal yenmez [oldu], haram kıymetli oldu."],["Okunan Kur'an'a kulak verilmez (tutulmaz);","şeytanlar semirdi (şişti), güçlü (kuvvetli) oldu."],["Haram, maya (hamîr) gibi cihanı tuttu (kapladı);","bozgunculuk (fesad) işleyen, saygın (hürmetli) oldu."],["Kime ki Tanrı'dan haber verirsen,","başını [öfkeyle] sallar (kakır) — [karşı] delilli (hüccetli) [iddiacı] oldu."],["Öğrenci (şakird), ustasıyla (üstâd) kavga (arbede) eder;","oğul, babaya (ata) karşı 'izzetli' (üstün/saygın) oldu (büyüklük tasladı)."],["Fakirler [bile], miskinlikten (alçakgönüllülükten) elini çekti;","gönüller yıkarak (kırarak), heybetli (azametli) oldu."],["Peygamber'in yerine geçen hocalar (âlimler),","bu halkın başına zahmet (sıkıntı) oldu."],["Peygamber'in hadisi tutulmaz (uyulmaz) oldu;","yaratılmışların hepsi (halâyık cümle), Hak'tan utanır (Hak katında mahcup/yüzü kara) oldu."],["Yunus, gel — âşıksan tövbe eyle;","Nasuh [gibi samimi] tövbenin sonu (ucı), kutlu (uğurlu) oldu. (Tevbe-i Nasûh — içten, kesin tövbe, Tahrîm 8.)"]],"388":[["Ömrüm geldi geçti, şu yel (yil) esip geçmiş gibi;","işte bana öyle gelir [ki] — şu göz açıp yummuş (kapamış) gibi."],["Bu söze Hak şahittir (tanuk): bu can, gövdeye (bedene) konuktur (misafir);","bir gün ola, çıkıp gider — kafesten kuş uçmuş gibi."],["Miskin (zavallı) âdemoğlunu, ekinciye (çiftçiye) benzetmişler;","kimi biter (büyür), kimi yiter (yok olur) — yere tohum saçmış gibi."],["Bu dünyada bir şeye (nesneye), içim yanar, özüm için için yanar (göyner):","genç (yiğit) iken ölenlere — yeşil ekini (gök ekin) biçmiş gibi."],["Bir hastaya vardıysan, bir içim su verdiysen;","yarın (mahşerde) orada (anda), [bu] karşına gelir — Hakk'ın şarabını (ilahî feyzini) içmiş gibi."],["Bir yoksulu (miskîni) gördüysen, bir eski [giysi] (eskice) verdiysen;","yarın (mahşerde) orada (anda), sana [bu] gelir — Hakk'ın şarabını (ilahî feyzini) içmiş gibi."],["Yunus Emre, bu dünyada iki kişi kalır derler;","meğer [onlar] Hızır-İlyas ola — Âb-ı Hayât'ı (hayat suyu) içmiş gibi (ölümsüz erenler)."]],"389":[["Bugün gizli [sırrımı] (pinhânumı) açığa vurdum (eşkere kıldum);","can verip (benliğimi vererek), o cananı (Sevgili'yi/Hakk'ı) buldum. (Benliği vererek Hakk'ı bulmak — fenâ.)"],["Can [da] gönül [de], maşuka (Sevgili'ye) hayran kalmıştır;","[ben] devranımı (ömrümü), maşukla [birlikte] sürerim."],["Dert gerek, dert gerek, dert gerek;","[öyle biri] gerek ki, derde dermanımı [vereyim] (dertliye sevgi devasını sunayım)."],["Mekânsızım (bî-mekânam) — onun için, [bu] dünyada;","kimse benim [asıl] mekânımı bilmez (yerim Hak katında, mekânın ötesinde)."],["[Asıl] madeni/kaynağı (kânı) buldum — gerisini (ayrugı) ne yaparım?","Bugün dükkânımı yağmaya verdim (bütün dünyalığımı/benliğimi bıraktım)."],["Büsbütün top benim — çevgânı (cirit değneğini) [de] aldım, vururum (çalarım);","bu toptan, meydanımı kim alabilir? (Aşk meydanının/oyununun ustası benim.)"],["Yer benimdir, gök benimdir, Arş benimdir;","gör, gölgeliğimi (sayvânumı) nasıl [her yere] germişim. (Hak'ta erimiş canın, O'nun her şeyi kuşatan hakikatine katılması — benliğin Hak'ta fenâsıyla her şeye 'sahip' oluşu; sınırlı ego'nun gerçekten kâinata sahip olması/Tanrı olması değil — panteizm/hulûl değil.)"],["Adım Yunus olduysa, bunda ne şaşılacak (aceb) [var]?","Okusunlar [varsın] defterimi ve divanımı (şiirlerimi)."]],"390":[["Ey dostlar (yârenler), canımın neye daldığını söyleyemem (eydimezem);","gönlümü kimin aldığını, dille niteleyemem (vasf idemezem)."],["Gönlüm dolu, dile sığmaz; o kişi âşıktır ki [bu] hâli bile (bilir);","aşk niceyi sele verdi (selinde sürükledi) — [yabancı] ne olduğunu anlayamaz."],["Aşktan haber bilenlerin, aşk derdiyle dolanların;","küfrü iman olanların gülmesini ayıplamayın (kınamayın). (Âşıkların aklı aşan kendinden geçişi/salt şekli umursamayışı, en derin imana döner; gerçek inkâr değil.)"],["Ağlamak [da] gülmek [de] âşığa [birdir], dirilmek [de] ölmek [de] âşığa;","[âşık], kahırla lütfu bir bilir (Hak'tan geleni eşit kabul eder) — [yabancı] onun [hiç] mahzun (melûl) olduğunu [bile] bilmez."],["Aşk, Yunus'u dilsiz (lâl) eyledi; Yunus'un kanı aşka helaldir (canını aşka adamıştır);","bırak (kon), varını ayak altında çiğnetsin (pâyimâl) — [Sevgili'den] ayrıldığını görmesin (hiç ayrı düşmesin diye, her şeyini versin)."]],"391":[["O Sultan (Hak), erenlerin gönlünde [bir] dükkân açtı;","nicesi bizim gibi[ler], orada konaklayıp göçtü."],["Bütün erenler uçtu, dağları ovaları (yazılar) geçti;","aşk kazanına düştü — kaynayıp pişti (aşkın potasında olgunlaştı)."],["Bu dünyanın misali (mesel), pis bir leşe (murdâr gevde) benzer;","köpekler (itler) leşe üşüştü, Hak dostu [ise onu] bırakıp kaçtı."],["Âşık mı diyeyim ona — [ki o] canının (benliğinin) terkini vurmadı (bırakmadı)?","Âşık [ancak] ona desinler ki, [benliğinden geçip] melâmeti (kınanması) dile düştü. (Gerçek âşık benliğini bırakıp kınanmayı göze alır — melâmet.)"],["Yunus, Tapduk'un yüzünü göreli yine esridi (mest oldu);","meğer onun gönlünden bir yudum (cur'a) şerbet içmiş (şeyhinden manevî feyiz almış)."]],"392":[["Hasta bülbül, gülün yüzünü görüp mahşer gibi coştu (arasât eyledi);","âşık, maşukuna erişti — şükredip müjdeler (beşâret) verdi."],["Gaflet içinde yatıyordum, şah (Hak/sultan) bana [bir] nazar (bakış/lütuf) eyledi;","'gaflet uykusundan uyan!' dedi — gelip [bir] işaret eyledi."],["Epey (hayli) zamandır, zayıf [kulunu] bir vadeye (sonraya) ertelemişti (salmıştı);","[şimdi] gönlün kırıklığını (şikeste) gördü, [onu] kapıp onardı (imaret eyledi)."],["Şu Sevgili (sanem), ben garibin (gurbet ehlinin) hâtırını (gönlünü) sormaya geldi;","gönlün kırığını (sınuk) onardı — gönlü ziyaret eyledi."],["Gör bu derviş Yunus'u — 'dilin tercümanı' (ilahî ilhamın taşıyıcısı/Cebrail gibi) olarak okur;","der ki: 'Tanrı beni bu aşkla doğru yola iletti (delâlet eyledi).'"]],"393":[["Allah'ı arıyordum — buldumsa ne oldu (ne var bunda)?","Gece gündüz ağlardım — [şimdi sevinçle] güldümse ne oldu?"],["Erenlerin meydanında yuvarlanan [bir] top idim;","Padişah'ın (Hakk'ın) çevgânında (değneğinde) kaldımsa ne oldu? (Gûy-u çevgan — can, Hakk'ın değneğine teslim top gibi.)"],["Erenlerin sohbetinde, [bir] demet kızıl gül idim;","açıldım, ele geldim — soldumsa ne oldu (ne çıkar)?"],["Âlimler, müderrisler [onu] medresede buldular;","ben [de] harabatta (gönül meyhanesinde) buldumsa ne oldu? (Harabat, gerçek meyhane değil — tekke/mürşidin gönlü; gönül yolu, kitabî ilmin karşısında.)"],["İşit Yunus'u, işit — işte (uş) yine deli olmuş;","erenlerin mânâsına daldımsa ne oldu? (Onun 'deliliği', erenlerin manevî hakikatine dalmaktır.)"]],"394":[["Aşk benimle yoldaş olalı (olduğundan beri),","bana Rahmân'ın (Allah'ın) yolunu göstermeye önder (baş) oldu."],["Canımın üzerine dikildi (turdı), Rahmân'ın ordusunu (çeri) derdi (topladı);","Şeytan'ın ilini (ülkesini) vurdu — iyice (key) bir yağma ve süpürme (taraş) oldu."],["Aşk, nefsin iline (ülkesine) aktı — ne bulduysa yaktı;","kibir kalesini yıktı, orada çok savaş oldu (içteki cihad)."],["Dostun (Hakk'ın) yüzünü ayan (açıkça) gördüm, sır haberlerini sordum;","dedi ki: '[yoksa] gizliyi bilmezsin' — işte söyledim, [sır] açığa çıktı (fâş oldı)."],["Nefsin ili harap oldu, kibir ayaklar altında toprak (türâb) [oldu];","perde ve örtü (hicâb) gitti — Dost (Hak), gözüme karşı geldi (tuş oldı / göründü)."],["Aşk benim elim (kılavuzum) oldu, doğru yolumu gösterdi;","Hakk'a şükür ki hâlim, eskisinden (bayagı) [daha] hoş oldu."],["[Manevî] gözünü açanlar, bu dünyadan geçtiler;","bekaya (ebedîliğe) ulaştılar — menzilleri (durakları) Arş oldu."],["Bunlar [ise] burada kaldılar, dünyaya aldandılar;","yalancılar oldular — hepsi bunların, hilekâr (kolmaş) oldu."],["[Gafiller] ölenlerin hâlini bilmez, göz açıp aklını (ög) dermez (toplamaz);","meğer [bundandır ki] miskin Yunus Emre'nin bağrı yara (baş) oldu."]],"395":[["Aşkla arıyorduk — yine bulduk o canı (Sevgili'yi/can[lılık] sırrını);","[o] gömlek edinmiş, bu bedeni sûretiyle (şekliyle) giyer (can/ilahî hakikat, bedeni giysi gibi giyer)."],["Sûrete (şekle) girmiş dolaşır, bütün işleri düzenler (düzer);","yine kendine söyler — cevheriyle (öz) bu maden/kaynak (kân). (Bir olan ilahî hakikat, sûretler aracılığıyla tecellî eder — bir bakıma kendine seslenir.)"],["Bu dünya bir pazardır (bâzâr), sûretler (şekiller) dükkân olmuş;","bu dükkâna girip satan, O'dur — bu maden/kaynak (kân). (İlahî hakikat, dünyanın sûretleri aracılığıyla tecellî eder; her şey varlığını O'ndan alır — hulûl veya panteizm değil, Hak münezzeh kalır.)"],["Kimisi kaygılanır: 'bunca malım [geride] kaldı' der;","Veren O'dur, alan O — [O'nun için] ziyanın (zararın) ne olduğu sorulmaz (her şey O'nun verip almasıdır, gerçek kayıp yok)."],["Yunus, şimdi (imdi) sen kendinden ayrı değilsin, candan da [değilsin];","[O'nu] sen kendinde bulmazsan, O'nu nerede (kanda) bulursun? (Kendini bilen Rabbini bilir — Hak, insanın özünde aranır; benliğin Tanrı olması değil.)"]],"396":[["Ey dünyaya aldanan — hayrın, ihsanın (iyiliğin) hani?","Ahireti unuttun — şefkatin, imanın hani?"],["Kimde şefkat varsa, rahmet de ondadır;","şimdi gönlü açık [bir] Sünnî Müslüman hani?"],["İbrahim Halil geldi, Kâbe'nin temelini (bünyâd) attı;","oğluna bıçak çaldı — kurban [edilen] İsmail hani?"],["Şeddad bir [sahte] cennet (uçmak) yaptı, Nemrud göğe ok attı;","Karun'u da yer yuttu — Âdil Nuşirevan hani?"],["Kim istediyse buldu, kulluğu tamam oldu;","Mısır'a sağlam (key) sultan oldu — Ken'anlı Yusuf hani?"],["Resul (Peygamber) Mi'rac'a ağdı (çıktı), gökten yere nur yağdı;","'Habîbim' deyip [Allah onu] övdü — o cihanın övüncü (Fahr-ı cihân) hani?"],["Ebubekir ile Ömer — yüzlerinden nur damlar (tamar);","sînesi (göğsü) Kur'an dolu — Affan oğlu Osman hani?"],["Düldül'e binerdi, belinde Zülfikâr'ı [vardı];","erenler dini açtı (yaydı) — [o] Tanrı Arslanı (Hz. Ali) hani?"],["Çalap Tanrı'nın hası (seçkini), nazı Hazret'e (huzura) geçer [makbuldür];","Peygamber'in amcası — Hamza pehlivan hani?"],["Cüneyd-i Bağdâdî, Şiblî ve Ma'rûf-ı Kerhî —","onlar bu yolu yürüdü (vardı); şimdi o erkân (yol/töre) hani?"],["Bâyezîd-i Bestâmî — yedi kat göğün seyranı (seyircisi);","o erenler sultanı — [o] maden cevheri (gevher-i ma'den) hani?"],["Bunların çağı geçti; dünya, kahrın (kederin) ocağıdır;","Ebu'l-Müslim Necefî — [o] sâhib-i kırân (uğurlu/muzaffer) hani?"],["Bir gönül kazan (ele getür), kanaatli ol (ferâgât), çekil otur;","Konya şehrinde yatar — o iki sultan hani?"],["Fakih Ahmed Kutbüddin, Sultan Seyyid Necmüddin;","Mevlânâ Celâleddin — o cihanın kutbu (Kutb-ı cihân) hani?"],["O Seyyid Ahmed Kebîr — ona nur müyesserdi (nasipti);","müritleri (iyâlleri) hep arslan (şîr) — o mertçe huylu (hulk-ı merdân) hani?"],["Yunus Emrem, gözünü aç, yüzünü toprak eyle (alçal/fâniliği bil);","senin için de diyecekler: 'ciğeri [aşkla] kebap olan (biryân) hani?'"]],"397":[["Baktığım yüzde, Tapduk'umun nurunu gördüm;","maksudumu (gayemi) bugün buldum — ben yarını ne yaparım?"],["Yarınım, bugündür bana — hoş bir bayram, düğün[dür] bana;","düşte (görüde) bana bir ses (ün) gelir — onun haberlerini (ahbâr) işitin."],["Dostun (Hakk'ın) sözüyle (haber), nefsini kendine yâr (dost/müttefik) eyle;","bu bedenin şehrini (şâr) yık, [onu] Dost için azık/ibadet (yarag) eyle (ego kalesini yıkıp her şeyi Hakk'a adamak)."],["[İnsan] vücuda (varlığa) gelmeyince, kimse Hakk'ı bilmedi;","bu vücut (yaratılmış varlık) aracılığıyla Dost (Hak), bize dîdârını (cemalini) gösterdi. (Hak, yaratılmış varlık aracılığıyla bilinir/görünür; hulûl/bedene girme değil.)"],["Erin (velînin) dîdârını gördüm, şüphenin (gümân) terkini vurdum (bıraktım);","Dostun bahçesine girdim — gül bahçesini (gül-zâr) överim."],["Dostun yüzü bana güldür, [ben] âşığım — sen [de] O'na yol bul;","dört yana sapmam (kaykımazam), çünkü aşk erini (kâmil rehberi/Sevgili'yi) buldum."],["'Ben sizin Rabbiniz değil miyim?' (Elestü bi-Rabbiküm) — Hak'tan nidâ (seslenme) gelince;","mü'minler 'Evet (Belî)' deyip ikrarlarını (kabullerini) ettiler. (Elest bezmi — A'râf 172.)"],["'Kâlu belî' (dediler: evet) denildi; münkir (inkârcı) ile muhib (seven/mü'min) [böylece] belli oldu;","o andan (dem) beri, cahiller inkârını sürdüregeldi. (Elest'teki 'evet', mü'mini münkirden ayırdı.)"],["Yunus'u küfür (inkâr) [suçlaması] yüzünden şikâyete geldiler;","ey sultanım, [ey] gerçek er — onun zünnârını kes [de] gider (Yunus'u haksız küfür suçlamasından arındır; aşk sözleri inkâr değil)."]],"398":[["Âşık, kendi kanını (canını) maşuka helal kıldı (uğruna feda etmeyi göze aldı);","her âşık, Kur'an'ını maşukun nakşından (sûretinden/tecellîsinden) okur (Sevgili'nin güzelliğinde ilahî kelâmı okur)."],["Yârdan (Sevgili'den) ayrı olmaktansa, asılıp ölmek yeğdir;","âşık, urganı (ipi) kendi [eliyle] boynuna geçirir (ayrılığa düşmektense ölümü seçer)."],["Maşukun hayali, âşığın gözünden asla (hergiz) gitmez;","nitekim Zeliha, Yusuf'un nişanını (alâmetlerini) [ezbere] verir (zihni tümüyle sevgilinin hayaliyle dolu)."],["Âşığa dirlik (hayat) şudur: maşukun yolunda öle;","sorarlarsa, âşığın burhanını (kanıtını) söyleyeyim (gerçek aşkın delili, Sevgili yolunda ölmektir)."],["Belkıs ile Süleyman, bir zaman aşka düştü;","arayıp [da] bu derdin dermanını bulamadılar (aşkın derdine çare yok)."],["Gökteki Hârût-Mârût, aşk için yere indi;","Zühre'nin (Çoban yıldızı) yüzünü görünce, Rahmân'ını (Allah'ı) unuttular. (Hârût-Mârût efsanesi — rivayet olarak, aşkın kahredici gücüne dair; itikat değil.)"],["Aşkı boş (güzâf) görmeyin siz — kime uğradıysa,","sultanı tahttan (baştan) eder, ocağını (hânmân) yitirtir (aşkın kahredici gücü kimseyi esirgemez)."],["Ferhad, bu aşk yolunda başını külünge (taş kazmasına) tuttu;","Hüsrev, Şirin'in derdinden canını dosta (sevgiliye) verdi (aşk için can verenler)."],["Leyla ile Mecnun'un işi, bu halka şaşılası (aceb) gelir;","Abdürrezzak (Şeyh San'an), aşk için imanını terk etti. (Şeyh San'an efsanesi — aşkın kahredici imtihanına dair ibretlik bir kıssa; imandan vazgeçmenin onaylanması değil.)"],["Zamanın vefasızları (bî-vefâ), Yunus'a cefa eder;","bir doğru yâr (sadık dost/Sevgili) bulunca, [Yunus] canını feda (fidî) eder."]],"399":[["Ey dostlar (yârânlar), ey kardeşler — görün, ne ettim ahî (be kardeş);","ere (kâmile) eriştim, eri buldum, erin eteğini tuttum ahî."],["Canım, kör (gözsüz) bir candı, içi 'sen-ben' (benlik) doluydu;","miskinlik (benlik terki — fenâ) eteğini tuttum, ben menzile (durağa) eriştim ahî."],["Bir Tanrı'dan korkar oldum, kötü huydan (yatlu hu) bîzâr (bezgin) oldum;","işbu işimi (gayemi) düşünerek (sagınç), ben yoluma gittim ahî."],["Kendi hâlimi anladım, doğru yolumu gözettim;","uluların (büyüklerin/velîlerin) eteğini tuttum, Hazret'e (Hakk'ın huzuruna) ben eriştim ahî."],["Gönlümden kini giderdim — kin tutanın dini yoktur;","ey dostlar, ben bu sözü [bir] uludan (velîden) işittim ahî."],["Âşıksan, miskin Yunus, yüzünü Hazret'e (Hakk'a) tut;","söz, anlayana cevherdir (incidir) — [ben onu] sarrafa (kâmile/değerini bilene) sattım ahî."]],"400":[["Yine yüzünü gördüm, yine yüreğim yandı;","Dost, senin aşkının ateşi (odı) yüreğime dayandı (yaslandı)."],["Görklü (güzel) yüzünü gören, gönlünü sana veren,","açıkça (bellü) huzurunda (tapu) duran — ne doydu ne usandı."],["Senin özün cevherdir (incidir), yüzün güneşten [daha] saf (arı);","sözün şekerden tatlı — her kim gördü[yse] utandı (mahcup oldu)."],["Şu gönlüm garipti, ciğerim kebaptı (aşkla kavrulmuştu);","görklü (güzel) yüzünü gördüm — içim [de] dışım (taş) [da] bezendi (süslendi)."],["Yunus Emre kararsız (bî-karâr), şu güzel (hûb) yüze intizar (hasret) içinde;","nazarı (bakışı) senden ayrılmaz — vardı, yakıldı, yandı (aşkla tutuşup yandı)."]],"401":[["Müslümanlar, [bir] âşığın aşktan tövbe ettiğini kim görmüş?","Ya da, denize ateş düşüp [de] tüttüğünü (dumanı çıktığını) kim işitti? (Gerçek âşık aşktan dönmez.)"],["Şahım (Hak), senin aşkının ateşi (od), gönül deryasına (denizine) düştü;","[o deniz] kaynayıp marifetler (Hakk'a dair irfan) bitirip yeşerttiğine şaşma."],["Yüz bin İsa ile Musa [bile], aşkla başı dönmüş (ser-gerdân) gezer;","aşk timsahının (nihengin / aşk denizinin canavarının) beni de yuttuğuna şaşma."],["Yüzme/dalgıçlık (yüzgeçlik) öğrenmeyen kul, bu denize girmesin;","aşk denizi derin olur — [hazırlıksızın] battığına (boğulduğuna) şaşma."],["Sarraflığı (değer bilmeyi) öğrenmeyen, bu cevheri (inciyi) boncuk (cam süs) sanır;","gider, [onu] değersiz bir şeye verir — neye sattığını bilmez."],["Her kim o Dostun (Hakk'ın) cemalini (dîdâr) burada açıkça (ıyân) görmezse,","yarın (mahşerde) o, başı dönmüş (ser-gerdân) gezer — ne ettiğini hiç bilmez."],["İşte (uşda) miskin Yunus söyler: 'Tapduk'umuz, Dostun (Hakk'ın) yüzüdür';","bu söze inanmayan, [varsın] diyebileceğini desin. (Kâmil mürşidin yüzünde ilahî tecellînin görünmesi; mürşidin Tanrı olması değil.)"]],"402":[["Bu aşk denizine dalan için, gemiye hacet (gerek) yoktur;","yoksa (yahud), bu demi, [bu manevî] sohbetle nerede (kanda) bulalım?"],["'Dünyalığım (malım) yok' deme, bu gamı (gussa) çokça (öküş) yeme;","maşuku (Sevgili'yi) eğer sevdiysen, [o sevgi] gönüldeki gamı giderir."],["Ben sevdiğim maşuku (Sevgili'yi), sen de bir görseydin;","bu öğüdü vermezdin — sen [de] canını feda ederdin."],["Âşık kişi öğüt bilmez, zira öğüt fayda (assı) vermez;","o, kibir ile kini unutur — dükkânını (dünya kazancını) bırakıp gider."],["Gerçek (girçek) âşık olanların yüzünde [bir] nişan (alâmet) olur;","gözlerinin yaşının kanı, gece gündüz durmadan akar."],["Bu bütün âlemin sevdiği, şu din ile imandır;","vallahi, aşksız [olunca] o din ile iman [makbul/yeterli] olmaz (aşk, imanın canıdır — iman aşkla dirilir; dinin gereksizliği değil)."],["Yunus, yüzünü âşıkların ayağından kaldırma;","yüz bin canı [orada] feda et — bununla (andan) Sübhân'ı (her kusurdan münezzeh Hakk'ı) bulasın."]],"403":[["Yürü (yort), ey gönül — bir zaman âsûde (rahat), gönlü ferah (fârig), hoş yürü;","kimseden korkma, kaygılanma — gam ve tasadan (gussa) arınmış (boş) yürü."],["Hakikate bakarsan, [düşman olarak] sana nefsin yeter;","var şimdi (imdi), o nefsinle vuruş-tokuş [et], savaş[arak] yürü (içteki cihad)."],["Kişiyi (eri) yolda [yarı] bırakan, nefistir; nefse uyan, yolda kalır;","kimseyle ne işin var — [sen] nefsine öfkelen (kakı), kızgın (buş) [ol da] yürü."],["Bu dünyanın şerrinden (kötülüğünden) emin (güvende) olmak dilersen,","bu kibir ile kini bırak (terk eyle) — hırkaya gir, derviş[çe] yürü."],["Bu dünyada ebedî (hep) sarhoş (serhoş) olmak istersen,","aşk kadehini dolu kaldır — yılın on iki ayı [aşkla] sarhoş yürü. (Buradaki sarhoşluk/kadeh, ilahî aşkın mestliğidir; gerçek içki değil.)"],["Kimsenin bağına (bahçesine) girme, kimsenin gülünü derme;","var, kendi maşukunla (Sevgili'nle) bahçede el ele tutuşup (el alış) yürü."],["Gönüllerde [bir] illet (ig) olma, meclislerde (mahfil) ham (çig) olma;","ham şeyin ne tadı (dad) var — gel, aşk ateşine (od) piş[erek] yürü (aşkın potasında olgunlaş)."],["Yunus, şimdi (imdi) hoş söylersin, dilinle şerh edersin (açıklarsın);","halka nasihat satacağına, [gerçek] er ol — yolunca hoş[ça] yürü (öğüdü satmaktan çok, onu yaşa)."]],"404":[["Gönlüm bir sevdaya düştü","Gel gör beni, aşk ne eyledi","Başımı kavgaya (gavga) verdim","Gel gör beni, aşk ne eyledi"],["Ben yana yana yürürüm","Aşk beni kana boyadı","Ne akıllıyım (âkil) ne deli (dîvâne)","Gel gör beni, aşk ne eyledi"],["Ben ilden ile yürürüm","Dilden dile Dost'u sorarım","Gurbette hâlimi kim bilir","Gel gör beni, aşk ne eyledi"],["Benzim sarı, gözlerim yaşlı","Bağrım parça (pâre), yüreğim yara (baş)","Hâlimi bilen, dertli kardeş[tir]","Gel gör beni, aşk ne eyledi"],["Gurbet ilinde yürürüm","Dost'u düşümde görürüm","Uyanıp Mecnun olurum","Gel gör beni, aşk ne eyledi"],["Gâh (kimi zaman) yerler gibi tozarım","Gâh yeller gibi eserim","Gâh seller gibi çağlarım","Gel gör beni, aşk ne eyledi"],["Akarsular gibi çağlarım","Dertli ciğerimi dağlarım","Şeyhimi anıp ağlarım","Gel gör beni, aşk ne eyledi"],["Ya elimi al [da] kaldır beni","Ya aslına (özüne) erdir beni","Çok ağlattın — [bari] güldür beni","Gel gör beni, aşk ne eyledi"],["Ben çaresiz (bî-çâre) Yunus'um","Baştan ayağa yarayım","Dost ilinde avareyim","Gel gör beni, aşk ne eyledi"]],"405":[["Günü boş yere (yok yire) geçirdim","Âh, ne edeyim seni, ömrüm","Seninle [bir türlü] gani (doygun) olmadım","Âh, ne edeyim seni, ömrüm"],["Geldim [ve] geçtim, [farkına] varamadım","Ağlayıp [da] gam (gussa) yemedim","Senden ayrılırım demedim","Âh, ne edeyim seni, ömrüm"],["Seni bana yâr (yoldaş) sanırdım","Bana vefalı (vefâdâr) sanırdım","Meğer dönek/aldatıcı (aygâr) imişsin — bilmedim","Âh, ne edeyim seni, ömrüm"],["Hani sana güvendiğim","Sevinip [de] özendiğim (heves ettiğim)","Kazandığım[ın] hepsi (küllî) [geride] kalır","Âh, ne edeyim seni, ömrüm"],["Gidip [bir daha] geri gelmeyecek","Gelip beni bulmayacak","Bu beyliği (saltanatı) [artık] sürmeyecek","Âh, ne edeyim seni, ömrüm"],["Madem (çün) beni bırakıp gideceksin","Varıp mezara (sinle) gireceksin","Orada (anda) [gelip] söyleyeceksin","Âh, ne edeyim seni, ömrüm"],["Hayrım [ve] şerrim yazılacak","Ömrümün ipi üzülecek (kopacak)","Sûret (bedenimin şekli) benden bozulacak","Âh, ne edeyim seni, ömrüm"],["Miskin Yunus, gideceksin","Tuhaf/şaşılası (aceb) bir sefer edeceksin","Hasretle kalacaksın","Âh, ne edeyim seni, ömrüm"]],"406":[["Bir sâkîden (kadeh sunandan) şarap içtik — meyhanesi Arş'tan [bile] yüce;","o sâkînin mestleriyiz (sarhoşlarıyız), canlar onun kadehi (peymâne). (Buradaki şarap/sâki/meyhane, ilahî aşk ve irfanın mecazıdır; gerçek içki değil.)"],["Bizim meclisimiz [öyle] bir meclistir [ki] orada ciğer kebap olur;","orada [bir] mum (şem') yanar — ay ile güneş [onun] pervânesi[dir]."],["O muma (şem') karşı yananın bütün (küllî) varlığı (vücud) nur olur;","o ateş (od), bu [dünya] ateşine benzemez — alev dili (zebâne) hiç görünmez."],["O meclisin âşıklarından biri, İbrahim Edhem'dir (tahtını terk eden zâhid);","[aşk uğruna] Belh şehri gibi bin [şehir] olsun — her köşede [onların] viranesi (yıkıntısı). (İbrahim Edhem'in terk ettiği Belh gibi, dünya saltanatının aşk için viran edilmesi.)"],["Bizim meclisin mestlerinin (sarhoşlarının) nefesleri (dem) 'Ene'l-Hak' olur;","en âciz (kemîne) delisi (dîvâne) [bile], bin Hallâc-ı Mansûr gibidir. ('Ene'l-Hak' / 'Ben Hakk'ım', benliği Hak'ta tümüyle erimiş [fenâ] hâlde söylenir — kulun 'ben'i silinip yalnız Hakk'ın diliyle söylenen sözdür; ego'nun Tanrılık iddiası, hulûl veya panteizm değil.)"],["Aşk şarabını içenlere gel [de] bir nazar eyle (bak);","nice yıldır (bunca yıldur), o meclisin kadehi (piyâle) nasıl da döner (sürüp gider)."],["Yunus, senin bu sözlerin, bilenlere [katıksız] mânâdır;","akıllı ve olgun (âkil-kâmil) olan kişi, bu mânâya inanır (bu sözlerin altındaki hakikati kavrar)."]],"407":[["Erik dalına çıktım, orada üzüm yedim;","bostan sahibi (bostân ıssı) kızıp (kakıyup) der: 'niçin cevizimi (koz) yersin?'"],["Kerpici kazana koydum, poyrazla kaynattım;","'nedir?' diye sorana, [ekmek] banıp özünü verdim."],["İpliği çulhaya (dokumacıya) verdim, sarıp [da] yumak etmemiş;","ısrarla (becid becid) ısmarlar: 'gelsin, bezini (kumaşını) alsın.'"],["Bir serçenin kanadını, kırk kanlıya (katile) yükledim;","çifti (çift öküz) bile çekemedi — şöyle yazılı (mukadder) kaldı."],["Bir sinek, bir kartalı kaldırıp yere vurdu;","yalan değil, gerçektir — ben de tozunu gördüm."],["Balık, zift turşusu yemeye kavağa çıkmış;","leylek sıpa (koduk) doğurmuş — bak a şunun sözüne!"],["Bir kötürümle (küt) güreştim, elsiz [olduğu hâlde] ayağımı [çelip] aldı;","güreşip [de] yenemedim (basamadım) — özümü yandırdı (göyündürdi)."],["Kaf Dağı'ndan bana şöyle bir taş attılar;","öğle vakti (öylelik) yere düştü — neredeyse yüzümü berbat edecekti (bozayazdı)."],["Köre (gözsüz) fısıldadım, sağır sözümü işitmiş;","dilsiz, bağırıp (çağırup) dilimdeki sözümü söyler."],["Bir öküz boğazladım, yığıp harman yerine (sere) koydum;","öküz sahibi (ıssı) gelip der: 'kazımı boğazladın!'"],["Ona [karşı] bir hırsızlık (uğrulık) yaptım, [o] bana iftira (bühtân) etti;","bir çerçi gelip der: 'hani, aynamı (gözgü) aldın!'"],["Kaplumbağaya (tosbaga) rastladım — körköstebeğin (gözsüzsepek) yoldaşı;","'sefer nereye (kancaru)?' diye sordum — 'Kayseri'ye gidiyorum (azimi)' [dedi]."],["Yunus [öyle] bir söz söylemiş [ki] hiçbir söze benzemez;","münafıkların (iki yüzlülerin) elinden, mânânın yüzünü örter (gizler). (Bu, bir şathiyedir; abes/paradoks görünen yüzeyi, bâtınî mânâyı ehil olmayandan gizler.)"]],"408":[["Dostun yüzünü görünce, gözlerimin nuru artar;","cennet (uçmak) gözüme [bile] görünmez — binlerce (hezârân) huri olsa [da]. (Hakk'ın cemali, cennetin nimetinden üstün — menfaatsiz sevgi.)"],["Dost, gözümün nurudur, bu gönlümün sırrıdır;","bir an (dem) [bile] onsuz olamam — canım O'nunla diridir."],["Benim gece gündüz münacatım (yakarışım), o Dost iledir;","ben neredeysem (kanda), Dost oradadır — Musa ile Tur'u (Sina Dağı'ndaki tecellîyi) ne yapayım? (Dost her dem benimleyken, dışarıda bir tecellîye ihtiyacım yok.)"],["Herkesin (kamu) ihtiyacını (hâcet) yerine getiren (revâ kılan), o Dost'tur;","var, ihtiyacını O'ndan dile — yüzünü O'nun dergâhına (kapısına) sür."],["Eğer gerçek âşıksan, sır sözünü iyice (key) koru (sakla);","[zira] miskin Hallâc-ı Mansûr'u, [tek] bir söz yüzünden ateşe (od) attılar. (İlahî sırrı açıkça söylemekten sakın — Mansûr 'Ene'l-Hak' deyişiyle can verdi.)"],["Bu sözümü anlamayan, sana söyleyeyim neye benzer;","o, [bir] hayvan gibidir — dağda sürü sürü otlar (yürür)."],["Yunus, gerçek âşıksan, sapmadan (ırılmadın) dosdoğru dur;","sapmadan dosdoğru varan — işte o, [Hakk'ın] cemalini (dîdâr) görecektir."]],"409":[["Senin cevrinle (cefanla) geçirdiğim [bunca] günümü [bil ki];","aşkın ateşi (od), dumanını (dütün) Arş'a değin çıkaracak."],["Aşkın ateşi bana düştü, ben yanarım — sana ne gam?","Yanıp içim kül olmuş — sen dış giysimi (taşra ton) gözetme (boşuna bakma)."],["'Yanarak ateşe gir' desen [bile], kötülüğe (yatlu) baş eğmem;","senden yüzümü döndürmem — madem (çün) yüzümü sana tuttum (çevirdim)."],["Gündüz hâlimi gören kişi, kâfir [bile] olsa içi (özi) yanar;","kim ne bilir — ben bilirim gecemin (dün) nasıl geçtiğini."],["Niyetim (kasd) şu: şehre girip feryat u figan koparayım;","[ama] yine dönüp korkarım — düşman sesimi (ün) işitir diye."],["Yunus der ki: gerçekten ben, sonunda (âkıbet) Mecnun oldum;","'ne olmuş, Mecnun gibi[ymiş]' dersen — [bari] benim Mecnun'umu hoş tutun (ona güzel davranın)."]],"410":[["Gerçek (girçek) âşık olduysan, gel aşk kitabından oku;","can gözünü açtıysan, hakikaten Hakk'ı bulursun."],["Her (degme) âlim, bu âşıklar kitabını okuyamaz;","zira onu yazan O'dur — ezelden ebede baki (kalıcı) olan, O'dur."],["Âşıkların maşuku, Arş'ın yüzünden [bile] gözlerinden gitmez;","daima O'nun sözünden okur — zira [gerçek] fakih (din bilgini) O'dur."],["Şeyh, danişmend (âlim) ve fakih [arasında], Hakk'ı bulan, gönül yapandır;","sen bir gönül yıktıysan, istersen var [da] yüz yıl oku (boşuna — gönül yıkmak, bunca ilmi hükümsüz kılar)."],["Yunus, âşık olduysan, maşukunu (Sevgili'ni) bulduysan;","maşukunu bulan kişiye, [hiçbir] yaratılmış şeyden (nesne) baki kalmaz. (Sevgili'yi bulan, Hak'tan gayrı her şeyden geçer — fenâ.)"]],"411":[["Ne hoş (zihî) [bir] deryadır [ki] bir damladan (katre) göründü;","ne [yalnızca] deryadır ne [yalnızca] damla — işte (indi) [sırra] bak. (Bir olan ilahî 'derya'nın, 'damla'da [yaratılmışta] tecellîsi; damla deryayı gösterir — yaratılmış varlığını O'ndan alır, kaba panteizm değil.)"],["Şaşılası (aceb) [bir] damla [ki] derya onda gizli (mahfî);","bu gizli sırrı, sen kendinden sor işte. (İlahî 'derya'nın 'damla'da [özde] gizli oluşu; kendini bilmekle keşfedilir.)"],["On sekiz bin âlemin muradı (gayesi), sensin;","öyleyse (pes) bu gaflet [de] sana, kendindendir işte. (İnsan, yaratılışın gayesi/özeti; hakikatten perdeleyen gaflet ise kendi eseridir.)"],["Kendine gel (sana gel), sen kendini kendinde buluver;","kendine bak, sendeki[nin] kim olduğunu bil işte. (Kendini bilmekle, özünde tecellî edeni tanı — 'kendini bilen Rabbini bilir'; benliğin Tanrı olması değil.)"],["Fena ol (benlikten geç) ki kavuşmanın zevkini (zevk-i vuslat) bulasın;","bu sözüm bir rüya (düş) mıdır — [öyleyse] sen yorumla (yor) işte. (Benliğin silinmesi — fenâ — Hakk'a kavuşmanın zevkine erdirir.)"],["Nur ve karanlık (zulmet) perdesi (hicab), bütünüyle (külli) sende[dir];","'sen-sen,' 'ben-ben' [diye ikilik] nasıl [kalır] — [artık] dur (sus) işte. (Hakikati örten perdeler kendindendir; birlik karşısında ego'nun 'ben/sen' ikiliği son bulmalı — benliğin silinmesi; Yaratan-yaratılan ayrımının inkârı değil.)"],["[O], sana senden [bile] yakındır — iyice (tap) bak;","hükmeden[in] (Yoran — Hakîm Allah) mülküne sultan ol — [şimdi] yorumla (yor) işte. (Hak, insana kendinden yakındır — Kaf 16, 'şah damarından yakın.')"],["Aslında (kökende), âşık, maşuk ve aşk birdir;","bu Bir'den, gerçi yüz bin [sûret] göründü. (İlahî kökende/birlikte âşık-maşuk-aşk tek hakikat; çokluk, o Bir'in tecellîsidir.)"],["Bin ayna (âyîne) olsa [bile], [aynaya] bakan birdir;","gören birdir — [gerçi] görünen, bin bin göründü. (Bir olan hakikat, sayısız 'ayna'da [yaratılışta] çoğul görünür, kendisi bir kalır.)"],["Batmak (gark olmak) dileyen kim varsa — işte davet (sala);","Yunus, bu denize (bahr) dalgıç (gavvâs) ol — [şimdi] gir işte. (İlahî birlik denizinde erimeye çağrı.)"]],"412":[["Bu beden (vücud) bir kaledir, akıl [onun] içindeki sultanı;","bu gönül bir hazinedir, aşk [onu] tutmuş bekler (korur)."],["Görme (nazar) üzerine dil kapıcıdır, hepsi (cümle) akla hizmetçi (tapucı);","işleri yapan, akıldır — hepsini o bayındır (âbâd) eder."],["Akıl başta iş görür, görme (nazar) gözden bakıp görür;","akıl gönlün içinde durur — [insan] bu üç hasleti (huyu) besler."],["Akıl, başı kendine taht eyledi — böylece her işi bilir;","dünyada akıllı (âkil) kişinin zararı, kimseye dokunmaz."],["Baş, bu bedenin şahıdır; baş, aklın taht yeridir (taht-gâh);","bakışında çok öfkelenme (buşma) — öfke (buşu), aklın düşmanıdır."],["Eğer çok öfkelenir (buşar), başını nefse koşarsan (bağlarsan);","nefsin hâline düşersen — o öfkelendiğin [an], aklın hani [nerede]?"],["Akıl gitti, öfke (buşu) geldi — aklın evini öfke aldı;","şimdi sultan, öfke oldu — [artık] göze dünyayı (cihan) göstermez (öfke insanı kör eder)."],["Eğer açgözlülük (tama') edersen, gördüğüne takılıp kalırsan;","nefsini yoldan çıkarırsan (güm-râh) — basiret/görme (nazar) de fâni oldu (yitti)."],["Basiret (nazar) gitti, açgözlülük (tama') koptu — basiretin yerini açgözlülük tuttu;","[açgözlülük] nerede bastıysa fitne bitti (türedi) — yine nefse ait [işleri] işletti."],["Basiret (nazar) de gözdedir — kimde ne var bakıp görür;","açgözlülük (tama') ona düşman olur — o [hakikat] nişanını gözden savar (uzaklaştırır)."],["İman, canın kandilidir (çerağ); gövde (beden), canın durağıdır;","kin, imana düşmandır (yağı) — gelirse, imanı giderir."],["Eğer kin tutarsan, iman da senden gitti;","vallahi, o Tanrı hakkı [için] — bu sözün yalanı yoktur."],["Yunus, aşkın artadursun, canın yanıp tütedursun (göynep düte);","üstad (mürşid) kusurunu (ayb) örtedursun — [o], üstadların sultanıdır (kusurları lütufla örten kâmil rehber)."]],"413":[["Nice yıllar ömür sürdüm","Onca (anca) ağlayıp [da] güldüm","İşte ecel — sana geldim","Seni esenledim, dünyam"],["Ömrümü sürdüm, geçirdim","Canımı Hazret'e (Hakk'ın huzuruna) uçurdum","Ecel şerbetini içtim","Seni esenledim, dünyam"],["Sağ salim (sağ selâmet) yürüyordum","Takdir, melâmeti (çileyi) yazdı (eyledi)","Ecel, hoş bir melâmet (son) kıldı","Seni esenledim, dünyam"],["Gelen geçermiş — ne edelim (n'idelim)","Gelin, ahirete gidelim","Bu fâni [dünyayı] (fenâ) terk edelim","Seni esenledim, dünyam"],["Hayır [ve] şer [olarak] ettiğin işler","O görünen türlü düşler [gibiymiş]","Bitti bütün (kamu) bu kargaşalar (teşviş)","Seni esenledim, dünyam"],["Gece gündüz zikir ederdim","Hakk'a şükür, zikir kılardım","Ecel erişti — bizi [göçe] çağırır (okur)","Seni esenledim, dünyam"],["Ben bir derviştim, dostum","Niyetim (kasdım), Hak'tan yana oldu","Ecel tuzağına bastım","Seni esenledim, dünyam"],["Dostlarım (yârânlarım), kardeşlerim","Hakk'a lâyık yoldaşlarım","Esen kalsın sırdaşlarım (râzdaş)","Seni esenledim, dünyam"],["Ey çaresiz (bî-çâre) Yunus Emre","Özünü, doğru Yâr'e (Hakk'a) tut (yönelt)","Ölüme çare yokmuş","Seni esenledim, dünyam"]],"414":[["Şu dünyaya sıkıca (berk) yapıştın — sanki bırakıp gitmeyeceksin gibi;","[sanki] karanlık mezara (sin) varıp yalnız yatmayacaksın gibi."],["Bu sıkıntı yurduna (dâr-ı mihnet) geldin, fâni lezzete (geçici hazza) aldandın;","[boş] hevese kapılıp, Hak ile sohbetin tadını tatmayasın diye [uyan]."],["Behey biçare (miskin), [gözünü] aç — bu fâni [dünyaya] gözünü yum;","günahtan kararan yüzünü, hiç ağartamayasın diye [uyan]."],["Behey biçare, gafil olma — fâni dünyayı baki (kalıcı) sanma;","ecel erişince, ağzından [bir] lokmayı [bile] yutamayasın diye [uyan]."],["Derneği (topluluğu) dağıtan [ölüm] gelmiş, can ile gönül mahpus olmuş;","bütün uzuvlarını (aza) şeytan almış — öğüt tutmayasın diye [uyan]."],["Âşıklara, gönül gözü açık olanlara ta'n edersin (kınarsın);","münafıklara uymuşsun — sıdka (içtenliğe/doğruluğa) gelmeyesin diye [uyan]."],["Yunus, özün için yalvarırsan, sıdkla (içtenlikle) yola girersen;","el alıp (mürşide intisap edip) tevbe edersen — mahrum kalmayasın diye [böyle yap]. (El almak: bir mürşide bağlanmak.)"]],"415":[["Dostu gerçek sevenlerin canları, Dost'a ulaşır;","ezelden ebede, Dost (Hak) bunları kendine hayran eylemiş."],["Sabah akşam (irte gice) huzurları (ârâm) yok, gece gündüz maksudları o Efendi (hoca — Hak);","onun için, aşk gelince, sultanları tahttan yıkar (devirir)."],["O er-şah (yiğit), Dostun elinden aşk şarabını alıp içti;","onun için âhı (iniltisi) hiç gitmez — sofrası (hon), Dostun firakıdır (ayrılığıdır). (Aşk şarabı, ilahî aşkın mecazı; lokması, ayrılık derdidir.)"],["'Âşığım' diyen canların bağrı, kebaptır onların;","gözlerinin akan yaşı, ciğerlerinin kanıdır."],["'Âşığım' diyen canların bir nişanı (alâmeti) vardır;","etleri tenleri arı (tertemiz) olur, hem giysileri (ton) [bir] çul (palas) olur."]],"416":[["Ansızın (nâgâh), aşkın ateşi (od) canımızı yağmaladı;","hiç kimse, [dış] nitelikten bizim nişanımızı (alâmetimizi) veremez (bizi tarif edemez)."],["Ne imana baktırır, ne de dine [dış] ibadet ettirir;","aşkın ateşi bizi öyle bir tuttu [ki] dükkânımızı (benlik/dünya dükkânını) yıktı. (Aşkın fenâ hâlinde, âşığı, [imanın/ibadetin] dış sûretine takılmaktan alıp öze/Hakk'a çeker; dini/ibadeti inkâr/iptal değil — sûreti aşıp öze ermek.)"],["Birlikten (ilahî vahdetten) şarap verdi, dükkânı harap kıldık;","hepsini (cümle) terk ettik — kâr-zararımızı (assı-ziyan). (Vahdet şarabının mestliğinde, âşık dünyevî kâr-zararı bırakır.)"],["Ne (niçe) nişan (iz) verebilirler — hangi (kangı) yoldan [bizi] sorabilirler?","Hepsini (kamu) elden bıraktık — [kendi] dinimizi ve imanımızı [bile]. (Fenâ hâlinde âşık, 'kendi' din-imanını bile bir benlik/mülk olarak elinde tutmaktan vazgeçip tümüyle Hakk'a teslim eder — imanı inkâr/terk değil, 'benim' demekten geçip Hakk'ın kılmak.)"],["Ne kazanç (assı) var ne zarar (ziyan) — canını feda edecek (kıyan) [olan] gelsin;","hepsinden (cümle) geçip, Sultanımızı (Hakk'ı) bulduk."],["Varlığımız, birliktedir (ilahî vahdettedir); biz hepimiz (kamu) bir olduk;","[bu birlik], dilimize ikilik söylemeye [yer] bırakmaz. (Fenâ hâlinde ego'nun ikiliği ilahî birlikte erir; kulun 'ben' deyişi silinir — Tanrı olma iddiası/Yaratan-yaratılan ayrımının inkârı değil.)"],["Yüz bin dil (lisan) geldi [de], yüz bin can yolda kaldı;","yüz bin gözler [bile] göremez bizim cevlânımızı (birlikteki dolaşımımızı/hâlimizi)."],["Beraberlikten (bilelikten), canımızın hiç gamı kalmadı;","[O], hâlis (sâfî) [bir biçimde] kendinden açar madenimizi ve kaynağımızı (kân — varlığımızın pınarını)."],["Gel gör şimdi (imdi) bu kaynaktan (kân), bu madenden ne biter (türer);","birlikten ayrılmayız — mekânımızı (makamımızı) [onda] bulduk."],["Gözler nasıl (nite) görsün — kimse [bize] nasıl erişsin?","İki cihandan (dünyadan) öte, sayvanımızı (gölgeliğimizi/otağımızı) kurduk."],["Yunus, şimdi (imdi) yitip gittin (yavu var) — [gerçek] ikrar, birliktendir;","hiç kimse, bu diyardan (milk) bizim nişanımızı (izimizi) veremez. (Yunus, ilahî birlikte kaybolup silinmiş — hiçbir dünyevî 'iz'le bulunamaz; fenâ.)"]],"417":[["Yâ İlâhî, eğer bana sual edersen (sorarsan);","işte (uş) orada (mahşerde) sana cevabım budur."],["Ben kendime zulmettim, günah işledim;","sana ne yaptım, ne ettim, ey Padişah? (Günah, ancak kendime zarardır; sana değil.)"],["Ben gelmeden (var olmadan), hakkımda 'eksik/kötü (kem)' dedin;","doğmadan, 'âsi Âdem [oğlu]' dedin. (Münâcâtın, ilahî takdir karşısındaki içten/cüretli hâli — sonunda Hakk'ın rahmetine sığınır.)"],["Sen ezelde beni 'âsi' yazasın;","[sonra] âlemi [bunun] âvâzesiyle (yankısıyla) doldurasın [öyle mi]?"],["Hakkımda her ne dilediysen, [onu] işledin;","hangi hedefe (tuş) durduysam, [beni oraya] sen nişanladın (tuşladın). (Her hâlim, senin takdirinle.)"],["Beni ben mi düzdüm (yaptım), [yoksa] beni sen mi düzdün?","Niçin [beni] kusur dolu (pür ayb) yarattın, ey Ganî (hiçbir şeye muhtaç olmayan Allah)? (Münâcâtın içten cüreti — inkâr değil, rahmete sığınan bir niyaz.)"],["Gözümü açıp gördüğüm [yer], bir zindanın içiydi;","nefs ve heva ile dolu, içi şeytan[la] dolu."],["Hapsin (zindanın) içinde açlıktan ölmeyeyim diye;","[hem] temiz/helal (mismil) [hem] murdar [şeyler] yedim, bir iki [kez]."],["Senin mülkünden bir şey mi (nesne) eksildi?","Yoksa sözüm, senin hükmünü mü geçti (aştı)? (Günahım ne mülkünü eksiltir ne hükmünü aşar.)"],["Rızkını alıp, seni muhtaç mı bıraktım?","Yoksa öğününü (yemeğini) yiyip, [seni] aç mı bıraktım? (Senin rızkından yemem, seni eksiltmez.)"],["Kıl gibi (ince) bir köprü (Sırat) yaparsın, 'geç' diye;","'geçip Kevser şarabını iç' diye. (Sırat köprüsü ve Kevser.)"],["Kıl gibi (ince) Sırat'tan Âdem [oğlu] geçebilir mi?","Ya [köprü] kopar, ya [ayağı] kayar, ya [aşağı] düşer."],["Yine [de] kulunu [Sırat'tan] geçiren, senin fazlındır (lütfundur);","geçirip [de] Kevser şarabını içiren [de odur]. (Kurtaran, kulun ameli değil; Hakk'ın lütfudur.)"],["Kulların, hayır (sevap) için köprüler yapar;","onun hayrı (faydası) şudur ki [insanlar] yolculuk (seyr) için [üstünden] geçerler."],["Öyleyse (pes) gerekir ki o [köprü] orada sağlam (muhkem) ola;","görenler 'işte (uş) doğru/sağlam yol' desinler. (İyi bir köprü sağlam olmalı — nazik bir niyaz.)"],["Günahımı tartmak için terazi (mizan) kurdun;","beni ateşe atmaya kastedersin (niyet edersin)."],["Terazi, [ancak] bakkal olana gerek[ir];","ya da tüccar (bazirgân), tacir ve attar (aktar) olana. (Tartı, alışveriş edenin âletidir — her şeyi bilen Hakk'ın tartıya ne ihtiyacı var?)"],["Madem (çün) günah, murdarların (pisliklerin) [en] murdarıdır;","[o], senin huzurunda (Hazret) yaramazların (günahkârların) işidir (kârı)."],["Öyleyse (pes) niçin murdarı (günahı) açıp tartasın?","Sen, onu lütfunla örtmelisin (bağışlamalısın). (Münâcâtın özü: günahı teşhir edip tartmak yerine, rahmetinle ört.)"],["Şimdi dersin: 'seni ateşe atayım';","'şerri (kötülüğü) bir denk (zerre) [bile] fazlaysa göreyim' [diye]."],["Şerri az, hayrı çok olanı azat etmek (kurtarmak) gerekir;","hayrı [hiç] olmayanlar, orada yok oldu (helâk oldu). (Hayrı çok olana rahmet; tümüyle hayırsız olan kaybeder.)"],["Sen Basîr'sin (her şeyi görensin), zaten (hod) hâlimi bilirsin;","öyleyse (pes) amellerimi (a'mal) tartmana ne hacet (gerek var)? (Her şeyi bilen Hakk'ın tartıya ihtiyacı yok.)"],["Hâşâ (haşâlillah) [bu] senden [uzaktır], ey Rabbü'l-enâm (bütün yaratılmışların Rabbi);","sen [seyre durup] temaşa kılasın [da] ben güzelce (hoş) yanayım — [bu olamaz]. (Rahmet sahibi Rabbin, kulunu yanarken seyretmesi düşünülemez.)"],["İntikamın geçmedi mi (alınmadı mı) — [beni] öldürüp;","çürütüp, gözüme toprak doldurup? (Ölüm ve mezarın çürütmesi, yeterli bir hesap değil mi?)"],["Bir avuç toprağa (bu âciz insana) bunca kıyl u kâl (dedikodu/hesap);","neye gerek, ey Kerîm-i Zü'l-Celâl (cömertlik ve celâl sahibi Allah)? (Bir avuç toprak için bunca uzun hesap niye?)"],["Madem (çün ki) kara kıl[ların], ağardı [da] ak kıl oldu (saçın ağardı);","bu cihanın sevdalarını (tutkularını) elden bırak. (Yaşlandın — dünya tutkularını terk et.)"],["Madem (çün) Yunus'tan hiçbir zaman (hergiz) [sana] zarar gelmedi;","sen, [onun] açığını da gizlisini de (âşikâre vü nihân) bilirsin. (Yunus sana zarar vermedi; her hâlini sen bilirsin.)"],["Bizden sana, [bundan] başka (ayruk) bir cevap olmasın;","söz budur — vallahü a'lem bi's-sevab (doğrusunu Allah bilir). (Yunus, bunca cüretli niyazını, sonunda tam bir teslimiyetle Hakk'ın bilgisine bırakır.)"]]};
